export const part2: Record<string, string[]> = {
  "10:1": ["A. L. R. These (letters) are the proofs of this book of wisdom.","অ, ল, র,  এসব (অক্ষরগুলো) এই প্রজ্ঞাময় গ্রন্থের প্রমান।"],
  "10:2": ["Is it too much of a wonder for the people that we inspired a man like them? He (was inspired to say), \"You shall warn the people, and give good news to those who believe that they have attained a position of prominence at their Lord.\" The disbelievers said, \"This is a clever magician!\"","এটা কি লোকদের জন্য খুব বেশি বিস্ময়কর যে আমরা তাদের মতো কোন লোককে অনুপ্রাণিত করেছি? তাকে (অনুপ্রাণিত করা হয়েছে বলার জন্য যে), “তুমি লোকদের সতর্ক করবে, এবং যারা বিশ্বাস করে তাদেরকে সুসংবাদ দিবে যে তারা তাদের প্রভুর কাছে বিশেষ অবস্থান অর্জন করেছে”। অবিশ্বাসীরা বলল, “এ তো এক চালাক যাদুকর!"],
  "10:3": ["Your only Lord is Allah; the One who created the heavens and the earth in six days, then assumed all authority. He controls all matters. There is no intercessor, except in accordance with His will. Such is Allah your Lord. You shall worship Him. Would you not take heed?","আল্লাহ-ই তোমাদের একমাত্র প্রভু; যিনি আকাশমণ্ডলী ও পৃথিবীকে ছয় দিনে সৃষ্টি করেছেন, এরপর সকল কর্তৃত্ব গ্রহণ করেছেন। তিনি সকল বিষয় নিয়ন্ত্রণ করেন। কোন সুপারিশকারী নেই, তাঁর ইচ্ছানুসারে ব্যতিত। এমনই হচ্ছেন তোমাদের প্রভু, আল্লাহ। তোমরা তাঁর উপাসনা করবে। তোমরা কি মনোযোগী হবে না?"],
  "10:4": ["To Him is your ultimate return, all of you. This is Allah's truthful promise. He initiates the creation, then repeats it, in order to reward those who believe and lead a righteous life, equitably. As for those who disbelieve, they incur hellish drinks, and a painful retribution for their disbelieving.","তাঁর কাছে তোমাদের চূড়ান্ত প্রত্যাবর্তন, তোমাদের সকলের। এটি আল্লাহর সত্য অঙ্গীকার। তিনি সৃষ্টির সূচনা করেন, এরপর এর পুনরাবৃত্তি করেন তাদের পুরস্কৃত করার জন্য যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, ন্যায়সঙ্গতভাবে। আর তাদের বিষয়ে যারা অবিশ্বাস করে, তারা নিজেদের প্রতি টেনে এনেছে নারকীয় পানীয়, এবং এক যন্ত্রণাদায়ক শাস্তি, তাদের অবিশ্বাসের জন্য।"],
  "10:5": ["He is the One who rendered the sun radiant, and the moon a light, and He designed its phases that you may learn to count the years and to calculate. Allah did not create all this, except for a specific purpose. He explains the revelations for people who know.","তিনিই সেই সত্ত্বা, যিনি সূর্যকে করেছেন প্রজ্বলিত, এবং চাঁদকে আলোকিত, এবং তিনি এর পর্যায়সমূহ নকশা করেছেন যাতে তোমরা বছর গণনা এবং এর হিসাব করা শিখতে পারো। আল্লাহ এই সবকিছু সৃষ্টি করেননি, কোন বিশেষ উদ্দেশ্য ছাড়া। তিনি সেসব লোকদের জন্য প্রকাশনাবলী ব্যাখ্যা করেন যারা জানে।"],
  "10:6": ["Surely, in the alternation of night and day, and what Allah created in the heavens and the earth, there are proofs for people who are righteous.","নিশ্চয়, রাত এবং দিনের পালা-বদলে, এবং যা আল্লাহ আকাশমন্ডলী ও পৃথিবীতে সৃষ্টি করেছেন, তাতে লোকদের জন্য প্রমান রয়েছে যারা সৎকর্মশীল।"],
  "10:7": ["Those who are not expecting to meet us, and are preoccupied with this worldly life and are content with it, and refuse to heed our proofs;","যারা আমাদের সাক্ষাতের আশা করছে না, এবং এই পার্থিব জীবনে নিবিষ্ট হয়ে আছে ও তাতেই পরিতৃপ্ত, এবং আমাদের প্রমাণগুলোতে মনোযোগ দিতে চায় না;"],
  "10:8": ["these have incurred Hell as their ultimate abode, as a consequence of their own works.","এরা নরক টেনে এনেছে তাদের চূড়ান্ত আবাস হিসেবে, তাদের নিজেদের কাজের পরিণামে।"],
  "10:9": ["As for those who believe and lead a righteous life, their Lord guides them, by virtue of their belief. Rivers will flow beneath them in the gardens of bliss.","আর যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, তাদের প্রভু তাদের পথ-প্রদর্শন করেন, তাদের বিশ্বাসের গুণে। সবচেয়ে সুখময় বাগানসমূহে যেখানে তাদের তলদেশে প্রবাহিত হবে নদ-নদী।"],
  "10:10": ["Their prayer therein is: \"Be You glorified, our god,\" their greeting therein is, \"Peace,\" and their ultimate prayer is: \"Praise be to Allah, Lord of the universe.\"","সেখানে তাদের প্রার্থনা হচ্ছেঃ “আপনি মহিমান্বিত, আমাদের উপাস্য”। সেখানে তাদের সম্ভাষণ হচ্ছে, “শান্তি,”এবং তাদের পরম প্রার্থনা হচ্ছেঃ “প্রশংসা আল্লাহর, মহাবিশ্বের প্রভু”।"],
  "10:11": ["If Allah hastened the retribution incurred by the people, the way they demand provisions, they would have been annihilated long ago. However, we leave those who do not believe in meeting us in their transgressions, blundering.","যদি আল্লাহ লোকদের অর্জিত শাস্তি ত্বরান্বিত করতেন, যেভাবে তারা জীবিকা দাবি করে, তারা অনেক আগেই ধ্বংস হয়ে যেতো। যাহোক, যারা আমাদের সাথে সাক্ষাতে বিশ্বাস করে না আমরা তাদের সীমালঙ্ঘনে ছেড়ে দেই, পথভ্রষ্টতায় মগ্ন।"],
  "10:12": ["When adversity touches the human being, he implores us while lying down, or sitting, or standing up. But as soon as we relieve his adversity, he goes on as if he never implored us to relieve any hardship! The works of the transgressors are thus adorned in their eyes.","যখন দূর্দশা মানুষকে স্পর্শ করে, সে আমাদের কাছে শুয়ে, বসে, অথবা দাঁড়িয়ে মিনতি করে। কিন্তু, যখনই আমরা তার দূর্দশা দূর করি, সে এমনভাবে চলে যেন সে কখনোই আমাদের কাছে কোন কষ্ট দূর করতে মিনতি করেনি। সীমালঙ্ঘনকারীদের কাজ এভাবেই তাদের চোখে সজ্জিত করা হয়।"],
  "10:13": ["Many a generation we have annihilated before you when they transgressed. Their messengers went to them with clear proofs, but they refused to believe. We thus requite the guilty people.","আমরা তোমাদের আগে কত প্রজন্মই না ধ্বংস করেছি যখন তারা সীমালঙ্ঘন করেছিল। তাদের কাছে তাদের বার্তাবাহকগন সুস্পষ্ট প্রমাণাদি নিয়ে গিয়েছিল, কিন্তু তারা বিশ্বাস করতে প্রত্যাক্ষান করেছিল। আমরা এভাবেই অপরাধী লোকদের প্রতিফল দেই।"],
  "10:14": ["Then we made you inheritors of the earth after them, to see how you will do.","এরপর আমরা তাদের পর তোমাদেরকে পৃথিবীর উত্তরাধিকারী করলাম, তোমরা কেমন করবে তা দেখতে।"],
  "10:15": ["When our revelations are recited to them, those who do not expect to meet us say, \"Bring a Quran other than this, or change it!\" Say, \"I cannot possibly change it on my own. I simply follow what is revealed to me. I fear, if I disobey my Lord, the retribution of an awesome day.\"","যখন আমাদের প্রকাশনাবলি তাদের কাছে আবৃতি করা হয়, যারা আমাদের সাথে সাক্ষাতের আশা করে না তারা বলে, \"এটা ছাড়া অন্য কোন কুরআন নিয়ে আসো, অথবা একে পরিবর্তন করো।”বলএটা সম্ভবই না যে আমি নিজে নিজে এর পরিবর্তন করি। আমি শুধু অনুসরণ করি যা আমার কাছে প্রকাশিত হয়। আমি ভয় করি, সেই ভয়ঙ্কর দিনের শাস্তিকে, যদি আমি আমার প্রভুকে অমান্য করি। \""],
  "10:16": ["Say, \"Had Allah willed, I would not have recited it to you, nor would you have known anything about it. I have lived among you a whole life before this (and you have known me as a sane, truthful person). Do you not understand?\"","বল, “আল্লাহ যদি চাইতেন, না আমি এটি তোমাদের কাছে আবৃতি করতাম, না তোমরা এটি সম্পর্কে কোনকিছু জানতে পারতে। আমি তোমাদের মধ্যে এর আগের পুরোটা জীবন পার করেছি (এবং তোমরা আমাকে একজন বিবেকবান, সত্যবাদী ব্যক্তি হিসেবে জেনেছো)। তোমরা কি বুঝো না?”"],
  "10:17": ["Who is more evil than one who fabricates lies about Allah, or rejects His revelations. Certainly, the transgressors never succeed.","কে তার চেয়ে বেশি মন্দ যে আল্লাহ সম্পর্কে মিথ্যা রচনা করে, অথবা তাঁর প্রকাশনাবলি প্রত্যাখ্যান করে? নিশ্চয়, সীমাতিক্রমকারীরা কখনো সফল হয় না।"],
  "10:18": ["They worship beside Allah idols that possess no power to harm them or benefit them, and they say, \"These are our intercessors at Allah!\" Say, \"Are you informing Allah of something He does not know in the heavens or the earth?\" Be He glorified. He is the Most High; far above needing partners.","তারা আল্লাহর পাশে অংশীদারদের উপাসনা করে যা তাদের ক্ষতি বা উপকার করার কোন ক্ষমতা রাখে না, এবং তারা বলে, “এরা আল্লাহর কাছে আমাদের সুপারিশকারী!” বল, “তোমরা কি আল্লাহকে আকাশমন্ডলী বা পৃথিবীর কোনকিছু জানাচ্ছ যা তিনি জানেন না?” তিনি মহিমান্বিত। তিনি সর্বোচ্চ; অংশীদারের প্রয়োজন থেকে অনেক উর্ধ্বে।"],
  "10:19": ["The people used to be one congregation, then they disputed. If it were not for a predetermined word from your Lord, they would have been judged immediately regarding their disputes.","লোকেরা এক ধর্মীয় সম্প্রদায়ভূক্ত ছিল, এরপর তারা বিবাদ করলো। যদি এটা আল্লাহর পক্ষ থেকে কোন পূর্ব নির্ধারিত আদেশ না হতো, তারা তাৎক্ষণাৎ তাদের বিবাদের বিষয়ে রায় পেতো।"],
  "10:20": ["They say, \"How come no miracle came down to him from his Lord?\" Say, \"The future belongs to Allah; so wait, and I am waiting along with you.\"","তারা বলে, “কেমন করে তার কাছে তার প্রভুর পক্ষ থেকে কোন অলৌকিকতা অবতীর্ণ হল না?’ বল, “ভবিষ্যৎ আল্লাহর অধীনে; তাই অপেক্ষা করো, এবং আমিও তোমাদের সাথে অপেক্ষা করছি”।"],
  "10:21": ["When we bestow mercy upon the people, after adversity had afflicted them, they immediately scheme against our revelations! Say, \"Allah's scheming is far more effective. For our messengers are recording everything you scheme.\"","লোকেরা দুর্দশাগ্রস্থ হওয়ার পর আমরা যখন তাদের উপর দয়া করলাম, তারা তৎক্ষনাৎ আমাদের প্রকাশনাবলির বিরুদ্ধে ষড়যন্ত্র করলো! বল, \"আল্লাহর পরিকল্পনা আরো অধিক কার্যকর। কারণ আমাদের বার্তাবাহকরা তোমাদের সকল ষড়যন্ত্র সংরক্ষণ করছে।"],
  "10:22": ["He is the One who moves you across the land and sea. You get onto the ships, and they sail smoothly in nice breeze. Then, while rejoicing therein, violent wind blows, and the waves surround them from every side. This is when they implore Allah, sincerely devoting their prayers to Him alone: \"If You only save us this time, we will be eternally appreciative.\"","তিনিই সে সত্ত্বা যিনি তোমাদেরকে ভূখণ্ড এবং সাগরে ভ্রমন করান। তোমরা জাহাজে আরোহন করো এবং এগুলো পাল খাটিয়ে চমৎকার মৃদু বাতাসে   মসৃণভাবে চলে। এরপর, যখন সেখানে তারা আনন্দ করতে থাকে, যখন প্রচণ্ড বাতাস প্রবাহিত হয়, এবং ঢেউ তাদেরকে সব দিক থেকে ঘিরে ফেলে। সেই মুহূর্তেই তারা আল্লাহর কাছে মিনতি করে, তাদের প্রার্থনা আন্তরিকভাবে একমাত্র তাঁর নিকট উৎসর্গ করে, \"আপনি যদি আমাদেরকে এবারের মতো রক্ষা করেন, আমরা চিরকাল কৃতজ্ঞ থাকবো।"],
  "10:23": ["But as soon as He saves them, they transgress on earth, and oppose the truth. O people, your transgression is only to the detriment of your own souls. You remain preoccupied with this worldly life, then to us is your ultimate return, then we inform you of everything you had done.","কিন্তু যেই মুহূর্তে তিনি তাদের রক্ষা করেন, তারা পৃথিবীতে সীমালঙ্ঘন করে, এবং সত্যের বিরোধিতা করে। হে লোকেরা, তোমাদের সীমালঙ্ঘন শুধু তোমাদের নিজ আত্মার ক্ষতি করে। তোমরা এই পার্থিব জীবনে নিয়ে নিবিষ্ট থাকো, এরপর আমাদের কাছে তোমাদের চূড়ান্ত প্রত্যাবর্তন, এরপর আমরা তোমাদেরকে জানাবো যা তোমরা করেছিলে।"],
  "10:24": ["The analogy of this worldly life is like this: we send down water from the sky to produce with it all kinds of plants from the earth, and to provide food for the people and the animals. Then, just as the earth is perfectly adorned, and its people think that they are in control thereof, our judgment comes by night or by day, leaving it completely barren, as if nothing existed the previous day. We thus explain the revelations for people who reflect.","এই পার্থিব জীবনের উপমা হচ্ছে এরকম: আমরা আকাশ থেকে পানি বর্ষণ করি, তা দিয়ে পৃথিবী থেকে সব ধরণের উদ্ভিদ উৎপন্ন করতে, এবং লোকদের ও প্রানীদের জন্য খাদ্যের সংস্থান করতে। এরপর, যখনই পৃথিবীকে যথাযথভাবে সজ্জিত করা হয়, এবং এর লোকেরা ভাবে যে তারা এর নিয়ন্ত্রনে, আমাদের বিচার আসে রাতে বা দিনে, একে সম্পূর্ণ ধূলিসাৎ করে দিয়ে, যেন আগের দিন কোনকিছুরই অস্তিত্ব ছিল না। আমরা এভাবে প্রকাশনাবলি ব্যাখ্যা করি সে লোকদের জন্য যারা গভীর ভাবে চিন্তা করে।"],
  "10:25": ["Allah invites to the abode of peace, and guides whomever He wills in a straight path.","আল্লাহ শান্তির নীড়ের দিকে আমন্ত্রন করেন, এবং যাকে ইচ্ছা তিনি সরল পথে পরিচালিত করেন।"],
  "10:26": ["For the righteous, the reward will be multiplied manifold. Their faces will never experience any deprivation or shame. These are the dwellers of Paradise; they abide therein forever.","সৎকর্মশীলদের জন্য, পুরুস্কার বহুগুনে বৃদ্ধি করা হবে। তাদের মুখমণ্ডলসমূহ কখনো কোন বঞ্চনা বা লজ্জা অনুভব করবে না। এরাই স্বর্গের বাসিন্দা; তারা সেখানে চিরকাল বাস করে।"],
  "10:27": ["As for those who earned sins, their requital is equivalent to their sin. Humiliation is their lot, and no one beside Allah can protect them. Their faces will seem overwhelmed by masses of dark night. They will be the dwellers of Hell; they abide therein forever.","আর তাদের ক্ষেত্রে যারা পাপ অর্জন করেছে, তাদের প্রতিফল তাদের পাপের সমতুল্য। অপমান হচ্ছে তাদের ভাগ্য, এবং আল্লাহর পাশে অন্য কেউ তাদেরকে রক্ষা করতে পারে না। তাদের মুখমণ্ডলকে মনে হবে যেন অন্ধকার রাতের টুকরা দিয়ে ছেয়ে আছে। তারা হবে নরকের বাসিন্দা; তারা সেখানে চিরকাল বাস করবে।"],
  "10:28": ["On the day when we summon them all, we will say to those who worshiped idols, \"We have summoned you, together with your idols.\" We will have them confront each other, and their idols will say to them, \"We had no idea that you idolized us.","সেদিন যখন আমরা তাদের সকলকে সমবেত করবো, যারা অংশীদার উপাসনা করেছিল আমরা তাদের বলব, “আমরা তোমাদের একত্রিত করেছি, তোমাদের উপাস্যদের সাথে”। আমরা তাদেরকে একে অন্যের মুখোমুখি করবো, এবং তাদের উপাস্যরা তাদেরকে বলবে, “আমাদের কোন ধারনা ছিল না যে তোমরা আমাদের উপাস্য করেছ”।"],
  "10:29": ["Allah suffices as a witness between us and you, that we were completely unaware of your worshiping us.","“আমাদের এবং তোমাদের মাঝে সাক্ষী হিসাবে আল্লাহ যথেষ্ট, যে আমরা সম্পূর্ণ অনবগত ছিলাম আমাদেরকে তোমাদের উপাসনার ব্যাপারে”।"],
  "10:30": ["That is when each soul will examine everything it had done. They will be returned to Allah, their rightful Lord and Master, and the idols they had fabricated will disown them.","সেই সময় প্রত্যেক আত্মা পরীক্ষা করবে সবকিছু যা সে করেছিল। তারা তাদের ন্যায়সঙ্গত প্রভু এবং মনিব, আল্লাহর কাছে ফিরে যাবে এবং তাদের বানানো উপাস্যরা তাদেরকে প্রত্যাক্ষান করবে।"],
  "10:31": ["Say, \"Who provides for you from the heaven and the earth? Who controls all the hearing and the eyesight? Who produces the living from the dead, and the dead from the living? Who is in control of all things?\" They would say, \"Allah.\" Say, \"Why then do you not observe the commandments?\"","বল, “কে আকাশ এবং পৃথিবী থেকে তোমাদের জন্য জীবিকা প্রদান করেন? কে তোমাদের সকল শ্রবন এবং দৃষ্টিশক্তি নিয়ন্ত্রন করেন? কে মৃত থেকে জীবিতকে বের করেন, এবং জীবিত থেকে মৃতকে বের করেন? কে সবকিছুর নিয়ন্ত্রনে রয়েছেন? তারা বলবে, “আল্লাহ”। বল, “তাহলে কেন তোমরা প্রত্যাদেশগুলো পালন করো না?”"],
  "10:32": ["Such is Allah, your rightful Lord. What is there after the truth, except falsehood? How could you disregard all this?","এমনই আল্লাহ, তোমাদের ন্যয়সঙ্গত প্রভু। সত্যের পর আর কি থাকতে পারে, মিথ্যা ছাড়া? কিভাবে তোমরা এই সবকিছু উপেক্ষা করতে পারো?"],
  "10:33": ["This is what your Lord's decision does to those who choose to be wicked: they cannot believe.","এটিই হচ্ছে আল্লাহর সিদ্ধান্ত তাদের প্রতি যারা মন্দ হতে চায়; তারা বিশ্বাস করতে পারে না।"],
  "10:34": ["Say, \"Can any of your idols initiate creation, then repeat it?\" Say, \"Allah initiates the creation, then repeats it.\"","বল, “তোমাদের কোন উপাস্য কি সৃষ্টির সূচনা করে, এরপর এর পূনঃরাবৃতি করে? বল, “আল্লাহ সৃষ্টির সূচনা করেন, এরপর এর পূনঃরাবৃতি করেন?”"],
  "10:35": ["Say, \"Does any of your idols guide to the truth?\" Say, \"Allah guides to the truth. Is one who guides to the truth more worthy of being followed, or one who does not guide, and needs guidance for himself? What is wrong with your judgment?\"","বল, “তোমাদের কোন উপাস্য কি সত্যের দিকে পথ-প্রদর্শন করেন?”বল, “আল্লাহ সত্যের দিকে পথ-প্রদর্শন করেন। যে সত্যের দিকে পথ-প্রদর্শন করে সে কি অনুসরণের অধিক যোগ্য, নাকি যে পথ-প্রদর্শন করে না, বরং নিজের জন্যই পথ-নির্দেশনার দরকার হয়? তোমাদের বিচার-বিবেচনায় সমস্যা কি?"],
  "10:36": ["Most of them follow nothing but conjecture, and conjecture is no substitute for the truth. Allah is fully aware of everything they do.","তাদের অধিকাংশই অনুমান ছাড়া কিছু অনুসরণ করে না, এবং অনুমান সত্যের কোন বিকল্প নয়। তারা যা কিছু করে আল্লাহ সে সম্পর্কে সম্পূর্ণ অবগত।"],
  "10:37": ["This Quran could not possibly be authored by other than Allah. It confirms all previous messages, and provides a fully detailed scripture. It is infallible; for it comes from the Lord of the universe.","আল্লাহ ব্যতিত অন্য কারো পক্ষে কুরআন রচনা সম্ভব হতেই পারে না। এটি সকল পূর্ববর্তী বার্তা নিশ্চিত করে, এবং প্রদান করে একটি পূর্ণ বিস্তারিত ঐশীগ্রন্থ। এটি ভূলের উর্ধ্বে; কারন এটি মহাবিশ্বের প্রভুর কাছ থেকে আগত।"],
  "10:38": ["If they say, \"He fabricated it,\" say, \"Then produce one sura like these, and invite whomever you wish, other than Allah, if you are truthful.\"","যদি তারা বলে, “সে এটা মিথ্যা উদ্ভাবন করেছে,”“তবে এগুলোর মতো একটি সুরা তৈরি করো, এবং অন্য যে কাউকে ইচ্ছা আমন্ত্রন করো, আল্লাহ ছাড়া, যদি তোমরা সত্যবাদী হও”।"],
  "10:39": ["Indeed, they have rejected this without studying and examining it, and before understanding it. Thus did those before them disbelieve. Therefore, note the consequences for the transgressors.","নিশ্চয়, তারা এটি অধ্যয়ন এবং পরখ না করে, এবং এটি বুঝার আগেই প্রত্যাখ্যান করেছে। এভাবেই তাদের পূর্ববর্তীরা অবিশ্বাস করেছিল। সুতরাং, সীমাতিক্রমকারীদের পরিণাম লক্ষ্য করো।"],
  "10:40": ["Some of them believe (in this scripture), while others disbelieve in it. Your Lord is fully aware of the evildoers.","তাদের কেউ কেউ বিশ্বাস করে (এই ঐশীগ্রন্থে), যখন অন্যরা এতে অবিশ্বাস করে। তোমার প্রভু মন্দকর্মীদের ব্যাপারে পূর্ণ অবগত।"],
  "10:41": ["If they reject you, then say, \"I have my works, and you have your works. You are innocent of anything I do, and I am innocent of anything you do.\"","যদি তারা তোমাকে প্রত্যাখ্যান করে, তবে বল, “আমার কর্ম আমার জন্য, এবং তোমাদের কর্ম তোমাদের জন্য। আমি যা কিছু করি তার জন্য তোমরা দায়ী নও, এবং তোমরা যা কিছু করো তার জন্য আমি দায়ী নই”।"],
  "10:42": ["Some of them listen to you, but can you make the deaf hear, even though they cannot understand?","তাদের কেউ কেউ তোমার কথা শোনে, কিন্তু তুমি কি বধিরকে শোনাতে পারো, যদিও তারা বুঝতে পারে না?"],
  "10:43": ["Some of them look at you, but can you guide the blind, even though they do not see?","তাদের কেউ কেউ তোমার দিকে তাকায়, কিন্তু তুমি কি অন্ধকে পথ দেখাতে পারো, যদিও তারা দেখে না?"],
  "10:44": ["Allah never wrongs the people; it is the people who wrong their own souls.","আল্লাহ কখনো লোকদের প্রতি ক্ষতি করেন না; লোকেরা নিজেরাই তাদের আত্মার ক্ষতি করে।"],
  "10:45": ["On the day when He summons all of them, they will feel as if they lasted in this world one hour of the day, during which they met. Losers indeed are those who disbelieved in meeting Allah; and chose to be misguided.","সে দিন যখন তিনি তোমাদের সকলকে সমবেত করবেন, তারা সাক্ষাতের সময়, উপলব্ধি করবে যে তারা এই দুনিয়াতে দিনের একটি ঘণ্টা অবস্থান করেছিল। তারা নিশ্চয় ক্ষতিগ্রস্থ যারা আল্লাহর সাথে সাক্ষাতে অবিশ্বাস করেছিল; এবং পথভ্রষ্টতা বেছে নিয়েছিল।"],
  "10:46": ["Whether we show you some (of the retribution) we promise them, or terminate your life before that, to us is their ultimate return. Allah witnesses everything they do.","যে (শাস্তির) বিষয়ে আমরা তাদের অঙ্গীকার করি যদি এর কিছু অংশ আমরা তোমাকে দেখাই, অথবা এর আগেই তোমার জীবনাবসান করি, তবে আমাদের কাছে তাদের চূড়ান্ত প্রত্যাবর্তন। আল্লাহ তাদের করা সবকিছুর সাক্ষী।"],
  "10:47": ["To each community, a messenger. After their messenger comes, they are judged equitably, without the least injustice.","প্রত্যেক সম্প্রদায়ের প্রতি, একজন বার্তাবাহক। তাদের বার্তাবাহক আসার পর, তাদেরকে ন্যায়সঙ্গতভাবে মূল্যায়ন করা হয়, সামান্যতম অবিচার ছাড়াই।"],
  "10:48": ["They challenge: \"When will this prophecy come to pass, if you are telling the truth?\"","তারা চ্যালেঞ্জ করেঃ “কখন এই ভবিষ্যৎবানী ঘটবে, যদি তুমি সত্য বলে থাক?"],
  "10:49": ["Say, \"I possess no power to harm myself, or benefit myself; only what Allah wills takes place.\" Each community has a predetermined life span. Once their interim comes to an end, they cannot delay it by one hour, nor advance it.","বল, “আমার কোন ক্ষমতা নেই নিজের ক্ষতি করার, অথবা নিজের উপকার করার; আল্লাহ যা চান শুধু তা-ই হয়”। প্রত্যেক সম্প্রদায়ের একটি পূর্বনির্ধারিত জীবনকাল রয়েছে। যখন তাদের সময় শেষ হয়ে যায়, তারা একে এক ঘণ্টা বিলম্ব করাতে পারে না, না একে এগোতে পারে।"],
  "10:50": ["Say, \"Whether His retribution comes to you by night or by day, why are the transgressors in such a hurry?","বল, “যদি তোমাদের কাছে তাঁর শাস্তি রাতে বা দিনে আসে, তবে কেন সীমালঙ্গনকারীরা এমন তাড়াহুড়া করছে?"],
  "10:51": ["\"If it does happen, will you believe then? Why should you believe then? You used to challenge it to come?\"","“যদি এটা ঘটে, তোমরা কি তখন বিশ্বাস করবে? কেন তোমরা তখন বিশ্বাস করবে? তোমরা এর আসার ব্যাপারে চ্যালেঞ্জ করতে?"],
  "10:52": ["It will be said to the transgressors, \"Taste the eternal retribution. Are you not requited precisely for what you have earned?\"","সীমালঙ্ঘনকারীদের বলা হবে, “চিরস্থায়ী শাস্তি আস্বাদন করো। তোমরা কি সঠিক প্রতিদান পাওনি যা অর্জন করেছ তার জন্য”।"],
  "10:53": ["They challenge you to prophesy: \"Is this really what will happen?\" Say, \"Yes indeed, by my Lord, this is the truth, and you can never escape.\"","তারা তোমার ভবিষ্যদ্বানী করাকে চ্যালেঞ্জ করেঃ “এটা কি সত্যিই ঘটবে?”বল, “হ্যাঁ নিশ্চয়, আমার প্রভুর শপথ, এটাই সত্য, এবং তোমরা কখনই পালাতে পারবে না”।"],
  "10:54": ["If any wicked soul possessed everything on earth, it would readily offer it as ransom. They will be ridden with remorse when they see the retribution. They will be judged equitably, without the least injustice.","যদি কোন মন্দ আত্মা পৃথিবীর সবকিছুর অধিকারী হয়, সে তৎক্ষণাৎ মুক্তিপন হিসাবে তা উপস্থাপন করবে। যখন তারা শাস্তি দেখবে তারা অনুশোচনায় জর্জরিত হবে। তারা ন্যায়সঙ্গতভাবে বিচার পাবে, সামান্যতম অবিচার ছাড়া।"],
  "10:55": ["Absolutely, to Allah belongs everything in the heavens and the earth. Absolutely, Allah's promise is truth, but most of them do not know.","নিঃসন্দেহে, আকাশমণ্ডলী এবং পৃথিবীর সবকিছু আল্লাহর। নিঃসন্দেহে, আল্লাহর অঙ্গীকার সত্য, কিন্তু তাদের অধিকাংশই জানে না।"],
  "10:56": ["He controls life and death, and to Him you will be returned.","তিনি জীবন এবং মৃত্যু নিয়ন্ত্রন করেন, এবং তাঁর কাছেই তোমাদের প্রত্যাবর্তন।"],
  "10:57": ["O people, enlightenment has come to you herein from your Lord, and healing for anything that troubles your hearts, and guidance, and mercy for the believers.","হে লোকেরা, এখানে তোমাদের প্রভুর কাছ থেকে এসেছে জ্ঞানালোক, এবং যা কিছু তোমাদের হৃদয়কে যন্ত্রণা দেয়, তার জন্য নিরাময়, এবং পথনির্দেশনা, এবং বিশ্বাসীদের জন্য দয়া।"],
  "10:58": ["Say, \"With Allah's grace and with His mercy they shall rejoice.\" This is far better than any wealth they can accumulate.","বল, “আল্লাহর করুণা এবং তাঁর দয়ায় তারা আনন্দ করবে”। এটা যেকোন সম্পদ থেকে অনেক উত্তম যা তারা সঞ্চয় করতে পারে।"],
  "10:59": ["Say, \"Did you note how Allah sends down to you all kinds of provisions, then you render some of them unlawful, and some lawful?\" Say, \"Did Allah give you permission to do this? Or, do you fabricate lies and attribute them to Allah?\"","বল, “তোমরা কি লক্ষ্য করেছো, কিভাবে আল্লাহ সকল প্রকার জীবিকা তোমাদের নিকট অবতীর্ণ করেন, এরপর তোমরা এগুলোর কতগুলোকে বে-আইনি, এবং কতগুলোকে আইনসিদ্ধ বলে উপস্থাপন করো?”বল, “আল্লাহ কি তোমাদের এটা করার অনুমতি দিয়েছেন?”নাকি তোমরা মিথ্যা বানাও এবং সেগুলো আল্লাহর প্রতি আরোপ করো?”"],
  "10:60": ["Does it ever occur to those who fabricate lies about Allah that they will have to face Him on the Day of Resurrection? Certainly, Allah showers the people with His grace, but most of them are unappreciative.","যারা আল্লাহ সম্পর্কে মিথ্যা বানায় তাদের কি কখনো এটা মনে হয় যে, তাদেরকে পুনরুত্থান দিনে তাঁর মুখোমুখি হতে হবে? নিশ্চয়, আল্লাহ লোকদের প্রতি তাঁর করুণা বর্ষণ করেন, কিন্তু তাদের অধিকাংশই অকৃতজ্ঞ।"],
  "10:61": ["You do not get into any situation, nor do you recite any Quran, nor do you do anything, without us being witnesses thereof as you do it. Not even an atom's weight is out of your Lord's control, be it in the heavens or the earth. Nor is there anything smaller than an atom, or larger, that is not recorded in a profound record.","তোমরা এমন কোন পরিস্থিতির মধ্যে জড়িত হও না, না তোমরা আবৃতি করো কোন কুরআন, না তোমরা কোন কিছু করো, যাতে আমরা সাক্ষী থাকি না যখন তোমরা তা করো। এমনকি একটি পরমানুর ভরও তোমার প্রভুর নিয়ন্ত্রনের বাইরে নয়, তা হোক আকাশমণ্ডলীতে অথবা পৃথিবীতে। না কোন কিছু আছে পরমানুর চেয়ে ছোট, অথবা বড়, যা লিপিবদ্ধ নেই একটি সুস্পষ্ট দলিলে।"],
  "10:62": ["Absolutely, Allah's allies have nothing to fear, nor will they grieve.","নিঃসন্দেহে, আল্লাহর মিত্রদের কোন ভয় নেই, না তারা শোক করবে।"],
  "10:63": ["They are those who believe and lead a righteous life.","তারা হচ্ছে সেসব লোক যারা বিশ্বাস করে এবং ন্যায়পরায়ন জীবন-যাপন করে।"],
  "10:64": ["For them, joy and happiness in this world, as well as in the Hereafter. This is Allah's unchangeable law. Such is the greatest triumph.","তাদের জন্য, আনন্দ এবং সুখ এই দুনিয়ায়, সেই সাথে পরকালে। এটা আল্লাহর অপরিবর্তনীয় আইন, এটাই হচ্ছে শ্রেষ্ঠ বিজয়।"],
  "10:65": ["Do not be saddened by their utterances. All power belongs to Allah. He is the Hearer, the Omniscient.","তাদের কথায় দুঃখ পেও না। সকল ক্ষমতা আল্লাহর। তিনি সর্বশ্রোতা, সর্বজ্ঞ।"],
  "10:66": ["Absolutely, to Allah belongs everyone in the heavens and everyone on earth. Those who set up idols beside Allah are really following nothing. They only think that they are following something. They only guess.","নিঃসন্দেহে, আকাশমণ্ডলীর সকলে এবং পৃথিবীর সকলে আল্লাহর অধীন। যারা আল্লাহর পাশে উপাস্য স্থাপন করে তারা প্রকৃতপক্ষে কিছুই অনুসরন করছে না। তারা শুধু ভাবে যে তারা কোন কিছু অনুসরণ করছে। তারা শুধু অনুমান করে।"],
  "10:67": ["He is the One who rendered the night for your rest, and rendered the day lighted. These are proofs for people who can hear.","তিনিই সে সত্ত্বা যিনি রাতকে করেছেন তোমাদের বিশ্রামের জন্য, এবং দিনকে করেছেন আলোকিত। এগুলো প্রমান সে লোকদের জন্য যারা শুনতে পারে।"],
  "10:68": ["They said, \"Allah has begotten a son!\" Be He glorified. He is the Most Rich. To Him belongs everything in the heavens and everything on earth. You have no proof to support such a blasphemy. Are you saying about Allah what you do not know?","তারা বলে, “আল্লাহ পুত্র জন্ম দিয়েছেন!” মহিমা তাঁরই। তিনি সবচেয়ে ধনী। আকাশমণ্ডলীর সবকিছু এবং পৃথিবীর সবকিছু তাঁর। এমন মিথ্যারোপের সমর্থনে তোমাদের কোন প্রমান নেই।  আল্লাহর যে বিষয়ে  তোমরা জানো না, তোমরা কি তা বলছো?"],
  "10:69": ["Proclaim: \"Those who fabricate lies about Allah will never succeed.\"","ঘোষণা করোঃ “যারা আল্লাহ সম্পর্কে মিথ্যা বানায় তারা কখনোই সফল হবে না”।"],
  "10:70": ["They get their temporary share in this world, then to us is their ultimate return, then we commit them to severe retribution for their disbelieving.","তারা এই বিশ্বে তাদের ক্ষণস্থায়ী অংশ পায়, এরপর আমাদের কাছে তাদের চুড়ান্ত প্রত্যাবর্তন, এরপর আমরা তাদের অবিশ্বাসের জন্য তাদেরকে কঠিন শাস্তি প্রদান করি।"],
  "10:71": ["Recite for them the history of Noah. He said to his people, \"O my people, if you find my position and my reminding you of Allah's revelations too much for you, then I put my trust in Allah. You should get together with your leaders, agree on a final decision among yourselves, then let me know it without delay.","তাদের জন্য আবৃতি করো নুহের ইতিহাস। সে তার লোকদের বলেছিল, “হে আমার লোকেরা,  যদি তোমরা আমার অবস্থান এবং তোমাদেরকে আমার আল্লাহর প্রকাশনাবলি স্মরণ করিয়ে দেয়াকে তোমাদের জন্য সাধ্যের অতীত মনে করো, তাহলে আল্লাহতে আমি আমার আস্থা রাখি। তোমাদের উচিত তোমাদের নেতাদের সাথে মিলিত হওয়া, তোমাদের নিজেদের মাঝে একটি চুড়ান্ত সিদ্ধান্তে সম্মত হওয়া, এরপর অনতিবিলম্বে আমাকে তা জানানো।"],
  "10:72": ["\"If you turn away, then I have not asked you for any wage. My wage comes from Allah. I have been commanded to be a submitter.\"","\"যদি তোমরা মুখ ফিরিয়ে নাও, আমি তো তোমাদের কাছে কোন পারিশ্রমিক চাই নি। আমার পারিশ্রমিক আল্লাহ থেকে আসে। আমাকে একজন আত্মসমর্পণকারী হওয়ার জন্য আদেশ করা হয়েছে।"],
  "10:73": ["They rejected him and, consequently, we saved him and those who joined him in the ark; we made them the inheritors. And we drowned those who rejected our revelations. Note the consequences; they have been warned.","তারা তাকে প্রত্যাক্ষান করলো এবং, পরিনামে, আমরা তাকে এবং যারা তার সাথে নৌকায় যোগ দিয়েছিল তাদের রক্ষা করলাম; আমরা তাদেরকে উত্তরাধিকারী বানালাম। আর আমরা ডুবিয়ে দিলাম তাদেরকে যারা আমাদের প্রকাশনাবলি প্রত্যাক্ষান করেছিল। পরিনাম লক্ষ করো; তাদের সতর্ক করা হয়েছিল।"],
  "10:74": ["Then we sent after him messengers to their people, and they showed them clear proofs. But they were not to believe in what they had rejected in the past. We thus seal the hearts of the transgressors.","এরপর আমরা তার পরবর্তীতে তাদের লোকদের কাছে বার্তাবাহকদের পাঠালাম, এবং তারা তাদেরকে সুস্পষ্ট প্রমানাদি দেখালো। কিন্তু তারা তাতে বিশ্বাস করার ছিল না যা তারা অতীতে প্রত্যাক্ষান করেছিল। আমরা এভাবে সীমালংঘনকারীদের হৃদয়ে মোহর মেরে দেই।"],
  "10:75": ["Then we sent after them Moses and Aaron to Pharaoh and his group, with our proofs. But they turned arrogant; and were transgressing people.","এরপর আমরা তাদের পরবর্তীতে ফেরাউন এবং তার দলের কাছে মুসা ও হারুনকে পাঠালাম, আমাদের প্রমানাদি সহকারে। কিন্তু তারা উদ্ধত হলো; এবং তারা সীমালংঘনকারী লোক ছিল।"],
  "10:76": ["When the truth came to them from us, they said, \"This is obviously magic!\"","আমাদের কাছ থেকে যখন সত্য তাদের কাছে আসলো, তারা বলল, “এটা স্পষ্টতই জাদু!”"],
  "10:77": ["Moses said, \"Is this how you describe the truth when it comes to you? Is this magic? How can any magicians prevail?\"","মুসা বলল, “তোমরা কি এভাবেই সত্যের বর্ণনা করো থাকো যখন তা তোমাদের কাছে আসে? এটা কি জাদু? কিভাবে কোন জাদুকর জয়ী হতে পারে?"],
  "10:78": ["They said, \"Did you come to divert us from what we found our parents doing, and to attain positions of prominence for yourselves? We will never join you as believers.\"","তারা বলল, “তোমরা কি এসেছ আমাদেরকে তা থেকে সরিয়ে দিতে  যা আমরা আমাদের পিতামাতাদের করতে দেখেছি এবং নিজেরা বিশেষ অবস্থান অর্জণ করার জন্য? আমরা কখনই তোমাদের সাথে বিশ্বাসী হিসাবে যোগ দেবো না”।"],
  "10:79": ["Pharaoh said, \"Bring to me every experienced magician.\"","ফেরাউন বলল, “আমার কাছে প্রত্যেক অভিজ্ঞ জাদুকরকে নিয়ে আসো”।"],
  "10:80": ["When the magicians came, Moses said to them, \"Throw whatever you are going to throw.\"","যখন জাদুকররা আসলো, মুসা তাদের বলল, “তোমরা যা ছুড়ঁতে চাও ছোড়।"],
  "10:81": ["When they threw, Moses said, \"What you have produced is magic, and Allah will make it fail. Allah does not support the transgressors' work.\"","যখন তারা ছুড়ঁলো, মুসা বলল, “যা তোমরা উপস্থাপন করেছ তা জাদু এবং আল্লাহ তা ব্যর্থ  করে দেবেন। আল্লাহ সীমালঙ্ঘনকারীদের কাজ সমর্থন করেন না”।"],
  "10:82": ["Allah establishes the truth with His words, despite the criminals.","আল্লাহ তাঁর বানী দিয়ে সত্যকে প্রতিষ্ঠিত করেন, অপরাধীদের সত্ত্বেও।"],
  "10:83": ["None believed with Moses except a few of his people, while fearing the tyranny of Pharaoh and his elders. Surely, Pharaoh was much too arrogant on earth, and a real tyrant.","কেউ মুসার সাথে বিশ্বাস করেনি তার লোকদের মধ্যে অল্প কয়েকজন ছাড়া, ফেরাউন এবং তার সভাসদের অত্যাচারের ভয়ে। নিশ্চয়, ফেরাউন ছিল পৃথিবীতে অত্যন্ত উদ্ধত, এবং প্রকৃতই অত্যাচারী।"],
  "10:84": ["Moses said, \"O my people, if you have really believed in Allah, then put your trust in Him, if you are really submitters.\"","মুসা বলল, \"হে আমার লোকেরা, যদি তোমরা সত্যিই আল্লাহতে বিশ্বাস করো, তাহলে তার উপর তোমাদের আস্থা রাখো,  যদি তোমরা সত্যিই আত্মসমর্পণকারী হও।\""],
  "10:85": ["They said, \"We trust in Allah. Our Lord, save us from the persecution of these oppressive people.","তারা বলল, \"আমরা আল্লাহতে আস্থা রাখি। আমাদের প্রভু, এই অত্যাচারী লোকদের নির্যাতন থেকে আমাদের রক্ষা করুন।"],
  "10:86": ["\"Deliver us, with Your mercy, from the disbelieving people.\"","“আমাদের উদ্ধার করুন, আপনার দয়া দিয়ে, অবিশ্বাসী লোকদের থেকে”।"],
  "10:87": ["We inspired Moses and his brother. \"Maintain your homes in Egypt for the time being, turn your homes into synagogues, and maintain the Contact Prayers (Salat). Give good news to the believers.\"","আমরা মুসা এবং তার ভাইকে উদবুদ্ধ করলাম। “এখনকার জন্য মিসরে তোমাদের ঘর গুলো বহাল রাখ, তোমাদের ঘরগুলো সেনেগগে পরিণত করো, এবং সংযোগ প্রার্থনা (সালাত) পালন করো। বিশ্বাসীদের সুসংবাদ দাও।"],
  "10:88": ["Moses said, \"Our Lord, You have given Pharaoh and his elders luxuries and wealth in this world. Our Lord, they only use them to repulse others from Your path. Our Lord, wipe out their wealth, and harden their hearts to prevent them from believing, until they see the painful retribution.\"","মুসা বলল, “আমাদের প্রভু, আপনি ফেরাউন এবং তার সভাসদদের এই দুনিয়ায় বিলাসিতা এবং সম্পদ দিয়েছেন। আমাদের প্রভু, তারা এগুলো শুধু অন্যদেরকে আপনার পথ থেকে বিতাড়িত করতে ব্যবহার করে। অমাদের প্রভু, তাদের সম্পদ নিশ্চিহ্ন করে দিন, এবং তাদের হৃদয় কঠোর করে দিন তাদেরকে বিশ্বাস করা থেকে বিরত রাখতে, যতক্ষণ না তারা যন্ত্রণাদায়ক শাস্তি দেখে।"],
  "10:89": ["He said, \"Your prayer has been answered (O Moses and Aaron), so be steadfast, and do not follow the ways of those who do not know.\"","তিনি বললেন, “তোমারদের প্রার্থনা মঞ্জুর করা হল (হে মুসা এবং হারুন), সুতরাং অবিচল থাকো, এবং তাদের পথ অনুসরণ কর না যারা জানে না”।"],
  "10:90": ["We delivered the Children of Israel across the sea. Pharaoh and his troops pursued them, aggressively and sinfully. When drowning became a reality for him, he said, \"I believe that there is no god except the One in whom the Children of Israel have believed; I am a submitter.\"","আমরা সাগর পার করিয়ে ইসরাঈলের সন্তানদের  উদ্ধার করেছিলাম। ফেরাউন এবং তার সৈন্যদল তাদের পিছু ধাওয়া করলো, সহিংসতা এবং পাপের সাথে। যখন ডুবে যাওয়া তার জন্য বাস্তবতা হয়ে গেল, সে বলল, “আমি বিশ্বাস করি যে কোন উপাস্য নাই সেই এক সত্ত্বা ব্যতিত যাকে ইসরাঈলের সন্তানেরা বিশ্বাস করেছে, আমি একজন আত্মসমর্পণকারী”।"],
  "10:91": ["\"Too late! For you have rebelled already, and chose to be a transgressor.","“অনেক দেরি হয়ে গেছে! কারন তুমি ইতোমধ্যে বিদ্রোহ করেছ, এবং একজন সীমালঙ্ঘনকারী হতে পছন্দ করেছ।"],
  "10:92": ["\"Today, we will preserve your body, to set you up as a lesson for future generations.\" Unfortunately, many people are totally oblivious to our signs.","“আজ, আমরা তোমার দেহ সংরক্ষন করবো, তোমাকে ভবিষ্যৎ প্রজন্মের জন্য একটি শিক্ষা হিসাবে দাড় করাতে। দুর্ভাগ্যবশত, অনেক মানুষ আমাদের নিদর্শনের ব্যাপারে সম্পূর্ণ অন্যমনস্ক।"],
  "10:93": ["We have endowed the Children of Israel with a position of honor, and blessed them with good provisions. Yet, they disputed when this knowledge came to them. Your Lord will judge them on the Day of Resurrection regarding everything they disputed.","আমরা ইসরাইলের সন্তানদেরকে এক সন্মানিত অবস্থান দিয়েছি, এবং তাদেরকে ভালো জীবিকা দিয়ে সৌভাগ্যবান করেছি। তাসত্ত্বেও, এই জ্ঞান যখন তাদের কাছে আসলো তারা বিবাদ করলো। তোমার প্রভু পুনুরুত্থান দিবসে তাদের বিবাদকৃত সকল বিষয়ে বিচার করবেন।"],
  "10:94": ["If you have any doubt regarding what is revealed to you from your Lord, then ask those who read the previous scripture. Indeed, the truth has come to you from your Lord. Do not be with the doubters.","যদি তোমার প্রভুর পক্ষ থেকে তোমার কাছে যা প্রকাশ করা হয়েছে সে ব্যাপারে তোমার কোন সন্দেহ থাকে, তবে যারা পূর্ববর্তী ঐশীগ্রন্থ পড়ে তাদের জিজ্ঞাসা করো। প্রকৃতপক্ষে, তোমার প্রভুর পক্ষ থেকে তোমার কাছে সত্য এসেছে। সন্ধেহ পোষণকারীদের অন্তর্ভুক্ত না।"],
  "10:95": ["Nor shall you join those who rejected Allah's revelations, lest you be with the losers.","না তুমি তাদের সাথে যোগ দেবে যারা আল্লাহর প্রকাশনাবলী প্রত্যাখ্যান করেছে, পাছে তুমি ক্ষতিগ্রস্থদের অন্তরভুক্ত হবে।"],
  "10:96": ["Surely, those condemned by a decree from your Lord cannot believe.","নিশ্চিতভাবে, যারা তোমার প্রভুর পক্ষ থেকে একটি হুকুম, জারির দ্বারা দোষী সাব্যস্ত হয়েছে তারা বিশ্বাস কতে পারে না।"],
  "10:97": ["No matter what kind of proof you show them, (they cannot believe), until they see the painful retribution.","যে প্রমানই তুমি তাদের দেখাও না কেন, (তারা বিশ্বাস করতে পারে না), যতক্ষণ না তারা যন্ত্রণাদায়ক শাস্তি দেখে।"],
  "10:98": ["Any community that believes will surely be rewarded for believing. For example, the people of Jonah: when they believed, we relieved the humiliating retribution they had been suffering in this world, and we made them prosperous.","বিশ্বাসী যে কোন সম্প্রদায় অবশ্যই বিশ্বাসের জন্য পুরস্কৃত হবে। উদাহরণ স্বরূপ, ইউনুসের লকেরাঃ যখন তারা বিশ্বাস করল, আমরা সেই অপমানকর শাস্তি মুক্ত করলাম যা তারা এই দুনিয়ায় ভোগ করছিল, এবং আমরা তাদেরকে সমৃদ্ধশালী করলাম।"],
  "10:99": ["Had your Lord willed, all the people on earth would have believed. Do you want to force the people to become believers?","যদি তোমার প্রভু চাইতেন, পৃথিবীর সকল লোক বিশ্বাস করতো। তুমি কি লোকদের বিশ্বাসী হওয়ার জন্য জোর করতে চাও?"],
  "10:100": ["No soul can believe except in accordance with Allah's will. For He places a curse upon those who refuse to understand.","আল্লাহর ইচ্ছা ব্যতিত কোন আত্মা বিশ্বাস করতে পারে না। কারন তিনি তাদের উপর অভিশাপ আরোপ করেন যারা বুঝতে অস্বীকার করে।"],
  "10:101": ["Say, \"Look at all the signs in the heavens and the earth.\" All the proofs and all the warnings can never help people who decided to disbelieve.","বল, \"আকাশমন্ডলী ও পৃথিবীর নিদর্শনাবলি দেখো\"। যারা অবিশ্বাস করার সিদ্ধান্ত নিয়েছে তাদের জন্য সকল প্রমান এবং সকল সতর্কবার্তা কখনো কাজে আসে না।"],
  "10:102": ["Can they expect other than the fate of their counterparts in the past? Say, \"Just wait, and, along with you, I am also waiting.\"","তারা কি তাদের অনুরূপ অতীত ব্যক্তিদের থেকে আলাদা কোন পরিনাম আশা করতে পারে? বল, \"শুধু অপেক্ষা করো, এবং, তোমাদের সাথে, আমিও অপেক্ষা করছি।\""],
  "10:103": ["We ultimately save our messengers and those who believe. It is our immutable law that we save the believers.","আমরা অবশেষে আমাদের বার্তাবাহকদের এবং যারা বিশ্বাস করে তাদের রক্ষা করি। এটা আমাদের অপরিবর্তনীয় আইন যে আমরা বিশ্বাসীদের রক্ষা করি।"],
  "10:104": ["Say, \"O people, if you have any doubt regarding my religion, I do not worship what you worship beside Allah. I worship Allah alone; the One who will terminate your lives. I am commanded to be a believer.\"","বল, \"হে লোকেরা, যদি আমার ধর্ম সম্বন্ধে তোমাদের কোন সন্দেহ থাকে, তোমরা আল্লাহর পাশে যা উপাসনা করো আমি তার উপাসনা করি না; আমি একমাত্র আল্লাহর উপাসনা করি, সেই সত্ত্বা যিনি তোমাদের জীবনাবসান ঘটাবেন আমি আদিষ্ট হয়েছি একজন বিশ্বাসী হওয়ার জন্য।\""],
  "10:105": ["I was commanded: \"Keep yourself devoted to the religion of monotheism; you shall not practice idol worship.","আমি আদিষ্ট হয়েছি: \"নিজেকে একেশ্বরবাদ ধর্মের প্রতি নিবেদিত রাখো; তুমি অংশীদার উপাসনা চর্চা করবে না।"],
  "10:106": ["\"You shall not worship beside Allah what possesses no power to benefit you or harm you. If you do, you will be a transgressor.\"","“তুমি আল্লাহর পাশে এমন কিছুর উপাসনা করবে না, যা তোমার উপকার বা ক্ষতি করার কোন ক্ষমতা রাখে না। যদি তুমি তা করো, তবে তুমি সীমালঙ্ঘকারী হবে”।"],
  "10:107": ["If Allah touches you with a hardship, none can relieve it except He. And when He blesses you, no force can prevent His grace. He bestows it upon whomever He chooses from among His servants. He is the Forgiver, Most Merciful.","আল্লাহ যদি তোমাকে দুঃখ-কষ্ট দিয়ে স্পর্শ করেন, তবে তিনি ব্যতীত কেউ তা লাঘব করতে পারে না। আর তিনি তোমাকে সৌভাগ্যশালী করলে, কোন শক্তি তাঁর অনুগ্রহকে প্রতিরোধ করতে পারে না। তিনি এটি অর্পণ করেন তাঁর বান্দাদের মধ্যে যাকে তিনি পছন্দ করেন। তিনি ক্ষমাশীল, পরম করুণাময়।"],
  "10:108": ["Proclaim: \"O people, the truth has come to you herein from your Lord. Whoever is guided is guided for his own good. And whoever goes astray, goes astray to his own detriment. I am not a guardian over you.\"","ঘোষণা করঃ “হে লোকেরা, তোমাদের প্রভুর পক্ষ থেকে তোমাদের কাছে এখানে সত্য এসেছে। যে কেউ সুপথে পরিচালিত হয় সে তার নিজের ভালোর জন্য সুপথে পরিচালিত হয়। এবং যেকেউ পথভ্রষ্ট হয়, পথভ্রষ্ট হয় তার নিজের ক্ষতির জন্য। আমি তোমাদের অভিভাবক নই।"],
  "10:109": ["Follow what is revealed to you, and be patient until Allah issues His judgment; He is the best judge.","যা তোমার কাছে প্রকাশ করা হয় তা অনুসরণ করো, এবং ধৈর্য ধারন করো যতক্ষণ না আল্লাহ তাঁর রায় দেন, তিনি সর্বোত্তম বিচারক।"],
  "11:1": ["A.L.R. This is a scripture whose verses have been perfected, then elucidated. It comes from a Most Wise, Most Cognizant.","অ, ল, র। এটি একটি ঐশীগ্রন্থ যার আয়াতগুলো নিখুঁত করা হয়েছে, তারপর বিশদভাবে বর্ণিত হয়েছে। এটি এসেছে এক সর্বজ্ঞ, সবজান্তার কাছ থেকে।"],
  "11:2": ["Proclaiming: \"You shall not worship except Allah. I come to you from Him as a warner, as well as a bearer of good news.","ঘোষনা করছে “তোমরা আল্লাহ ব্যতীত আর কারো উপাসনা করবে না। আমি তাঁর পক্ষ থেকে তোমাদের কাছে এসেছি একটি সর্তককারী, সেই সাথে, সুসংবাদ বহনকারী হিসেবে।"],
  "11:3": ["\"You shall seek your Lord's forgiveness, then repent to Him. He will then bless you generously for a predetermined period, and bestow His grace upon those who deserve it. If you turn away, then I fear for you the retribution of an awesome day.\"","“তোমরা  তোমাদের প্রভুর ক্ষমা পেতে চেষ্টা করবে, আর তাঁর কাছে অনুশোচনা করবে। তাহলে তিনি তোমাদেরকে একটি নির্ধারিত সময় পর্যন্ত উদারভাবে অনুগ্রহ করে যাবেন, এবং  তাঁর করুনা বর্ষণ করবেন তাদের উপর যারা এর যোগ্য।  তোমরা যদি ফিরে যাও, তবে আমি তোমাদের জন্য এক মারাত্মক দিনের শাস্তির ভয় করছি।”"],
  "11:4": ["To Allah is your ultimate return, and He is Omnipotent.","আল্লাহর কাছে তোমাদের চুড়ান্ত প্রত্যাবর্তন, এবং তিনি সর্বশক্তিমান।"],
  "11:5": ["Indeed, they hide their innermost thoughts, as if to keep Him from knowing them. In fact, as they cover themselves with their clothes, He knows all their secrets and declarations. He knows the innermost thoughts.","প্রকৃতপক্ষে, তারা তাদের গভীরতম চিন্তাভাবনা লুকায়, যেন তিনি সেগুলো না জানতে পারেন। মূলত, যদিও তারা নিজেদেরকে তাদের কাপড় দিয়ে আর্বৃত করে, তিনি তাদের গোপন ও প্রকাশ্য ব্যাপারগুলো জানেন। তিনি সকল গভীরতম চিন্তাভাবনা জানেন।"],
  "11:6": ["There is not a creature on earth whose provision is not guaranteed by Allah. And He knows its course and its final destiny. All are recorded in a profound record.","পৃথিবীতে এমন কোন জীব নেই যার জীবিকা আল্লাহ কর্তৃক নির্ধারিত নয়। আর তিনি এর গতিবিধি এবং এর চুড়ান্ত পরিনতি জানেন। সবকিছু একটি সুস্পষ্ট নথিতে লিপিবদ্ধ।"],
  "11:7": ["He is the One who created the heavens and the earth in six days—and His (earthly) domain was completely covered with water—in order to test you, to distinguish those among you who work righteousness. Yet, when you say, \"You will be resurrected after death,\" those who disbelieve would say, \"This is clearly witchcraft.\"","তিনিই সে সত্ত্বা যিনি আকাশমন্ডলী ও পৃথিবী ছয় দিনে সৃষ্টি করেছেন- আর তাঁর (পৃথিবীর) রাজত্ব পানি দিয়ে পুরোপুরি আবৃত ছিল- তোমাদেরকে পরীক্ষা করার জন্য, তোমাদের মধ্যে যারা সৎ কাজ করে তাদের আলাদা করার জন্য। এরপরও, যখন তোমরা বল, “তোমাদেরকে মৃত্যুর পর পুনরজ্জীবিত করা হবে,”যারা অবিশ্বাস করে তারা বলবে, “এটি সুস্পষ্ট কালো যাদু।”"],
  "11:8": ["And if we delay the retribution they have incurred—for we reserve it for a specific community—they say, \"What is keeping Him?\" In fact, once it comes to them, nothing can stop it, and their mocking will come back to haunt them.","এবং আমরা যদি তাদের অর্জিত শাস্তি দিতে দেরি করি- কারণ আমরা তা কোন নির্দিষ্ট সম্প্রদায়ের জন্য জমা রাখি- তারা বলে, “কিসে উনাকে আটকে রেখেছে? মূলত, একবার এটি তাদের কাছে আসলে, কোনকিছুই একে থামাতে পারে না, উলটো তাদের উপহাস তাদেরকে তাড়া করে বেড়াবে।"],
  "11:9": ["Whenever we bless the human being with mercy from us, then remove it, he turns despondent, unappreciative.","আমাদের পক্ষ থেকে যখনই আমরা দয়া দিয়ে মানব জাতিকে অনুগ্রহ করি, এরপর তা সরিয়ে নেই, সে হয়ে যায় নিরাশ, অকৃতজ্ঞ।"],
  "11:10": ["Whenever we bless him, after adversity had afflicted him, he says, \"All adversity has gone away from me;\" he becomes excited, proud.","যখনই আমরা অনুগ্রহ করি, সে দুর্দশাগ্রস্থ হওয়ার পর, সে বলে, “আমার কাছ থেকে সকল দুর্দশা চলে গেছে,” সে হয়ে পরে উদ্বেলিত, গর্বিত।"],
  "11:11": ["As for those who steadfastly persevere, and lead a righteous life, they deserve forgiveness and a generous recompense.","আর যারা দৃড়তার সাথে অবিচল থাকে, এবং সৎ জীবন-যাপন করে, তারা ক্ষমা ও এক উদার প্রতিদানের যোগ্য হয়েছে।"],
  "11:12": ["You may wish to disregard some of that which is revealed to you, and you may be annoyed by it. Also, they may say, \"How come no treasure comes down to him, or an angel?\" You are only a warner; Allah controls all things.","তোমার কাছে যা প্রকাশ করা হয় তুমি হয়তো এর কিছু অংশ উপেক্ষা করতে চাইতে পারো এবং হয়তো এর দ্বারা তুমি বিচলিত হতে পারো। এছাড়াও, তারা হয়তো বলতে পারে, “এটা কেমন যে তার কাছে কোন ধনভান্ডার অথবা কোন ফেরেশতা নেমে আসে না?”তুমি শুধু একজন সতর্ককারী; আল্লাহ সবকিছু নিয়ন্ত্রন করেন।"],
  "11:13": ["If they say, \"He fabricated (the Quran),\" tell them, \"Then produce ten suras like these, fabricated, and invite whomever you can, other than Allah, if you are truthful.\"","যদি তারা বলে,“সে (কুরআন) বানিয়েছে,”তাদেরকে বল, “তবে এগুলোর মত দশটি সূরা উপস্থাপন করো,যা বানানো,এবং যাকে পারো আমন্ত্রন করো,আল্লাহকে ছাড়া,যদি তোমরা সত্যবাদী হও।”"],
  "11:14": ["If they fail to meet your challenge, then know that this is revealed with Allah's knowledge, and that there is no god except He. Will you then submit?","তারা যদি তোমাদের চ্যালেঞ্জের কাছে পরাস্ত হয়, তবে জেনে রাখো যে এটি আল্লাহর জ্ঞান থেকে প্রকাশিত হয়, এবং তিনি ছাড়া কোন উপাস্য নেই। তোমরা কি এবার আত্মসমর্পণ করবে?"],
  "11:15": ["Those who pursue this worldly life and its material vanities, we will pay them for their works in this life; without the least reduction.","যারা এই পার্থিব জীবন আর এর বস্তুগত সৌন্দর্যের পিছনে ছুটে বেড়ায়, আমরা এই জীবনে তাদের কাজের জন্য তাদের প্রতিদান দেবো; সামান্যতম কম না দিয়ে।"],
  "11:16": ["It is they who gave up their share in the Hereafter, and, consequently, Hell is their lot. All their works are in vain; everything they have done is nullified.","এরা তারাই যারা তাদের পরকালের অংশ ছেড়ে দিয়েছে,এবং,পরিনামে,নরকই তাদের নিয়তি। তাদের সকল কাজ অর্থহীন; তারা যা কিছু করেছে সবই বিনষ্ট হয়েছে।"],
  "11:17": ["As for those who are given solid proof from their Lord, reported by a witness from Him, and before it, the book of Moses has set a precedent and a mercy, they will surely believe. As for those who disbelieve among the various groups, Hell is awaiting them. Do not harbor any doubt; this is the truth from your Lord, but most people disbelieve.","আর যাদেরকে তাদের প্রভুর পক্ষ থেকে জোড়ালো প্রমান দেয়া হয়েছে,যা তাঁর পক্ষ থেকে একজন স্বাক্ষী দ্বারা উপস্থাপিত, এবং এর আগে,মূসার ঐশীগ্রন্থ এক উদাহরণ ও দয়া স্থাপন করেছে,তারা অবশ্যই বিশ্বাস করবে। আর বিভিন্ন দলের মধ্যে যারা অবিশ্বাস করে,তাদের জন্য নরক অপেক্ষা করছে। কোন সন্দেহ পোষন করো না; এটি তোমার প্রভুর পক্ষ থেকে সত্য, কিন্তু বেশিরভাগ মানুষই অবিশ্বাস করে।"],
  "11:18": ["Who are more evil than those who fabricate lies about Allah? They will be presented before their Lord, and the witnesses will say, \"These are the ones who lied about their Lord. Allah's condemnation has befallen the transgressors.\"","তাদের থেকে খারাপ আর কারা যারা আল্লাহ সম্পর্কে মিথ্যা বানায়? তাদেরকে তাদের প্রভুর সামনে উপস্থিত করা হবে,এবং স্বাক্ষীরা বলবে,“এরাই তারা যারা তাদের প্রভু সম্পর্কে মিথ্যা বলেছিল। আল্লাহর অভিসম্পাত সীমালঙনকারীদের উপর পড়েছে।”"],
  "11:19": ["They repel from the way of Allah and seek to make it crooked, and they are disbelievers in the Hereafter.","তারা আল্লাহর পথে বাধা দেয় এবং একে বক্র করতে চেষ্টা করে,এবং তারা পরকালে অবিশ্বাসী।"],
  "11:20": ["These will never escape, nor will they find any lords or masters to help them against Allah. Retribution will be doubled for them. They have failed to hear, and they have failed to see.","এরা কখনও পালাতে পারবে না,না তারা আল্লাহর বিপক্ষে তাদেরকে সাহায্য করতে কোন প্রভু বা মনিব পাবে। শাস্তি তাদের জন্য দ্বিগুন করা হবে। তারা শুনতে ব্যর্থ হয়েছে,এবং তারা ব্যর্থ হয়েছে দেখতে।"],
  "11:21": ["These are the ones who lose their souls, and the idols they had fabricated will disown them.","এরাই তারা যারা তাদের আত্মা হারায়, এবং তাদের বানানো উপাস্যরা তাদের পরিত্যাগ করবে।"],
  "11:22": ["There is no doubt that, in the Hereafter, they will be the worst losers.","কোন সন্দেহ নেই যে,পরকালে,তারা হবে সর্বাধিক ক্ষতিগ্রস্থ।"],
  "11:23": ["As for those who believe and lead a righteous life, and devote themselves to their Lord, they are the dwellers of Paradise; they abide therein forever.","আর যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে,এবং তাদের প্রভুর প্রতি নিজেদের উৎসর্গ করে,তারা স্বর্গের বাসিন্দা; তারা সেখানে চিরকাল বসবাস করে।"],
  "11:24": ["The example of these two groups is like the blind and deaf, compared to the seer and hearer. Are they equal? Would you not take heed?","এই দুই শ্রেনীর উদাহরণ হচ্ছে অন্ধ ও বধিরের সাথে,দৃষ্টিবান ও শ্রবনশক্তিবানের তুলনা করার মত। তারা কি সমান? তোমরা কি চিন্তা করবে না?"],
  "11:25": ["We sent Noah to his people, saying, \"I come to you as a clear warner.","আমরা নুহকে তার লোকদের কাছে পাঠিয়েছিলাম, এটা বলতে,“আমি তোমাদের কাছে এসেছি স্পষ্ট সতর্ককারী হিসেবে।"],
  "11:26": ["\"You shall not worship except Allah. I fear for you the retribution of a painful day.\"","“তোমরা আল্লাহ ছাড়া অন্য কারো উপাসনা করবে না। আমি তোমাদের জন্য এক যন্ত্রনাদায়ক দিনের শাস্তির ভয় করি।”"],
  "11:27": ["The leaders who disbelieved among his people said, \"We see that you are no more than a human being like us, and we see that the first people to follow you are the worst among us. We see that you do not possess any advantage over us. Indeed, we think you are liars.\"","তার লোকদের মধ্যে যে নেতারা অবিশ্বাস করেছিল তারা বলল, “আমরা দেখছি যে তুমি আমাদের মত মানুষ ছাড়া কিছু নও, আর আমাদের মধ্যে নিকৃষ্ট লোকেরাই প্রথমে তোমার অনুসরণ করছে। আমরা দেখছি যে আমাদের উপর তোমাদের কোন শ্রেষ্ঠত্ব নেই। মূলত, আমরা তোমাদের মিথ্যাবাদী মনে করি।”"],
  "11:28": ["He said, \"O my people, what if I have a solid proof from my Lord? What if He has blessed me out of His mercy, though you cannot see it? Are we going to force you to believe therein?","সে বলল, “হে আমার লোকেরা,যদি এমন হয় যে আমার প্রভুর পক্ষ থেকে আমার কাছে একটি জোড়ালো প্রমান থাকে? যদি এমন হয় যে তাঁর দয়া থেকে তিনি আমাকে অনুগ্রহ করেছেন, যদিও তোমরা তা দেখতে পারো না? আমরা কি তোমাদেরকে তাতে বিশ্বাস করতে জোর করতে যাচ্ছি?"],
  "11:29": ["\"O my people, I do not ask you for any money; my wage comes only from Allah. I am not dismissing those who believed; they will meet their Lord (and He alone will judge them). I see that you are ignorant people.","“হে আমার লোকেরা,আমি তোমাদের কাছে কোন অর্থ চাই না; আমার পারিশ্রমিক একমাত্র আল্লাহ থেকে আসে। যারা বিশ্বাস করে তাদেরকে আমি তাড়িয়ে দিচ্ছি না; তারা তাদের প্রভুর সাথে সাক্ষাত করবে (এবং একমাত্র তিনি তাদের বিচার করবেন )। আমি দেখি যে তোমরা অজ্ঞ লোক।"],
  "11:30": ["\"O my people, who can support me against Allah, if I dismiss them? Would you not take heed?","“হে আমার লোকেরা,আল্লাহর বিরুদ্ধে কে আমাকে সহায়তা করতে পারে,যদি আমি তাদেরকে তাড়িয়ে দেই? তোমরা কি মনোযোগ দিবে না?"],
  "11:31": ["\"I do not claim that I possess the treasures of Allah, nor do I know the future, nor do I claim to be an angel. Nor do I say to those despised by your eyes that Allah will not bestow any blessings upon them. Allah knows best what is in their innermost thoughts. (If I did this,) I would be a transgressor.\"","আমি দাবি করি না যে আমার কাছে আল্লাহর ধন-ভান্ডার আছে,না আমি ভবিষৎ জানি,না আমি ফেরেশতা হওয়ার দাবি করি। না আমি ওদেরকে বলি যারা তোমাদের দৃষ্টিতে ঘৃনিত যে আল্লাহ তাদের উপর অনুগ্রহ বর্ষণ করবেন না। আল্লাহ সবচেয়ে ভাল জানেন কি তাদের গভীরতম চিন্তা। (যদি এটি আমি করে থাকি,) আমি একজন সীমালংঘনকারী হবো।”"],
  "11:32": ["They said, \"O Noah, you have argued with us, and kept on arguing. We challenge you to bring the doom you threaten us with, if you are truthful.\"","তারা বলল, “হে নুহ, তুমি আমাদের সাথে তর্ক করছো,এবং তর্ক করেই যাচ্ছো। আমরা তোমাকে সে অনিবার্য ধ্বংস আনতে চ্যালেঞ্জ করি যা দিয়ে তুমি আমাদের ভয় দেখাও, যদি তুমি সত্যবাদী হও।”"],
  "11:33": ["He said, \"Allah is the One who brings it to you, if He so wills, then you cannot escape.","সে বলল, “আল্লাহই সেই সত্ত্বা যিনি এটি তোমাদের কাছে নিয়ে আসেন, যদি তিনি এমনই চান, তখন তোমরা পালাতে পারবে না।"],
  "11:34": ["\"Even if I advised you, my advice cannot benefit you if it is Allah's will to send you astray. He is your Lord, and to Him you will be returned.\"","“যদিও আমি তোমাদের উপদেশ দিয়েছি,তোমাদের বিপথে পাঠানো যদি আল্লাহর ইচ্ছা হয় আমার উপদেশ তোমাদের কোন উপকারে আসতে পারে না। তিনি তোমাদের প্রভু,এবং তাঁর কাছেই তোমরা ফিরে যাবে।”"],
  "11:35": ["If they say, \"He made up this story,\" then say, \"If I made it up, then I am responsible for my crime, and I am innocent of any crime you commit.\"","যদি তারা বলে,“সে এই গল্প বানিয়েছে,”তাহলে বল, “যদি আমি তা বানিয়ে থাকি,তবে আমি আমার অপরাধের জন্য দায়ী,এবং তোমাদের করা কোন অপরাধের জন্য আমি দায়ী নই।”"],
  "11:36": ["Noah was inspired: \"No more of your people are going to believe, beyond those who already believe. Do not be saddened by their actions.","নূহ অনুপ্রানিত হয়েছিলঃ “তোমার লোকদের মধ্যে আর কেউ বিশ্বাস করবে না,যারা ইতোমধ্যে বিশ্বাস করেছে তারা ছাড়া। তাদের কর্মকান্ডে দুঃখ পেয়ো না।"],
  "11:37": ["\"Build the ark under our watchful eyes, and with our inspiration, and do not implore Me on behalf of those who have transgressed; they are destined to drown.\"","“নৌকাটি নির্মান করো আমাদের সতর্ক দৃষ্টির আওতায়, এবং আমাদের অনুপ্রেরনায়, এবং তাদের হয়ে আমার কাছে মিনতি করো না যারা সীমালংঘন করেছে;ডুবে মরাই তাদের নিয়তি।”"],
  "11:38": ["While he was building the ark, whenever some of his people passed by him they laughed at him. He said, \"You may be laughing at us, but we are laughing at you, just as you are laughing.","যখন সে নৌকাটি বানাচ্ছিল, তার লোকদের কেউ কেউ যখনি তার পাশ দিয়ে যেতো তারা তাকে নিয়ে হাসতো। সে বলেছিল, “তোমরা হয়তো  আমাদের নিয়ে হাসছ, কিন্তু আমরা তোমাদের নিয়ে হাসছি,ঠিক যেমন তোমরা হাসছ।"],
  "11:39": ["\"You will surely find out who will suffer a shameful retribution, and incur an everlasting punishment.\"","“তোমরা অবশ্যই দেখতে পাবে কারা লজ্জাকর শাস্তি ভোগ করবে,এবং কারা টেনে আনবে এক চিরস্থায়ী শাস্তি”।"],
  "11:40": ["When our judgment came, and the atmosphere boiled over, we said, \"Carry on it a pair of each kind, together with your family, except those who are condemned. Carry with you those who have believed,\" and only a few have believed with him.","যখন আমাদের বিচার আসলো,এবং বায়ুমণ্ডল অত্যাধিক উত্তপ্ত হয়ে উঠল, আমরা বললাম, “এর উপর প্রত্যেক প্রকারের এক জোড়া তুলো, তোমার পরিবারের সাথে,তাদের ছাড়া যারা দোষী। তোমার সাথে তাদেরকে নাও যারা বিশ্বাস করেছে,”এবং অল্প কয়েকজন তার সাথে বিশ্বাস করেছিল।"],
  "11:41": ["He said, \"Come on board. In the name of Allah shall be its sailing, and its mooring. My Lord is Forgiver, Most Merciful.\"","সে বলেছিল, “আরোহণ করো,আল্লাহর নামে হবে এর ভেসে চলা,এবং এর  নোঙ্গর। আমার প্রভু ক্ষমাশীল, পরম দয়ালু”।"],
  "11:42": ["As it sailed with them in waves like hills, Noah called his son, who was isolated: \"O my son, come ride with us; do not be with the disbelievers.\"","যখন এটি তাদের নিয়ে পাহাড় সমান ঢেউয়ের মাঝে ভেসে গেল, “নূহ তার ছেলেকে ডাকলো,যে আলাদা হয়েছিলঃ “হে আমার পূত্র, আমাদের সাথে উঠো; অবিশ্বাসীদের সাথে থেকো না।”"],
  "11:43": ["He said, \"I will take refuge on top of a hill, to protect me from the water.\" He said, \"Nothing can protect anyone today from Allah's judgment; only those worthy of His mercy (will be saved).\" The waves separated them, and he was among those who drowned.","সে বলল, “আমি কোন পাহাড়ের চূড়ায় আশ্রয় নিব, নিজেকে পানি থেকে রক্ষা করতে।”সে বলল, “আজ আল্লাহর বিচার হতে কাউকে কোনকিছুই রক্ষা করতে পারবে না; শুধু তারা (রক্ষা পাবে) যারা তার দয়ার যোগ্য।”ঢেউ তাদের আলাদা করে দিল, এবং সে ছিল তাদের মধ্যে যারা নিমজ্জিত হয়েছিল।"],
  "11:44": ["It was proclaimed: \"O earth, swallow your water,\" and \"O sky, cease.\" The water then subsided; the judgment was fulfilled. The ark finally rested on the hills of Judea. It was then proclaimed: \"The transgressors have perished.\"","এটি ঘোষনা করা হলঃ “হে পৃথিবী,তোমার পানি গিলে ফেল, ”এবং “হে আকাশ, থামো।”পানি তখন কমে গেল; বিচার পরিপূর্ণ হল। অবশেষে নৌকাটি জুদেয়া-এর পাহাড়গুলোতে থামালো। এটি তখন ঘোষনা করা হলঃ “সীমালঙ্গঘনকারীরা ধংস হয়েছে।”"],
  "11:45": ["Noah implored his Lord: \"My Lord, my son is a member of my family, and Your promise is the truth. You are the wisest of the wise.\"","নূহ তার প্রভুর কাছে মিনতি করলোঃ “আমার প্রভু,আমার পুত্র আমার পরিবারের সদস্য, এবং আপনার অংগীকার সত্য। আপনি বিজ্ঞদের চেয়েও বিজ্ঞ।”"],
  "11:46": ["He said, \"O Noah, he is not of your family. It is unrighteous to ask Me for something you do not know. I enlighten you, lest you be like the ignorant.\"","তিনি বলেছিলেন, “হে নূহ, সে তোমার পরিবারের কেউ নয়। এটি অন্যায্য আমার কাছে কোনকিছু চাওয়া যা তুমি জানো না। আমি তোমাকে জ্ঞানালোক দিয়েছি,যাতে তুমি অজ্ঞদের মত না হও।”"],
  "11:47": ["He said, \"My Lord, I seek refuge in You, lest I implore You again for something I do not know. Unless You forgive me, and have mercy on me, I will be with the losers.\"","সে বলল, “আমার প্রভু,আমি আপনার কাছে আশ্রয় চাই, যাতে আমি আবারো আপনার কাছে এমনকিছুর জন্য মিনতি না করি যা আমি জানি না। যদি আপনি আমাকে ক্ষমা না করেন, এবং আমার উপর দয়া না করেন, আমি ক্ষতিগ্রস্থদের অন্তর্ভূক্ত হয়ে যাব।"],
  "11:48": ["It was proclaimed: \"O Noah, disembark, with peace and blessings upon you, and upon nations who will descend from your companions. As for the other nations descending from you, we will bless them for awhile, then commit them to painful retribution.\"","এটি ঘোষনা করা হলঃ “হে নূহ, অবতরণ কর, শান্তি এবং অনুগ্রহের সাথে তোমার উপর, এবং সে জাতির উপর যারা তোমার সংগীদের বংশদের হবে। আর অপর জাতি যারা তোমার বংশধর হবে,আমরা তাদেরকে কিছু সময়ের জন্য অনুগ্রহ করবো,এরপর তাদেরকে যন্ত্রনাদায়ক শাস্তি দিব।”"],
  "11:49": ["This is news from the past that we reveal to you. You had no knowledge about them—neither you, nor your people—before this. Therefore, be patient. The ultimate victory belongs to the righteous.","এটি অতীতের সংবাদ যা আমরা তোমার কাছে প্রকাশ করি। তাদের সম্পর্কে তোমার কোন জ্ঞান ছিল না- না তোমার, বা তোমার লোকদের- এর পূর্বে। অতএব, ধৈর্য্য ধারণ করো। চূড়ান্ত বিজয় সৎকর্মশীলদের জন্য।"],
  "11:50": ["To 'Ãd we sent their brother Hûd. He said, \"O my people, worship Allah; you have no other god besides Him. You are inventing.","আদ জাতির কাছে আমরা তাদের ভাই হুদকে পাঠিয়েছিলাম। সে বলেছিল, “হে আমার লোকেরা,আল্লাহর উপাসনা কর; তাঁর পাশে তোমাদের অন্য কোন উপাস্য নেই। তোমরা উদ্ভাবন করছো।"],
  "11:51": ["\"O my people, I do not ask you for any wage. My wage comes only from the One who initiated me. Do you not understand?","“হে আমার লোকেরা,আমি তোমাদের কাছে কোন পারিশ্রমিক চাই না। আমার পারিশ্রমিক শুধু সেই সত্ত্বার কাছ থেকে আসে যিনি আমার সূচনা করেছেন। তোমরা কি বুঝো না?"],
  "11:52": ["\"O my people, seek forgiveness from your Lord, then repent to Him. He will then shower you with provisions from the sky, and augment your strength. Do not turn back into transgressors.\"","“হে আমার লোকেরা,তোমাদের প্রভুর ক্ষমা অন্বেষন করো,এরপর তাঁর কাছে অনুশোচনা করো। তাহলে তিনি আকাশ হতে তোমাদের জন্য জীবিকা বর্ষণ করবেন, এবং তোমাদের শক্তি বৃদ্ধি করবেন। সীমা লঙ্গনকারীদের মাঝে ফিরে যেও না।"],
  "11:53": ["They said, \"O Hûd, you did not show us any proof, and we are not abandoning our gods on account of what you say. We will never be believers with you.","তারা বলল, “হে হুদ, তুমি আমাদেরকে কোন প্রমান দেখাওনি,আর তোমার কথার উপর ভিত্তি করে আমরা আমাদের উপাস্যগুলো পরিত্যাগ করছি না। আমরা কখনোই তোমার সাথে বিশ্বাসী হবো না।"],
  "11:54": ["\"We believe that some of our gods have afflicted you with a curse.\" He said, \"I bear witness before Allah, and you bear witness as well, that I disown the idols you have set up—","“আমরা বিশ্বাস করি যে আমাদের কিছু উপাস্য অভিশাপ দিয়ে তোমাকে পীড়িত করেছে।”সে বলল, “আমি আল্লাহর সামনে সাক্ষ্য দিচ্ছি,আর তোমরাও সাক্ষী থাকো যে,আমি সেই উপাস্যগুলোকে পরিত্যাগ করেছি যেগুলো তোমরা স্থাপন করেছ"],
  "11:55": ["\"—beside Him. So, give me your collective decision, without delay.","“তাঁর পাশে। সুতরাং তোমাদের সম্মিলিত সিদ্ধান্ত আমাকে জানাও, বিলম্ব না করে।"],
  "11:56": ["\"I have put my trust in Allah, my Lord and your Lord. There is not a creature that He does not control. My Lord is on the right path.","“আমি আল্লাহর উপর ভরসা করেছি,আমার প্রভু এবং তোমাদের প্রভু। এমন কোন সৃষ্টি নেই যাকে তিনি নিয়ন্ত্রন করেন না। আমার প্রভু সঠিক পথে আছেন।"],
  "11:57": ["\"If you turn away, I have delivered to you what I was sent with. My Lord will substitute other people in your place; you cannot harm Him in the least. My Lord is in control of all things.\"","\"যদি তোমরা মুখ ফিরিয়ে নাও, আমি তোমাদের কাছে পৌঁছে দিয়েছি যা দিয়ে আমাকে পাঠানো হয়েছিল। আমার প্রভু তোমাদের জায়গায় অন্য লোকদের আনবেন। তোমরা তাঁর এতটুকু ক্ষতি করতে পারবে না। আমার প্রভু সবকিছু নিয়ন্ত্রন করেণ।"],
  "11:58": ["When our judgment came, we saved Hûd and those who believed with him, by mercy from us. We saved them from a terrible retribution.","যখন আমাদের বিচার আসলো,আমরা আমাদের দয়ায় হুদ এবং যারা তার সাথে বিশ্বাস করেছিল তাদের রক্ষা করেছিলাম। আমরা তাদেরকে এক ভয়ানক শাস্তি থেকে রক্ষা করেছিলাম।"],
  "11:59": ["Such was 'Ãd—they disregarded the revelations of their Lord, disobeyed His messengers, and followed the ways of every stubborn tyrant.","এমনই ছিল আদ জাতি- তারা তাদের প্রভুর প্রকাশনাবলি অগ্রাহ্য করেছিল, তাঁর বার্তাবাহকদের অমান্য করেছিল, এবং প্রত্যেক একগুঁয়ে অত্যাচারী শাসকের পথ অনুসরণ করলো।"],
  "11:60": ["Consequently, they incurred condemnation in this world, and on the Day of Resurrection. Indeed, 'Ãd rejected their Lord. Indeed, 'Ãd, the people of Hûd, have perished.","ফলশ্রুতিতে,তারা অভিশাপ টেনে এনেছে এই পৃথিবীতে,এবং পুনরুত্থান দিবসে। প্রকৃতই, আদ জাতি তাদের প্রভুকে প্রত্যাখ্যান করেছিল। প্রকৃতই, আদ জাতি,হুদের লোকেরা,বিলুপ্ত হয়েছে।"],
  "11:61": ["To Thamûd we sent their brother Sãleh. He said, \"O my people, worship Allah; you have no other god beside Him. He initiated you from the earth, then settled you in it. You shall seek His forgiveness, then repent to Him. My Lord is always near, responsive.\"","সামূদ জাতির কাছে আমরা তাদের ভাই সালেহকে পাঠিয়েছিলাম। সে বলেছিল, “হে আমার লোকেরা,আল্লাহর উপাসনা কর; তাঁর পাশে তোমাদের আর কোন উপাস্য নেই। তিনি পৃথিবী থেকে তোমাদের সূচনা করেছেন, তারপর এর মধ্যে তোমাদের প্রতিষ্ঠিত করেছেন। তোমাদের উচিত তাঁর কাছে ক্ষমা চাওয়া,এরপর তাঁর কাছে অনুশোচনা করা। আমার প্রভু সর্বদাই নিকটে,সাড়াদানকারী।”"],
  "11:62": ["They said, \"O Sãleh, you used to be popular among us before this. Are you enjoining us from worshiping what our parents are worshiping? We are full of doubt concerning everything you have told us.\"","তারা বলল, “হে সালেহ, তুমি তো এর আগে আমাদের মাঝে জনপ্রিয় ছিলে। আমাদের পিতামাতারা যা উপাসনা করে তার উপাসনা করতে তুমি কি আমাদের নিষেধ করছো? তুমি আমাদেরকে যাকিছু বলেছ সে সবকিছু সম্পর্কে আমরা গভীর সন্দেহে আছি।”"],
  "11:63": ["He said, \"O my people, what if I have solid proof from my Lord, and mercy from Him? Who would support me against Allah, if I disobeyed Him? You can only augment my loss.","সে বলল, “হে আমার লোকেরা,যদি আমার কাছে থেকে থাকে আমার প্রভুর পক্ষ থেকে জোড়ালো প্রমান, এবং তাঁর পক্ষ থেকে দয়া? আল্লাহর বিপক্ষে কে আমার সহায় হবে,যদি আমি তাঁকে অমান্য করি? তোমরা শুধু আমার ক্ষতি বৃদ্ধি করতে পার।"],
  "11:64": ["\"O my people, this is Allah's camel to serve as a proof for you. You shall let her eat from Allah's earth, and do not touch her with any harm, lest you incur an immediate retribution.\"","“হে আমার লোকেরা,এটি আল্লাহর উট যা তোমাদের জন্য একটি প্রমান হিসেবে কাজ করবে। তোমরা একে আল্লাহর পৃথিবী/ভূমি থেকে খেতে দিবে,এবং কোন প্রকার ক্ষতি করার জন্য একে স্পর্শ করবে না,অন্যথায় তোমরা এক আশু শাস্তি টেনে আনবে।”"],
  "11:65": ["They slaughtered her. He then said, \"You have only three days to live. This is a prophecy that is inevitable.\"","তারা একে হত্যা করল। এরপর সে বলল, “তোমরা শুধু আর তিন দিন বাচঁবে। এটা একটি ভবিষ্যদ্বানী যা অবধারিত।”"],
  "11:66": ["When our judgment came, we saved Sãleh and those who believed with him by mercy from us, from the humiliation of that day. Your Lord is the Most Powerful, the Almighty.","যখন আমাদের বিচার আসলো,আমাদের কাছ থেকে দয়া দিয়ে আমরা সালেহ এবং তার সাথে যারা বিশ্বাস করেছিল তাদের রক্ষা করেছিলাম দ্বারা,ঐ দিনের অপমানকর অবস্থা হতে। তোমার প্রভু পরম ক্ষমতাবান, সর্বশক্তিমান।"],
  "11:67": ["Those who transgressed were annihilated by the disaster, leaving them in their homes, dead.","যারা সীমালঙ্গন করেছিল সেই দূর্যোগ তাদেরকে ধ্বংস করে দিয়েছিল, তাদেরকে তাদের বাড়িতে ফেলে রেখেছিল, মৃতবস্থায়।"],
  "11:68": ["It was as if they never lived there. Indeed, Thamûd have rejected their Lord. Absolutely, Thamûd have incurred their annihilation.","এটা এমন ছিল যেন তারা কখনো সেখানে বসবাস করেনি। মূলত, সামূদ তাদের প্রভুকে প্রত্যাখ্যান করেছে। অবশ্যই, সামূদ তাদের ধ্বংস টেনে এনেছে।"],
  "11:69": ["When our messengers went to Abraham with good news, they said, \"Peace.\" He said, \"Peace,\" and soon brought a roasted calf.","যখন আমাদের বার্তাবাহকেরা ইব্রাহিমের কাছে সুসংবাদ নিয়ে গিয়েছিল, তারা বলেছিল, “শান্তি।”সে বলল, “শান্তি।”এবং কিছু সময়ের মধ্যেই একটি রোস্ট করা (ঝলসানো) বাছুর নিয়ে আসলো।"],
  "11:70": ["When he saw that their hands did not touch it, he became suspicious and fearful of them. They said, \"Do not be afraid, we are being dispatched to the people of Lot.\"","যখন সে দেখলো তাদের হাত এটা স্পর্শ করছে না,সে তাদের ব্যাপারে সন্দেহ পোষন করলো এবং ভীত হল। তারা বলল, “ভয় পেও না,আমাদেরকে লূতের লোকদের কাছে পাঠানো হয়েছে।”"],
  "11:71": ["His wife was standing, and she laughed when we gave her the good news about Isaac, and after Isaac, Jacob.","তার স্ত্রী দাঁড়িয়ে ছিল, এবং সে হাসলো যখন আমরা সুসংবাদ দিলাম ইসহাকের, এবং ইসহাকের পর ইয়াকুবের।"],
  "11:72": ["She said, \"Woe to me, how could I bear a child at my age, and here is my husband; an old man? This is really strange!\"","সে বলল, “আমার আফসোস, কেমন করে আমি আমার এই বয়সে সন্তান ধারণ করতে পারি,এবং এই হচ্ছে আমার স্বামী; একজন বৃদ্ধলোক? এটি সত্যিই বিস্ময়কর!”"],
  "11:73": ["They said, \"Do you find it strange for Allah? Allah has bestowed His mercy and blessings upon you, O inhabitants of the shrine. He is Praiseworthy, Glorious.\"","তারা বলল, “তুমি কি আল্লাহর জন্য এটি বিস্ময়কর মনে করো? আল্লাহ তাঁর দয়া এবং অনুগ্রহ তোমাদের উপর অর্পন করেছেন, হে এই ঘরের বাসিন্দারা। তিনি প্রশংসনীয়, মহিমান্বিত।”"],
  "11:74": ["When Abraham's fear subsided, and the good news was delivered to him, he proceeded to argue with us on behalf of Lot's people.","যখন ইব্রাহিমের ভয় কেটে গেল, এবং সুসংবাদটি তার কাছে পৌঁছে দেয়া হল, সে তখন লুতের লোকদের পক্ষে আমাদের সাথে তর্ক শুরু করলো।"],
  "11:75": ["Indeed, Abraham was clement, extremely kind, and obedient.","প্রকৃতপক্ষে,ইব্রাহিম ছিল কোমল হৃদয়, অত্যন্ত দয়ালু,এবং অনুগত।"],
  "11:76": ["\"O Abraham, refrain from this. Your Lord's judgment has been issued; they have incurred unavoidable retribution.\"","“হে ইব্রাহীম, এটা থেকে বিরত হও। তোমার প্রভুর রায় হয়ে গেছে;তারা টেনে এনেছে অনিবার্য শাস্তি।”"],
  "11:77": ["When our messengers went to Lot, they were mistreated, and he was embarrassed by their presence. He said, \"This is a difficult day.\"","যখন আমাদের বার্তাবাহকরা লুতের কাছে গেল, তাদের সাথে দুর্ব্যবহার করা হয়েছিল, এবং সে তাদের উপস্থিতিতে অস্বস্তিকর অবস্থায় পড়লো। সে বলল, “এটা এক কঠিন দিন।”"],
  "11:78": ["His people came rushing; they had grown accustomed to their sinful acts. He said, \"O my people, it would be purer for you, if you take my daughters instead. You shall reverence Allah; do not embarrass me with my guests. Have you not one reasonable man among you?\"","তার লোকেরা ছুটে আসলো; তারা তাদের পাপপূর্ণ কর্মকান্ডে অভ্যস্থ হয়ে ওঠেছিল। সে বলল, “হে আমার লোকেরা,এটি তোমাদের জন্য পবিত্রতর হবে,যদি বিনিময়ে তোমরা আমার মেয়েদের গ্রহণ করো। তোমাদের উচিত আল্লাহকে ভয় করা; আমার অতিথিদের ব্যাপারে আমাকে অস্বস্থিকর অবস্থায় ফেলো না। তোমাদের মাঝে কি একজনও কান্ডজ্ঞান সম্পন্ন ব্যক্তি নেই?”"],
  "11:79": ["They said, \"You know well that we have no need for your daughters; you know exactly what we want.\"","তারা বলল, “তুমি ভাল করেই জানো যে তোমার মেয়েদের আমাদের কোন প্রয়োজন নেই; তুমি ঠিকই জানো আমরা কী চাই।”"],
  "11:80": ["He said, \"I wish I were strong enough, or had a powerful ally!\"","সে বলল, “আমি যদি যথেষ্ঠ শক্তিশালী হতাম, অথবা আমরা যদি কোন ক্ষমতাবান মিত্র থাকতো!”"],
  "11:81": ["(The angels) said, \"O Lot, we are your Lord's messengers, and these people cannot touch you. You shall leave with your family during the night, and let not anyone of you look back, except your wife; she is condemned along with those who are condemned. Their appointed time is the morning. Is not the morning soon enough?\"","(ফেরেশতারা ) বলল, “হে লুত, আমরা তোমার প্রভুর বার্তাবাহক, এবং এই লোকেরা তোমাকে স্পর্শ করতে পারবে না। তুমি তোমার পরিবার নিয়ে রাতে চলে যাবে,আর তোমাদের কাউকে পিছনে তাকাতে দিবে না,তোমার স্ত্রী ছাড়া; সে তাদের সাথে দোষী যারা দোষীসাব্যস্ত হয়েছে। তাদের নির্ধারিত সময় হচ্ছে সকাল। সকাল কি খুব নিকটে নয়?”"],
  "11:82": ["When our judgment came, we turned it upside down, and we showered it with hard, devastating rocks.","যখন আমাদের বিচার আসলো,আমরা একে উল্টে দিলাম এবং আমরা এর উপর কঠিন, বিধ্বংসী পাথর বর্ষণ করলাম।"],
  "11:83": ["Such rocks were designated by your Lord to strike the transgressors.","এরকম পাথরগুলো সীমালঙ্গনকারীদের আঘাত করার জন্য তোমার প্রভুর দ্বারা নির্বাচিত।"],
  "11:84": ["To Midyan we sent their brother Shu'aib. He said, \"O my people, worship Allah; you have no other god beside Him. Do not cheat when you measure or weigh. I see that you are prosperous, and I fear for you the retribution of an overwhelming day.","মাদিয়ানবাসীদের কাছে আমরা তাদের ভাই সো’য়েবকে পাঠিয়েছিলাম। সে বলল, “হে আমার লোকেরা,আল্লাহর উপাসনা করো; তাঁর পাশে তোমাদের অন্য কোন উপাস্য নেই। তোমরা যখন পরিমাপ অথবা ওজন করো তখন ধোঁকা দিও না। আমি দেখছি যে তোমরা সমৃদ্ধিশালী,আর আমি তোমাদের জন্য এক বিধ্বংসী দিনের শাস্তির ভয় করছি।"],
  "11:85": ["\"O my people, you shall give full measure and full weight, equitably. Do not cheat the people out of their rights, and do not roam the earth corruptingly.","“হে আমার লোকেরা, তোমরা পূর্ন পরিমাপ এবং পূর্ণ ওজন দেবে,ন্যায়সঙ্গতভাবে। লোকদেরকে তাদের অধিকার থেকে বঞ্চিত করো না, আর পৃথিবীতে দূর্নীতি করে ঘুরে বেড়িও না।"],
  "11:86": ["\"Whatever Allah provides for you, no matter how small, is far better for you, if you are really believers. I am not a guardian over you.\"","যাকিছু আল্লাহ তোমাদের প্রদান করেন, তা যত ক্ষুদ্রই হোক, তোমাদের জন্য অনেক উত্তম, যদি তোমরা সত্যিই বিশ্বাসী হও। আমি তোমাদের কোন অভিভাবক নই।”"],
  "11:87": ["They said, \"O Shu'aib, does your religion dictate upon you that we must abandon our parents' religion, or running our businesses in any manner we choose? Surely, you are known for being clement, wise.\"","তারা বলল, “হে শু’আইব, তোমার ধর্ম কি তোমাকে নির্দেশ দেয় যে আমাদের অবশ্যই আমাদের পিতামাতার ধর্ম, বা আমাদের পছন্দমত যেকোন পন্থায় আমাদের ব্যবসা চালানো পরিত্যাগ করতে হবে? নিশ্চয়ই, তুমি দয়ালু, বিজ্ঞ হিসেবে পরিচিত।”"],
  "11:88": ["He said, \"O my people, what if I have solid proof from my Lord; what if He has provided me with a great blessing? It is not my wish to commit what I enjoin you from. I only wish to correct as many wrongs as I can. My guidance depends totally on Allah; I have put my trust in Him. To Him I have totally submitted.","সে বলল, “হে আমার লোকেরা, যদি এমন হয় যে আমার কাছে আমার প্রভুর পক্ষ থেকে জোড়ালো প্রমান থাকে;  যদি এমন হয় যে তিনি আমাকে এক মহা অনুগ্রহ প্রদান করেছেন? এটা আমার ইচ্ছা নয় যে আমি তা-ই করবো যা আমি তোমাদেরকে করতে নিষেধ করি। আমি শুধু যতবেশি সম্ভব আমার ভুলগুলো সংশোধন করতে চাই। আমার পথপ্রাপ্তি সম্পূর্ণ আল্লাহর উপর নির্ভর করে; আমি আমার আস্থা তাঁর উপর রেখেছি। আমি তাঁর কাছে পুরোপুরি আত্মসমর্পণ করেছি।"],
  "11:89": ["\"And, O my people, do not be provoked by your opposition to me into incurring the same disasters as the people of Noah, or the people of Hûd, or the people of Sãleh; and the people of Lot are not too far from you.","“আর, হে আমার লোকেরা, আমার প্রতি তোমাদের বিরোধীতা দ্বারা প্ররোচিত হয়ে একই বিপর্যয় টেনে এনো না নুহের লোকদের, বা হুদের লোকদের, বা সালেহের লোকদের মত; এবং লুতের লোকেরা তোমাদের থেকে খুব বেশি দূরে নয়।"],
  "11:90": ["\"You shall implore your Lord for forgiveness, then repent to Him. My Lord is Most Merciful, Kind.\"","“তোমাদের উচিত তোমাদের প্রভুর কাছে ক্ষমার জন্য মিনতি করা, এরপর তাঁর কাছে অনুশোচনা করো। আমার প্রভু পরম দয়ালু,প্রেমময়।”"],
  "11:91": ["They said, \"O Shu'aib, we do not comprehend many of the things you are telling us, and we see that you are powerless among us. If it were not for your tribe, we would have stoned you. You have no value for us.\"","তারা বলল, “হে শু’আইব, তুমি যা বলছো তার অনেক কিছু আমরা বুঝি না, এবং আমরা দেখি যে তুমি আমাদের মাঝে ক্ষমতাহীন। যদি তোমার গোত্র না থাকতো, আমরা তোমাকে পাথর মারতাম। আমাদের কাছে তোমার কোন মূল্য নেই।”"],
  "11:92": ["He said, \"O my people, does my tribe command a greater respect than Allah? Is this why you have been heedless of Him? My Lord is fully aware of everything you do.","সে বলল, “হে আমার লোকেরা, আমার গোত্র কি আল্লাহর থেকে বেশি সম্মানের অধিকারী? এ কারণেই কি তোমরা তাঁর প্রতি উদাসীন হয়ে আছো? তোমরা যা কিছু করো সে সম্পর্কে আমার প্রভু পূর্ণ অবগত।"],
  "11:93": ["\"O my people, go on doing what you wish, and so will I. You will certainly find out which of us will incur shameful retribution; you will find out who the liar is. Just wait in anticipation, and I will wait in anticipation along with you.\"","“হে আমার লোকেরা, যা তোমাদের ইচ্ছা করতে থাকো, আর আমিও তা করবো। তোমরা অবশ্যই দেখতে পাবে কে আমাদের মাঝে লজ্জাজনক শাস্তি টেনে আনে; তোমরা দেখতে পাবে মিথ্যাবাদী কে। শুধু আশা নিয়ে অপেক্ষা করো, এবং আমিও তোমাদের সাথে আশা নিয়ে অপেক্ষা করবো।"],
  "11:94": ["When our judgment came, we saved Shu'aib and those who believed with him, by mercy from us. As for the evil ones, they were struck by a disaster that left them dead in their homes.","যখন আমাদের বিচার আসলো,আমরা শু’আইব এবং তার সাথে যারা বিশ্বাস করেছিল তাদের রক্ষা করেছিলাম, আমাদের পক্ষ থেকে দয়া দিয়ে। আর যারা মন্দ ব্যক্তি ছিল, তারা এক বিপর্যয় দ্বারা আঘাতপ্রাপ্ত হয়েছিল যা তাদেরকে তাদের বাড়িতে মৃত ফেলে রেখেছিল।"],
  "11:95": ["It was as though they never existed. Thus, Midyan perished, just like Thamûd had perished before that.","এটা এমন ছিল যেন তাদের কখনো অস্থিত্ব ছিল না। এভাবে,মাদিয়ানবাসী বিলুপ্ত হয়েছিল, যেভাবে এর আগে সামুদ জাতি বিলুপ্ত হয়েছিল।"],
  "11:96": ["We sent Moses with our signs and a profound authority.","আমরা মূসাকে আমাদের নিদর্শনাবলি ও এক সুস্পষ্ট কর্তৃত্বসহ পাঠিয়েছিলাম।"],
  "11:97": ["To Pharaoh and his elders. But they followed the command of Pharaoh, and Pharaoh's command was not wise.","ফেরাউন এবং তার সভাসদদের কাছে। কিন্তু তারা ফেরাউনের আদেশ অনুসরণ করলো আর ফেরাউনের আদেশ বিচক্ষন ছিল না।"],
  "11:98": ["He will lead his people on the Day of Resurrection, all the way to Hell; what a miserable abode to live in!","সে পুনরুত্থান দিনে তার লোকদের নেতৃত্ব দিবে,নরকের পথে;কি এক শোচনীয় বাসস্থান বসবাসের জন্য!"],
  "11:99": ["They have incurred condemnation in this life, as well as on the Day of Resurrection; what a miserable path to follow!","তারা এই জীবনে অভিশাপ টেনে এনেছে একইসাথে পুনরুত্থান দিনে; অনুসরণের কি এক শোচনীয় পথ!"],
  "11:100": ["This is news from the past communities that we narrate to you. Some are still standing, and some have vanished.","এটি অতীত সম্প্রদায়ের সংবাদ যা আমরা তোমাদের কাছে বর্ণনা করি। কিছু এখনো টিকে আছে,আর কিছু বিলুপ্ত হয়েছে।"],
  "11:101": ["We never wronged them; they wronged their own souls. Their gods, whom they invoked beside Allah, could not help them in the least when the judgment of your Lord came. In fact, they only ensured their doom.","আমরা কখনও তাদের প্রতি অন্যায় করিনি; তারাই তাদের নিজেদের আত্মার প্রতি অন্যায় করেছে। তাদের উপাস্যরা,যাদেরকে তারা আল্লাহর পাশে ডেকেছে, তাদেরকে একটুও সাহায্য করতে পারেনি যখন তোমার প্রভুর বিচার আসলো। কার্যত, তারা শুধু তাদের সর্বনাশ নিশ্চিত করেছে।"],
  "11:102": ["Such was the retribution enforced by your Lord when the communities transgressed. Indeed, His retribution is painful, devastating.","এমনই ছিল তোমার প্রভুর আরোপিত শাস্তি যখন সম্প্রদায়গুলো সীমালংঘন করেছিল। প্রকৃতপক্ষে,তাঁর শাস্তি যন্ত্রনাদায়ক, ধ্বংসাত্মক।"],
  "11:103": ["This should be a lesson for those who fear the retribution of the Hereafter. That is a day when all the people will be summoned—a day to be witnessed.","এটি তাদের জন্য একটি শিক্ষনীয় বিষয় হওয়া উচিত যারা পরকালের শাস্তিকে ভয় করে। এটি এমন এক দিন যখন সকল মানুষকে ডাকা হবে- যেদিন হবে সাক্ষী হওয়ার দিন।"],
  "11:104": ["We have appointed a specific time for it to take place.","আমরা এটি ঘটানোর জন্য একটি নির্দিষ্ট সময় নির্ধারণ করেছি।"],
  "11:105": ["The day it comes to pass, no soul will utter a single word, except in accordance with His will. Some will be miserable, and some will be happy.","যেদিন এটি আসবে, কোন আত্মা একটি শব্দও উচ্চারণ করবে না, তাঁর ইচ্ছা ব্যতীত। কেউ কেউ হবে দুর্দশাগ্রস্থ, আর কেউ হবে সুখী।"],
  "11:106": ["As for the miserable ones, they will be in Hell, wherein they sigh and wail.","আর যারা দুর্দশাগ্রস্থ, তারা থাকবে নরকে, যেখানে তারা দীর্ঘশ্বাস ফেলবে ও আর্তনাত করবে।"],
  "11:107": ["Eternally they abide therein, for as long as the heavens and the earth endure, in accordance with the will of your Lord. Your Lord is doer of whatever He wills.","তারা সেখানে চিরকাল বাস করে, যতকাল আকাশমন্ডলী এবং পৃথিবী টিকে থাকে, তোমার প্রভুর ইচ্ছা অনুযায়ী। তোমার প্রভু তা-ই করেন যা কিছু তিনি ইচ্ছা করেন।"],
  "11:108": ["As for the fortunate ones, they will be in Paradise. Eternally they abide therein, for as long as the heavens and the earth endure, in accordance with the will of your Lord—an everlasting reward.","আর যারা সৌভাগ্যবান, তারা থাকবে স্বর্গে। তারা সেখানে চিরকাল বাস করবে, যতকাল আকাশমন্ডলী এবং পৃথিবী টিকে থাকে, তোমার প্রভুর ইচ্ছা অনুযায়ী - এক চিরস্থায়ী পুরষ্কার।"],
  "11:109": ["Do not have any doubt regarding what these people worship; they worship exactly as they found their parents worshiping. We will requite them their due share fully, without reduction.","এই লোকেরা যা উপাসনা করে সে ব্যাপারে কোন সন্দেহ রেখো না; তারা উপাসনা করে ঠিক যেভাবে তারা তাদের পিতামাতাকে উপাসনা করতে দেখেছে। আমরা তাদের প্রাপ্য অংশ তাদেরকে সম্পূর্ণরূপে দিয়ে দেবো, কম না করে।"],
  "11:110": ["We have given Moses the scripture, but it was disputed, and if it were not for a predetermined word decreed by your Lord, they would have been judged immediately. They are full of doubt about this, suspicious.","আমরা মুসাকে ঐশ্বীগ্রন্থ দিয়েছিলাম, কিন্তু এটি বিতর্কিত হয়েছিল, আর যদি তা তোমার প্রভুর দ্বারা জারি করা একটি পূর্বনির্ধারিত আদেশ না হতো, অবিলম্বে তাদের বিচার করা হতো। তারা এ ব্যাপারে পুরোপুরি সন্দেহে আছে,দ্বিধাগ্রস্থ।"],
  "11:111": ["Your Lord will surely recompense everyone for their works. He is fully Cognizant of everything they do.","তোমার প্রভু অবশ্যই সবাইকে তাদের কাজের প্রতিদান দিবেন। তারা যা করে তিনি সেসব ব্যাপারে সম্পূর্ণ অবগত।"],
  "11:112": ["Therefore, continue on the path you have been enjoined to follow, together with those who repented with you, and do not transgress. He is Seer of everything you do.","সুতরাং, সে পথে চলতে থাকো যা তোমাকে অনুসরণের আদেশ করা হয়েছে,তাদের সাথে একত্রে যারা তোমার সাথে অনুশোচনা করেছে, এবং সীমালংঘন করো না। তোমরা যা কিছু করো তিনি তা দেখেন।"],
  "11:113": ["Do not lean towards those who have transgressed, lest you incur Hell, and find no allies to help you against Allah, then end up losers.","যারা সীমালংঘন করেছে তাদের প্রতি ঝুঁকে পড়ো না,পাছে তোমরা নরক টেনে আনো,এবং আল্লাহর বিপক্ষে তোমাদের সাহায্য করার জন্য কোন মিত্র খোঁজে না পাও, এরপর সবশেষে ক্ষতিগ্রস্থ হও।"],
  "11:114": ["You shall observe the Contact Prayers (Salat) at both ends of the day, and during the night. The righteous works wipe out the evil works. This is a reminder for those who would take heed.","তুমি দিনের উভয় প্রান্তে সংযোগ প্রার্থনা (সালাত) পালন করবে, এবং রাতের বেলা। সৎকাজ মন্দ কাজকে মুছে ফেলে। এটি একটি সতর্কবার্তা তাদের জন্য যারা চিন্তা-ভাবনা করবে।"],
  "11:115": ["You shall steadfastly persevere, for Allah never fails to recompense the righteous.","তুমি দৃড়তার সাথে অবিচল থাকবে, কারণ আল্লাহ সৎকর্মশীলদের প্রতিদান দিতে কখনও ব্যর্থ হন না।"],
  "11:116": ["If only some of those among the previous generations possessed enough intelligence to forbid evil! Only a few of them deserved to be saved by us. As for the transgressors, they were preoccupied with their material luxuries; they were guilty.","যদি শুধু পূর্ববর্তী প্রজন্মের মধ্যে কেউ কেউ মন্দ কাজ নিষিদ্ধ করার জন্য যথেষ্ঠ বুদ্ধিমত্তা রাখতো! তাদের অল্প কয়েকজনই আমাদের দ্বারা রক্ষা পাওয়ার যোগ্য ছিল। আর যারা সীমালংঘনকারী,তারা তাদের বৈষয়িক বিলাসিতা নিয়ে ব্যস্ত ছিল, তারা ছিল অপরাধী।"],
  "11:117": ["Your Lord never annihilates any community unjustly, while its people are righteous.","তোমার প্রভু কখনও অন্যায়ভাবে কোন সম্প্রদায়কে ধ্বংস করেন না,যখন এর লোকেরা সৎকর্মশীল।"],
  "11:118": ["Had your Lord willed, all the people would have been one congregation (of believers). But they will always dispute (the truth).","তোমার প্রভু যদি চাইতেন, তবে সকল মানুষ একটি (বিশ্বাসী ) দল হতো। কিন্তু তারা সবসময় (সত্যকে ) বিতর্কিত করবেই।"],
  "11:119": ["Only those blessed with mercy from your Lord (will not dispute the truth). This is why He created them. The judgment of your Lord has already been issued: \"I will fill Hell with jinns and humans, all together.\"","শুধু যারা তোমার প্রভুর কাছ থেকে দয়া দ্বারা অনুগ্রহপ্রাপ্ত  (তারা সত্যকে বিতর্কিত করবে না)। এই জন্য তিনি তাদের সৃষ্টি করেছেন। তোমার প্রভুর রায় পূর্বেই জারি হয়েছেঃ “আমি জীন ও মানুষ দিয়ে নরক পূর্ন করবো,সবাইকে একসাথে।”"],
  "11:120": ["We narrate to you enough history of the messengers to strengthen your heart. The truth has come to you herein, as well as enlightenments and reminders for the believers.","আমরা তোমাকে বার্তাবাহকদের যথেষ্ঠ পরিমান ইতিহাস বর্ণনা করি তোমার হৃদয়কে শক্তিশালি করতে। এখানে তোমার কাছে সত্য এসেছে, সেই সাথে বিশ্বাসীদের জন্য আলোকিত জ্ঞান ও সতর্কবানী।"],
  "11:121": ["Say to those who disbelieve, \"Do whatever you can, and so will we.","যারা অবিশ্বাস করে তাদের বল, “তোমরা যা পারো করো,এবং আমরাও তা করবো।"],
  "11:122": ["\"Then wait; we too will wait.\"","“তারপর অপেক্ষা করো; আমরাও অপেক্ষা করবো।”"],
  "11:123": ["To Allah belongs the future of the heavens and the earth, and all matters are controlled by Him. You shall worship Him and trust in Him. Your Lord is never unaware of anything you do.","আকাশমন্ডলী ও পৃথিবীর ভবিষ্যৎ আল্লাহর অধীনে, আর সব বিষয় তাঁর দ্বারা নিয়ন্ত্রিত হয়। তুমি তাঁর উপাসনা করবে এবং তাঁর প্রতি আস্থা রাখবে। তোমার প্রভু কখনোই অনবগত নন যা কিছু তোমরা করো।"],
  "12:1": ["A. L. R. These (letters) are proofs of this profound scripture.","অ. ল. র। এইসব (অক্ষরগুলো) এই জ্ঞানগর্ভ ঐশীগ্রন্থের প্রমাণ।"],
  "12:2": ["We have revealed it an Arabic Quran, that you may understand.","আমরা একে আরবী কুরআন রূপে প্রকাশ করেছি, যাতে তোমরা বুঝতে পারো।"],
  "12:3": ["We narrate to you the most accurate history through the revelation of this Quran. Before this, you were totally unaware.","আমরা এই কুরআনের ঐশীবার্তার মাধ্যমে তোমাদের নিকট সবচেয়ে নির্ভূল ইতিহাস বর্ণনা করি। এর আগে, তোমরা ছিলে সম্পূর্ণ অসচেতন।"],
  "12:4": ["Recall that Joseph said to his father, \"O my father, I saw eleven planets, and the sun, and the moon; I saw them prostrating before me.\"","স্মরণ করো যে ইউসুফ তার পিতাকে বলেছিল, \"হে আমার পিতা, আমি এগারটি গ্রহ, ও সূর্য, ও চাঁদ দেখেছি ; আমি দেখেছি এগুলোকে আমার সামনে সেজদা করতে। \""],
  "12:5": ["He said, \"My son, do not tell your brothers about your dream, lest they plot and scheme against you. Surely, the devil is man's worst enemy.","সে বলল, \"আমার পুত্র, তোমার স্বপ্নের বিষয়ে তোমার ভাইদের বলো না, পাছে তারা তোমার বিরুদ্ধে চক্রান্ত করে ও ফন্দি আটে। নিশ্চয়ই, শয়তান হচ্ছে মানুষের ঘোরতর শত্রু।"],
  "12:6": ["\"Your Lord has thus blessed you, and has given you good news through your dream. He has perfected His blessings upon you and upon the family of Jacob, as He did for your ancestors Abraham and Isaac before that. Your Lord is Omniscient, Most Wise.\"","“এভাবে তোমার প্রভু তোমাকে সৌভাগ্যশালী করেছেন, এবং তোমাকে তোমার সপ্নের মাধ্যমে সুসংবাদ দিয়েছেন। তোমার প্রতি এবং ইয়াকুবের পরিবারের প্রতি তিনি তাঁর আশীর্বাদ সুসম্পন্ন করেছেন, যেমন ভাবে এর আগে তিনি তোমার পূর্বপুরুষ ইব্রাহীম এবং ইসহাকের জন্য করেছিলেন। তোমরা প্রভু সর্বজ্ঞ, সবচেয়ে জ্ঞানী।"],
  "12:7": ["In Joseph and his brothers there are lessons for the seekers.","ইউসুফ এবং তার ভাইদের মধ্যে অন্বেষণকারীদের জন্য শিক্ষা রয়েছে।"],
  "12:8": ["They said, \"Joseph and his brother are favored by our father, and we are in the majority. Indeed, our father is far astray.","তারা বলেছিল, “ইউসুফ এবং তার ভাই আমাদের পিতার সুনজরে রয়েছে, এবং আমরা সংখ্যায় বেশি। আসলেই, আমাদের পিতা স্পষ্ট ভ্রান্তিতে আছে।"],
  "12:9": ["\"Let us kill Joseph, or banish him, that you may get some attention from your father. Afterwards, you can be righteous people.\"","“চল আমরা ইউসুফকে হত্যা করি, অথবা তাকে নির্বাসিত করি, যাতে তোমরা তোমাদের পিতার মনোযোগ পেতে পারো। এরপর, তোমরা সৎকর্মশীল লোক হতে পারবে।"],
  "12:10": ["One of them said, \"Do not kill Joseph; let us throw him into the abyss of the well. Perhaps some caravan can pick him up, if this is what you decide to do.\"","তাদের একজন বলেছিল, “ইউসুফকে হত্যা করো না; চল আমরা তাকে কুপের গভীরে নিক্ষেপ করি। হয়তো কোন কাফেলা তাকে তুলে নিতে পারে, যদি তোমরা এটা করার জন্যই সিদ্ধান্ত নিয়ে থাকো।"],
  "12:11": ["They said, \"Our father, why do you not trust us with Joseph? We will take good care of him.","তারা বলল, \"আমাদের পিতা, কেন আপনি ইউসুফের বিষয়ে আমাদের উপর আস্থা রাখেন না? আমরা তাকে ভালো করে দেখে রাখবো।"],
  "12:12": ["\"Send him with us tomorrow to run and play. We will protect him.\"","\"কাল তাকে আমাদের সাথে দৌঁড়তে এবং খেলতে পাঠান। আমরা তাকে নিরাপদে রাখবো।\""],
  "12:13": ["He said, \"I worry lest you go away with him, then the wolf may devour him while you are not watching him.\"","সে বলল, \"আমার ভয় হয় পাছে তোমরা তাকে নিয়ে দূরে চলে যাও, এরপর যখন তার প্রতি তোমরা খেয়াল না করো নেকড়ে তাকে খেয়ে ফেলতে পারে।\""],
  "12:14": ["They said, \"Indeed, if the wolf devours him, with so many of us around, then we are really losers.\"","তারা বলল, \"নিশ্চয়, যদি নেকড়ে তাকে খেয়ে ফেলে, আমরা অনেকেই আশেপাশে থাকা সত্ত্বেও, তাহলে আমরা সত্যিই ক্ষতিগ্রস্ত।\""],
  "12:15": ["When they went away with him, and unanimously decided to throw him into the abyss of the well, we inspired him: \"Some day, you will tell them about all this, while they have no idea.\"","যখন তারা তাকে নিয়ে দূরে চলে গেল, এবং সর্বসম্মতিক্রমে তাকে কুপের গভীরে নিক্ষেপ করার সিদ্ধান্ত নিল, আমরা তাকে অনুপ্রাণিত করলাম, \"একদিন, তুমি এই সবকিছু সম্পর্কে তাদের বলবে, অথচ তাদের কোন ধারণাই থাকবে না।\""],
  "12:16": ["They came back to their father in the evening, weeping.","তারা সন্ধ্যায় তাদের পিতার কাছে ফিরে এলো, কাঁদতে কাঁদতে।"],
  "12:17": ["They said, \"Our father, we went racing with each other, leaving Joseph with our equipment, and the wolf devoured him. You will never believe us, even if we were telling the truth.\"","তারা বলল, “আমাদের পিতা, আমরা একে অন্যের সাথে দৌড়াতে গিয়েছিলাম, ইউসুফকে আমাদের সরঞ্জামের কাছে রেখে, আর নেকড়ে তাকে খেয়ে ফেলল। আপনি কখনই আমাদের বিশ্বাস করবেন না, যদিও আমরা আপনাকে সত্য বলছি।"],
  "12:18": ["They produced his shirt with fake blood on it. He said, \"Indeed, you have conspired with each other to commit a certain scheme. All I can do is resort to a quiet patience. May Allah help me in the face of your conspiracy.\"","তারা তার জামায় নকল রক্ত লাগিয়ে উপস্থাপন করলো। সে বলল, “নিশ্চয়, তোমরা পরস্পর চক্রান্ত করেছ একটা নির্দিষ্ট পরিকল্পনা বাস্তবায়ন করতে। আমি যা করতে পারি তা হল নীরবে ধৈর্য ধারন। তোমাদের ষড়যন্ত্রের মুখে আল্লাহ আমাকে সাহায্য করুন”।"],
  "12:19": ["A caravan passed by, and soon sent their waterer. He let down his bucket, then said, \"How lucky! There is a boy here!\" They took him along as merchandise, and Allah was fully aware of what they did.","একটি কাফেলা পাশ দিয়ে যাচ্ছিল, এবং শীঘ্রই তাদের পানি সংগ্রাহককে পাঠালো। সে তার বালতি নিচে ফেললো, তারপর বলল, “কি সৌভাগ্য! এখানে তো দেখি এক বালক! তারা তাকে পণ্যদ্রব্য হিসাবে সাথে নিল, এবং তারা যা করেছিল আল্লাহ সে বিষয়ে সম্পূর্ণ অবগত ছিলেন।"],
  "12:20": ["They sold him for a cheap price— a few Dirhams—for they did not have any need for him.","তারা সস্তা মুল্যে তাকে বিক্রি করলো- অল্প কিছু দিরহামে-কারন তাকে তাদের কোন প্রয়োজন ছিল না।"],
  "12:21": ["The one who bought him in Egypt said to his wife, \"Take good care of him. Maybe he can help us, or maybe we can adopt him.\" We thus established Joseph on earth, and we taught him the interpretation of dreams. Allah's command is always done, but most people do not know.","যে ব্যক্তি তাকে মিশরে এনেছিল সে তার স্ত্রীকে বলল, \"তার ভাল যত্ন নাও। হয়তো সে আমাদের উপকারে আসবে, অথবা আমরা তাকে দত্তক নিতে পারি।\"এভাবে আমরা ইউসুফকে পৃথিবীতে প্রতিষ্ঠিত করেছি, এবং আমরা তাকে স্বপ্নের ব্যাখ্যা করতে শিখিয়েছি, আল্লাহর নির্দেশ সর্বদাই সম্পন্ন হয়, কিন্তু বেশির ভাগ লোক জানে না।"],
  "12:22": ["When he reached maturity, we endowed him with wisdom and knowledge. We thus reward the righteous.","যখন সে পরিণত বয়সে পৌছল, আমরা তাকে প্রজ্ঞা ও জ্ঞান দান করলাম। আমরা এভাবে সৎকর্মশীলদের পুরষ্কৃত করি।"],
  "12:23": ["The lady of the house where he lived tried to seduce him. She closed the doors and said, \"I am all yours.\" He said, \"May Allah protect me. He is my Lord, who gave me a good home. The transgressors never succeed.\"","যেখানে সে বাস করতো সে বাড়ির কর্ত্রী তাকে প্রলুব্ধ করার চেষ্টা করলো। সে দরজাগুলো বন্ধ করলো এবং বলল, \"আমি সম্পূর্ণরূপে তোমার।”সে বলল, \"আল্লাহ আমায় রক্ষা করুক। তিনি আমার প্রভু, যিনি আমাকে একটি ভালো বাসস্থান দিয়েছেন। সীমালঙ্ঘনকারীরা কখনো সফল হয় না।\""],
  "12:24": ["She almost succumbed to him, and he almost succumbed to her, if it were not that he saw a proof from his Lord. We thus diverted evil and sin away from him, for he was one of our devoted servants.","সে (মহিলা) তার প্রতি প্রায় ঢলে পড়েছিল এবং সে (ইউসুফ) তার প্রতি প্রায় ঢলে পড়েছিল, যদি সে(ইউসুফ) তার প্রভুর পক্ষ থেকে একটি প্রমাণ না দেখতো। আমরা এভাবে মন্দ ও পাপকে তার থেকে সরিয়ে দিয়েছিলাম, কারণ সে ছিল আমাদের নিবেদিত বান্দাদের একজন।"],
  "12:25": ["The two of them raced towards the door, and, in the process, she tore his garment from the back. They found her husband at the door. She said, \"What should be the punishment for one who wanted to molest your wife, except imprisonment or a painful punishment?\"","তাদের দুজনে দরজার দিকে ছুটল, এবং, এক পর্যায়ে, সে(মহিলা) পিছন থেকে তার পোষাক ছিঁড়ে ফেললো। তারা তার স্বামীকে দরজায় পেল। সে বলল, \"যে ব্যক্তি তোমার স্ত্রীর সাথে অপকর্ম করতে চেয়েছে তার শাস্তি কি হওয়া উচিত, বন্দী থাকা বা এক যন্ত্রণাকর শাস্তি পাওয়া ছাড়া?\""],
  "12:26": ["He said, \"She is the one who tried to seduce me.\" A witness from her family suggested: \"If his garment is torn from the front, then she is telling the truth and he is a liar.","সে বলল, “সে-ই আমাকে প্রলুব্ধ করার চেষ্টা করেছিল”। তার পরিবারের একজন সাক্ষী পরামর্শ দিলঃ “যদি তার পোশাক সামনে থেকে ছেঁড়া থাকে, তবে সে (মহিলা) সত্য বলছে, এবং সে(ইউসুফ) মিথ্যুক”।"],
  "12:27": ["\"And if his garment is torn from the back, then she lied, and he is telling the truth.\"","“এবং যদি তার পোশাক পেছন থেকে ছেঁড়া থাকে, তবে সে (মহিলা) মিথ্যা বলছে, এবং সে(ইউসুফ) সত্য বলছে”।"],
  "12:28": ["When her husband saw that his garment was torn from the back, he said, \"This is a woman's scheme. Indeed, your scheming is formidable.","যখন তার স্বামী দেখলো যে তার পোশাক পেছন থেকে ছেঁড়া, সে বলল, “এটা এক নারীর চক্রান্ত। নিশ্চয়, তোমার চক্রান্ত দূর্ভেদ্য”।"],
  "12:29": ["\"Joseph, disregard this incident. As for you (my wife), you should seek forgiveness for your sin. You have committed an error.\"","“ইউসুফ, এ ঘটনা উপেক্ষা করো। আর (আমার স্ত্রী) তোমার উচিত তোমার পাপের জন্য ক্ষমা চাওয়া। তুমি একটি ভুল করেছ”।"],
  "12:30": ["Some women in the city gossiped: \"The governor's wife is trying to seduce her servant. She is deeply in love with him. We see that she has gone astray.\"","শহরে কিছু নারী বলাবলি করতে লাগলোঃ “শাসকের স্ত্রী তার ভৃত্যকে প্রলুব্ধ করার চেষ্টা করছে। সে তার গভীর প্রেমে পড়েছে। আমরা দেখছি যে সে বিপথে গেছে”।"],
  "12:31": ["When she heard of their gossip, she invited them, prepared for them a comfortable place, and gave each of them a knife. She then said to him, \"Enter their room.\" When they saw him, they so admired him, that they cut their hands. They said, \"Glory be to Allah, this is not a human being; this is an honorable angel.\"","যখন সে(মহিলা) তাদের রটনা শুনলো, সে তাদের আমন্ত্রণ জানালো, তাদের জন্য একটি আরামদায়ক স্থান প্রস্তুত করলো, এবং তাদের প্রত্যেককে একটি ছুরি দিল। এরপর সে তাকে বলল, \"তাদের কক্ষে প্রবেশ করো।”যখন তারা তাকে দেখল, তারা তার রূপে এতোই বিমুগ্ধ হলো, যে তারা তাদের হাত কেটে ফেলল। তারা বলল, \"মহিমা আল্লাহরই, এ তো কোন মানুষ নয়; এ এক সম্মানিত ফেরেশতা।\""],
  "12:32": ["She said, \"This is the one you blamed me for falling in love with. I did indeed try to seduce him, and he refused. Unless he does what I command him to do, he will surely go to prison, and will be debased.\"","সে বলল, \"এই সে ব্যক্তি যার প্রেমে পড়ার কারণে তোমরা আমাকে দোষী করেছিলে। আসলে আমিই তাকে প্রলুব্ধ করার চেষ্টা করেছিলাম, এবং সে প্রত্যাখ্যান করেছিল। যদি সে আমি যা আদেশ করি তা না করে, নির্ঘাৎ সে জেলে যাবে এবং হেয় হবে।"],
  "12:33": ["He said, \"My Lord, the prison is better than giving in to them. Unless You divert their scheming from me, I may desire them and behave like the ignorant ones.\"","সে বলল, \"আমার প্রভু, তাদের কাছে নতি স্বীকার করার থেকে জেলে যাওয়া ভাল। যদি না আমার থেকে আপনি তাদের চক্রান্ত সরিয়ে দেন, আমি হয়তো তাদের আকাঙ্ক্ষা করবো এবং নির্বোধের মত আচরণ করবো।"],
  "12:34": ["His Lord answered his prayer and diverted their scheming from him. He is the Hearer, the Omniscient.","তার প্রভু তার প্রার্থনার জবাব দিলেন এবং তার থেকে তাদের চক্রান্ত সরিয়ে দিলেন। তিনি সর্বশ্রোতা, সর্বজ্ঞানী।"],
  "12:35": ["Later, they saw to it, despite the clear proofs, that they should imprison him for awhile.","পরবর্তীতে, তারা এটি দেখেছিল, স্পষ্ট প্রমাণাদি সত্ত্বেও, যে তাদের উচিৎ তাকে কিছুকালের জন্য বন্দী রাখা।"],
  "12:36": ["Two young men were in the prison with him. One of them said, \"I saw (in my dream) that I was making wine,\" and the other said, \"I saw myself carrying bread on my head, from which the birds were eating. Inform us of the interpretation of these dreams. We see that you are righteous.\"","তার সাথে কারাগারে দুজন যুবক ছিল। তাদের একজন বলল, “আমি (আমার স্বপ্নে) দেখেছি যে আমি মদ তৈরি করছি,”এবং অন্যজন বলল, “আমি দেখেছি আমি আমার মাথায় রুটি বহন করছি, যা থেকে পাখিরা খাচ্ছে। এই স্বপ্নগুলোর ব্যাখ্যা আমাদের জানাও। আমরা দেখছি যে তুমি সৎকর্মশীল”।"],
  "12:37": ["He said, \"If any food is provided to you, I can inform you about it before you receive it. This is some of the knowledge bestowed upon me by my Lord. I have forsaken the religion of people who do not believe in Allah, and with regard to the Hereafter, they are really disbelievers.","সে বলল, “যদি তোমাদের কোন খাবার দেয়া হয়, তা তোমরা পাওয়ার আগে আমি তোমাদেরকে এর সম্পর্কে জানাতে পারবো। এগুলো আমার প্রতি আমার প্রভুর প্রদত্ত কিছু জ্ঞান। আমি পরিত্যাগ করেছি সেই লোকদের ধর্ম যারা আল্লাহতে বিশ্বাস করে না, এবং পরকালের ব্যাপারে, তারা আসলেই অবিশ্বাসী”।"],
  "12:38": ["\"And I followed instead the religion of my ancestors, Abraham, Isaac, and Jacob. We never set up any idols beside Allah. Such is the blessing from Allah upon us and upon the people, but most people are unappreciative.","“এবং আমি এর পরিবর্তে অনুসরণ করেছি আমার পূর্বপুরুষ ইব্রাহীম, ইসহাক, এবং ইয়াকুবের ধর্ম। আমরা কখনো আল্লাহর পাশে কোন উপাস্য স্থাপন করি না। এমনই আল্লাহর আশীর্বাদ আমাদের প্রতি এবং মানুষের প্রতি, কিন্তু বেশিরভাগ মানুষ অকৃতজ্ঞ।"],
  "12:39": ["\"O my prison mates, are several gods better, or Allah alone, the One, the Supreme?","“হে আমার কারাসঙ্গিরা, অনেক উপাস্য উত্তম, নাকি একমাত্র আল্লাহ, একক সত্ত্বা, সর্বোচ্চ?”"],
  "12:40": ["\"You do not worship beside Him except innovations that you have made up, you and your parents. Allah has never authorized such idols. All ruling belongs to Allah, and He has ruled that you shall not worship except Him. This is the perfect religion, but most people do not know.","“তোমরা তার পাশে কোন কিছুর উপাসনা করো না উদ্ভাবন ছাড়া, যা তোমরা বানিয়েছো, তোমরা এবং তোমাদের পিতামাতারা। আল্লাহ কখনই এমন উপাস্যের অনুমোদন দেননি। সকল বিধান আল্লাহর, এবং তিনি বিধান দিয়েছেন যে তোমরা তাকে ছাড়া অন্যকিছুর উপাসনা করবে না। এটাই সঠিক ধর্ম, কিন্তু বেশিরভাগ মানুষ জানে না”।"],
  "12:41": ["\"O my prison mates, one of you will be the wine butler for his lord, while the other will be crucified— the birds will eat from his head. This settles the matter about which you have inquired.\"","\"হে আমার কারাসঙ্গীরা, তোমাদের একজন তার মনিবের মদ পরিবেশক হবে, যখন অন্যজন হবে ক্রুশবিদ্ধ- পাখিরা তার মাথা থেকে খাবে। তোমরা যা জানতে চেয়েছ এটা তা পূর্ণ করে।"],
  "12:42": ["He then said to the one to be saved \"Remember me at your lord.\" Thus, the devil caused him to forget his Lord, and, consequently, he remained in prison a few more years.","সে এরপর যার রক্ষা পাওয়ার কথা তাকে বলল, \"তোমার মনিবের কাছে আমার কথা স্মরণ করো।” এরূপে, শয়তান তাকে তার প্রভুর কথা ভুলিয়ে দিল, এবং, পরিনামে, সে আরো কয়েক বছর কারাগারে রইলো ।"],
  "12:43": ["The king said, \"I saw seven fat cows being devoured by seven skinny cows, and seven green spikes (of wheat), and others shriveled. O my elders, advise me regarding my dream, if you know how to interpret the dreams.\"","রাজা বলল, “আমি দেখলাম সাতটি মোটাতাজা গরুকে গিলে ফেলছে সাতটি কঙ্কালসার গরু, এবং (গমের) সাতটি সবুজ শীষ, এবং অন্যগুলো কোঁকড়ানো। হে আমার সভাসদরা, আমাকে আমার স্বপ্নের বিষয়ে পরামর্শ দাও, যদি তোমরা স্বপ্নের ব্যাখ্যা দিতে জানো।”"],
  "12:44": ["They said, \"Nonsense dreams. When it comes to the interpretation of dreams, we are not knowledgeable.\"","তারা বলল, \"অর্থহীন স্বপ্ন। যখন স্বপ্ন ব্যাখ্যা করার বিষয় আসে, সে ব্যাপারে আমরা জ্ঞানী নই।\""],
  "12:45": ["The one who was saved (from the prison) said, now that he finally remembered, \"I can tell you its interpretation, so send me (to Joseph).\"","যে ব্যক্তি (কারাগার থেকে) রক্ষা পেয়েছিল সে বলল, অবশেষে যেহেতু তার মনে পড়লো, \"আমি আপনাকে এর ব্যাখ্যা বলতে পারি, তাই আমাকে (ইউসুফের) কাছে পাঠান।\""],
  "12:46": ["\"Joseph my friend, inform us about seven fat cows being devoured by seven skinny cows, and seven green spikes, and others shriveled. I wish to go back with some information for the people.\"","“আমার বন্ধু ইউসুফ, সাতটি মোটাতাজা গরুকে গিলে ফেলছে সাতটি হাড্ডিসার গরু, এবং সাতটি সবুজ শীষ, ও অন্যগুলো কোঁকড়ানো, এ বিষয়ে আমাদের জানাও। আমি লোকদের জন্য কিছু তথ্য নিয়ে ফিরে যেতে চাই”।"],
  "12:47": ["He said, \"What you cultivate during the next seven years, when the time of harvest comes, leave the grains in their spikes, except for what you eat.","সে বলল, “পরবর্তী সাত বছর  যা তোমরা আবাদ করো, যখন ফসল তোলার সময় আসে, শস্য তার শীষের মধ্যে রেখে দাও, যা তোমরা খাও সেগুলো ছাড়া”।"],
  "12:48": ["\"After that, seven years of drought will come, which will consume most of what you stored for them.","“এরপর, সাত বছরের খরা আসবে, যা এদের জন্য তোমাদের জমা রাখা বেশির ভাগ অংশ সাবাড় করবে।"],
  "12:49": ["\"After that, a year will come that brings relief for the people, and they will, once again, press juice.\"","“এরপর, একটি বছর আসবে যা লোকদের জন্য পরিত্রান নিয়ে আসবে, এবং তারা আবারও, রস নিংড়াবে”।"],
  "12:50": ["The king said, \"Bring him to me.\" When the messenger came to him, he said, \"Go back to your lord and ask him to investigate the women who cut their hands. My Lord is fully aware of their schemes.\"","রাজা বলল, “তাকে আমার কাছে আনো”। যখন বার্তাবাহক তার কাছে আসলো, সে বলল, “তোমার মনিবের কাছে ফিরে যাও এবং তাকে বল সে নারীদের বিষয়ে অনুসন্ধান করতে যারা তাদের হাত কেটে ফেলেছিল। আমার প্রভু তাদের চক্রান্ত সন্মন্ধে পূর্ণ অবগত”।"],
  "12:51": ["(The king) said (to the women), \"What do you know about the incident when you tried to seduce Joseph?\" They said, \"Allah forbid; we did not know of anything evil committed by him.\" The wife of the governor said, \"Now the truth has prevailed. I am the one who tried to seduce him, and he was the truthful one.","(রাজা সে নারীকে) বলল, \"তোমরা সে ঘটনা সম্পর্কে কি জানো যখন তোমরা ইউসুফকে প্রলুব্ধ করার চেষ্টা করেছিলে? তারা বলল, “আল্লাহ না করুন; তার দ্বারা কোন মন্দ কাজ হয়েছে বলে আমরা জানতাম না। “শাসকের স্ত্রী বলল, \"এখন সত্যের জয় হয়েছে। আমি-ই তাকে প্রলুব্ধ করার চেষ্টা করেছিলাম, এবং সে সত্যবাদী ছিল।"],
  "12:52": ["\"I hope that he will realize that I never betrayed him in his absence, for Allah does not bless the schemes of the betrayers.","“আমি আশা করি- সে (ইউসুফ) বুঝবে যে আমি কখনো তার অনুপস্থিতিতে তাকে প্রতারিত করিনি, যেহেতু আল্লাহ প্রতারণাকারীর পরিকল্পনা আশীর্বাদ করেণ না।"],
  "12:53": ["\"I do not claim innocence for myself. The self is an advocate of vice, except for those who have attained mercy from my Lord. My Lord is Forgiver, Most Merciful.\"","“আমি নিজেকে নির্দোষ দাবি করি না।  স্বীয়-মন খারাপ কাজের পরামর্শ দেয়, তাদের ব্যতীত যারা আমার প্রভুর কাছ থেকে দয়া অর্জণ করেছে। আমার প্রভু ক্ষমাকারী, সবচেয়ে দয়ালু।”"],
  "12:54": ["The king said, \"Bring him to me, so I can hire him to work for me.\" When he talked with him, he said, \"Today, you have a prominent position with us.\"","রাজা বলল, “তাকে আমার কাছে নিয়ে আসো, যেন আমি তাকে আমার জন্য কাজে নিয়োগ দিতে পারি।”যখন সে তার সাথে কথা বলল, সে বলল, “আজ, আমাদের মাঝে তুমি বিশেষ পদমর্যাদা পেয়েছ।”"],
  "12:55": ["He said, \"Make me the treasurer, for I am experienced in this area and knowledgeable.\"","সে বলল, “আমাকে কোষাধ্যক্ষ করুন, যেহেতু এক্ষেত্রে আমি অভিজ্ঞ এবং জ্ঞান রাখি”"],
  "12:56": ["We thus established Joseph on earth, ruling as he wished. We shower our mercy upon whomever we will, and we never fail to recompense the righteous.","আমরা এভাবে ইউসুফকে পৃথিবীতে প্রতিষ্ঠিত করলাম, তার ইচ্ছামুসারে শাসন করতে। আমরা যার উপর ইচ্ছা আমাদের দয়া বর্ষণ করি, এবং আমরা কখনো সৎকর্মশীলদের প্রতিদান দিতে ব্যর্থ হই না।"],
  "12:57": ["Additionally, the reward in the Hereafter is even better for those who believe and lead a righteous life.","উপরন্তু, যারা বিশ্বাস করে ও সৎকর্মশীল জীবন-যাপন করে তাদের জন্য পরকালের পুরষ্কার অনেক উত্তম।"],
  "12:58": ["Joseph's brothers came; when they entered, he recognized them, while they did not recognize him.","ইউসুফের ভাইয়েরা আসল; তারা যখন প্রবেশ করলো, সে তাদের চিনতে পারলো, যদিও তারা তাকে চিনেনি।"],
  "12:59": ["After he provided them with their provisions, he said, \"Next time, bring with you your half-brother. Do you not see that I give full measure, and treat you generously?","সে তাদেরকে তাদের রসদ প্রদান করার পর, সে বলল, “পরের বার, তোমাদের সাথে তোমাদের সৎ ভাইকে নিয়ে এসো। তোমরা কি দেখো না যে আমি পরিপূর্ণ মাপ দেই, এবং তোমাদের প্রতি উদার?"],
  "12:60": ["\"If you fail to bring him to me, you will get no share from me; you will not even come close.\"","“যদি তোমরা তাকে আমার কাছে আনতে ব্যর্থ হও, তোমরা আমার কাছে কোন অংশ পাবে না; তোমরা আমার নিকটেও আসতে পারবে না।”"],
  "12:61": ["They said, \"We will negotiate with his father about him. We will surely do this.\"","তারা বলল, “আমরা তার বিষয়ে রাজি করাতে তার পিতার সাথে কথা বলবো। অবশ্যই আমরা তা করবো।\""],
  "12:62": ["He then instructed his assistants: \"Put their goods back in their bags. When they find them upon their return to their family, they may come back sooner.\"","সে এরপর তার সহকারীদের নির্দেশ দিল, \"তাদের পন্যগুলো পুনরায় তাদের ব্যাগে রেখে দাও। যখন তারা তাদের পরিবারের কাছে ফিরে এগুলো পাবে, তারা হয়তো শীঘ্রই ফিরে আসবে।\""],
  "12:63": ["When they returned to their father, they said, \"Our father, we can no longer get any provisions, unless you send our brother with us. We will take good care of him.\"","যখন তারা তাদের পিতার কাছে ফিরল, তারা বলল, \"আমাদের পিতা, আমরা আর কোন খাদ্যদ্রব্য পাব না, যদি না আপনি আমাদের সাথে আমাদের ভাইকে পাঠান। আমরা তা্র ভাল দেখ-ভাল করবো।\""],
  "12:64": ["He said, \"Shall I trust you with him, as I trusted you with his brother before that? Allah is the best Protector, and, of all the merciful ones, He is the Most Merciful.\"","সে বলল, \"আমি কি তার ব্যাপারে তোমাদের উপর আস্থা রাখবো, যেমন এর আগে আমি তার ভাইয়ের ব্যাপারে আস্থা রেখেছিলাম? আল্লাহ সর্বোত্তম রক্ষাকারী, এবং, সকল দয়ালুদের মধ্যে, তিনি পরম দয়ালু।"],
  "12:65": ["When they opened their bags, they found their goods returned to them. They said, \"Our father, what more can we ask for? Here are our goods returned to us. We can thus provide for our family, protect our brother, and receive one more camel-load. This is certainly a profitable deal.\"","যখন তারা তাদের ব্যাগগুলো খুলল, তারা দেখল যে তাদের পন্য তাদের ফেরত দেয়া হয়েছে। তারা বলল, \"আমাদের পিতা, আমরা এর বেশি কি চাইতে পারি? এগুলো আমাদের পন্য যা আমাদের ফেরত দেয়া হয়েছে। এরুপে আমরা আমাদের পরিবারের প্রয়োজন মেটাতে পারি, আমাদের ভাইকে রক্ষা করতে পারি, এবং আরও এক উট মাল পেতে পারি। এ তো নিশ্চয় এক লাভজনক লেনদেন। \""],
  "12:66": ["He said, \"I will not send him with you, unless you give me a solemn pledge before Allah that you will bring him back, unless you are utterly overwhelmed.\" When they gave him their solemn pledge, he said, \"Allah is witnessing everything we say.\"","সে বলল, \"আমি তাকে তোমাদের সাথে পাঠাবো না, যদি না তোমরা আল্লাহর সামনে আমাকে দৃঢ় অঙ্গীকার দাও যে তোমরা তাকে ফেরত আনবে, যদি না তোমরা একেবারেই অসহায় হয়ে পড়ো।”যখন তারা তাকে তাদের দৃড় অঙ্গীকার দিল, সে বলল, \"আমাদের বলা সবকিছু আল্লাহ প্রত্যক্ষ করছেন।\""],
  "12:67": ["And he said, \"O my sons, do not enter from one door; enter through separate doors. However, I cannot save you from anything that is predetermined by Allah. To Allah belongs all judgments. I trust in Him, and in Him shall all the trusters put their trust.\"","এবং সে বলল, \"হে আমার ছেলেরা, এক দরজা দিয়ে প্রবেশ করো না; আলাদা আলাদা দরজা দিয়ে প্রবেশ করো। যাহোক, আমি আল্লাহর পূর্বনির্ধারিত কোন কিছু থেকে তোমাদের রক্ষা করতে পারি না। সকল বিচার আল্লাহর অধীন। আমি তাঁর উপর আস্থা রাখি, এবং তাঁর উপরেই সকল আস্থাকারীদের আস্থা রাখা উচিত।\""],
  "12:68": ["When they went (to Joseph), they entered in accordance with their father's instructions. Although this could not change anything decreed by Allah, Jacob had a private reason for asking them to do this. For he possessed certain knowledge that we taught him, but most people do not know.","যখন তারা (ইউসুফের) কাছে গেল, তারা তাদের পিতার নির্দেশনা অনুযায়ী প্রবেশ করলো। যদিও এটি আল্লাহর আদেশক্রিত কোন কিছু পরিবর্তন করতে পারতো না, ইয়াকুবের একটি ব্যক্তিগত কারণ ছিল তাদেরকে তা করতে বলার জন্য। কারন সে নির্দিষ্ট জ্ঞান অর্জন করেছিল যা আমরা তাকে শিখিয়েছিলাম, কিন্তু অধিকাংশ লোক জানে না।"],
  "12:69": ["When they entered Joseph's place, he brought his brother closer to him and said, \"I am your brother; do not be saddened by their actions.\"","যখন তারা ইউসুফের জায়গায় প্রবেশ করলো, সে তার ভাইকে কাছে আনলো এবং বলল, \"আমি তোমার ভাই, তাদের কাজে দু:খ করো না।\""],
  "12:70": ["When he provided them with their provisions, he placed the drinking cup in his brother's bag, then an announcer announced: \"The owners of this caravan are thieves.\"","যখন সে তাদেরকে তাদের রসদ দিল, সে পানির কাপটি তার ভাইয়ের ব্যাগে রেখে দিল, এরপর একজন ঘোষণাকারী ঘোষনা করলো, \"এই কাফেলার মালিকেরা চোর।\""],
  "12:71": ["They said, as they came towards them, \"What did you lose?\"","তারা বলল, যখন তারা তাদের দিকে আসল, \"তোমরা কি হারিয়েছ?\""],
  "12:72": ["They said, \"We lost the king's cup. Anyone who returns it will receive an extra camel-load; I personally guarantee this.\"","তারা বলল, \"আমরা রাজার কাপ হারিয়েছি। এটি যে-ই ফেরত দেবে সে অতিরিক্ত এক উট বোঝাই মাল পাবে; আমি ব্যক্তিগতভাবে এর নিশ্চয়তা দিচ্ছি”।"],
  "12:73": ["They said, \"By Allah, you know full well that we did not come here to commit evil, nor are we thieves.\"","তারা বলল, \"আল্লাহর শপথ, তোমরা ভালো করে জানো যে আমরা এখানে মন্দ কাজ করতে আসিনি, আর না আমরা চোর।\""],
  "12:74": ["They said, \"What is the punishment for the thief, if you are liars?\"","তারা বলল, \"চোরের শাস্তি কি, যদি তোমরা মিথ্যুক হও?"],
  "12:75": ["They said, \"The punishment, if it is found in his bag, is that the thief belongs to you. We thus punish the guilty.\"","তারা বলল, \"শাস্তি হচ্ছে, যদি এটি তার ব্যাগে পাওয়া যায়, যে সে চোর তোমাদের মালিকানাভুক্ত হবে। আমরা এভাবে অপরাধীদের শাস্তি দেই।\""],
  "12:76": ["He then started by inspecting their containers, before getting to his brother's container, and he extracted it out of his brother's container. We thus perfected the scheme for Joseph; he could not have kept his brother if he applied the king's law. But that was the will of Allah. We exalt whomever we choose to higher ranks. Above every knowledgeable one, there is one who is even more knowledgeable.","এরপর সে তাদের পাত্রগুলো থেকে পর্যবেক্ষণ শুরু করলো, তার ভাইয়ের পাত্রের কাছে যাওয়ার আগে, এবং সে তার ভাইয়ের পাত্র থেকে এটি বের করলো। আমরা এভাবে পরিকল্পনাটি ইউসুফের জন্য নিখুঁত করলাম; সে তার ভাইকে রাখতে পারতো না, যদি সে রাজার আইন প্রয়োগ করতো। কিন্তু ঐটাই ছিল আল্লাহর ইচ্ছা। আমরা উচ্চতর পদে উন্নীত করি যাকেই আমরা পছন্দ করি। সকল জ্ঞানবানদের মধ্যে, রয়েছেন এমন এক সত্ত্বা যিনি আরোও জ্ঞানবান।"],
  "12:77": ["They said, \"If he stole, so did a brother of his in the past.\" Joseph concealed his feelings in himself, and did not give them any clue. He said (to himself), \"You are really bad. Allah is fully aware of your accusations.\"","তারা বলল, \"সে চুরি করে থাকলে, অতীতে তার ভাইও তা করেছিল। ইউসুফ নিজের মধ্যে তার অনুভূতি লুকালো, এবং তাদেরকে কোন ইঙ্গিত দেয়নি। সে (নিজে নিজে) বলল, \"তোমরা আসলেই খারাপ। আল্লাহ তোমাদের অভিযোগের বিষয়ে পূর্ণ সচেতন। \""],
  "12:78": ["They said, “O you noble one, he has a father who is elderly; would you take one of us in his place? We see that you are a kind man.\"","তারা বলল, \"হে উদার বাক্তি, তার একজন পিতা আছে যিনি বয়স্ক ; আপনি কি তার বদলে আমাদের একজনকে নেবেন? আমরা দেখছি যে আপনি একজন দয়ালু ব্যাক্তি।\""],
  "12:79": ["He said, \"Allah forbid that we should take other than the one in whose possession we found our goods. Otherwise, we would be unjust.\"","সে বলল, \"আল্লাহ না করুন যে আমরা তাকে ছাড়া অন্য কাউকে নেই যার কাছে আমরা আমাদের পন্য পেয়েছি। অন্যথায়, আমরা অন্যায়কারী হবো।\""],
  "12:80": ["When they despaired of changing his mind, they conferred together. Their eldest said, \"Do you realize that your father has taken a solemn pledge from you before Allah? In the past you lost Joseph. I am not leaving this place until my father gives me permission, or until Allah judges for me; He is the best Judge.","যখন তারা তার মন পরিবর্তন করার বিষয়ে হতাশ হলো, তারা একত্রে পরামর্শ করলো। তাদের বয়োজ্যেষ্ঠ জন বলল, \"তোমরা কি অনুধাবন করো যে তোমাদের পিতা তোমাদের থেকে আল্লাহর সামনে একটি দৃঢ় অঙ্গীকার নিয়েছেন? অতীতে তোমরা ইউসুফকে হারিয়েছ। আমি এই স্থান ছেড়ে যাচ্ছি না যতক্ষণ না আমার পিতা আমাকে অনুমতি দেন; অথবা যতক্ষণ না আল্লাহ আমার জন্য সিদ্ধান্ত দেন; তিনি সর্বোত্তম বিচারক।"],
  "12:81": ["\"Go back to your father and tell him...'Our father, your son has committed a theft. We know for sure, because this is what we have witnessed. This was an unexpected occurrence.","“তোমাদের পিতার কাছে ফিরে যাও এবং তাকে বলো..."],
  "12:82": ["You may ask the community where we were, and the caravan that came back with us. We are telling the truth.'\"","আপনি ঐ সম্প্রদায়কে জিজ্ঞেস করতে পারেন যেখানে আমরা ছিলাম, এবং ঐ কাফেলাকে যেটা আমাদের সাথে ফেরত এসেছে। আমরা সত্য বলছি।'"],
  "12:83": ["He said, \"Indeed, you have conspired to carry out a certain scheme. Quiet patience is my only recourse. May Allah bring them all back to me. He is the Omniscient, Most Wise.\"","সে বলল, “নিশ্চয়, তোমরা চক্রান্ত করেছ একটা নির্দিষ্ট পরিকল্পনা বাস্তবায়ন করতে। নীরবে ধৈর্যধারণ আমার একমাত্র অবলম্বন। আল্লাহ যেন তাদের সকলকে আমার কাছে ফিরিয়ে আনেন। তিনি সর্বজ্ঞ, সবচেয়ে জ্ঞানী।\""],
  "12:84": ["He turned away from them, saying, \"I am grieving over Joseph.\" His eyes turned white from grieving so much; he was truly sad.","সে তাদের থেকে মুখ ফিরিয়ে নিল, এ বলে যে, \"আমি ইউসুফকে নিয়ে শোক করছি।” খুব বেশি শোক করার কারনে তার চোখ সাদা হয়ে পড়েছিল; সে আসলেই দু:খ ভারাক্রান্ত ছিল।"],
  "12:85": ["They said, \"By Allah, you will keep on grieving over Joseph until you become ill, or until you die.\"","তারা বলল, \"আল্লাহর শপথ, আপনি ইউসুফের জন্য শোক করতে থাকবেন যতক্ষণ না আপনি অসুস্থ হচ্ছেন, অথবা যতক্ষণ না আপনি মারা যাচ্ছেন\""],
  "12:86": ["He said, \"I simply complain to Allah about my dilemma and grief, for I know from Allah what you do not know.","সে বলল, \"আমি তো কেবল আল্লাহর নিকট আমার দ্বিধা-দ্বন্দ ও দুঃখের বিষয়ে অভিযোগ করি, যেহেতু আমি আল্লাহ থেকে জানি যা তোমরা জানো না।"],
  "12:87": ["\"O my sons, go fetch Joseph and his brother, and never despair of Allah's grace. None despairs of Allah's grace except the disbelieving people.","\"হে আমার ছেলেরা, ইউসুফ ও তার ভাইকে গিয়ে নিয়ে আসো, এবং কখনো আল্লাহর দয়া থেকে নিরাশ হয়ো না। অবিশ্বাসী লোকেরা ছাড়া আল্লাহর দয়া থেকে কেউ নিরাশ হয় না।\""],
  "12:88": ["When they entered (Joseph's) quarters, they said, \"O you noble one, we have suffered a lot of hardship, along with our family, and we have brought inferior goods. But we hope that you will give us full measure and be charitable to us. Allah rewards the charitable.\"","যখন তারা (ইউসুফের) আবাসস্থলে প্রবেশ করলো, তারা বলল, \"হে মহানুভব, আমরা অনেক কষ্ট ভোগ করেছি, আমাদের পরিবার সহ, এবং আমরা নিম্নমানের পন্য এনেছি। কিন্তু আমরা আশা করি যে আপনি পূর্ণ মাপ দিবেন এবং আমাদের প্রতি দানশীল হবেন। আল্লাহ দানশীলদের পুরষ্কৃত করেন।\""],
  "12:89": ["He said, \"Do you recall what you did to Joseph and his brother when you were ignorant?\"","সে বলল, \"তোমাদের কি মনে পড়ে যা তোমরা ইউসুফ ও তার ভাইয়ের সাথে করেছ যখন তোমরা অজ্ঞ ছিলে?\""],
  "12:90": ["They said, \"You must be Joseph.\" He said, \"I am Joseph, and here is my brother. Allah has blessed us. That is because if one leads a righteous life, and steadfastly perseveres, Allah never fails to reward the righteous.\"","তারা বলল, \"তুমি নিশ্চয় ইউসুফ। \"সে বলল, \"আমি ইউসুফ, এবং এই হচ্ছে আমার ভাই। আল্লাহ আমাদের অনুগ্রহ করেছেন। এটা এ কারণে যে - যদি কেউ সৎকর্মশীল জীবন-যাপন করে, এবং অবিচলভাবে অধ্যবসায়ী হয়, আল্লাহ কখনো সৎকর্মশীলদের পুরষ্কৃত করতে ব্যর্থ হন না।\""],
  "12:91": ["They said, \"By Allah, Allah has truly preferred you over us. We were definitely wrong.\"","তারা বলল, \"আল্লাহর শপথ, আল্লাহ সত্যিই তোমাকে আমাদের উপর পছন্দ করেছেন। আমরা স্পষ্টই ভুল ছিলাম।\""],
  "12:92": ["He said, \"There is no blame upon you today. May Allah forgive you. Of all the merciful ones, He is the Most Merciful.","সে বলল, \"তোমাদের উপর আজকে কোন অভিযোগ নেই। আল্লাহ তোমাদের ক্ষমা করুন। সকল দয়ালুদের মধ্যে, তিনি সবচেয়ে দয়ালু।"],
  "12:93": ["\"Take this shirt of mine; when you throw it on my father's face, his vision will be restored. Bring your whole family and come back to me.\"","আমার এই শার্টটি নাও; যখন তোমরা এটি আমার পিতার মুখে ছুড়বে, তার দৃষ্টিশক্তি ফিরে আসবে। তোমাদের পুরো পরিবার নিয়ে আমার কাছে ফিরে আসো। \""],
  "12:94": ["Even before the caravan arrived, their father said, \"I can sense the smell of Joseph. Will someone enlighten me?\"","এমনকি কাফেলা ফিরে আসার পূর্বেই, তাদের পিতা বলল, \"আমি ইউসুফের গন্ধ আচঁ করতে পারছি। কেউ কি আমাকে এই বিষয়ে জানাবে?\""],
  "12:95": ["They said, \"By Allah, you are still in your old confusion.\"","তারা বলল, \"আল্লাহর শপথ, আপনি এখনও আপনার পুরনো বিভ্রান্তিতে আছেন।\""],
  "12:96": ["When the bearer of good news arrived, he threw (the shirt) on his face, whereupon his vision was restored. He said, \"Did I not tell you that I knew from Allah what you did not know?\"","যখন সুসংবাদ বাহক পৌছঁলো, সে তার মুখে (শার্টটি ) নিক্ষেপ করলো, যার ফলে তার দৃষ্টি ফিরে এলো। সে বলল, \"আমি কি তোমাদের বলিনি যে আমি আল্লাহ থেকে জানতাম যা তোমরা জানতে না?”"],
  "12:97": ["They said, \"Our father, pray for our forgiveness; we were wrong indeed.\"","তারা বলল, \"আমাদের পিতা, আমাদের ক্ষমার জন্য প্রার্থনা করুন; সত্যিই আমরা ভুলে ছিলাম।\""],
  "12:98": ["He said, \"I will implore my Lord to forgive you; He is the Forgiver, Most Merciful.\"","তারা বলল, \"আমি তোমাদের ক্ষমার জন্য আল্লাহর কাছে মিনতি করবো; তিনি ক্ষমাকারী, সবচেয়ে দয়ালু।\""],
  "12:99": ["When they entered Joseph's quarters, he embraced his parents, saying, \"Welcome to Egypt. Allah willing, you will be safe here.\"","যখন তারা ইউসুফের আবাসস্থলে প্রবেশ করলো, সে তার পিতা-মাতার সাথে আলিঙ্গন করলো, এ বলে যে, \"মিশরে স্বাগতম, আল্লাহ চাইলে, আপনারা এখানে নিরাপদে থাকবেন।\""],
  "12:100": ["He raised his parents upon the throne. They fell prostrate before him. He said, \"O my father, this is the fulfillment of my old dream. My Lord has made it come true. He has blessed me, delivered me from the prison, and brought you from the desert, after the devil had driven a wedge between me and my brothers. My Lord is Most Kind towards whomever He wills. He is the Knower, the Most Wise.\"","সে তার পিতা-মাতাকে সিংহাসনের উপর উঠালো, তারা তার সামনে সেজদায় পড়লো। সে বলল, \"হে আমার পিতা, এটি আমার পুরনো স্বপ্নের পূর্ণতা। আমার প্রভু একে সত্য করেছেন। তিনি আমাকে সৌভাগ্যশালী করেছেন, আমাকে কারাগার থেকে মুক্ত করেছেন, এবং মরুভূমি থেকে তোমাদের এনেছেন, শয়তান আমার এবং আমার ভাইদের মধ্যে প্রতিবন্ধকতা সৃষ্টি করার পর।  আমার প্রভু পরম দয়ালু যার উপরই তিনি ইচ্ছা করেন। তিনি সর্বজান্তা, সর্বজ্ঞানী।”"],
  "12:101": ["\"My Lord, You have given me kingship and taught me the interpretation of dreams. Initiator of the heavens and the earth; You are my Lord and Master in this life and in the Hereafter. Let me die as a submitter, and count me with the righteous.\"","“আমার প্রভু, আপনি আমাকে রাজত্ব দিয়েছেন এবং আমাকে স্বপ্নের ব্যাখ্যা করা শিখিয়েছেন। আকাশমন্ডলী ও পৃথিবীর সূচনাকারী; আপনি আমার অভিভাবক এই জীবনে এবং পরকালে। আমাকে একজন আত্মসমর্পণকারী হিসেবে মৃত্যু দিন, এবং আমাকে সৎকর্মশীলদের সাথে গণনা করুন।”"],
  "12:102": ["This is news from the past that we reveal to you. You were not present when they made their unanimous decision (to throw Joseph in the well), as they conspired together.","এটি অতীতের সংবাদ যা আমরা তোমার কাছে প্রকাশ করি। তুমি উপস্থিত ছিলে না যখন তারা তাদের সর্বসম্মত সিদ্ধান্ত নিয়েছিল (ইউসুফকে কূপে ফেলতে), যখন তারা একত্রে ফন্দী এটেঁছিল।"],
  "12:103": ["Most people, no matter what you do, will not believe.","বেশির ভাগ লোক, তুমি যা-ই করো না কেন, বিশ্বাস করবে না।"],
  "12:104": ["You are not asking them for any money; you simply deliver this reminder for all the people.","তুমি তাদের কাছে কোন অর্থ চাচ্ছ না; তুমি কেবলমাত্র এই স্মারক সকল লোকদের জন্য পৌঁছে দাও।"],
  "12:105": ["So many proofs in the heavens and the earth are given to them, but they pass by them, heedlessly!","আকাশমন্ডলী ও পৃথিবীতে অনেক প্রমানাদি তাদেরকে দেয়া হয়েছে, কিন্তু তারা সেগুলো পিছনে ফেলে যায়, অমনোযোগী হয়ে!"],
  "12:106": ["The majority of those who believe in Allah do not do so without committing idol worship.","যারা আল্লাহতে বিশ্বাস করে তাদের অধিকাংশই অংশীদার উপাসনা করা ছাড়া তা করে না।"],
  "12:107": ["Have they guaranteed that an overwhelming retribution from Allah will not strike them, or the Hour will not come to them suddenly, when they least expect it?","তারা কি নিশ্চয়তা পেয়েছে যে আল্লাহ থেকে কোন বিধ্বংসী শাস্তি তাদের আঘাত করবে না, অথবা সেই ঘণ্টা হঠাৎ করেই তাদের কাছে আসবে না, যখন তারা খুব অল্পই এর প্রত্যাশা করে?"],
  "12:108": ["Say, \"This is my path: I invite to Allah, on the basis of a clear proof, and so do those who follow me. Allah be glorified. I am not an idol worshiper.\"","বল, \"এটা আমার পথ: আমি আল্লাহর দিকে আহবান করি, একটি স্পষ্ট প্রমানের ভিত্তিতে, এবং তারাও তা-ই করে যারা আমার অনুসরণ করে। মহিমা আল্লাহর। আমি কোন প্রতিমা উপাসক নই।\""],
  "12:109": ["We did not send before you except men whom we inspired, chosen from the people of various communities. Did they not roam the earth and see the consequences for those before them? The abode of the Hereafter is far better for those who lead a righteous life. Would you then understand?","আমরা তোমার আগে মানুষ ছাড়া কারো কাছে অনুপ্রেরনা দিয়ে পাঠাইনি, বিভিন্ন সম্প্রদায়ের লোক থেকে পছন্দকৃত। তারা কি পৃথিবীতে ঘুড়ে বেড়ায়নি এবং তাদের পূর্বেকার লোকদের পরিণাম দেখেনি। পরকালের আবাস অনেক উত্তম তাদের জন্য যারা সৎকর্মশীল জীবন যাপন করে। তবে কি তোমরা বুঝবে?"],
  "12:110": ["Just when the messengers despair, and think that they had been rejected, our victory comes to them. We then save whomever we choose, while our retribution for the guilty people is unavoidable.","ঠিক যখন বার্তাবাহকরা হতাশ হয়, এবং মনে করে যে তাদের প্রত্যাখ্যান করা হয়েছে, আমাদের বিজয় তাদের কাছে আসে। আমরা এরপর রক্ষা করি যাকে আমরা পছন্দ করি, যখন অপরাধী লোকদের জন্য আমাদের শাস্তি অনিবার্য।"],
  "12:111": ["In their history, there is a lesson for those who possess intelligence. This is not fabricated Hadith; this (Quran) confirms all previous scriptures, provides the details of everything, and is a beacon and mercy for those who believe.","তাদের ইতিহাসে, তাদের জন্য শিক্ষা রয়েছে যারা বুদ্ধিমত্তার অধিকারী। এটি মিথ্যা উদ্ভাবিত হাদীস নয়; এটি (কুরআন) সুনিশ্চিত করে পূর্ববর্তী সকল ঐশীগ্রন্থ, সবকিছু সবিস্তারে প্রদান করে,এবং এক আলোকবর্তিকা এবং দয়া তাদের জন্য যারা বিশ্বাস করে।"],
  "13:1": ["A. L. M. R. These (letters) are proofs of this scripture. What is revealed to you from your Lord is the truth, but most people do not believe.","অ ল ম র। এই (বর্ণ) গুলো এই ঐশীগ্রন্থের প্রমাণ। তোমার প্রভুর পক্ষ থেকে তোমার কাছে যা অবতীর্ণ হয়েছে তা সত্য, কিন্তু বেশির ভাগ মানুষ বিশ্বাস করে না।"],
  "13:2": ["Allah is the One who raised the heavens without pillars that you can see, then assumed all authority. He committed the sun and the moon, each running (in its orbit) for a predetermined period. He controls all things, and explains the revelations, that you may attain certainty about meeting your Lord.","আল্লাহই সেই সত্ত্বা যিনি আকাশমন্ডলীকে খুঁটি ছাড়া তুলে ধরেছেন, যা তোমরা দেখতে পাও, এরপর সকল কর্তৃত্ব গ্রহন করেছেন। তিনি সূর্য এবং চাঁদকে নিয়োজিত করেছেন, প্রত্যেকে (এর কক্ষপথে) একটি পূর্বনির্ধারিত সময় পর্যন্ত ঘুরছে। তিনি সবকিছু নিয়ন্ত্রন করেন, এবং প্রকাশনাবলি ব্যাখ্যা করেন, যাতে তোমরা তোমাদের প্রভুর সাথে সাক্ষাতের ব্যাপারে নিশ্চয়তা অর্জণ করতে পারো।"],
  "13:3": ["He is the One who constructed the earth and placed on it mountains and rivers. And from the different kinds of fruits, He made them into pairs—males and females. The night overtakes the day. These are solid proofs for people who think.","তিনিই সে সত্ত্বা যিনি পৃথিবী নির্মান করেছেন এবং এর উপর স্থাপন করেছেন পর্বতমালা এবং নদীসমূহ।এবং বিভিন্ন ধরনের ফল থেকে, তিনি এদের জোড়ায় তৈরী করেছেন- পুরুষ ও স্ত্রী-জাতিয়। রাত ছাড়িয়ে যায় দিনকে। এগুলো দৃড় প্রমান তাদের জন্য যারা চিন্তা করে।"],
  "13:4": ["On earth, there are adjacent lots that produce orchards of grapes, crops, palm trees—dioecious and non-dioecious. Although they are irrigated with the same water, we prefer some of them over others in eating. These are solid proofs for people who understand.","পৃথিবীতে, সন্নিহিত জমি রয়েছে যা উৎপন্ন করে আংগুরের বাগান, খাদ্যশস্য, খেঁজুর গাছ- এক লিংঙ্গধারী এবং উভলিংঙ্গধারী। যদিও তাদের একই পানি দিয়ে সেচ দেয়া হয়, আমরা এদের কতগুলোকে অন্যগুলোর চাইতে খাওয়ার জন্য উন্নততর করি। এগুলো জোড়ালো প্রমান সেসব লোকদের জন্য যারা বুঝে।"],
  "13:5": ["If you ever wonder, the real wonder is their saying: \"After we turn into dust, do we get recreated anew?\" These are the ones who have disbelieved in their Lord. These are the ones who have incurred shackles around their necks. These are the ones who have incurred Hell, wherein they abide forever.","যদি তুমি কখনও আশ্চর্য হও, তবে প্রকৃত আশ্চর্যের বিষয় হচ্ছে তাদের কথা: “আমরা ধূলায় পরিনত হবার পর, আমরা কি আবার নতুন করে সৃষ্টি হবো?”এরা সেই ব্যক্তি যারা তাদের প্রভুকে অবিশ্বাস করেছে। এরা সেই ব্যক্তি যারা তাদের গলায় টেনে এনেছে জড়ানো শিকল। এরা সেই ব্যক্তি যারা নরক টেনে এনেছে, যেখানে তারা চিরকাল বাস করে।"],
  "13:6": ["They challenge you to bring doom upon them, rather than turning righteous! Sufficient precedents have been set for them in the past. Indeed, your Lord is full of forgiveness towards the people, in spite of their transgressions, and your Lord is also strict in enforcing retribution.","তারা তোমাকে তাদের উপর ধ্বংস আনার চ্যালেঞ্জ করে, সৎকর্মশীল হবার বদলে। অতীতে তাদের জন্য যথেষ্ট দৃষ্টান্ত স্থাপন করা হয়েছে। প্রকৃতপক্ষে, তোমাদের প্রভু লোকদের প্রতি ক্ষমায় পূর্ণ, তাদের সীমালঙ্ঘন সত্ত্বেও, এবং তোমাদের প্রভু শাস্তি আরোপেও কঠোর।"],
  "13:7": ["Those who disbelieved say, \"If only a miracle could come down to him from his Lord (we will then believe).\" You are simply a warner—every community receives a guiding teacher.","যারা অবিশ্বাস করেছিল তারা বলল, \"শুধু যদি একটি অলৌকিকতা তাঁর প্রভুর পক্ষ থেকে তার কাছে আসত (তবে আমরা বিশ্বাস করতাম)। তুমি কেবল একজন সতর্ককারী - প্রত্যেক সম্প্রদায় একজন পথ-প্রদর্শক শিক্ষক পায়।"],
  "13:8": ["Allah knows what every female bears, and what every womb releases, or gains. Everything He does is perfectly measured.","আল্লাহ জানেন প্রত্যেক নারী কি বহন করে, এবং প্রত্যেক জরায়ু কি ছেড়ে দেয়, বা অর্জন করে। যা তিনি করেন তা যথাযথভাবে পরিমাপকৃত।"],
  "13:9": ["The Knower of all secrets and declarations; the Supreme, the Most High.","সকল গোপনীয়তা এবং প্রকাশিত বিষয়ের জ্ঞাতা; সর্বপ্রধান, সর্বোচ্চ।"],
  "13:10": ["It is the same whether you conceal your thoughts, or declare them, or hide in the darkness of the night, or act in the daylight.","তুমি তোমার ভাবনাগুলো গোপন, বা প্রকাশ করো, কিংবা রাতের অন্ধকারে লুকাও, অথবা দিনের আলোয় কাজ করো তা একই।"],
  "13:11": ["Shifts (of angels) take turns, staying with each one of you—they are in front of you and behind you. They stay with you, and guard you in accordance with Allah's commands. Thus, Allah does not change the condition of any people unless they themselves make the decision to change. If Allah wills any hardship for any people, no force can stop it. For they have none beside Him as Lord and Master.","পালাক্রমে (ফেরেশতারা) অবস্থান নিয়ে; তোমাদের প্রত্যেকের সাথে থাকছে-তারা আছে তোমাদের সামনে এবং তোমাদের পেছনে। তারা তোমাদের সঙ্গে থাকে, এবং তোমাদের পাহারা দেয় আল্লাহর হুকুম অনুসারে। সুতরাং, আল্লাহ কোন লোকের অবস্থা পরিবর্তন করেন না যদিনা তারা নিজেরা পরিবর্তনের সিদ্ধান্ত নেয়। যদি আল্লাহ কোন লোকের জন্য কোন কষ্ট চান, কোন শক্তি তা থামাতে পারে না। কারন তাঁর পাশে তাদের কোনো প্রভু এবং মনিব নেই।"],
  "13:12": ["He is the One who shows you the lightning as a source of fear, as well as hope, and He initiates the loaded clouds.","তিনিই সেই সত্ত্বা যিনি তোমাদের বিদ্যুৎ চমক দেখান ভয়ের উৎস হিসেবে, সেই সাথে আশার উৎস হিসেবে, এবং তিনি পুঞ্জিভূত মেঘের সূচনা করেন।"],
  "13:13": ["The thunder praises His glory, and so do the angels, out of reverence for Him. He sends the lightning bolts, which strike in accordance with His will. Yet, they argue about Allah, though His power is awesome.","বজ্র তাঁর মহিমার প্রশংসা করে, এবং ফেরেশতারাও, তাঁর প্রতি ভক্তি থেকে। তিনি বজ্রপাত ঘটান, যা তাঁর ইচ্ছা অনুসারে আঘাত করে। এরপরও, তারা আল্লাহর ব্যাপারে তর্ক করে, যদিও তাঁর ক্ষমতা ভীষন।"],
  "13:14": ["Imploring Him is the only legitimate supplication, while the idols they implore beside Him, cannot ever respond. Thus, they are like those who stretch their hands to the water, but nothing reaches their mouths. The supplications of the disbelievers are in vain.","তাঁর কাছে চাওয়াই একমাত্র বৈধ মিনতি, যেখানে তাঁর পাশে যেসব উপাস্যদের তারা মিনতি করে, তারা কখনো ডাকে সাড়া দিতে পারে না। সুতরাং, তারা ওদের মতো যারা পানির দিকে হাত বাড়ায়, কিন্তু তাদের মুখে কিছুই পৌঁছে না। অবিশ্বাসীদের মিনতি নিরর্থক।"],
  "13:15": ["To Allah prostrates everyone in the heavens and the earth, willingly or unwillingly, and so do their shadows in the mornings and the evenings.","আল্লাহকে সেজদা করে আকাশমণ্ডলী এবং পৃথিবীর সকলে, স্বেচ্ছায় অথবা অনিচ্ছায়, এবং তাদের ছায়াও তা করে সকালে এবং সন্ধ্যায়।"],
  "13:16": ["Say, \"Who is the Lord of the heavens and the earth?\" Say, \"Allah.\" Say, \"Why then do you set up besides Him masters who do not possess any power to benefit or harm even themselves?\" Say, \"Is the blind the same as the seer? Is darkness the same as the light?\" Have they found idols besides Allah who created creations similar to His creations, to the point of not distinguishing the two creations? Say, \"Allah is the Creator of all things, and He is the One, the Supreme.\"","বল, “আকাশমণ্ডলী এবং পৃথিবীর প্রভু কে?”বল, “আল্লাহ।”বল, “তাহলে কেন তোমরা তাঁর পাশে মনিব স্থাপন করো, তাদেরকে, যারা এমনকি তাদের নিজেদেরও উপকার অথবা ক্ষতি করার কোন ক্ষমতা রাখে না?”বল, “অন্ধ কি চক্ষুষ্মানের সমান? অন্ধকার কি আলোর সমান?”তারা কি আল্লাহর পাশে এমন উপাস্যদের পেয়েছে যারা তাঁর সৃষ্টির অনুরুপ সৃষ্টি করেছে, এমনভাবে যে দুটো সৃষ্টিকে আলাদা করা যায় না? বল, “আল্লাহ সকল বস্তুর সৃষ্টিকর্তা, এবং তিনিই এক, সর্বোচ্চ।"],
  "13:17": ["He sends down water from the sky, causing the valleys to overflow, then the rapids produce abundant foam. Similarly, when they use fire to refine metals for their jewelry or equipment, foam is produced. Allah thus cites analogies for the truth and falsehood. As for the foam, it goes to waste, while that which benefits the people stays close to the ground. Allah thus cites the analogies.","তিনি আকাশ থেকে পানি বর্ষণ করে, উপত্যকাগুলোকে প্লাবিত করেন, এরপর স্রোতধারা প্রচুর ফেনা উৎপাদন করে। একইভাবে, তারা যখন তাদের অলঙ্কার বা সরঞ্জামাদির জন্য ধাতু পরিশোধন করতে আগুন ব্যবহার করে, ফেনা উৎপা্দিত হয়। আল্লাহ এভাবে সত্য ও মিথ্যার উপমা দেন। ফেনার ক্ষেত্রে, এটা আবর্জনা হয়ে যায়, যেখানে লোকদের যা উপকারে আসে তা মাটির কাছে থাকে। আল্লাহ এভাবে উপমা দেন।"],
  "13:18": ["Those who respond to their Lord deserve the good rewards. As for those who failed to respond to Him, if they possessed everything on earth—even twice as much—they would readily give it up as ransom. They have incurred the worst reckoning, and their final abode is Hell; what a miserable destiny.","যারা তাদের প্রভুর ডাকে সাড়া দেয় তারা ভাল পুরস্কারের যোগ্য। আর তাদের ক্ষেত্রে যারা তাঁর ডাকে সাড়া দিতে ব্যর্থ হল, যদি তারা পৃথিবীর সবকিছু অধিকার করে-এমনকি দিগুন পরিমান- তারা তৎক্ষণাৎ তা মুক্তিপণ হিসেবে দিয়ে দেবে। তারা নিকৃষ্টতম হিসাব টেনে এনেছে, এবং তাদের চূড়ান্ত বাসস্থান নরক; কি এক শোচনীয় ভাগ্য।"],
  "13:19": ["Is one who recognizes that your Lord's revelations to you are the truth equal to one who is blind? Only those who possess intelligence will take heed.","যে ব্যক্তি তোমার প্রতি তোমার প্রভুর প্রকাশনাবলি চিনতে পারে সে কি তার সমান যে অন্ধ? শুধু যারা বুদ্ধিমত্তার অধিকারী তারা মনোযোগ দেবে।"],
  "13:20": ["They are the ones who fulfill their pledge to Allah, and do not violate the covenant.","তারাই সেসব লোক যারা আল্লাহর সাথে তাদের অঙ্গীকার পূর্ণ করে, এবং অঙ্গীকার ভঙ্গ করে না।"],
  "13:21": ["They join what Allah has commanded to be joined, reverence their Lord, and fear the dreadful reckoning.","তারা তাতে যোগ দেয় যাতে আল্লাহ যোগ দিতে আদেশ করেছেন, তাদের প্রভুকে ভক্তি করে, এবং সেই ভয়ানক হিসাব গ্রহনকে ভয় করে।"],
  "13:22": ["They steadfastly persevere in seeking their Lord, observe the Contact Prayers (Salat), spend from our provisions to them secretly and publicly, and counter evil with good. These have deserved the best abode.","তাদের প্রভুর অন্বেষণে তারা দৃঢ়তার সাথে অধ্যবসায়ী, সংযোগ প্রার্থনাসমূহ (সালাত) পালন করে, তাদেরকে দেয়া আমাদের খাদ্যসম্ভার থেকে ব্যয় করে গোপনে এবং প্রকাশ্যে, এবং ভালো দিয়ে মন্দকে প্রতিহত করে। তারা সর্বোত্তম বাসস্থানের যোগ্য হয়েছে।"],
  "13:23": ["They enter the gardens of Eden, together with the righteous among their parents, their spouses, and their children. The angels will enter to them from every door.","তারা ইডেনের বাগানগুলোতে প্রবেশ করে, তাদের পিতামাতা, তাদের জীবনসঙ্গি, এবং তাদের সন্তানদের মধ্য থেকে সৎ-কর্মীদের সাথে, একত্রে। ফেরেশতারা তাদের কাছে প্রবেশ করবে প্রত্যেক দরজা দিয়ে।"],
  "13:24": ["\"Peace be upon you, because you steadfastly persevered. What a joyous destiny.\"","“তোমাদের উপর শান্তি বর্ষিত হোক, কারন তোমরা দৃঢ়তার সাথে অধ্যবসায়ী ছিলে। কি এক আনন্দদায়ক নিয়তি”।"],
  "13:25": ["As for those who violate Allah's covenant after pledging to keep it, and sever what Allah has commanded to be joined, and commit evil, they have incurred condemnation; they have incurred the worst destiny.","আর তাদের ক্ষেত্রে যারা আল্লাহর অঙ্গীকার লঙ্ঘন করে, তা রক্ষা করার অঙ্গীকার করার পর, এবং ছিন্ন করে, যাতে আল্লাহ যুক্ত থাকতে হুকুম করেছেন, এবং দুষ্কর্ম করে বেড়ায়, তারা টেনে এনেছে দন্ডাদেশ; তারা টেনে এনেছে নিকৃষ্টতম নিয়তি।"],
  "13:26": ["Allah is the One who increases the provision for whomever He wills, or withholds it. They have become preoccupied with this life, and this life, compared to the Hereafter, is nil.","আল্লাহ সেই সত্ত্বা যিনি যার জন্য ইচ্ছা জীবিকা বাড়িয়ে দেন, অথবা তা থামিয়ে রাখেন। তারা এই জীবনে আচ্ছন্ন হয়ে আছে, এবং এই জীবন, পরকালের তুলনায়, কিছুই না।"],
  "13:27": ["Those who disbelieve would say, \"If only a miracle could come down to him from his Lord (we would believe).\" Say, \"Allah sends astray whomever He wills, and guides to Him only those who obey.\"","যারা অবিশ্বাস করে তারা বলবে, “যদি শুধু একটি অলৌকিকতা তার কাছে আসতো তার প্রভুর পক্ষ থেকে (তবে আমরা বিশ্বাস করতাম)”। বল, “আল্লাহ যাকে ইচ্ছা পথভ্রষ্ট করেন, এবং শুধু তাদেরকে তাঁর দিকে পথ-প্রদর্শন করেন যারা মান্য করে।"],
  "13:28": ["They are the ones whose hearts rejoice in remembering Allah. Absolutely, by remembering Allah, the hearts rejoice.","তারা সেসব লোক যাদের হৃদয় উল্লসিত হয়, আল্লাহর স্মরণে। নিঃসন্দেহে, আল্লাহর স্মরণে, হৃদয় উল্লসিত হয়।"],
  "13:29": ["Those who believe and lead a righteous life have deserved happiness and a joyous destiny.","যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে তারা অর্জন করেছে সুখ এবং এক আনন্দদায়ক নিয়তি।"],
  "13:30": ["We have sent you (O Rashad) to this community, just as we did for other communities in the past. You shall recite to them what we reveal to you, for they have disbelieved in the Most Gracious. Say, \"He is my Lord. There is no god except He. I put my trust in Him alone; to Him is my ultimate destiny.\"","আমরা তোমাকে পাঠিয়েছি (হে রাশাদ) এই জাতির কাছে, ঠিক যেমন অতীতে আমরা অন্য জাতির জন্য করেছিলাম। তুমি তাদের কাছে আবৃত্তি করবে যা আমরা তোমার কাছে প্রকাশ করি, কারন তারা পরম করুনাময়ে অবিশ্বাস করেছে। বল, “তিনি আমার প্রভু। তিনি ছাড়া কোন উপাস্য নাই। আমি শুধু তার প্রতি আমার আস্থা রাখি; তার কাছেই আমার চূড়ান্ত নিয়তি।"],
  "13:31": ["Even if a Quran caused mountains to move, or the earth to tear asunder, or the dead to speak (they will not believe). Allah controls all things. Is it not time for the believers to give up and realize that if Allah willed, He could have guided all the people? The disbelievers will continue to suffer disasters, as a consequence of their own works, or have disasters strike close to them, until Allah's promise is fulfilled. Allah will never change the predetermined destiny.","এমনকি কোন কুরআন যদি পাহাড়কে চালিত করে, বা পৃথিবীকে দুই ভাগে বিভক্ত করে দেয়, বা মৃতকে দিয়ে কথা বলায় (তবুও তারা বিশ্বাস করবে না)। আল্লাহ সকল বস্তু নিয়ন্ত্রন করেন। এখনও কি বিশ্বাসীদের জন্য সময় হয় নি চেষ্টা পরিত্যাগ করার এবং এটা অনুধাবন করার যে যদি আল্লাহ চাইতেন, তিনি সকল মানুষকে পথ প্রদর্শন করতে পারতেন? অবিশ্বাসীরা দুর্দশা ভোগ করতে থাকবে, তাদের নিজেদের কাজের পরিণামে, অথবা তাদের কাছেই দুর্দশা আঘাত করবে, যতক্ষন না আল্লাহর অঙ্গীকার পূর্ণ হয়। আল্লাহ কখনোই পূর্বনির্ধারিত নিয়তি পরিবর্তন করেন না।"],
  "13:32": ["Messengers before you have been ridiculed; I permitted the disbelievers to carry on, then I punished them. How terrible was My retribution!","তোমার পূর্বেও বার্তাবাহকদের উপহাস করা হয়েছে; আমি অবিশ্বাসীদের চালিয়ে যেতে দিয়েছি, এরপর আমি তাদের শাস্তি দিয়েছি। কেমন ভয়ানক ছিল আমার শাস্তি!"],
  "13:33": ["Is there any equal to the One who controls every single soul? Yet, they set up idols to rival Allah. Say, \"Name them. Are you informing Him of something on earth that He does not know? Or, are you fabricating empty statements?\" Indeed, the schemes of those who disbelieve have been adorned in their eyes. They are thus diverted from the right path. Whomever Allah sends astray can never find a guiding teacher.","সেই সত্ত্বার সমান কি কিছু আছে যিনি প্রত্যক আত্মা নিয়ন্ত্রন করেন? এরপরও, তারা আল্লাহর সাথে প্রতিদ্বন্দ্বিতা করতে উপাস্য স্থাপন করে। বল, “তাদের নাম বলো, তোমরা কি পৃথিবীর কোনকিছুর বিষয়ে তাঁকে জানাচ্ছ যা তিনি জানেন না? নাকি, তোমরা ফাকা বুলি রচনা করছো? নিশচয়, যারা অবিশ্বাস করে তাদের চক্রান্ত তাদের চোখে সাজিয়ে দেয়া হয়েছে। তারা এভাবে সঠিক পথ থেকে বিচ্যুত হয়। যাকে আল্লাহ পথভ্রষ্ট করেন সে কখনই কোন পথপ্রদর্শক শিক্ষক পায় না।"],
  "13:34": ["They have incurred retribution in this life, and the retribution in the Hereafter is far worse. Nothing can protect them against Allah.","তারা এই জীবনে শাস্তি টেনে এনেছে, এবং পরকালের শাস্তি আরো অনেক নিকৃষ্ট। আল্লাহর বিরুদ্ধে কোন কিছুই তাদের রক্ষা করতে পারে না।"],
  "13:35": ["The allegory of Heaven, which is promised for the righteous, is flowing streams, inexhaustible provisions, and cool shade. Such is the destiny for those who observe righteousness, while the destiny for the disbelievers is Hell.","স্বর্গ, যা সৎকর্মশীলদের জন্য অঙ্গীকার করা হয়, তার উপমা হল প্রবাহিত ঝর্ণা, অফুরন্ত খাদ্যসম্ভার, এবং শীতল ছায়া। তাদের জন্য এমনই ভাগ্য যারা সৎকর্মপরায়নতা বজায় রাখে, যেখানে অবিশ্বাসীদের ভাগ্য নরক।"],
  "13:36": ["Those who received the scripture rejoice in what was revealed to you; some others may reject parts of it. Say, \"I am simply enjoined to worship Allah, and never associate any idols with Him. I invite to Him, and to Him is my ultimate destiny.\"","যারা ঐশীগ্রন্থ পেয়েছে তারা তাতে উল্লসিত হয় যা তোমার কাছে প্রকাশিত হয়েছে। অন্যদের কেউ কেউ হয়তো এর কিছু অংশ প্রত্যাখ্যান করে। বল, “আমাকে তো কেবল আদেশ করা হয়েছে আল্লাহর উপাসনা করতে, এবং কখনো তাঁর সাথে অন্যকোন উপাস্য যুক্ত না করতে। আমি তাঁর দিকে আমন্ত্রন জানাই, এবং তাঁর দিকেই আমার চূড়ান্ত নিয়তি।"],
  "13:37": ["We revealed these laws in Arabic, and if you ever acquiesce to their wishes, after this knowledge has come to you, you will have no ally, nor a protector, against Allah.","আমরা এই আইনগুলো আরবিতে প্রকাশ করেছি, এবং যদি তুমি কখনো তাদের ইচ্ছায় সম্মত হও, এই জ্ঞান তোমার কাছে আসার পর, তবে আল্লাহর বিরুদ্ধে তোমার কোন মিত্র থাকবে না, না কোন রক্ষাকারী।"],
  "13:38": ["We have sent messengers before you (O Rashad), and we made them husbands with wives and children. No messenger can produce a miracle without Allah's authorization, and in accordance with a specific, predetermined time.","আমরা তোমার আগে বার্তাবাহক পাঠিয়েছি (হে রাশাদ), এবং আমরা তাদেরকে স্ত্রী-সন্তান সহ স্বামী বানিয়েছি। কোন বার্তাবাহক অলৌকিকতা তৈরি করতে পারে না, আল্লাহর অনুমোদন, এবং একটি সুনির্দিষ্ট, পূর্বনির্ধারিত সময়ানুসারে ব্যতীত।"],
  "13:39": ["Allah erases whatever He wills, and fixes. With Him is the original Master Record.","আল্লাহ মুছে দেন যা তিনি চান, এবং ঠিক করে দেন। তাঁর কাছেই রয়েছে প্রকৃত মূল নথি/রেকর্ড।"],
  "13:40": ["Whether we show you what we promise them, or terminate your life before that, your sole mission is to deliver (the message). It is us who will call them to account.","যদি আমরা তোমাকে দেখাই যা আমরা তাদেরকে অঙ্গীকার করেছি, অথবা তোমার জীবন তার আগেই শেষ করে দেই, তোমার একমাত্র উদ্দেশ্য (বার্তা) প্রদান করা। আমরাই তাদেরকে হিসাবের জন্য ডাকবো।"],
  "13:41": ["Do they not see that every day on earth, brings them closer to the end, and that Allah decides their life span, irrevocably? He is the most efficient Reckoner.","তারা কি দেখে না যে পৃথিবীর প্রতিটি দিন, তাদেরকে সমাপ্তির কাছে নিয়ে যায়, এবং আল্লাহ তাদের জীবনের ব্যপ্তি নির্ধারণ করেন, অপরিবর্তনীয় ভাবে? তিনি সবচেয়ে দক্ষ হিসাব গ্রহণকারী।"],
  "13:42": ["Others before them have schemed, but to Allah belongs the ultimate scheming. He knows what everyone is doing. The disbelievers will find out who the ultimate winners are.","তাদের পূর্বে অন্যরাও চক্রান্ত করেছে, কিন্তু আল্লাহর অধীনেই রয়েছে চূড়ান্ত চক্রান্ত। তিনি জানেন  প্রত্যেকে কি করছে। অবিশ্বাসীরা দেখবে কারা চূড়ান্ত বিজয়ী।"],
  "13:43": ["Those who disbelieved will say, \"You are not a messenger!\" Say, \"Allah suffices as a witness between me and you, and those who possess knowledge of the scripture.\"","যারা অবিশ্বাস করেছিল তারা বলবে, “তুমি কোন বার্তাবাহক নও!” বল, “তোমাদের এবং আমার মাঝে সাক্ষী হিসাবে যথেষ্ট, আল্লাহ এবং যারা ঐশীগ্রন্থের জ্ঞান রাখে”।"],
  "14:1": ["A. L. R. A scripture that we revealed to you, in order to lead the people out of darkness into the light—in accordance with the will of their Lord —to the path of the Almighty, the Praiseworthy.","অ.ল.র। একটি ঐশীগ্রন্থ যা আমরা তোমার কাছে প্রকাশ করেছি, লোকদের অন্ধকার থেকে আলোতে পরিচালিত করার জন্য- তাদের প্রভুর ইচ্ছানুসারে- সর্বশক্তিমান, প্রশংসনীয়-এর পথে।"],
  "14:2": ["(The path of) Allah; the One who possesses everything in the heavens and everything on earth. Woe to the disbelievers; they have incurred a terrible retribution.","আল্লাহ (-এর পথ) ; সেই সত্ত্বা যিনি আকাশমন্ডলীর সবকিছু এবং পৃথিবীর সবকিছুর অধিকারী। অবিশ্বাসীদের জন্য দু:খ; তারা এক ভয়ানক শাস্তি টেনে এনেছে।"],
  "14:3": ["They are the ones who give priority to this life over the Hereafter, repel from the way of Allah, and seek to make it crooked; they have gone far astray.","তারাই সে লোক যারা পরকালের উপর এই জীবনকে প্রাধান্য দেয়, আল্লাহর পথে বাঁধা দেয়, এবং একে বাঁকা করার পথ খোঁজে; এরা বহুদূর পথভ্রষ্ট হয়েছে।"],
  "14:4": ["We did not send any messenger except (to preach) in the tongue of his people, in order to clarify things for them. Allah then sends astray whomever He wills, and guides whomever He wills. He is the Almighty, the Most Wise.","আমরা কোন বার্তাবাহককে পাঠাইনি তার লোকদের ভাষায় (ধর্ম-প্রচার করার জন্য) ছাড়া, তাদের জন্য বিষয়াদি পরিষ্কার করতে। আল্লাহ এরপর পথভ্রষ্ট করেন যাকে তিনি ইচ্ছা করেন, এবং পথ-প্রদর্শণ করেন যাকে তিনি ইচ্ছা করেন। তিনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "14:5": ["Thus, we sent Moses with our miracles, saying, \"Lead your people out of darkness into the light, and remind them of the days of Allah.\" These are lessons for every steadfast, appreciative person.","এভাবে, আমরা মুসাকে আমাদের অলৌকিকতা দিয়ে পাঠিয়েছিলাম, এ বলে যে, \"তোমার লোকদের অন্ধকার থেকে আলোতে পরিচালনা করো, এবং তাদেরকে আল্লাহর দিনগুলো স্মরণ করাও।”এগুলো প্রত্যেক অবিচল, কৃতজ্ঞ লোকের জন্য শিক্ষা।"],
  "14:6": ["Recall that Moses said to his people, \"Remember Allah's blessings upon you. He saved you from Pharaoh's people who inflicted the worst persecution upon you, slaughtering your sons and sparing your daughters. That was an exacting trial from your Lord.\"","স্মরণ করো যে মুসা তার লোকদের বলেছিল, \"তোমাদের উপর আল্লাহর অনুগ্রহ স্মরণ করো। তিনি তোমাদের রক্ষা করেছিলেন ফেরাউনের লোকদের থেকে যে তোমাদের উপর নির্মম অত্যাচার চালাতো, তোমাদের পুত্রদের হত্যা করতো এবং কন্যাদের ছেড়ে দিতো। সেটা ছিল তোমাদের প্রভুর পক্ষ থেকে এক কঠোর পরীক্ষা।\""],
  "14:7": ["Your Lord has decreed: \"The more you thank Me, the more I give you.\" But if you turn unappreciative, then My retribution is severe.","তোমাদের প্রভু আদেশ করেছেন, \"যত বেশি তোমরা আমাকে ধন্যবাদ দাও, তত বেশি আমি তোমাদের প্রদান করি।”কিন্তু যদি তোমরা অকৃতজ্ঞ হয়ে পড়ো, তাহলে আমার শাস্তি কঠোর।"],
  "14:8": ["Moses said, \"If you disbelieve, along with all the people on earth, Allah is in no need, Praiseworthy.\"","মুসা বলল, \"যদি তোমরা অবিশ্বাস করো, পৃথিবীর সকল লোকদের সাথে, আল্লাহর কোনকিছু্র প্রয়োজন নেই, প্রশংসনীয়। \""],
  "14:9": ["Have you not heard about those before you—the people of Noah, 'Ãd, Thamûd, and others who came after them and known only to Allah? Their messengers went to them with clear proofs, but they treated them with contempt and said, \"We disbelieve in what you are sent with. We are skeptical about your message; full of doubt.\"","তোমরা কি তোমাদের পূর্বে তাদের সম্পর্কে শোননি - নুহ, আদ, সামুদের লোক, এবং অন্যরা যারা তাদের পরে এসেছে এবং যাদেরকে শুধু আল্লাহই জানেন? তাদের বার্তাবাহকরা তাদের কাছে সুস্পষ্ট প্রমাণাদি নিয়ে গিয়েছিল, কিন্তু তারা তাদের অবমাননা করেছিল এবং বলেছিল, \"যা দিয়ে তোমাদের পাঠানো হয়েছে আমরা তা অবিশ্বাস করি; আমরা তোমাদের বার্তার বিষয়ে সংশয়বাদী ; সন্দেহে পরিপূর্ণ। \""],
  "14:10": ["Their messengers said, \"Do you have doubts about Allah; the Initiator of the heavens and the earth? He invites you only to forgive your sins, and to give you another chance to redeem yourselves.\" They said, \"You are no more than humans like us, who want to repel us from the way our parents used to worship. Show us some profound authority.\"","তাদের বার্তাবাহকরা বলল, “তোমাদের কি আল্লাহর বিষয়ে সন্দেহ আছে; আকাশমন্ডলী ও পৃথিবীর সূচনাকারী?   তিনি তোমাদের আমন্ত্রন করেন শুধু তোমাদের পাপ ক্ষমা করে দিতে, এবং তোমাদের নিজেদের পাপমুক্ত করার জন্য আরেকটি সুযোগ  দিতে।” তারা বলল, “তোমরা আমাদের মত মানুষ ছাড়া আর কিছু নও, যারা আমাদের মাতা-পিতার করে যাওয়া উপাসনার পথ থেকে আমাদের সরিয়ে দিতে চায়। আমাদের কিছু সুস্পষ্ট কর্তৃত্ব দেখাও।’’"],
  "14:11": ["Their messengers said to them, \"We are no more than humans like you, but Allah blesses whomever He chooses from among His servants. We could not possibly show you any kind of authorization, except in accordance with Allah's will. In Allah the believers shall trust.","তাদের বার্তাবাহকরা তাদের বলেছিল, “আমরা তোমাদের মত মানুষ ছাড়া কিছু নই, কিন্তু আল্লাহ অনুগ্রহ করেন তাঁর বান্দাদের মধ্য থেকে যাকে তিনি পছন্দ করেন। আমরা সম্ভবত তোমাদেরকে কোন ধরণের কর্তৃত্ব দেখাতে পারবো না, আল্লাহর ইচ্ছানুযায়ী ব্যতীত। আল্লাহর প্রতি বিশ্বাসীদের আস্থা রাখা উচিত।"],
  "14:12": ["\"Why should we not trust in Allah, when He has guided us in our paths? We will steadfastly persevere in the face of your persecution. In Allah all the trusters shall trust.\"","\"কেন আমরা আল্লাহর প্রতি আস্থা রাখবো না, যখন তিনি আমাদের পথসমূহে আমাদেরকে পরিচালিত করেছেন? আমরা তোমার নির্যাতনের মুখে দৃড়তার সাথে  অবিচল থাকবো। আল্লাহর প্রতি সকল আস্থাকারীদের আস্থা রাখা উচিত।\""],
  "14:13": ["Those who disbelieved said to their messengers, \"We will banish you from our land, unless you revert to our religion.\" Their Lord inspired them: \"We will inevitably annihilate the transgressors.","যারা অবিশ্বাস করেছিল তারা তাদের বার্তাবাহকদের বলল, “তোমাদেরকে আমরা আমাদের ভূমি থেকে বের করে দেবো, যদি না তোমরা আমাদের ধর্মে ফিরে আসো।” তাদেরকে তাদের প্রভু অনুপ্রেরণা দিলেন: \"আমরা অবশ্যই সীমালঙ্ঘনকারীদের ধ্বংস করবো।"],
  "14:14": ["\"And we will let you dwell in their land after them. This is (the reward) for those who reverence My majesty, and reverence My promise.\"","\"এবং আমরা তোমাদেরকে তাদের পর তাদের ভূমিতে বাস করতে দেবো। এটা (পুরষ্কার) তাদের জন্য যারা আমার ঐশরিক ক্ষমতাকে ভক্তি করে, এবং আমার প্রতিশ্রুতিকে ভক্তি করে।\""],
  "14:15": ["They issued a challenge, and consequently, every stubborn tyrant ended up doomed.","তারা একটি চ্যালেঞ্জ করলো, এবং ফলস্বরুপ, প্রত্যেক একগুঁয়ে অত্যাচারী শাসক অবশেষে ধ্বংস হলো।"],
  "14:16": ["Awaiting him is Hell, wherein he will drink putrid water.","তার জন্য অপেক্ষা করছে নরক, যেখানে সে পঁচা পানি পান করবে।"],
  "14:17": ["He will gulp it down, though he cannot stand it, as death comes to him from every direction, but he will never die. Awaiting him is a terrible retribution.","সে তা গিলবে, যদিও তা সে সহ্য করতে পারবে না, যেন মৃত্যু প্রত্যেক দিক থেকে তার কাছে আসবে, কিন্তু সে কখনো মরবে না। তার জন্য অপেক্ষায় আছে এক ভয়ানক শাস্তি।"],
  "14:18": ["The allegory of those who disbelieve in their Lord: their works are like ashes in a violent wind, on a stormy day. They gain nothing from whatever they earn; such is the farthest straying.","যারা তাদের প্রভুকে অবিশ্বাস করে তাদের উপমা হচ্ছেঃ তাদের কাজগুলো তীব্র বাতাসের মাঝে ছাইয়ের মত, কোন ঝড়ো দিনে। যা কিছু তারা উপার্জন করে তা থেকে তারা কিছুই পায় না; এমনই হচ্ছে দূরতম পথভ্রষ্টতা।"],
  "14:19": ["Do you not realize that Allah has created the heavens and the earth for a specific purpose? If He wills, He can remove you, and substitute a new creation in your place.","তুমি কি অনুধাবন করো না যে আল্লাহ আকাশমন্ডলী ও পৃথিবী একটি নির্দিষ্ট উদ্দেশ্যে সৃষ্টি করেছেন? যদি তিনি ইচ্ছা করেন, তিনি তোমাদের সরিয়ে দিতে পারেন, এবং তোমাদের জায়গায় নতুন সৃষ্টি আনতে পারেন।"],
  "14:20": ["This is not too difficult for Allah.","এটি আল্লাহর জন্য খুব কঠিন নয়।"],
  "14:21": ["When they all stand before Allah, the followers will say to the leaders, \"We used to follow you. Can you spare us even a little bit of Allah's retribution?\" They will say, \"Had Allah guided us, we would have guided you. Now it is too late, whether we grieve or resort to patience, there is no exit for us.\"","যখন তারা সকলে আল্লাহর সামনে দাঁড়াবে, অনুসারীরা নেতাদের বলবে, \"আমরা তোমাদের অনুসরণ করতাম। তোমরা কি আল্লাহর শাস্তি থেকে আমাদের একটুখানি হলেও মুক্তি দিতে পারো? তারা বলবে, \"যদি আল্লাহ আমাদের পথপ্রদর্শণ করতেন, আমরা তোমাদের পথ দেখাতাম। এখন অনেক দেরি হয়ে গিয়েছে, আমরা শোক করি বা ধৈর্য্যধারণ করি, আমাদের কোন নিস্তার নেই।\""],
  "14:22": ["And the devil will say, after the judgment had been issued, \"Allah has promised you the truthful promise, and I promised you, but I broke my promise. I had no power over you; I simply invited you, and you accepted my invitation. Therefore, do not blame me, and blame only yourselves. My complaining cannot help you, nor can your complaining help me. I have disbelieved in your idolizing me. The transgressors have incurred a painful retribution.\"","এবং শয়তান বলবে, বিচার কার্যকর হওয়ার পর, \"আল্লাহ তোমাদের প্রতিশ্রুতি দিয়েছিলেন সত্য প্রতিশ্রুতি, এবং আমি তোমাদের প্রতিশ্রুতি দিয়েছিলাম, কিন্তু আমি আমার প্রতিশ্রুতি ভংগ করেছি। তোমাদের উপর আমার কোন ক্ষমতা ছিল না; আমি শুধু তোমাদের আমন্ত্রণ করতাম, এবং তোমরা আমার আমন্ত্রণ গ্রহণ করতে। অতএব, আমাকে দোষ দিও না, এবং শুধু নিজেদের দোষ দাও। আমার অভিযোগ তোমাদের সাহায্য করতে পারবে না, না তোমাদের অভিযোগ আমার কোন সাহায্য করতে পারবে। আমাকে তোমাদের উপাস্য বানানোকে আমি অবিশ্বাস করেছি। সীমালঙ্ঘনকারীরা এক যন্ত্রণাদায়ক শাস্তি টেনে এনেছে।\""],
  "14:23": ["As for those who believe and lead a righteous life, they will be admitted into gardens with flowing streams. They abide therein forever, in accordance with the will of their Lord. Their greeting therein is: \"Peace.\"","আর তাদের জন্য যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, তারা প্রবাহিত ঝর্নাসহ বাগানগুলোতে প্রবেশ করবে। তারা সেখানে চিরকাল বসবাস করবে, তাদের প্রভুর ইচ্ছানুসারে। সেখানে তাদের সম্ভাষণ হবে, \"শান্তি\"।"],
  "14:24": ["Do you not see that Allah has cited the example of the good word as a good tree whose root is firmly fixed, and its branches are high in the sky?","তুমি কি দেখো না যে আল্লাহ ভাল কথার উপমা দিয়েছেন একটি ভাল গাছ হিসেবে যার মূল শক্ত করে আটকানো, এবং শাখাগুলো আকাশে বিস্তৃত?"],
  "14:25": ["It produces its crop every season, as designed by its Lord. Allah thus cites the examples for the people, that they may take heed.","এটি প্রত্যেক ঋতুতে এর শস্য উৎপন্ন করে, যেভাবে এর প্রভু নকশা করেছেন। আল্লাহ এভাবে লোকদের জন্য উপমা বর্ণনা করেণ, যাতে তারা উপদেশ নিতে পারে।"],
  "14:26": ["And the example of the bad word is that of a bad tree chopped at the soil level; it has no roots to keep it standing.","এবং মন্দ কথার উপমা হচ্ছে একটি মন্দ গাছ যা মাটির স্তরে কাঁটা হয়েছে; একে দাঁড় করিয়ে রাখার জন্য এর কোন মূল নেই।"],
  "14:27": ["Allah strengthens those who believe with the proven word, in this life and in the Hereafter. And Allah sends the transgressors astray. Everything is in accordance with Allah's will.","যারা বিশ্বাস করে তাদেরকে প্রমাণিত কথা দিয়ে আল্লাহ শক্তিশালী করেন, এই জীবনে এবং পরকালে। এবং আল্লাহ সীমালঙ্ঘনকারীদের পথভ্রষ্ট করেন। সবকিছু আল্লাহর ইচ্ছানুসারে হয়।"],
  "14:28": ["Have you noted those who responded to Allah's blessings by disbelieving, and thus brought disaster upon their own families?","তুমি কি তাদের লক্ষ্য করেছ যারা অবিশ্বাস দিয়ে আল্লাহর অনুগ্রহের প্রতি সাড়া দিয়েছে, এবং এভাবে তাদের নিজেদের পরিবারের উপর দুর্দশা এনেছে?"],
  "14:29": ["Hell is their destiny, wherein they burn; what a miserable end!","নরক হচ্ছে তাদের নিয়তি, যেখানে তারা দগ্ধ হয়; কি এক শোচনীয় পরিসমাপ্তি!"],
  "14:30": ["They set up rivals to rank with Allah and to divert others from His path. Say, \"Enjoy for awhile; your final destiny is Hell.\"","তারা আল্লাহর সমপর্যায়ে স্থান দিতে এবং অন্যদেরকে তাঁর পথ থেকে বিচ্যুত করতে প্রতিদ্বন্দ্বীদের স্থাপন করে। বল, \"ক্ষনিকের জন্য উপভোগ করে নাও; তোমাদের চুড়ান্ত নিয়তি নরক।\""],
  "14:31": ["Exhort My servants who believed to observe the Contact Prayers (Salat), and to give (to charity) from our provisions to them, secretly and publicly, before a day comes where there is neither trade, nor nepotism.","আমার বান্দাদের মধ্যে যারা বিশ্বাস করেছে তাদেরকে উদ্বুদ্ধ করো সংযোগ প্রার্থনা (সালাত) পালন করতে, এবং আমাদের দেয়া জীবিকা থেকে দিতে (দান হিসেবে), গোপনে ও প্রকাশ্যে, সে দিন আসার আগে যখন থাকবে না কোন বাণিজ্য, না কোন সজনপ্রীতি।"],
  "14:32": ["Allah is the One who created the heavens and the earth, and He sends down from the sky water to produce all kinds of fruit for your sustenance. He has committed the ships to serve you on the sea in accordance with His command. He has committed the rivers as well to serve you.","আল্লাহই সেই সত্ত্বা যিনি আকাশমন্ডলী ও পৃথিবী সৃষ্টি করেছেন, এবং তোমাদের জীবিকার জন্য সকল প্রকার ফল উৎপন্ন করতে আকাশ থেকে পানি বর্ষণ করেন। তিনি জাহাজগুলোকে সমুদ্রে তোমাদের সেবায় নিয়োজিত করেছেন তাঁর আদেশ অনুসারে। তিনি নদীগুলোকেও একইভাবে তোমাদের সেবায় নিয়োজিত করেছেন।"],
  "14:33": ["He has committed the sun and the moon in your service, continuously. He has committed the night and the day to serve you.","তিনি সূর্য ও চাঁদকে তোমাদের সেবায় নিয়োজিত করেছেন, অনবরত। তিনি রাত ও দিনকে তোমাদের সেবায় নিয়োজিত করেছেন।"],
  "14:34": ["And He gives you all kinds of things that you implore Him for. If you count Allah's blessings, you can never encompass them. Indeed, the human being is transgressing, unappreciative.","এবং তিনি তোমাদেরকে সব ধরণের জিনিস দেন যা কিছুর জন্য তোমরা তাঁর কাছে মিনতি করো। যদি তোমরা আল্লাহর অনুগ্রহ গননা করো, তোমরা কখনো সেগুলো বেষ্টন করতে পারবে না। প্রকৃতপক্ষে, মানবজাতি সীমালঙ্ঘনে রত, অকৃতজ্ঞ।"],
  "14:35": ["Recall that Abraham said, \"My Lord, make this a peaceful land, and protect me and my children from worshiping idols.","স্মরণ করো যে ইব্রাহিম বলেছিল, \"আমার প্রভু, একে এক শান্তিময় ভূমি করুন, এবং আমাকে ও আমার সন্তানদের অংশীদার উপাসনা থেকে রক্ষা করুন।"],
  "14:36": ["\"My Lord, they have misled so many people. As for those who follow me, they belong with me. As for those who disobey me, You are Forgiver, Most Merciful.","\"আমার প্রভু, তারা অনেক লোককে পথভ্রষ্ট করেছে। আর তাদের জন্য যারা আমাকে অনুসরণ করে, তারা আমার সাথে আছে। আর তাদের ক্ষেত্রে যারা আমাকে অমান্য করে, আপনি ক্ষমাকারী, পরম দয়ালু।"],
  "14:37": ["\"Our Lord, I have settled part of my family in this plantless valley, at Your Sacred House. Our Lord, they are to observe the Contact Prayers (Salat), so let throngs of people converge upon them, and provide for them all kinds of fruits, that they may be appreciative.","“আমাদের প্রভু, আমি আমার পরিবারের একাংশের জন্য বসতি স্থাপন করলাম এই তরুলতাহীন উপত্যাকায়, তোমার পবিত্র ঘরে। আমাদের প্রভু, তারা যাতে সংযোগ প্রার্থনা (সালাত) পালন করে, তাই জনতাকে তাদের সাথে একত্রিত করুন, এবং তাদের জন্য সকল প্রকার ফল সরবরাহ করুন, যাতে তারা কৃতজ্ঞ হয়।"],
  "14:38": ["\"Our Lord, You know whatever we conceal and whatever we declare— nothing is hidden from Allah on earth, nor in the heavens.","“আমাদের প্রভু, আপনি জানেন যা কিছু আমরা গোপন করি এবং যা কিছু আমরা প্রকাশ করি- আল্লাহর কাছে কোনকিছু লুকানো নেই পৃথিবীতে, না আছে আকাশমন্ডলীতে।"],
  "14:39": ["\"Praise be to Allah for granting me, despite my old age, Ismail and Isaac. My Lord answers the prayers.","“প্রশংসা আল্লাহর আমাকে দেয়ার জন্য, আমার বৃদ্ধ বয়স সত্ত্বেও, ইসমাইল ও ইসহাককে। আমার প্রভু প্রার্থনার জবাব দেন।"],
  "14:40": ["\"Our Lord, make me one who consistently observes the Contact Prayers (Salat), and also my children. Our Lord, please answer my prayers.","“আমার প্রভু, আমাকে এমন একজন করুন যে নিয়ম-মাফিক সংযোগ প্রার্থনা (সালাত) পালন করে, এবং আমার সন্তানদেরও। আমাদের প্রভু, দয়া করে আমাদের প্রার্থনার জবাব দিন।"],
  "14:41": ["\"My Lord, forgive me and my parents, and the believers, on the day when the reckoning takes place.\"","“আমার প্রভু, ক্ষমা করুন আমাকে এবং আমার পিতা-মাতাকে, এবং বিশ্বাসীদের, ঐ দিনে যখন হিসাব নেয়া হয়।”"],
  "14:42": ["Do not ever think that Allah is unaware of what the transgressors are doing. He only respites them until a day where the eyes stare in horror.","কখনো ভেবো না যে সীমালঙনকারীরা যা করছে আল্লাহ সে বিষয়ে অসচেতন। তিনি শুধু তাদের ঐ দিন পর্যন্ত অবকাশ দেন যেদিন চোখগুলো আতঙ্কে বিস্ফোরিত হয়।"],
  "14:43": ["As they rush (out of the graves), their faces will be looking upward, their eyes will not even blink, and their minds will be horrified.","যখন তারা (কবর থেকে) দ্রুত বের হবে,  তাদের মুখগুলো উপরের দিকে তাকানো থাকবে, এমনকি তাদের চোখের পলকও পড়বে না, এবং তাদের হৃদয় আতংকিত হবে।"],
  "14:44": ["You shall warn the people of the day when the retribution comes to them. Those who transgressed will say, \"Our Lord, give us one more respite. We will then respond to Your call and follow the messengers.\" Did you not swear in the past that you will last forever?","তুমি লোকদের ঐ দিনের বিষয়ে সতর্ক করবে যখন তাদের কাছে শাস্তি আসবে। যারা সীমালংঘন করেছে তারা বলবে, “আমাদের প্রভু, আমাদেরকে আর একবার অবকাশ দিন। তখন আমরা আপনার ডাকে সাঁড়া দিবো এবং বার্তাবাহকদের অনুসরণ করবো।”তোমরা কি অতীতে শপথ করে বলতে না যে তোমরা চিরকাল টিকে থাকবে?"],
  "14:45": ["You dwelled in the homes of those before you, who wronged their souls, and you have seen clearly what we did to them. We have set many precedents for you.","তোমরা তোমাদের পূর্ববর্তীদের বাড়িতে বাস করতে, যারা তাদের আত্মার ক্ষতি করেছিল, এবং তোমরা স্পষ্টই দেখেছ যা আমরা তাদের সাথে করেছিলাম। আমরা তোমাদের জন্য অনেক উদাহরণ স্থাপন করেছি।"],
  "14:46": ["They schemed their schemes, and Allah is fully aware of their schemes. Indeed, their schemes were sufficient to erase mountains.","তারা তাদের চক্রান্ত করেছিল, এবং আল্লাহ তাদের চক্রান্ত সম্পর্কে পূর্ণ অবগত। প্রকৃতপক্ষে, তাদের চক্রান্ত পাহাড়গুলো মুছে দিতে যথেষ্ঠ ছিল।"],
  "14:47": ["Do not think that Allah will ever break His promise to His messengers. Allah is Almighty, Avenger.","মনে করো না যে আল্লাহ কখনো তাঁর বার্তাবাহকদের সাথে করা অঙ্গীকার ভংগ করবেন। আল্লাহ সর্বশক্তিমান, প্রতিশোধ গ্রহনকারী।"],
  "14:48": ["The day will come when this earth will be substituted with a new earth, and also the heavens, and everyone will be brought before Allah, the One, the Supreme.","ঐ দিন আসবে যখন এই পৃথিবীর জায়গায় এক নতুন পৃথিবী আনা হবে, এবং আকাশমন্ডলীও, এবং সকলকে আল্লাহর সামনে উপস্থিত করা হবে, সেই একক সত্ত্বা, সর্বোচ্চ।"],
  "14:49": ["And you will see the guilty on that day chained in shackles.","আর সেদিন তুমি অপরাধীদের দেখবে শিকলে বাঁধা।"],
  "14:50": ["Their garments will be made of tar, and fire will overwhelm their faces.","তাদের জামা আলকাতরায় তৈরী হবে, এবং আগুন তাদের মুখ আচ্ছন্ন করবে।"],
  "14:51": ["For Allah will pay each soul for whatever it earned; Allah is the most efficient reckoner.","কারণ আল্লাহ প্রত্যেক আত্মাকে শোধ করবেন যা তারা অর্জণ করেছে; আল্লাহ সবচেয়ে দক্ষ হিসাব গ্রহনকারী।"],
  "14:52": ["This is a proclamation for the people, to be warned herewith, and to let them know that He is only one god, and for those who possess intelligence to take heed.","এটি লোকদের জন্য একটি ঘোষনাপত্র, এর দ্বারা সতর্ক করতে, এবং তাদেরকে জানাতে যে তিনিই একমাত্র উপাস্য, এবং যারা বুদ্ধিমত্তার অধিকারী তারা যেন মনোনিবেশ করে।"],
  "15:1": ["A.L.R. These (letters) are proofs of this scripture; a profound Quran.","অ, ল, র। এই (অক্ষর গুলো) এই ঐশীগ্রন্থের প্রমান; এক জ্ঞানগর্ভ কুরআন।"],
  "15:2": ["Certainly, those who disbelieved will wish they were submitters.","নিশ্চয়, যারা অবিশ্বাস করতো তারা আকাঙ্ক্ষা করবে যে যদি তারা আত্মসমর্পণকারী হতো।"],
  "15:3": ["Let them eat, enjoy, and remain blinded by wishful thinking; they will find out.","তাদেরকে খেতে, আনন্দ করতে এবং ইচ্ছেমতো চিন্তায় অন্ধ থাকতে দাও; তারা দেখতে পাবে।"],
  "15:4": ["We never annihilated any community, except in accordance with a specific, predetermined time.","আমরা কখনও কোন সম্প্রদায়কে ধ্বংস করি না, একটি নির্দিষ্ট, পূর্বনির্ধারিত সময় অনুসারে ছাড়া।"],
  "15:5": ["The end of any community can never be advanced, nor delayed.","কোন সম্প্রদায়ের সমাপ্তি না কখনো এগোতে পারে, না পেছাতে পারে।"],
  "15:6": ["They said, \"O you who received this reminder, you are crazy.","তারা বলল, “হে তুমি যে এই সতর্কবানী পেয়েছ, তুমি একটা পাগল”।"],
  "15:7": ["\"Why do you not bring down the angels, if you are truthful?\"","“কেন তুমি ফেরেশতাদের নামিয়ে আনো না, যদি তুমি সত্যবাদী হও?”"],
  "15:8": ["We do not send down the angels except for specific functions. Otherwise, no one will be respited.","আমরা সুনির্দিষ্ট কাজ ছাড়া ফেরেশতাদের অবতরণ করাই না। অন্যথায়, কেউই রেহাই পাবে না।"],
  "15:9": ["Absolutely, we have revealed the reminder, and, absolutely, we will preserve it.","নিসন্দেহে, আমরা এই সতর্কবাণী প্রকাশ করেছি, এবং, নিসন্দেহে, আমরা একে সংরক্ষন করবো।"],
  "15:10": ["We have sent (messengers) before you to the communities in the past.","আমরা তোমার আগে অতীতের সম্প্রদায়ের কাছে (বার্তাবাহকদের) পাঠিয়েছি।"],
  "15:11": ["Every time a messenger went to them, they ridiculed him.","প্রতিবার যখন একজন বার্তাবাহক তাদের কাছে গিয়েছিলো, তারা তাকে উপহাস করেছিল।"],
  "15:12": ["We thus control the minds of the guilty.","আমরা এভাবে অপরাধীদের মনকে নিয়ন্ত্রণ করি।"],
  "15:13": ["Consequently, they cannot believe in him. This has been the system since the past generations.","ফলস্বরূপ, তারা তাকে বিশ্বাস করতে পারে না। অতীত প্রজন্মদের থেকে এই রীতিই চলে আসছে।"],
  "15:14": ["Even if we opened for them a gate into the sky, through which they climb;","এমনকি আমরা যদি তাদের জন্য আকাশে কোন দরজা খুলে দেই, যা দিয়ে তারা আরোহণ করে;"],
  "15:15": ["they will say, \"Our eyes have been deceived. We have been bewitched.\"","তারা বলবে, “আমাদের চোখকে ধোঁকা দেয়া হয়েছে। আমরা জাদুগ্রস্থ হয়ে পড়েছি”।"],
  "15:16": ["We placed galaxies in the sky, and adorned it for the beholders.","আমরা আকাশে নক্ষত্রপুঞ্জ স্থাপন করেছি, এবং দর্শকদের জন্য একে সুসজ্জিত করেছি।"],
  "15:17": ["And we guarded it against every rejected devil.","এবং আমরা প্রত্যেক বিতাড়িত শয়তান থেকে একে সুরক্ষিত করেছি।"],
  "15:18": ["If any of them sneaks around to listen, a mighty projectile will chase him back.","যদি তাদের কেউ শোনার জন্য চুপিসারে ঘুরে বেড়ায়, একটি শক্তিশালী ক্ষেপণাস্ত্র তার পিছু ধাওয়া করবে।"],
  "15:19": ["As for the earth, we constructed it, and placed on it stabilizers (mountains), and we grew on it a perfect balance of everything.","পৃথিবীর বিষয়ে, আমরা একে নির্মাণ করেছি, এবং এর উপর ভারসাম্যরক্ষাকারী (পর্বতমালা) রেখেছি এবং আমরা এর উপর দিয়েছি প্রত্যেক জিনিসের এক নিখুঁত ভারসাম্য।"],
  "15:20": ["We made it habitable for you, and for creatures you do not provide for.","আমরা একে বানিয়েছি বাসযোগ্য তোমাদের জন্য,  এবং জীবদের জন্য তোমরা যাদের জীবিকা দাও না।"],
  "15:21": ["There is nothing that we do not own infinite amounts thereof. But we send it down in precise measure.","সেখানে কোন কিছুই নেই যার সীমাহীন পরিমানের মালিক আমরা মালিক নই। কিন্তু আমরা তা সুনির্দিষ্ট পরিমাণে অবতীর্ণ করি।"],
  "15:22": ["And we send the winds as pollinators, and cause water to come down from the sky for you to drink. Otherwise, you could not keep it palatable.","এবং আমরা বাতাস পাঠাই পরাগায়নকারী হিসেবে, এবং তোমাদের পান করার জন্য আকাশ থেকে পানি বর্ষনের ব্যবস্থা করি। অন্যথায়, তোমরা একে সুস্বাদু রাখতে পারতে না।"],
  "15:23": ["It is we who control life and death, and we are the ultimate inheritors.","আমরাই জীবন ও মৃত্যু নিয়ন্ত্রন করি, এবং আমরাই চূড়ান্ত উত্তরাধিকারী।"],
  "15:24": ["And we fully know those among you who advance, and we fully know those who regress.","এবং আমরা তোমাদের মধ্যে তাদেরকে পূর্ণরূপে জানি যারা অগ্রগামী হয়, এবং আমরা তাদেরকে পূর্ণরূপে জানি যারা পশ্চাৎগামী হয়।"],
  "15:25": ["Your Lord will surely summon them. He is Most Wise, Omniscient.","তোমার প্রভু অবশ্যই তাদের ডেকে পাঠাবেন। তিনি পরম প্রজ্ঞাবান, সর্বজ্ঞ।"],
  "15:26": ["We created the human being from aged mud, like the potter's clay.","আমরা মানবজাতিকে সৃষ্টি করেছি পুরনো কাঁদা থেকে, কুমোরের মাটির মতো।"],
  "15:27": ["As for the jinns, we created them, before that, from blazing fire.","জীনদের ক্ষেত্রে, আমরা তাদের সৃষ্টি করেছি, এর আগে, জলন্ত আগুন থেকে।"],
  "15:28": ["Your Lord said to the angels, \"I am creating a human being from aged mud, like the potter's clay.","তোমার প্রভু ফেরেশতাদের বললেন, “আমি একজন মানুষ সৃষ্টি করছি পুরানো কাঁদা থেকে, কুমোরের মাটির মতো।"],
  "15:29": ["\"Once I perfect him, and blow into him from My spirit, you shall fall prostrate before him.\"","“একবার আমি তাকে সম্পূর্ণ করার পর, এবং তার মধ্যে আমার রূহ থেকে ফুঁকে দেবার পর, তোমরা তার সামনে সেজদাবনত হবে”।"],
  "15:30": ["The angels fell prostrate; all of them,","ফেরেশতারা সেজদাবনত হল; তাদের সকলে,"],
  "15:31": ["except Iblis (Satan). He refused to be with the prostrators.","ইবলিস (শয়তান) ছাড়া। সে সেজদাকারীদের সাথে থাকতে অস্বীকার করলো।"],
  "15:32": ["He said, \"O Iblis (Satan), why are you not with the prostrators?\"","তিনি বললেন, “হে ইবলিস (শয়তান), তুমি সেজদাকারীদের সাথে নেই কেন?"],
  "15:33": ["He said, \"I am not to prostrate before a human being, whom You created from aged mud, like the potter's clay.\"","সে বলল, “আমি কোন মানুষকে সেজদা করবো না, যাকে আপনি সৃষ্টি করেছেন পুরানো কাঁদা থেকে, কুমোরের মাটির মতো।\""],
  "15:34": ["He said, \"Therefore, you must get out; you are banished.","তিনি বললেন, “সেজন্য, তুমি অবশ্যই বেরিয়ে যাবে; তুমি নির্বাসিত।"],
  "15:35": ["\"You have incurred My condemnation until the Day of Judgment.\"","“তুমি বিচার দিন পর্যন্ত আমার অভিশাপ অর্জন করেছো।\""],
  "15:36": ["He said, \"My Lord, respite me until the day they are resurrected.\"","সে বলল, “আমার প্রভু, তাদের পুনরুত্থানের দিন অবধি আমাকে অবকাশ দিন।\""],
  "15:37": ["He said, \"You are respited.","তিনি বললেন, “তোমাকে অবকাশ দেয়া হল।\""],
  "15:38": ["\"Until the specified day and time.\"","“নির্দিষ্ট দিন এবং সময় পর্যন্ত।\""],
  "15:39": ["He said, \"My Lord, since You have willed that I go astray, I will surely entice them on earth; I will send them all astray.","সে বলল, “আমার প্রভু, যেহেতু আপনি ইচ্ছা করেছেন যে আমি বিপথে যাই, আমি অবশ্যই পৃথিবীতে তাদেরকে প্রলুব্ধ করবো; আমি তাদের সকলকে বিপথে পাঠাবো।"],
  "15:40": ["\"Except those among Your worshipers who are devoted absolutely to You alone.\"","\"শুধু আপনার উপাসনাকারীদের মধ্যে তাদের ছাড়া যারা সম্পূর্ণরূপে একমাত্র আপনার প্রতি উৎসর্গকৃত।\""],
  "15:41": ["He said, \"This is a law that is inviolable.","তিনি বললেন, “এটি একটি আইন যা অলঙ্ঘনীয়"],
  "15:42": ["\"You have no power over My servants. You only have power over the strayers who follow you.","\"আমার বান্দাদের উপর তোমার কোন ক্ষমতা নেই। তোমার ক্ষমতা আছে শুধু পথভ্রষ্টদের উপর যারা তোমাকে অনুসরণ করে।"],
  "15:43": ["\"And Hell awaits them all.","“এবং নরক তাদের সকলের জন্য অপেক্ষা করছে।"],
  "15:44": ["\"It will have seven gates. Each gate will get a specific share of them.\"","“এর সাতটি দরজা হবে। প্রত্যেক দরজা তাদের একটি নির্দিষ্ট অংশ পাবে।\""],
  "15:45": ["As for the righteous, they will enjoy gardens and springs.","সৎকর্মশীলদের ক্ষেত্রে, তারা বাগান এবং ঝর্না উপভোগ করবে।"],
  "15:46": ["Enter therein, peaceful and secure.","তাতে প্রবেশ করো, শান্তিময় এবং নিরাপদ।"],
  "15:47": ["We remove all jealousy from their hearts. Like one family, they will be on adjacent furnishings.","আমরা তাদের হৃদয় থেকে সকল হিংসা দূর করবো। তারা পাশাপাশি আসবাবপথ ও সাজসরঞ্জামের মাঝে থাকবে, একটি পরিবারের মতো।"],
  "15:48": ["Never will they suffer any fatigue therein; never will they be evicted therefrom.","সেখানে তারা কখনো ক্লান্তি বোধ করবে না; সেখান থেকে কখনো তারা বিতাড়িত হবে না।"],
  "15:49": ["Inform My servants that I am the Forgiver, Most Merciful.","আমার বান্দাদের জানাও যে আমি ক্ষমাকারী, পরম দয়ালু।"],
  "15:50": ["And that My retribution is the most painful retribution.","এবং যে আমার শাস্তি সবথেকে যন্ত্রণাদায়ক শাস্তি।"],
  "15:51": ["Inform them about Abraham's guests.","তাদেরকে ইব্রাহীমের অতিথিদের বিষয়ে জানাও।"],
  "15:52": ["When they entered his quarters, they said, \"Peace.\" He said, \"We are apprehensive about you.\"","যখন তারা তার বাসায় প্রবেশ করলো, তারা বলল, “শান্তি”। সে বলল, “আমরা তোমাদের ব্যপারে শঙ্কিত।\""],
  "15:53": ["They said, \"Do not be apprehensive. We have good news for you: an enlightened son.\"","তারা বলল, “শঙ্কিত হয়ো না। আমরা তোমার জন্য সুসংবাদ এনেছিঃ এক জ্ঞানদিপ্ত পুত্রের।\""],
  "15:54": ["He said, \"How can you give me such good news, when I am so old? Do you still give me this good news?\"","সে বলল, “কিভাবে তোমরা আমাকে এমন সুসংবাদ দিতে পারো, যখন আমি এতো বৃদ্ধ? এরপরও কি তোমরা আমাকে এই সুসংবাদ দাও?"],
  "15:55": ["They said, \"The good news we give you is true; do not despair.\"","তারা বলল, “যে সুসংবাদ আমরা তোমাকে দেই তা সত্য; হতাশ হয়ো না।\""],
  "15:56": ["He said, \"None despairs of his Lord's mercy, except the strayers.\"","সে বলল, “কেউ তার প্রভুর দয়া থেকে হতাশ হয় না, পথভ্রষ্টরা ছাড়া।\""],
  "15:57": ["He said, \"What is your mission, O messengers?\"","সে বলল, “তোমাদের পাঠানোর উদ্দেশ্য কি, হে বার্তাবাহকগন?”"],
  "15:58": ["They said, \"We are being dispatched to guilty people.","তারা বলল, “আমাদেরকে পাঠানো হয় অপরাধী লোকদের নিকট।"],
  "15:59": ["\"As for Lot's family, we will save them all.","“লুতের পরিবারের ক্ষেত্রে, আমরা তাদের সকলকে রক্ষা করবো।\""],
  "15:60": ["\"But not his wife; she is destined to be with the doomed.\"","“কিন্তু তার স্ত্রীকে নয়; সে দন্ডপ্রাপ্তদের সাথে থাকার জন্য নিয়তিপ্রাপ্ত।\""],
  "15:61": ["The messengers went to Lot's town.","বার্তাবাহকেরা লুতের শহরে গেল।"],
  "15:62": ["He said, \"You are unknown people.\"","সে বলল, “তোমরা অপরিচিত লোক।\""],
  "15:63": ["They said, \"We bring to you what they have been doubting.","তারা বলল, “আমরা তোমার কাছে এনেছি যাতে তারা সন্ধেহ করছে।"],
  "15:64": ["\"We bring to you the truth; we are truthful.","“আমরা তোমার কাছে সত্য আনি, আমরা সত্যবাদী।"],
  "15:65": ["\"You shall take your family during the night. Stay behind them, and make sure that none of you looks back. Go straight as commanded.\"","“রাতে তুমি তোমার পরিবারকে সঙ্গে নিবে। তাদের পেছনে থেকো, এবং নিশ্চিত করো যে তোমাদের কেউ যেন পেছনে না তাকায়। সোজা চলে যাও যেভাবে আদেশ করা হয়েছে।\""],
  "15:66": ["We delivered to him this command: those people are to be annihilated in the morning.","আমরা তার কাছে এই হুকুম পৌঁছালামঃ ঐ লোকেরা সকালে ধ্বংস হবে।"],
  "15:67": ["The people of the city came joyfully.","শহরের লোকরা আনন্দ করতে করতে আসলো।"],
  "15:68": ["He said, \"These are my guests; do not embarrass me.","সে বলল, “এরা আমার অতিথি; আমাকে বিব্রত করো না।”"],
  "15:69": ["\"Fear Allah, and do not shame me.\"","“আল্লাহকে ভয় করো, এবং আমাকে লজ্জিত করো না।\""],
  "15:70": ["They said, \"Did we not enjoin you from contacting anyone?\"","তারা বলল, “তোমাকে কি আমরা কারো সাথে যোগাযোগ করতে নিষেধ করিনি?”"],
  "15:71": ["He said, \"Here are my daughters, if you must.\"","সে বলল, “এখানে আছে আমার কন্যারা, যদি তোমাদের দরকারই হয়।\""],
  "15:72": ["But, alas, they were totally blinded by their lust.","কিন্তু, হায়, তারা তাদের কাম লালসায় সম্পূর্ণ অন্ধ ছিল।"],
  "15:73": ["Consequently, the disaster struck them in the morning.","ফলস্বরূপ, সকালে দুর্যোগ তাদের আঘাত করলো।"],
  "15:74": ["We turned it upside down, and showered them with devastating rocks.","আমরা একে উল্টে দিলাম, এবং তাদের উপর ধ্বংসাত্বক পাথর বর্ষণ করলাম।"],
  "15:75": ["This is a lesson for those who possess intelligence.","এটা তাদের জন্য একটি শিক্ষা যারা বুদ্ধিমত্তার অধিকারী।"],
  "15:76": ["This will always be the system.","এটাই হবে সবসময়কার রীতি।"],
  "15:77": ["This is a sign for the believers.","এটা বিশ্বাসীদের জন্য একটা নিদর্শন।"],
  "15:78": ["The people of the woods also were transgressors.","বনের অধিবাসীরাও সীমালঙ্ঘনকারী ছিল।"],
  "15:79": ["Consequently, we avenged from them, and both communities are fully documented.","ফলস্বরূপ, আমরা তাদের থেকে প্রতিশোধ নিলাম, এবং উভয় জনপদ সম্পূর্ণভাবে লিপিবদ্ধ।"],
  "15:80": ["The people of Al-Hijr disbelieved the messengers.","আল-হিজরের লোকেরা বার্তাবাহকদের অবিশ্বাস করেছিল।"],
  "15:81": ["We gave them our revelations, but they disregarded them.","আমরা তাদেরকে আমাদের প্রকাশনাবলি দিয়েছিলাম, কিন্তু তারা সেগুলো উপেক্ষা করেছে।"],
  "15:82": ["They used to carve secure homes out of the mountains.","তারা পাহাড়ে নিরাপদ ঘর খোদাই করতো।"],
  "15:83": ["The disaster hit them in the morning.","সকালে দুর্যোগ তাদের আঘাত করলো।"],
  "15:84": ["What they hoarded did not help them.","যা তারা জমা করেছিল তা তাদের সাহায্য করেনি।"],
  "15:85": ["We did not create the heavens and the earth, and everything between them, except for a specific purpose. The end of the world will come, so treat them with benign neglect.","আমরা আকাশমন্ডলী ও পৃথিবী, এবং এদের মাঝের সবকিছু একটি সুনির্দিষ্ট উদ্দেশ্য ছাড়া সৃষ্টি করিনি। বিশ্বের পরিসমাপ্তি আসবে, সুতরাং তাদেরকে মৃদুভাবে উপেক্ষা করো।"],
  "15:86": ["Your Lord is the Creator, the Omniscient.","তোমার প্রভু হচ্ছেন সৃষ্টিকর্তা, আর সর্বজ্ঞ।"],
  "15:87": ["We have given you the seven pairs, and the great Quran.","আমরা তোমাকে দিয়েছি সাত জোড়া, এবং মহান কুরআন।"],
  "15:88": ["Do not be jealous of what we bestowed upon the other (messengers), and do not be saddened (by the disbelievers), and lower your wing for the believers.","অন্য (বার্তাবাহকদের) উপর আমরা যা অর্পণ করেছি তাতে ঈর্ষান্বিত হয়ো না, এবং (অবিশ্বাসীদের কারণে) দুঃখিত হয়ো না, এবং বিশ্বাসীদের প্রতি সদয় হও।"],
  "15:89": ["And proclaim: \"I am the manifest warner.\"","এবং ঘোষণা করো, “আমি স্পষ্ট সতর্ককারী।\""],
  "15:90": ["We will deal with the dividers.","বিভক্তকারীদের সাথে আমি বোঝাপড়া করবো।"],
  "15:91": ["They accept the Quran only partially.","তারা কুরআনকে শুধু আংশিকভাবে গ্রহণ করে।"],
  "15:92": ["By your Lord, we will question them all,","তোমার প্রভুর শপথ, আমরা তাদের সবাইকে প্রশ্ন করবো,"],
  "15:93": ["about everything they have done.","সবকিছু সম্পর্কে যা তারা করেছে।"],
  "15:94": ["Therefore, carry out the orders given to you, and disregard the idol worshipers.","সুতরাং, তোমাকে দেয়া হুকুমগুলো পালন করো, এবং প্রতিমা উপাসকদের উপেক্ষা করো।"],
  "15:95": ["We will spare you the mockers,","আমরা উপহাসকারীদের থেকে তোমাকে নিষ্কৃতি দেব,"],
  "15:96": ["who set up another god beside Allah. They will surely find out.","যারা আল্লাহর পাশে অন্য উপাস্য স্থাপন করে, অবশ্যই তারা দেখতে পাবে।"],
  "15:97": ["We know full well that you may be annoyed by their utterances.","আমরা খুব ভালোভাবে জানি যে তুমি হয়তো তাদের কথায় বিরক্ত হও।"],
  "15:98": ["You shall sing the praises of your Lord, and be with the prostrators.","তুমি তোমার প্রভুর গুন কীর্তন করবে, এবং সেজদাকারিদের সাথে থাকবে।"],
  "15:99": ["And worship your Lord, in order to attain certainty.","এবং তোমার প্রভুর উপাসনা করো, নিশ্চয়তা অর্জন করার জন্য।"],
  "16:1": ["Allah's command has already been issued (and everything has already been written), so do not rush it. Be He glorified; the Most High, far above any idols they set up.","আল্লাহর হুকুম এরই মধ্যে এসে গেছে (এবং সবকিছু এরই মধ্যে লেখা হয়ে গেছে), তাই এতে তাড়াহুড়া করো না। মহিমা তাঁরই; সর্বোচ্চ, তাদের স্থাপন করা যেকোন অংশীদার থেকে অনেক ঊর্ধ্বে।"],
  "16:2": ["He sends down the angels with the revelations, carrying His commands, to whomever He chooses from among His servants: \"You shall preach that there is no other god beside Me; You shall reverence Me.\"","তিনি প্রকাশনাবলী দিয়ে ফেরেশতাদের অবতরণ করান, তাঁর হুকুম বহন করে, তার প্রতি যাকে তিনি পছন্দ করেন তাঁর বান্দাদের মধ্য থেকে: “তোমরা প্রচার করবে যে, কোন উপাস্য নাই আমার পাশে; তোমরা আমাকে ভক্তি করবে”।"],
  "16:3": ["He created the heavens and the earth for a specific purpose. He is much too High, far above any idols they set up.","তিনি আকাশমন্ডলী এবং পৃথিবী একটি সুনির্দিষ্ট উদ্দেশ্যে সৃষ্টি করেছেন। তিনি অনেক অনেক উর্ধ্বে, তাদের স্থাপিত কোন অংশীদার থেকে অনেক উপরে।"],
  "16:4": ["He created the human from a tiny drop, then he turns into an ardent opponent.","তিনি মানুষকে অতিক্ষুদ্র এক ফোঁটা থেকে সৃষ্টি করেছেন, এরপর সে এক প্রকাশ্য প্রতিপক্ষে পরিণত হয়।"],
  "16:5": ["And He created the livestock for you, to provide you with warmth, and many other benefits, as well as food.","এবং তিনি তোমাদের জন্য গবাদি পশু সৃষ্টি করেছেন, তোমাদের জন্য উষ্ণতা জোগাতে, এবং আরও অনেক উপকারিতা, সেইসাথে খাবার।"],
  "16:6": ["They also provide you with luxury during your leisure, and when you travel.","এছাড়াও এগুলো বিলাস দ্রব্যের যোগান দেয় তোমাদের অবসর সময়ে, এবং যখন তোমরা ভ্রমন করো।"],
  "16:7": ["And they carry your loads to lands that you could not reach without a great hardship. Surely, your Lord is Compassionate, Most Merciful.","এবং তারা তোমাদের বোঝা এমন জায়গায় বহন করে নিয়ে যায় যেখানে তোমরা অনেক কষ্ট ব্যতীত পৌঁছতে পারতে না। নিশ্চয়, তোমার প্রভু দয়াবান, পরম করুণাময়।"],
  "16:8": ["And (He created) the horses, the mules, and the donkeys for you to ride, and for luxury. Additionally, He creates what you do not know.","এবং (তিনি সৃষ্টি করেছেন) ঘোড়া, খচ্চর, এবং গাধা তোমাদের আরহনের জন্য, এবং বিলাসিতার জন্য। উপরুন্তু, তিনি সৃষ্টি করেন যা তোমরা জানো না।"],
  "16:9": ["Allah points out the paths, including the wrong ones. If He willed, He could have guided all of you.","আল্লাহ পথসমূহ প্রদর্শন করেন, ভুলপথটিও। তিনি চাইলে, তোমাদের সকলকে সুপথপ্রাপ্ত করতে পারতেন।"],
  "16:10": ["He sends down from the sky water for your drink, and to grow trees for your benefit.","তিনি আকাশ থেকে পানি বর্ষণ করেন তোমাদের পান করার জন্য, এবং তোমাদের উপকারের জন্য গাছ জন্মাতে।"],
  "16:11": ["With it, He grows for you crops, olives, date palms, grapes, and all kinds of fruits. This is (sufficient) proof for people who think.","তা দিয়ে, তিনি তোমাদের জন্য উৎপাদন করেন শস্য, জলপাই, খেজুর গাছ, আঙ্গুর, এবং সকল প্রকার ফল। এটাই(যথেষ্ট) প্রমান লোকদের জন্য যারা চিন্তা করে।"],
  "16:12": ["And He commits, in your service, the night and the day, as well as the sun and the moon. Also, the stars are committed by His command. These are (sufficient) proofs for people who understand.","এবং তিনি  নিয়োজিত করেন, তোমাদের সেবায়, দিন ও রাত্রি, সেই সাথে সূর্য ও চাঁদকে। তারকারাজীও নিয়োজিত রয়েছে  তাঁর হুকুমে। এগুলো (যথেষ্ট) প্রমান লোকদের জন্য যারা বুঝে।"],
  "16:13": ["And (He created) for you on earth things of various colors. This is a (sufficient) proof for people who take heed.","এবং পৃথিবীতে তোমাদের জন্য (তিনি সৃষ্টি করেছেন) বিভিন্ন রঙের জিনিস। এটা (যথেষ্ট) প্রমান লোকদের জন্য যারা মনোযোগ দেয়।"],
  "16:14": ["And He committed the sea to serve you; you eat from it tender meat, and extract jewelry which you wear. And you see the ships roaming it for your commercial benefits, as you seek His bounties, that you may be appreciative.","এবং তিনি সমুদ্রকে নিয়োজিত করেছেন তোমাদের সেবায়; তোমরা এর থেকে নরম মাংস খাও এবং আহরণ করো অলঙ্কার যা তোমরা পরো। এবং তুমি জাহাজগুলোকে দেখো এতে বিচরণ করতে তোমাদের বাণিজ্যিক লাভের জন্য, যখন তোমরা তাঁর অনুগ্রহ অন্বেষণ করো, যাতে তোমরা কৃতজ্ঞ হতে পারো।"],
  "16:15": ["And He placed stabilizers (mountains) on earth, lest it tumbles with you, as well as rivers and roads, that you may be guided.","এবং তিনি পৃথিবীতে ভারসাম্যকারী (পর্বত) স্থাপন করেছেন, পাছে এটি তোমাদের নিয়ে উলটে পড়ে, সেই সাথে নদী এবং রাস্তা, যাতে তোমরা সুপথপ্রাপ্ত হও।"],
  "16:16": ["And landmarks, as well as the stars; to be used for navigation.","এবং স্থান নির্দেশক, সেই সাথে তারকারাজী; যান চালনায় ব্যবহারের জন্য।"],
  "16:17": ["Is One who creates like one who does not create? Would you now take heed?","যে সত্ত্বা সৃষ্টি করেন তিনি কি তার মতো যে সৃষ্টি করে না? এখন কি তোমরা মনোযোগ দেবে?"],
  "16:18": ["If you count Allah's blessings, you cannot possibly encompass them. Allah is Forgiver, Most Merciful.","যদি তুমি আল্লাহর অনুগ্রহ গণনা করো, তুমি কখনো তা পরিবেষ্টন করতে পারবে না। আল্লাহ ক্ষমাকারী, পরম দয়ালু।"],
  "16:19": ["And Allah knows whatever you conceal and whatever you declare.","এবং আল্লাহ জানেন যাকিছু তোমরা গোপন করো এবং যাকিছু তোমরা প্রকাশ করো।"],
  "16:20": ["As for the idols they set up beside Allah, they do not create anything; they themselves were created.","আর আল্লাহর পাশে তাদের স্থাপন করা অংশীদারদের ব্যাপারে, তারা কোন কিছু সৃষ্টি করে না; তারা নিজেরাই সৃজিত।"],
  "16:21": ["They are dead, not alive, and they have no idea how or when they will be resurrected.","তারা মৃত, জীবিত নয়, এবং তাদের কোন ধারনা নেই কিভাবে বা কখন তারা পুনরুত্থিত হবে।"],
  "16:22": ["Your god is one god. As for those who do not believe in the Hereafter, their hearts are denying, and they are arrogant.","তোমাদের খোদা হচ্ছেন একজন। তাদের ক্ষেত্রে যারা পরকালে বিশ্বাস করে না, তাদের হৃদয় অস্বীকার করছে, এবং তারা উদ্ধত।"],
  "16:23": ["Absolutely, Allah knows everything they conceal and everything they declare. He does not love those who are arrogant.","সম্পূর্ণরূপে, আল্লাহ জানেন সবকিছু যা তারা গোপন করে এবং সবকিছু যা তারা প্রকাশ করে। তিনি তাদের ভালোবাসেন না যারা উদ্ধত।"],
  "16:24": ["When they are asked, \"What do you think of these revelations from your Lord,\" they say, \"Tales from the past.\"","যখন তাদের জিজ্ঞেস করা হয়, “তোমাদের প্রভুর পক্ষ থেকে এই প্রকাশনাবলির ব্যাপারে তোমরা কি মনে করো,” তারা বলে, “অতীতের কল্প-কাহিনী।\""],
  "16:25": ["They will be held responsible for their sins on the Day of Resurrection, all of them, in addition to sins of all those whom they misled by their ignorance. What a miserable load!","পুনরুত্থান দিনে তাদেরকে দায়ী করা হবে তাদের পাপের জন্য, তাদের সকলকে, সেই সাথে ওদের সকলের পাপের জন্য তারা যাদেরকে পথভ্রষ্ট করেছে তাদের অজ্ঞতার দ্বারা। কি এক শোচনীয় বোঝা!"],
  "16:26": ["Others like them have schemed in the past, and consequently, Allah destroyed their building at the foundation, causing the roof to fall on them. The retribution struck them when they least expected.","তাদের মতো অন্যান্যরাও অতীতে চক্রান্ত করেছে, এবং ফলস্বরূপ, আল্লাহ তাদের ইমারতের ভিত্তি ধ্বংস করেছিলেন, তাদের উপর ছাদ পতিত করে। শাস্তি তাদের আঘাত করেছিল যখন তারা খুব কমই প্রত্যাশা করেছিল।"],
  "16:27": ["Then, on the Day of Resurrection, He will disgrace them and ask, \"Where are My partners that you had set up beside Me, and had opposed Me for their sake?\" Those blessed with knowledge will say, \"Today, the shame and misery have befallen the disbelievers.\"","এরপর, পুনরুত্থান দিনে, তিনি তাদের লাঞ্ছিত করবেন এবং জিজ্ঞেস করবেন, “কোথায় আমার শরিক-উপাস্যরা যাদেরকে তোমরা আমার পাশে স্থাপন করেছিলে, এবং তাদের কারনে আমার বিরোধিতা করেছিলে?” যারা জ্ঞান পেয়ে সৌভাগ্যশালী হয়েছিল তারা বলবে, “আজকে, লজ্জা ও দুর্দশা অবিশ্বাসীদের উপর পড়েছে।\""],
  "16:28": ["The angels put them to death in a state of wronging their souls. That is when they finally submit, and say, \"We did not do anything wrong!\" Yes indeed. Allah is fully aware of everything you have done.","তাদের আত্মার ক্ষতি করা অবস্থায় ফেরেশতারা তাদের মৃত্যু ঘটায়। ঠিক তখনই তারা অবশেষে আত্মসমর্পণ করে, এবং বলে, “আমরা কোন অন্যায় করিনি!” হ্যাঁ নিশ্চয়ই! আল্লাহ সবকিছুর ব্যাপারে সম্পূর্ণ অবগত, যা তোমরা করেছো।"],
  "16:29": ["Therefore, enter the gates of Hell, wherein you abide forever. What a miserable destiny for the arrogant ones.","অতএব, নরকের দরজা দিয়ে প্রবেশ করো, যেখানে তোমরা চিরকাল বাস করো। উদ্ধতদের জন্য কি এক শোচনীয় নিয়তি।"],
  "16:30": ["As for the righteous, when they are asked, \"What do you think of these revelations from your Lord,\" they say, \"Good.\" For those who lead a righteous life, happiness, and the abode of the Hereafter is even better. What a blissful abode for the righteous.","সৎ-কর্মীদের ক্ষেত্রে, যখন তাদের জিজ্ঞেস করা হয়, “তোমাদের প্রভুর পক্ষ থেকে এই প্রকাশনাবলির ব্যপারে কি মনে করো,” তারা বলে, “ভাল।\" যারা সৎ জীবন-যাপন করে তাদের জন্য, সুখ, এবং পরকালের গৃহ আরও উত্তম। কি এক পরম সুখের আবাস সৎ-কর্মশীলদের জন্য।"],
  "16:31": ["The gardens of Eden are reserved for them, wherein rivers flow. They have anything they wish therein. Allah thus rewards the righteous.","ইডেনের বাগানগুলো তাদের জন্য সংরক্ষিত রয়েছে, যেখানে নদী প্রবাহিত হয়। সেখানে তাদের তা-ই থাকে যা তারা  ইচ্ছা করে। আল্লাহ এভাবে সৎ-কর্মশীলদের পুরষ্কৃত করেন।"],
  "16:32": ["The angels terminate their lives in a state of righteousness, saying, \"Peace be upon you. Enter Paradise (now) as a reward for your works.\"","ফেরেশতারা সৎকর্মশীল অবস্থায় তাদের জীবন পরিসমাপ্তি করে, এ বলে, “তোমাদের উপর শান্তি বর্ষিত হোক। তোমাদের কাজের পুরস্কার হিসেবে (এখন) স্বর্গে প্রবেশ করো।\""],
  "16:33": ["Are they waiting for the angels to come to them, or until your Lord's judgment comes to pass? Those before them did the same thing. Allah is not the One who wronged them; they are the ones who wronged their own souls.","তারা কি অপেক্ষায় আছে তাদের কাছে ফেরেশতাদের আসবার, নাকি তোমার প্রভুর বিচার এসে যাবার? তাদের পূর্ববর্তীরাও একই কাজ করেছিল। আল্লাহ সেই সত্ত্বা নন যে তাদের প্রতি অন্যায় করেছে, তারা নিজেরাই নিজেদের আত্মার প্রতি অন্যায় করেছিল।"],
  "16:34": ["They have incurred the consequences of their evil works, and the very things they ridiculed came back to haunt them.","তারা তাদের মন্দ কাজের ফলাফল অর্জন করেছে, এবং যে বিষয়গুলোকে তারা উপহাস করতো সেগুলোই উল্টো তাদের তাড়া করে বেড়িয়েছিল।"],
  "16:35": ["The idol worshipers say, \"Had Allah willed, we would not worship any idols besides Him, nor would our parents. Nor would we prohibit anything besides His prohibitions.\" Those before them have done the same. Can the messengers do anything but deliver the complete message?","প্রতিমা উপাসকরা বলে, “আল্লাহ যদি চাইতেন, আমরা তাঁর পাশে কোন অংশীদার উপাসনা করতাম না, না আমাদের পিতা-মাতারা করতো। না আমরা তাঁর নিষেধগুলোর পাশে কোনকিছু নিষেধ করতাম।\" তাদের পূর্ববর্তীরাও একই রকম করেছিল। বার্তাবাহকরা কি পূর্ণ বার্তা পৌছে দেয়া ছাড়া কিছু করতে পারে?"],
  "16:36": ["We have sent a messenger to every community, saying, \"You shall worship Allah, and avoid idolatry.\" Subsequently, some were guided by Allah, while others were committed to straying. Roam the earth and note the consequences for the rejectors.","আমরা প্রত্যেক সম্প্রদায়ের নিকট একজন বার্তাবাহক পাঠিয়েছি, এই বলে, “তোমরা আল্লাহর উপাসনা করবে, এবং অংশিবাদকে এড়িয়ে চলবে। “পরবর্তীতে, কেউ কেউ আল্লাহ দ্বারা পথপ্রাপ্ত হয়েছিল, যখন অন্যরা ছিল পথভ্রষ্টতায় লিপ্ত। ঘুড়ে বেড়াও পৃথিবীতে এবং প্রত্যাখ্যানকারীদের পরিণতি লক্ষ্য করো।"],
  "16:37": ["No matter how hard you try to guide them, Allah does not guide the ones He had committed to straying. Thus, no one can help them.","তুমি তাদের সুপথপ্রাপ্ত করার যতো চেষ্টা-ই করো না কেন, আল্লাহ তাদের সুপথপ্রাপ্ত করেন না তিনি যাদের পথভ্রষ্ট করেছেন। এরুপে, কেউ তাদের সাহায্য করতে পারে না।"],
  "16:38": ["They swore solemnly by Allah: \"Allah will not resurrect the dead.\" Absolutely, such is His inviolable promise, but most people do not know.","তারা আল্লাহর নামে দৃড় শপথ করেঃ “আল্লাহ মৃতকে পুনরুত্থিত করবেন না।\" নিঃসন্দেহে, এমনই তাঁর অলঙ্ঘনীয় অঙ্গীকার, কিন্তু অধিকাংশ লোক জানে না।"],
  "16:39": ["He will then point out to everyone all the things they had disputed, and will let those who disbelieved know that they were liars.","এরপর তিনি সবাইকে সে সবকিছু দেখাবেন যে বিষয়ে তারা বিবাদ করতো, এবং যারা অবিশ্বাস করেছিল তাদেরকে জানতে দিবেন যে তারা ছিল মিথ্যাবাদী।"],
  "16:40": ["To have anything done, we simply say to it, \"Be,\" and it is.","কোন কিছু করতে হলে, আমরা একে শুধু বলি, “হও, ”এবং তা হয়ে যায়।"],
  "16:41": ["Those who emigrated for the sake of Allah, because they were persecuted, we will surely make it up to them generously in this life, and the recompense of the Hereafter is even greater, if they only knew.","যারা আল্লাহর নিমিত্তে দেশ ত্যাগ করেছিল, কারন তারা নির্যাতিত হয়েছিল, আমরা অবশ্যই উদারভাবে এই জীবনে তাদেরকে তা পুরন করে দেব, এবং পরকালের প্রতিদান আরও অধিক, যদি তারা শুধু জানত।"],
  "16:42": ["This is because they steadfastly persevere, and in their Lord they trust.","এটা এ কারনে যে তারা অবিচলভাবে অধ্যবসায়ী, এবং তাদের প্রভুর প্রতি তারা আস্থা রাখে।"],
  "16:43": ["We did not send before you except men whom we inspired. Ask those who know the scripture, if you do not know.","আমরা তোমার আগে মানুষ ছাড়া কারো কাছে অনুপ্রেরনা পাঠাইনি। তাদের জিজ্ঞেস করো যারা ঐশীগ্রন্থ জানে, যদি তোমরা না জানো।"],
  "16:44": ["We provided them with the proofs and the scriptures. And we sent down to you this message, to proclaim for the people everything that is sent down to them, perhaps they will reflect.","আমরা তাদেরকে প্রমানাদি এবং ঐশীগ্রন্থাবলী দিয়েছিলাম। এবং আমরা তোমার কাছে এই বার্তা অবতীর্ণ করেছি, লোকদের জন্য সবকিছু ঘোষণা করতে যা তাদের কাছে অবতীর্ণ হয়, সম্ভবত তারা অনুধাবন করবে।\""],
  "16:45": ["Did those who scheme evil schemes guarantee that Allah will not cause the earth to swallow them, or that the retribution will not come to them when they least expect it?","যারা মন্দ পরিকল্পনা করেছিল তারা কি নিশ্চয়তা দিয়েছিল যে আল্লাহ পৃথিবীকে দিয়ে তাদের গ্রাস করাবেন না, অথবা শাস্তি তাদের কাছে এসে যাবে না যখন তারা খুব কমই প্রত্যাশা করে?"],
  "16:46": ["It may strike them while they are asleep; they can never escape.","এটা তাদের আঘাত করতে পারে যখন তারা ঘুমন্ত; তারা কখনো পালাতে পারবে না।"],
  "16:47": ["Or it may strike them while they are fearfully expecting it. Your Lord is Compassionate, Most Merciful.","অথবা এটা তাদের আঘাত করতে পারে যখন তারা ভয়ে ভয়ে এর প্রত্যাশা করছে। তোমাদের প্রভু করুণাময়, পরম দয়ালু।"],
  "16:48": ["Have they not seen all the things created by Allah? Their shadows surround them right and left, in total submission to Allah, and willingly.","তারা কি আল্লাহর সৃষ্ট সব কিছু দেখেনি? তাদের ছায়া তাদেরকে ঘিরে থাকে ডানে এবং বায়ে, আল্লাহর প্রতি পরিপূর্ণ সমর্পিত হয়ে, এবং সেচ্ছায়।"],
  "16:49": ["To Allah prostrates everything in the heavens and everything on earth — every creature—and so do the angels; without the least arrogance.","আল্লাহকে সেজদা করে আকাশমণ্ডলীর সবকিছু ও পৃথিবীর সবকিছু-সকল সৃষ্টি- এবং ফেরেশতারাও; সামান্যতম ঔদ্ধত্য ছাড়াই।"],
  "16:50": ["They reverence their Lord, high above them, and they do what they are commanded to do.","তারা তাদের প্রভুকে ভক্তি করে,  যিনি তাদের অনেক উপরে, এবং তারা করে যা করতে তারা আদিষ্ট হয়।"],
  "16:51": ["Allah has proclaimed: \"Do not worship two gods; there is only one god. You shall reverence Me alone.\"","আল্লাহ ঘোষণা করেছেনঃ “দুই উপাস্যের উপাসনা করো না; উপাস্য একজনই। তোমরা একমাত্র আমার উপাসনা করবে”।"],
  "16:52": ["To Him belongs everything in the heavens and the earth and therefore, the religion shall be devoted absolutely to Him alone. Would you worship other than Allah?","আকাশমণ্ডলী ও পৃথিবীর সবকিছু তাঁর এবং সেজন্য, ধর্ম সম্পূর্ণরূপে একমাত্র তাঁর প্রতি উৎসর্গকৃত হবে। তোমরা কি আল্লাহ ছাড়া অন্যকারো উপাসনা করবে?"],
  "16:53": ["Any blessing you enjoy is from Allah. Yet, whenever you incur any adversity you immediately complain to Him.","যেকোন অনুগ্রহ তোমরা উপভোগ করো তা আল্লাহর পক্ষ থেকে। এরপরও, যখনই কোন দুর্দশা তোমরা টেনে আনো সাথে সাথেই তোমরা তাঁর নিকট অভিযোগ করো।"],
  "16:54": ["Yet, as soon as He relieves your affliction, some of you revert to idol worship.","এরপরও, যখনি তিনি তোমাদের দুর্দশা দূর করেন, তোমাদের কেউ কেউ অংশীদার উপাসনায় ফিরে যায়।"],
  "16:55": ["Let them disbelieve in what we have given them. Go ahead and enjoy temporarily; you will surely find out.","আমরা তাদেরকে যা দিয়েছি তাতে তাদের অবিশ্বাস করতে দাও। চালিয়ে যাও এবং সাময়িকভাবে উপভোগ করো; নিশ্চয় তোমরা দেখবে।"],
  "16:56": ["They designate for the idols they set up out of ignorance, a share of the provisions we bestow upon them. By Allah, you will be held accountable for your innovations.","তাদের অজ্ঞতা বশত: স্থাপন করা অংশীদারদের জন্য তারা নির্ধারণ করে,  খাদ্যদ্রব্যের একটি অংশ যা আমরা তাদেরকে দিয়েছি। আল্লাহর শপথ, তোমাদের নব-উদ্ভাবনের জন্য তোমাদেরকে হিসাব দিতে হবে।"],
  "16:57": ["They even assign daughters to Allah, be He glorified, while they prefer for themselves what they like.","তারা এমনকি আল্লাহর জন্য কন্যা সন্তানদের নির্ধারণ করে, মহিমা তাঁরই, যখন তারা নিজেদের জন্য অগ্রাধিকার দেয় যা তারা পছন্দ করে।"],
  "16:58": ["When one of them gets a baby girl, his face becomes darkened with overwhelming grief.","যখন তাদের কেউ কন্যা সন্তানপ্রাপ্ত হয়, তাঁর মুখমণ্ডল দূর্বিষহ দুঃখে কালো হয়ে যায়।"],
  "16:59": ["Ashamed, he hides from the people, because of the bad news given to him. He even ponders: should he keep the baby grudgingly, or bury her in the dust. Miserable indeed is their judgment.","লজ্জায়, সে লোকদের থেকে লুকায়, তাকে দেয়া খারাপ সংবাদটির কারণে। সে এমনকি চিন্তা করে: সে কি শিশুটিকে অনিচ্ছাকৃতভাবে ধরে রাখবে, নাকি তাকে ধুলোয় পুঁতে দেবে? সত্যিই তাদের বিচার কতই না দুঃখজনক।"],
  "16:60": ["Those who do not believe in the Hereafter set the worst examples, while to Allah belongs the most sublime examples. He is the Almighty, the Most Wise.","যারা পরকালে বিশ্বাস করে না তারা নিকৃষ্ট উদাহরণ স্থাপন করে, যখন সবচেয়ে মহৎ উদাহরণ আল্লাহর। তিনি সর্বশক্তিমান, সবচেয়ে জ্ঞানী।"],
  "16:61": ["If Allah punished the people for their transgressions, He would have annihilated every creature on earth. But He respites them for a specific, predetermined time. Once their interim ends, they cannot delay it by one hour, nor advance it.","যদি আল্লাহ লোকদেরকে তাদের সীমালঙ্ঘনের জন্য শাস্তি দিতেন,  তিনি পৃথিবীর প্রত্যেক সৃষ্টি ধ্বংস করে দিতেন। কিন্তু তিনি তাদেরকে একটি নির্দিষ্ট, পূর্বনির্ধারিত সময়ের জন্য অবকাশ দেন। একবার তাদের অন্তবর্তীকাল শেষ হলে, তারা এক ঘণ্টার জন্য তা বিলম্বিত করতে পারে না, না ত্বরান্বিত করতে পারে।"],
  "16:62": ["They ascribe to Allah what they dislike for themselves, then utter the lie with their own tongues that they are righteous! Without any doubt, they have incurred Hell, for they have rebelled.","তারা আল্লাহর প্রতি আরোপ করে যা তারা নিজেদের জন্য অপছন্দ করে, এরপর তারা নিজেদের মুখে মিথ্যা উচ্চারণ করে যে তারা সৎ-কর্মী! নিঃসন্দেহে, তারা অর্জন করেছে নরক, তাদের বিদ্রোহের কারনে।"],
  "16:63": ["By Allah, we have sent (messengers) to communities before you, but the devil adorned their works in their eyes. Consequently, he is now their lord, and they have incurred a painful retribution.","আল্লাহর শপথ, তোমার পূর্বে সম্প্রদায় গুলোর কাছে আমরা (বার্তাবাহক) পাঠিয়েছি, কিন্তু শয়তান তাদের চোখে তাদের কাজকে সুসজ্জিত করে দিয়েছিল। পরিনামে, সে এখন তাদের প্রভু, এবং তারা টেনে এনেছে এক যন্ত্রণাদায়ক শাস্তি।"],
  "16:64": ["We have revealed this scripture to you, to point out for them what they dispute, and to provide guidance and mercy for people who believe.","আমরা তোমার কাছে এই ঐশীগ্রন্থ প্রকাশ করেছি, তাদেরকে দেখাতে যাতে তারা মতবিরোধ করে, এবং লোকদের জন্য পথ নির্দেশনা ও দয়া প্রদান করতে যারা বিশ্বাস করে।"],
  "16:65": ["Allah sends down from the sky water to revive the land after it had died. This should be (sufficient) proof for people who hear.","আল্লাহ ভূমিকে এর মৃত্যুর পর পুনরুজ্জীবিত করতে আকাশ থেকে পানি বর্ষণ করেন। এটি (যথেষ্ট) প্রমান হওয়া উচিত লোকদের জন্য যারা শোনে।"],
  "16:66": ["And in the livestock there is a lesson for you: we provide you with a drink from their bellies. From the midst of digested food and blood, you get pure milk, delicious for the drinkers.","এবং গৃহপালিত পশুতে তোমাদের জন্য শিক্ষা রয়েছেঃ আমরা তাদের পেট থেকে তোমাদের পানীয় সরবরাহ করিঃ পরিপাককৃত খাদ্য এবং রক্তের মধ্য থেকে, তোমরা বিশুদ্ধ দুধ পাও, পানকারীদের জন্য সুস্বাদু।"],
  "16:67": ["And from the fruits of date palms and grapes you produce intoxicants, as well as good provisions. This should be (sufficient) proof for people who understand.","এবং খেজুর গাছ ও আঙুরের ফল থেকে তোমরা মাদকদ্রব্য উৎপন্ন করো, সেই সাথে ভাল খাদ্যদ্রব্য। এটি (যথেষ্ট) প্রমান হওয়া উচিত লোকদের জন্য যারা বোঝে।"],
  "16:68": ["And your Lord inspired the bee: build homes in mountains and trees, and in (the hives) they build for you.","এবং তোমার প্রভু মৌমাছিদের অনুপ্রাণিত করলেনঃ পর্বতসমূহে ও গাছে ঘর বানাও, এবং (মৌচাকে) তারা তোমাদের জন্য তৈরি করে।"],
  "16:69": ["Then eat from all the fruits, following the design of your Lord, precisely. From their bellies comes a drink of different colors, wherein there is healing for the people. This should be (sufficient) proof for people who reflect.","এরপর সকল প্রকার ফল থেকে খাও, তোমার প্রভুর নকশা অনুসরণ করে, যথাযথভাবে। তাদের পেট থেকে বিভিন্ন রঙের পানীয় বেরিয়ে আসে, যাতে লোকদের জন্য রয়েছে রোগের প্রতিকার। এটি (যথেষ্ট) প্রমান হওয়া উচিত লোকদের জন্য যারা অনুধাবন করে।"],
  "16:70": ["Allah created you, then He terminates your lives. He lets some of you live to the oldest age, only to find out that there is a limit to the knowledge they can acquire. Allah is Omniscient, Omnipotent.","আল্লাহ তোমাদের সৃষ্টি করেছেন, এরপর তিনি তোমাদের জীবনের পরিসমাপ্তি ঘটান। তিনি তোমাদের কতককে বৃদ্ধ বয়স পর্যন্ত বাঁচিয়ে রাখেন, শুধুমাত্র দেখাতে যে তাদের জ্ঞান অর্জন করতে পারার একটি সীমা আছে। আল্লাহ সর্বজ্ঞ, সর্বশক্তিমান।"],
  "16:71": ["Allah has provided for some of you more than others. Those who are given plenty would never give their properties to their subordinates to the extent of making them partners. Would they give up Allah's blessings?","আল্লাহ তোমাদের কাউকে কাউকে অন্যদের থেকে অধিক দিয়েছেন। যাদেরকে প্রচুর দেয়া হয়েছে তারা কখনো তাদের অধিনস্তদেরকে তাদের সম্পদ এমন পরিমানে দেবে না যে তারা তাদের অংশীদার হয়ে যায়। তারা কি আল্লাহর অনুগ্রহসমূহ ত্যাগ করবে?"],
  "16:72": ["And Allah made for you spouses from among yourselves, and produced for you from your spouses children and grandchildren, and provided you with good provisions. Should they believe in falsehood, and turn unappreciative of Allah's blessings?","এবং আল্লাহ তোমাদের জন্য তোমাদের নিজেদের মধ্য থেকে সহধর্মী/সহধর্মীনি সৃষ্টি করেছেন, এবং তোমাদের সহধর্মী/সহধর্মীনি থেকে তোমাদের জন্য সন্তানাদি এবং নাতি-নাতনি সৃষ্টি করেছেন, এবং তোমাদের জন্য প্রদান করেছেন উত্তাম রিযিক। তাদের কি উচিত মিথ্যায় বিশ্বাস করা, এবং আল্লাহর অনুগ্রহসমূহে অকৃতজ্ঞ হওয়া?"],
  "16:73": ["Yet, they worship beside Allah what possesses no provisions for them in the heavens, nor on earth, nor can provide them with anything.","এরপরও, তারা আল্লাহর পাশে উপাসনা করে তার, যা না পৃথিবীতে, না আকাশমণ্ডলীতে তাদের জন্য কোন রিজিকের ব্যবস্তা করে, না তাদের কোন কিছু দিতে পারে।"],
  "16:74": ["Therefore, do not cite the examples for Allah; Allah knows while you do not know.","অতএব, আল্লাহর জন্য কোন উদাহরণ দিও না; আল্লাহ জানেন যখন তোমরা জানো না।"],
  "16:75": ["Allah cites the example of a slave who is owned, and is totally powerless, compared to one whom we blessed with good provisions, from which he gives to charity secretly and publicly. Are they equal? Praise be to Allah, most of them do not know.","আল্লাহ একজন দাসের উদাহরণ দেন যে মালিকানাধীন, এবং পুরোপুরি ক্ষমতাহীন, তার সাথে তুলনা করে যাকে আমরা ভালো জীবিকা দিয়ে সৌভাগ্যশালী করেছি, যা থেকে সে দান করে গোপনে ও প্রকাশ্যে। তারা কি সমান? প্রশংসা আল্লাহর, তাদের অধিকাংশ জানে না।"],
  "16:76": ["And Allah cites the example of two men: one is dumb, lacks the ability to do anything, is totally dependent on his master—whichever way he directs him, he cannot produce anything good. Is he equal to one who rules with justice, and is guided in the right path?","এবং আল্লাহ উদাহরণ দেন দুজন মানুষেরঃ একজন নির্বোধ, কোনকিছু করতে সক্ষম নয়, পুরোপুরি তার মালিকের উপর নির্ভরশীল- যে পথেই সে তাকে নির্দেশ দেয়, সে ভাল কিছু করতে পারে না। সে কি তার সমান যে ন্যায়পরায়নতার সাথে শাসন করে, এবং সঠিক পথপ্রাপ্ত?"],
  "16:77": ["To Allah belongs the future of the heavens and the earth. As far as He is concerned, the end of the world (the Hour) is a blink of an eye away, or even closer. Allah is Omnipotent.","আকাশমণ্ডলী ও পৃথিবীর ভবিষ্যত আল্লাহর অধীন। যে পর্যন্ত তিনি সম্পর্কিত, বিশ্বের পরিসমাপ্তি (সেই ঘণ্টা) তো চোখের এক পলক দূরে, অথবা আরও কাছে। আল্লাহ সর্বশক্তিমান।"],
  "16:78": ["Allah brought you out of your mothers' bellies knowing nothing, and He gave you the hearing, the eyesight, and the brains, that you may be appreciative.","আল্লাহ মায়ের পেট থেকে তোমাদের বের করেন যখন কিছুই জানতে না, এবং তিনি তোমাদেরকে দিয়েছেন শ্রবণ শক্তি,  দৃষ্টি শক্তি, এবং মস্তিষ্ক, যাতে তোমরা কৃতজ্ঞ হও।"],
  "16:79": ["Do they not see the birds committed to fly in the atmosphere of the sky? None holds them up in the air except Allah. This should be (sufficient) proof for people who believe.","তারা কি আকাশের বায়ুমণ্ডলে পাখিদের উড়তে দেখে না? আল্লাহ ছাড়া কেউ এদেরকে ঊর্ধ্বে বাতাসে ধরে রাখে না। এটি লোকদের জন্য (যথেষ্ট) প্রমান হওয়া উচিত যারা বিশ্বাস করে।"],
  "16:80": ["And Allah provided for you stationary homes where you can live. And He provided for you portable homes made of the hides of livestock, so you can use them when you travel, and when you settle down. And from their wools, furs, and hair, you make furnishings and luxuries for awhile.","এবং আল্লাহ তোমাদের জন্য দিয়েছেন স্থির ঘর-বাড়ি যেখানে তোমরা বাস করতে পারো। এবং তিনি তোমাদের জন্য দিয়েছেন গবাদিপশুর চামড়া থেকে তৈরি বহনযোগ্য ঘর-বাড়ি, যেন তোমরা সেগুলো ব্যবহার করতে পারো যখন তোমরা ভ্রমন করো, এবং যখন তোমরা অবস্থান নাও। এবং সেগুলোর পশম, লোমশ চামড়া এবং চুল থেকে তোমরা তৈরি করো আসবাবপত্র এবং বিলাসদ্রব্য, কিছুকালের জন্য।"],
  "16:81": ["And Allah provided for you shade through things which He created, and provided for you shelters in the mountains, and provided for you garments that protect you from heat, and garments that protect when you fight in wars. He thus perfects His blessings upon you, that you may submit.","এবং আল্লাহ তোমাদের জন্য তার সৃষ্ট জিনিসের মাধ্যমে ছায়া দিয়েছেন, এবং তোমাদের জন্য আশ্রয় দিয়েছেন পর্বতে, এবং তোমাদের জন্য পোশাক দিয়েছে্ন যা তোমাদের তাপ থেকে রক্ষা করে, এবং পোশাক যা তোমাদের রক্ষা করে যখন তোমরা যুদ্ধে লড়াই করো। তিনি এভাবে তোমাদের প্রতি তাঁর অনুগ্রহ পূর্ণ করেন।"],
  "16:82": ["If they still turn away, then your sole mission is the clear delivery (of the message).","যদি তারা এরপরও মুখ ফিরিয়ে নেয়, তবে তোমার একমাত্র কাজ শুধু (বার্তা) পৌঁছে দেয়া।"],
  "16:83": ["They fully recognize Allah's blessings, then deny them; the majority of them are disbelievers.","তারা আল্লাহর অনুগ্রহগুলো সম্পূর্ণ রুপে চেনে, এরপর সেগুলো অস্বীকার করে; তাদের অধিকাংশ অবিশ্বাসী।"],
  "16:84": ["The day will come when we raise from every community a witness, then those who disbelieved will not be permitted (to speak), nor will they be excused.","সে দিন আসবে যখন আমি প্রত্যেক সম্প্রদায় থেকে একজন সাক্ষী উঠাবো, তখন যারা অবিশ্বাস করতো তারা (কথা বলার) অনুমতি পাবে না, না তারা ক্ষমা পাবে।"],
  "16:85": ["Once those who transgressed see the retribution, it will be too late; it will not be commuted for them, nor will they be respited.","যারা অবিশ্বাস করেছিল তারা একবার যখন শাস্তি দেখবে, তা খুব দেরি হয়ে যাবে; এটা তাদের জন্য কমানো হবে না, না তারা অবকাশ পাবে।"],
  "16:86": ["And when those who committed idol worship see their idols, they will say, \"Our Lord, these are the idols we had set up beside You.\" The idols will then confront them and say, \"You are liars.\"","এবং যারা অংশীদার উপাসনা করত ওরা যখন তাদের উপাস্যদের দেখবে, তারা বলবে, “আমাদের প্রভু, এরাই সেই উপাস্যরা যাদের আমরা আপনার পাশে স্থাপন করেছিলাম”। উপাস্যরা তখন তাদের মুখমুখি হবে এবং বলবে, “তোমরা মিথ্যাবাদী”।"],
  "16:87": ["They will totally submit to Allah on that day, and the idols they had invented will disown them.","তারা সে দিন সম্পূর্ণরুপে আল্লাহর কাছে আত্মসমর্পণ করবে, এবং যে উপাস্যদের তারা উদ্ভাবন করেছিল তারা তাদের প্রত্যাখ্যান করবে।"],
  "16:88": ["Those who disbelieve and repel from the path of Allah, we augment their retribution by adding more retribution, due to their transgressions.","যারা অবিশ্বাস করে এবং আল্লাহর পথে বাধা দেয়, আমরা আরও শাস্তি যোগ করে তাদের শাস্তি বাড়িয়ে দেই, তাদের সীমালঙ্ঘনের কারনে।"],
  "16:89": ["The day will come when we will raise from every community a witness from among them, and bring you as the witness of these people. We have revealed to you this book to provide explanations for everything, and guidance, and mercy, and good news for the submitters.","সে দিন আসবে যখন আমরা প্রত্যেক সম্প্রদায় থেকে একজন সাক্ষী উঠাব তাদেরই মধ্য থেকে, এবং তোমাকে আনব এই লোকদের সাক্ষী হিসাবে। আমরা তোমার কাছে এই গ্রন্থ প্রকাশ করেছি আত্মসমর্পণকারীদের জন্য প্রদান করতে সবকিছুর ব্যাখ্যা, এবং পথ নির্দেশনা, এবং দয়া, এবং সুসংবাদ।"],
  "16:90": ["Allah advocates justice, charity, and regarding the relatives. And He forbids evil, vice, and transgression. He enlightens you, that you may take heed.","আল্লাহ উপদেশ দেন ন্যায়পরায়ণতা, দান, এবং আত্মীয়স্বজনদের প্রতি দৃষ্টি দেয়ার। এবং নিষেধ করেন মন্দ, অনৈতিকতা, এবং সীমালঙ্ঘন। তিনি তোমাদের জ্ঞান দান করেন, যাতে তোমরা সতর্ক হও।"],
  "16:91": ["You shall fulfill your covenant with Allah when you make such a covenant. You shall not violate the oaths after swearing (by Allah) to carry them out, for you have made Allah a guarantor for you. Allah knows everything you do.","তোমরা আল্লাহর সাথে তোমাদের চুক্তি পূর্ণ করবে যখন তোমরা এমন কোন চুক্তি করো। তোমরা প্রতিজ্ঞা ভঙ্গ করবে না আল্লাহর নামে সেগুলো পালনের শপথ করার পর, কারন তোমরা আল্লাহকে তোমাদের জামিনদার করেছ। আল্লাহ জানেন সবকিছু যা তোমরা করো।"],
  "16:92": ["Do not be like the knitter who unravels her strong knitting into piles of flimsy yarn. This is your example if you abuse the oaths to take advantage of one another. Whether one group is larger than the other, Allah thus puts you to the test. He will surely show you on the Day of Resurrection everything you had disputed.","সেই বুননকারিণী শিল্পীর মতো হয়ো না যে তার মজবুত বুননের পাঁক খুলে তুচ্ছ সুতার স্তুপে পরিনত করে। এটাই তোমাদের উদাহরণ যদি তোমরা একে অপরের কাছ থেকে সুযোগ নিতে তোমাদের প্রতিজ্ঞার অপব্যবহার করো। এক দল অন্য দলের চেয়ে বড় হোক বা না হোক, আল্লাহ এভাবে তোমাদের পরীক্ষা করেন। তিনি নিশ্চয় পুনরুত্থান দিনে তোমাদের দেখাবেন সে সবকিছু যাতে তোমরা বিবাদ করেছিলে।"],
  "16:93": ["Had Allah willed, He could have made you one congregation. But He sends astray whoever chooses to go astray, and He guides whoever wishes to be guided. You will surely be asked about everything you have done.","আল্লাহ যদি চাইতেন, তিনি তোমাদের এক  ধর্মগোষ্ঠী করতে পারতেন। কিন্তু তিনি পথভ্রষ্ট করেন যেকেউ বিপথে যেতে পছন্দ করে, এবং তিনি পথপ্রদর্শন করেন যেকেউ সুপথপ্রাপ্ত হতে চায়। তোমাদের অবশ্যই প্রশ্ন করা হবে সে সব কিছু সম্পর্কে যা তোমরা করেছ।"],
  "16:94": ["Do not abuse the oaths among you, lest you slide back after having a strong foothold, then you incur misery. Such is the consequence of repelling from the path of Allah (by setting a bad example); you incur a terrible retribution.","তোমাদের মধ্যকার প্রতিজ্ঞার অপব্যবহার করো না, পাছে তোমরা পিছলে যাও সুদৃড় অবস্থান পাবার পর, এরপর তোমরা দুর্দশা টেনে আনো। এমনি পরিণাম আল্লাহর পথে বাঁধা দেবার (মন্দ উদাহরন স্থাপনের জন্য); তোমরা এক ভয়ানক শাস্তি টেনে আনো।"],
  "16:95": ["Do not sell your oaths before Allah short. What Allah possesses is far better for you, if you only knew.","অল্পতেই আল্লাহর সামনে তোমাদের করা প্রতিজ্ঞা বিকিয়ে দিয়না। আল্লাহর কাছে তোমাদের জন্য যা আছে তা অনেক উত্তম, যদি শুধু তোমরা জানতে।"],
  "16:96": ["What you possess runs out, but what Allah possesses lasts forever. We will surely reward those who steadfastly persevere; we will recompense them for their righteous works.","যা তোমাদের কাছে আছে তা শেষ হয়ে যায়, কিন্তু আল্লাহর কাছে যা আছে তা চিরকাল রয়ে যায়। আমরা অবশ্যই তাদের পুরস্কৃত করবো যারা অবিচলভাবে অটল; আমরা তাদের প্রতিদান দেব তাদের সৎ কর্মের জন্য।"],
  "16:97": ["Anyone who works righteousness, male or female, while believing, we will surely grant them a happy life in this world, and we will surely pay them their full recompense (on the Day of Judgment) for their righteous works.","যেকেউ সৎকর্ম করে, পুরুষ হোক বা নারী, বিশ্বাসী অবস্থায়, আমরা অবশ্যই তাদেরকে এই দুনিয়ায় একটি সুখী জীবন দেব, এবং (পুনরুত্থান দিনে)  আমরা অবশ্যই তাদের সৎকর্মের জন্য পূর্ণ প্রতিদান পরিশোধ করবো।"],
  "16:98": ["When you read the Quran, you shall seek refuge in Allah from Satan the rejected.","যখন তুমি কুরআন পড়ো, তুমি আল্লাহর কাছে আশ্রয় প্রার্থনা করবে বিতাড়িত শয়তান থেকে।"],
  "16:99": ["He has no power over those who believe and trust in their Lord.","তার কোনও শক্তি নাই ওদের উপর যারা বিশ্বাস করে এবং তাদের প্রভুর প্রতি আস্থা রাখে।"],
  "16:100": ["His power is limited to those who choose him as their master; those who choose him as their god.","তার ক্ষমতা ওদের উপর সীমাবদ্ধ যারা তাকে তাদের মনিব হিসেবে পছন্দ করে, যারা তাকে পছন্দ করে তাদের উপাস্য হিসাবে।"],
  "16:101": ["When we substitute one revelation in place of another, and Allah is fully aware of what He reveals, they say, \"You made this up!\" Indeed, most of them do not know.","যখন আমরা কোন প্রকাশনাকে আরেকটির জায়গায় প্রতিস্থাপন করি, এবং আল্লাহ পূর্ণ অবগত যা তিনি প্রকাশ করেন, তারা বলে, “এটি তুমি রচনা করেছ!”প্রকৃতপক্ষে, তাদের বেশির ভাগ জানে না।"],
  "16:102": ["Say, \"The Holy Spirit has brought it down from your Lord, truthfully, to assure those who believe, and to provide a beacon and good news for the submitters.\"","বল, “পবিত্র রূহ তোমার প্রভুর পক্ষ থেকে এটি অবতীর্ন করেছে, সত্যের সাথে, তাদের আশস্ত করতে যারা বিশ্বাস করে, এবং আত্মসমর্পণকারীদের জন্য আলোকবর্তিকা ও সুসংবাদ দিতে।"],
  "16:103": ["We are fully aware that they say, \"A human being is teaching him!\" The tongue of the source they hint at is non-Arabic, and this is a perfect Arabic tongue.","আমরা সম্পূর্ণ অবগত যে তারা বলে, “একজন মানুষ তাকে শিক্ষা দিচ্ছে!” তাদের ইঙ্গিত করা উৎসের ভাষা আরবি নয়, এবং এটি নিখুঁত আরবি ভাষা।"],
  "16:104": ["Surely, those who do not believe in Allah's revelations, Allah does not guide them. They have incurred a painful retribution.","নিশ্চয়, যারা আল্লাহর প্রকাশনায় বিশ্বাস করে না, আল্লাহ তাদের সুপথপ্রাপ্ত করেন না। তারা টেনে এনেছে এক যন্ত্রণাদায়ক শাস্তি।"],
  "16:105": ["The only ones who fabricate false doctrines are those who do not believe in Allah's revelations; they are the real liars.","তারাই কেবল মিথ্যা মতবাদ বানায় যারা আল্লাহর প্রকাশনাবলিতে বিশ্বাস করে না। তারাই আসল মিথ্যাবাদী।"],
  "16:106": ["Those who disbelieve in Allah, after having acquired faith, and become fully content with disbelief, have incurred wrath from Allah. The only ones to be excused are those who are forced to profess disbelief, while their hearts are full of faith.","যারা আল্লাহতে অবিশ্বাস করে, বিশ্বাস অর্জন করার পর, এবং অবিশ্বাসে পূর্ণ সন্তুষ্ট হয়ে যায়, তারা আল্লাহর অভিশাপ অর্জন করেছে। কেবল তারাই ক্ষমা পেতে পারে অবিশ্বাস স্বীকার করার জন্য যাদের উপর বল প্রয়োগ করা হয়, যখন তাদের হৃদয় বিশ্বাসে পূর্ণ।"],
  "16:107": ["This is because they have given priority to this life over the Hereafter, and Allah does not guide such disbelieving people.","এর কারন এই যে তারা এই জীবনকে পরকালের উপর প্রাধান্য দিয়েছে, এবং আল্লাহ এমন অবিশ্বাসী লোকদের পথপ্রদর্শণ করেন না।"],
  "16:108": ["Those are the ones whom Allah has sealed their hearts, and their hearing, and their eyesight. Consequently, they remain unaware.","এরাই তারা যাদের হৃদয়ে, এবং যাদের শ্রবণশক্তিতে, এবং যাদের দৃষ্টিশক্তিতে আল্লাহ মোহর মেরে দিয়েছেন। ফলস্বরূপ, তারা অসচেতন থাকে।"],
  "16:109": ["Without a doubt, they will be the losers in the Hereafter.","কোন সন্দেহ নেই, তারা পরকালে ক্ষতিগ্রস্ত হবে।"],
  "16:110": ["As for those who emigrate because of persecution, then continue to strive and steadfastly persevere, your Lord, because of all this, is Forgiver, Most Merciful.","ওদের ক্ষেত্রে যারা নিপীড়নের কারনে দেশ ত্যাগ করে, এরপর সংগ্রাম চালিয়ে যায় এবং অবিচলতার সাথে অটল থাকে, তোমরা প্রভু, এই সবের কারনে, ক্ষমাশীল, পরম দয়ালু।"],
  "16:111": ["The day will come when every soul will serve as its own advocate, and every soul will be paid fully for whatever it had done, without the least injustice.","সে দিন আসবে যখন প্রত্যেক আত্মা এর নিজের উকিল হিসেবে দায়িত্ব পালন করবে। এবং প্রত্যেক আত্মা পুরোপুরি মূল্য পাবে যা কিছু সে করেছে, সমান্যতম অবিচার ছাড়া।"],
  "16:112": ["Allah cites the example of a community that used to be secure and prosperous, with provisions coming to it from everywhere. But then, it turned unappreciative of Allah's blessings. Consequently, Allah caused them to taste the hardships of starvation and insecurity. Such is the requital for what they did.","আল্লাহ একটি জনপদের উদাহরণ দেন যা ছিল নিরাপদ ও সমৃদ্ধশালী, সেখানে সব জায়গা থেকে খাদ্যসম্ভার আসতো। কিন্তু এরপর, তা আল্লাহর অনুগ্রহের প্রতি অকৃতজ্ঞ হয়ে পড়লো। পরিনামে, আল্লাহ তাদেরকে অনাহার ও নিরাপত্তাহীনতার কষ্ট আস্বাদন করালেন। এমনই হচ্ছে তাদের কৃতকর্মের প্রতিদান।"],
  "16:113": ["A messenger had gone to them from among them, but they rejected him. Consequently, the retribution struck them for their transgression.","তাদের মধ্য থেকে একজন বার্তাবাহক তাদের কাছে গিয়েছিল, কিন্তু তারা তাকে প্রত্যাখ্যান করলো। ফলস্বরূপ, তাদের সীমালঙ্ঘনের জন্য শাস্তি তাদের আঘাত করেছিল।"],
  "16:114": ["Therefore, you shall eat from Allah's provisions everything that is lawful and good, and be appreciative of Allah's blessings, if you do worship Him alone.","অতএব, তোমরা আল্লাহর দেয়া সব খাদ্যসামগ্রী থেকে খাবে যা আইনসিদ্ধ ও ভালো, এবং আল্লাহর অনুগ্রহের প্রতি কৃতজ্ঞ হও, যদি তোমরা কেবল তাঁরই উপাসনা করো।"],
  "16:115": ["He only prohibits for you dead animals, blood, the meat of pigs, and food which is dedicated to other than Allah. If one is forced (to eat these), without being deliberate or malicious, then Allah is Forgiver, Most Merciful.","তিনি শুধু তোমাদের জন্য নিষিদ্ধ করেন মৃত পশু, রক্ত, শূকরের মাংস, এবং যে খাদ্য আল্লাহ ছাড়া অন্য কারো প্রতি উৎসর্গ করা হয়। যদি কেউ (এগুলো খেতে) বাধ্য  হয়, ইচ্ছাকৃত বা বিদ্রোহী না হয়ে, তবে আল্লাহ ক্ষমাশীল, পরম করুণাময়।"],
  "16:116": ["You shall not utter lies with your own tongues stating: \"This is lawful, and this is unlawful,\" to fabricate lies and attribute them to Allah. Surely, those who fabricate lies and attribute them to Allah will never succeed.","তোমাদের নিজ মুখে তোমরা মিথ্যা বলবে না এ বলে যেঃ “এটা আইনসম্মত, এবং এটা বেআইনী,” মিথ্যা বানাতে এবং তা আল্লাহর প্রতি আরোপ করতে। নিশ্চয়, যারা মিথ্যা বানায় এবং তা আল্লাহর প্রতি আরোপ করে তারা কখনো সফল হবে না।"],
  "16:117": ["They enjoy briefly, then suffer painful retribution.","তারা সাময়িক উপভোগ করে, এরপর ভোগ করে যন্ত্রণাদায়ক শাস্তি।"],
  "16:118": ["For the Jews, we prohibited what we narrated to you previously. It was not us who wronged them; they are the ones who wronged their own souls.","ইহুদীদের জন্য, আমরা নিষিদ্ধ করেছিলাম পূর্বে যা তোমার কাছে আমরা বর্ণনা করেছি। তাদের ক্ষতি আমাদের দ্বারা হয়নি; তারাই তাদের নিজ আত্মার ক্ষতি করেছিল।"],
  "16:119": ["Yet, as regards those who fall in sin out of ignorance then repent thereafter and reform, your Lord, after this is done, is Forgiver, Most Merciful.","তা সত্ত্বেও, তাদের ক্ষেত্রে যারা অজ্ঞতাবশত পাপে পতিত হয় এরপর অনুশোচনা করে ও সংশোধিত হয়, তোমার পালনকর্তা, এসবের পর, ক্ষমাশীল, পরম দয়ালু।"],
  "16:120": ["Abraham was indeed an exemplary vanguard in his submission to Allah, a monotheist who never worshiped idols.","ইব্রাহীম নিশ্চয়ই আল্লাহর কাছে তার আত্মসমর্পণে ছিল এক দৃষ্টান্তস্থাপনকারী অগ্রদূত, একজন একেশ্বরবাদী যে কখনও অংশীদার উপাসনা করেনি।"],
  "16:121": ["Because he was appreciative of His Lord's blessings, He chose him and guided him in a straight path.","যেহেতু সে তার প্রভুর অনুগ্রহের প্রতি কৃতজ্ঞ ছিল, তিনি তাকে পছন্দ করেছিলেন এবং তাকে পরিচালিত করেছিলেন এক সরল পথে।"],
  "16:122": ["We granted him happiness in this life, and in the Hereafter he will be with the righteous.","এই জীবনে আমরা তাকে সুখ দান করেছিলাম, এবং পরকালে সে সৎকর্মশীলদের সাথে থাকবে।"],
  "16:123": ["Then we inspired you (Muhammad) to follow the religion of Abraham, the monotheist; he never was an idol worshiper.","এরপর (হে মুহাম্মদ) তোমাকে আমরা ইব্রাহীমের ধর্ম অনুসরণ করতে অনুপ্রাণিত করেছিলাম, একেশ্বরবাদী, সে কখনও প্রতিমা উপাসক ছিল না।"],
  "16:124": ["The Sabbath was decreed only for those who ended up disputing it (Jews & Christians). Your Lord is the One who will judge them on the Day of Resurrection regarding their disputes.","সাব্বাত শুধু ওদের জন্য আদেশ করা হয়েছিল, শেষ পর্যন্ত যারা (ইহুদী এবং খ্রিষ্টানরা) এটাকে বিতর্কিত করেছিল। তোমার প্রভুই সেই সত্ত্বা যিনি পুনরুত্থান দিনে তাদের বিতর্কের বিষয়ে তাদের বিচার করবেন।"],
  "16:125": ["You shall invite to the path of your Lord with wisdom and kind enlightenment, and debate with them in the best possible manner. Your Lord knows best who has strayed from His path, and He knows best who are the guided ones.","তুমি তোমার প্রভুর পথে প্রজ্ঞা ও সদয় জ্ঞানালোক দিয়ে আমন্ত্রন করবে, এবং তাদের সাথে বিতর্ক করবে সম্ভাব্য সর্বোত্তম পন্থায়। তোমার প্রভু সবথেকে ভালো জানেন কে তার পথ থেকে বিচ্যুত হয়েছে, এবং তিনি সবথেকে ভালো জানেন কারা সুপথপ্রাপ্ত।"],
  "16:126": ["And if you punish, you shall inflict an equivalent punishment. But if you resort to patience (instead of revenge), it would be better for the patient ones.","এবং যদি তোমরা শাস্তি দাও, তোমরা সমতুল্য শাস্তি আরোপ করবে। কিন্তু যদি তোমরা ধৈর্য ধারন করো, এটি উত্তম হবে ধৈর্যশীলদের জন্য।"],
  "16:127": ["You shall resort to patience—and your patience is attainable only with Allah's help. Do not grieve over them, and do not be annoyed by their schemes.","তুমি ধৈর্য ধারন করবে-এবং একমাত্র আল্লাহর সাহায্য দিয়ে তোমার  ধৈর্য ধারন সম্ভব। তাদের জন্য পরিতাপ করো না, এবং তাদের চক্রান্তে বিরক্ত হইও না।"],
  "16:128": ["Allah is with those who lead a righteous life, and those who are charitable.","আল্লাহ তাদের সাথে আছেন যারা সৎ জীবন-যাপন করে, এবং যারা দানশীল।"],
  "17:1": ["Most glorified is the One who summoned His servant (Muhammad) during the night, from the Sacred Masjid (of Mecca) to the farthest place of prostration, whose surroundings we have blessed, in order to show him some of our signs. He is the Hearer, the Seer.","সর্বাধিক মহিমান্বিত সেই সত্ত্বা যিনি তাঁর বান্দা (মুহাম্মদ)-কে রাতের বেলায় তলব করেছিলেন, পবিত্র মসজিদ (মক্কা) থেকে সেজদার সবচেয়ে দূরতম স্থানে , যার চারপাশকে আমরা বরকতময় করেছি, তাকে আমাদের কিছু নিদর্শন দেখানোর জন্য। তিনি শ্রবণকারী, দর্শনকারী।"],
  "17:2": ["Similarly, we gave Moses the scripture, and rendered it a beacon for the Children of Israel that: \"You shall not set up any idol as a Lord and Master beside Me.\"","একইভাবে, আমরা মুসাকে ঐশীগ্রন্থ দিয়েছিলাম, এবং একে ইসরাইলের সন্তানদের জন্য একটি আলোকবর্তিকা করেছিলাম যেঃ “প্রভু এবং মনিব হিসাবে তোমরা আমার পাশে কোন অংশীদার স্থাপন করবে না”।"],
  "17:3": ["They are descendants of those whom we carried with Noah; he was an appreciative servant.","তারা ছিল তাদের বংশধর যাদেরকে আমরা নুহের সাথে বহন করেছিলাম; সে ছিল একজন কৃতজ্ঞ বান্দা।"],
  "17:4": ["We addressed the Children of Israel in the scripture: \"You will commit gross evil on earth, twice. You are destined to fall into great heights of arrogance.","আমরা ঐশীগ্রন্থে ইসরাইলের সন্তানদের উদ্দেশ্যে বলেছিলামঃ “তোমরা পৃথিবীতে ঘোর পাপে লিপ্ত হবে, দু'বার। ঔদ্ধত্যের চরম শিখরে উন্নীত হওয়া হচ্ছে তোমাদের নিয়তি।"],
  "17:5": ["\"When the first time comes to pass, we will send against you servants of ours who possess great might, and they will invade your homes. This is a prophecy that must come to pass.","“প্রথমবার যখন আসে, আমরা তোমাদের বিরুদ্ধে আমাদের বান্দাদের পাঠাবো যারা বিশাল শক্তির অধিকারী, এবং তারা তোমাদের ঘরে হানা দিবে। এটি একটি ভবিষ্যদ্বানী যা অবশ্যই ঘটবে।"],
  "17:6": ["\"Afterwards, we will give you a turn over them, and will supply you with a lot of wealth and children; we will give you the upper hand.","“পরবর্তীকালে, আমরা তাদের উপর তোমাদের পালা ঘুরিয়ে দেবো, এবং তোমাদের প্রচুর সম্পদ ও সন্তান দেবো; আমরা তোমাদের কর্তৃত্ব দেবো।"],
  "17:7": ["\"If you work righteousness, you work righteousness for your own good, but if you commit evil you do so to your own detriment. Thus, when the second time comes to pass, they will defeat you and enter the mosque (masjid), just as they did the first time. They will wipe out all the gains you had accomplished.\"","“যদি তোমরা সৎ-কর্ম করো, তোমরা সৎ-কর্ম করো নিজেদের ভালোর জন্যই, কিন্তু যদি তোমরা মন্দ-কর্ম করো তা নিজেদের ক্ষতির জন্যই করো।  সুতরাং, যখন দ্বিতীয ক্ষনটি আসে, তারা তোমাদের পরাজিত করবে এবং মসজিদে ঢুকবে, ঠিক যেরকম তারা প্রথমবার করেছিল। তারা তোমাদের সম্পন্ন করা সকল অর্জন মুছে ফেলবে।"],
  "17:8": ["Your Lord showers you with His mercy. But if you revert to transgression, we will counter with retribution. We have designated Gehenna as a final abode for the disbelievers.","তোমাদের প্রভু তোমাদের প্রতি তাঁর দয়া বর্ষণ করেন। কিন্তু যদি তোমরা সীমালঙ্ঘনে ফিরে যাও, আমরা বিপরীতে শাস্তি দেবো। আমরা জাহান্নামকে অবিশ্বাসীদের জন্য চূড়ান্ত বাসস্থান হিসাবে নির্ধারণ করেছি।"],
  "17:9": ["This Quran guides to the best path, and brings good news to the believers who lead a righteous life, that they have deserved a great recompense.","এই কুরআন সর্বোত্তম পথ প্রদর্শন করে, এবং সুসংবাদ নিয়ে আসে বিশ্বাসীদের কাছে যারা সৎ-জীবন যাপন করে, যে তারা এক মহা পুরস্কারের যোগ্য হয়েছে।"],
  "17:10": ["As for those who disbelieve in the Hereafter, we have prepared for them a painful retribution.","আর তাদের ক্ষেত্রে যারা পরকালে অবিশ্বাস করে, আমরা তাদের জন্য এক যন্ত্রণাদায়ক শাস্তি প্রস্তুত রেখেছি।"],
  "17:11": ["The human being often prays for something that may hurt him, thinking that he is praying for something good. The human being is impatient.","মানুষ প্রায়ই প্রার্থনা করে এমন কিছুর জন্য যা হয়তো তাকে কষ্ট দিবে, এই ভেবে যে সে ভালো কিছু প্রার্থনা করছে। মানুষ ধৈর্যহীন।"],
  "17:12": ["We rendered the night and the day two signs. We made the night dark, and the day lighted, that you may seek provisions from your Lord therein. This also establishes for you a timing system, and the means of calculation. We thus explain everything in detail.","রাত ও দিনকে আমরা দু'টি নিদর্শন হিসেবে উপস্থাপন করেছি। রাতকে আমরা করেছি অন্ধকার, এবং দিনকে আলোকিত, যাতে তোমরা তাতে তোমাদের প্রভুর কাছ থেকে রিজিক অন্বেষণ করতে পারো। এটি তোমাদের জন্য একটি সময় নির্ধারণ পদ্ধতিও প্রতিষ্ঠা করে, এবং হিসাবের উপায়। আমরা এভাবে সবকিছু বিস্তারিত ব্যখ্যা করি।"],
  "17:13": ["We have recorded the fate of every human being; it is tied to his neck. On the Day of Resurrection we will hand him a record that is accessible.","আমরা প্রত্যেক মানুষের ভাগ্য রেকর্ড করেছি; এটি তার গলায় আটকানো। পুনরুত্থান দিনে আমরা তার হাতে একটি রেকর্ড দেবো যা দেখা যায়।"],
  "17:14": ["Read your own record. Today, you suffice as your own reckoner.","পড়ো তোমার নিজের রেকর্ড। আজ, তুমি নিজেই নিজের হিসাবনিকাশের জন্য যথেষ্ট।"],
  "17:15": ["Whoever is guided, is guided for his own good, and whoever goes astray does so to his own detriment. No sinner will bear the sins of anyone else. We never punish without first sending a messenger.","যেকেউ সুপথপ্রাপ্ত, তার নিজের ভালোর জন্যই সুপথপ্রাপ্ত, এবং যেকেউ বিপথে যায় তার নিজের ক্ষতির জন্যই যায়। কোন পাপী অন্য কারো পাপ বহন করবে না। আমরা কখনোই শাস্তি দেই না আগে কোন বার্তাবাহক না পাঠিয়ে।"],
  "17:16": ["If we are to annihilate any community, we let the leaders commit vast corruption therein. Once they deserve retribution, we annihilate it completely.","যদি আমাদেরকে কোন সম্প্রদায় ধ্বংস করতে হয়, সেখানে আমরা নেতাদের ব্যাপক দুর্নীতি করতে দেই। যখনই তারা শাস্তির যোগ্য হয়, আমরা একে পুরোপুরি ধ্বংস করি।"],
  "17:17": ["Many a generation have we annihilated after Noah. Your Lord is most efficient in dealing with the sins of His servants; He is fully Cognizant, Seer.","নুহের পর আমরা অনেক প্রজন্ম ধ্বংস করেছি। তোমার প্রভু তাঁর বান্দাদের পাপের বোঝাপড়ায় সবচেয়ে দক্ষ। তিনি পূর্ণ জ্ঞাত, দ্রষ্টা।"],
  "17:18": ["Anyone who chooses this fleeting life as his priority, we will rush to him what we decide to give him, then we commit him to Gehenna, where he suffers forever, despised and defeated.","যেকেউ এই ক্ষণস্থায়ী জীবনকে তার অগ্রাধিকার হিসাবে পছন্দ করে, আমরা তাকে দ্রুত দিয়ে দেবো যা আমরা তাকে দেয়ার সিদ্ধান্ত নেই, এরপর আমরা তাকে জাহান্নামে ছেড়ে দেবো, যেখানে সে চিরকাল যন্ত্রণা ভোগ করে, ঘৃণিত ও পরাজিত হয়ে।"],
  "17:19": ["As for those who choose the Hereafter as their priority, and work righteousness, while believing, their efforts will be appreciated.","তাদের ক্ষেত্রে যারা পরকালকে তাদের অগ্রাধিকার হিসাবে পছন্দ করে, এবং সৎকর্ম করে, বিশ্বাসী অবস্থায়, তাদের প্রচেষ্টার সমাদর করা হবে।"],
  "17:20": ["For each one of them we provide; we provide those and these from your Lord's bounties. Your Lord's bounties are inexhaustible.","আমরা তাদের প্রত্যেককে প্রদান করি; আমরা প্রদান করি ওদেরকে এবং এদেরকে তোমার প্রভুর  উদার দান থেকে। তোমার প্রভুর উদার দানশীলতা অফুরন্ত।"],
  "17:21": ["Note how we preferred some people above others (in this life). The differences in the Hereafter are far greater and far more significant.","লক্ষ্য করো কেমন করে (এই দুনিয়াতে) কিছু লোককে আমরা অন্য লোকদের চেয়ে পছন্দ করি। পরকালে এই পার্থক্য অনেক বিশাল এবং অনেক বেশি তাৎপর্য পূর্ণ।"],
  "17:22": ["You shall not set up any other god beside Allah, lest you end up despised and disgraced.","তোমরা আল্লাহর পাশে অন্য কোন উপাস্য স্থাপন করবে না, পাছে তোমরা ঘৃণিত এবং অপদস্থ হয়ে পড়ো।"],
  "17:23": ["Your Lord has decreed that you shall not worship except Him, and your parents shall be honored. As long as one or both of them live, you shall never say to them, \"Uff\" (the slightest gesture of annoyance), nor shall you shout at them; you shall treat them amicably.","তোমার প্রভু হুকুম জারি করেছেন যে তোমরা তাকে ব্যতিত কারো উপাসনা করবে না, এবং তোমাদের পিতা-মাতার সম্মান করবে। যতকাল তাদের একজন বা উভয়জন বেঁচে থাকে, তোমরা কখনো তাদেরকে (বিরক্তির নূন্যতম প্রকাশ)  ‘উহ’ শব্দটি বলবে না, না তোমরা তাদের সাথে চিৎকার-চেঁচামেচি করবে; তোমরা তাদের সাথে অমায়িক আচরণ করবে।"],
  "17:24": ["And lower for them the wings of humility, and kindness, and say, \"My Lord, have mercy on them, for they have raised me from infancy.\"","এবং তাদের জন্য বিনয়, এবং দয়ার বাহু বাড়িয়ে দাও, এবং বল, “আমার প্রভু, তাদের প্রতি দয়া করুন, কারন তারা আমাকে শৈশব থেকে লালন-পালন করেছেন”।"],
  "17:25": ["Your Lord is fully aware of your innermost thoughts. If you maintain righteousness, He is Forgiver of those who repent.","তোমাদের প্রভু তোমাদের গভীরতম  চিন্তাগুলো সম্পর্কে পূর্ণ অবগত। যদি তোমরা সততা বজায় রাখো, তিনি তাদের প্রতি ক্ষমাশীল যারা অনুশোচনা করে।"],
  "17:26": ["You shall give the due alms to the relatives, the needy, the poor, and the traveling alien, but do not be excessive, extravagant.","তোমরা আত্মীয়-স্বজন, অভাবী, গরিব এবং মুসাফিরদের প্রাপ্য দান দেবে, কিন্তু অতিরিক্ত করো না, অপচয়কারী হয়ো না।"],
  "17:27": ["The extravagant are brethren of the devils, and the devil is unappreciative of his Lord.","অপচয়কারী শয়তানে ভাই, এবং শয়তান তার প্রভুর প্রতি অকৃতজ্ঞ।"],
  "17:28": ["Even if you have to turn away from them, as you pursue the mercy of your Lord, you shall treat them in the nicest manner.","এমনকি যদি তোমাকে তাদের কাছ থেকে মুখ ফিরিয়ে নিতে হয়, তুমি যেহেতু তোমার প্রভুর দয়া অন্বেষণ করো, তুমি তাদের সাথে অত্যন্ত সুন্দর ব্যবহার করবে।"],
  "17:29": ["You shall not keep your hand stingily tied to your neck, nor shall you foolishly open it up, lest you end up blamed and sorry.","তুমি কৃপণতায় তোমার হাত গলায় বেধে রাখবে না, না তুমি  বোকার মতো তা খুলে রাখবে, পাছে তুমি দোষী ও দুঃখিত হয়ে পড়ো।"],
  "17:30": ["For your Lord increases the provision for anyone He chooses, and reduces it. He is fully Cognizant of His creatures, Seer.","কারন তোমার প্রভু জীবিকা বাড়িয়ে দেন যার জন্য তিনি পছন্দ করেন, এবং তা কমিয়ে দেন। তিনি তাঁর সৃষ্টিকূলের ব্যাপারে পূর্ণ অবগত, দ্রষ্টা।"],
  "17:31": ["You shall not kill your children due to fear of poverty. We provide for them, as well as for you. Killing them is a gross offense.","দারিদ্রতার ভয়ে তোমরা তোমাদের সন্তানদের হত্যা করবে না। আমরা প্রদান করি তাদের জন্য, সেই সাথে তোমাদের জন্য। তাদের হত্যা করা একটি গুরুতর অপরাধ।"],
  "17:32": ["You shall not commit adultery; it is a gross sin, and an evil behavior.","তোমরা ব্যভিচার করবে না; এটি এক মহা পাপ, এবং একটি মন্দ আচরণ।"],
  "17:33": ["You shall not kill any person—for Allah has made life sacred—except in the course of justice. If one is killed unjustly, then we give his heir authority to enforce justice. Thus, he shall not exceed the limits in avenging the murder, he will be helped.","তোমরা কোন লোককে হত্যা করবে না- কারন আল্লাহ জীবনকে পবিত্র করেছেন- বিচার প্রক্রিয়া ব্যতীত। যদি কেউ অন্যায় ভাবে খুন হয়, তখন আমরা তার উত্তরাধিকারীকে বিচার প্রয়োগের কর্তৃত্ব দেই। সুতরাং, সে খুনের প্রতিশোধ নিতে সীমা অতিক্রম করবে না, যাতে সে সাহায্য প্রাপ্ত হয়।"],
  "17:34": ["You shall not touch the orphans' money except for their own good, until they reach maturity. You shall fulfill your covenants, for a covenant is a great responsibility.","তোমরা এতিমের অর্থ তাদের নিজেদের মঙ্গলের জন্য ছাড়া স্পর্শ করবে না, যতক্ষণ না তারা পরিণত বয়সে পৌঁছে।  তোমরা তোমাদের অঙ্গীকার পূর্ণ করবে, কারণ অঙ্গীকার এক বিশাল দায়িত্ব।"],
  "17:35": ["You shall give full measure when you trade, and weigh equitably. This is better and more righteous.","তোমরা পূর্ণ পরিমাপ দেবে যখন তোমরা বেচাকেনা করো, এবং সঠিক ওজন করবে। এটি উত্তম এবং অধিক ন্যায়পরায়ণ।"],
  "17:36": ["You shall not accept any information, unless you verify it for yourself. I have given you the hearing, the eyesight, and the brain, and you are responsible for using them.","তোমরা কোন তথ্য গ্রহণ করবে না,  যদি না তুমি নিজে তা যাচাই করো। আমি তোমাকে দিয়েছি শ্রবণশক্তি, দৃষ্টিশক্তি, এবং মস্তিষ্ক, এবং তুমি সেগুলো ব্যবহারের জন্য দায়ী।"],
  "17:37": ["You shall not walk proudly on earth —you cannot bore through the earth, nor can you be as tall as the mountains.","তুমি গর্বভরে পৃথিবীতে চলবে না-তুমি পৃথিবী ছেদ করতে পারবে না, না তুমি পারবে উচ্চতায় পর্বত সমান হতে।"],
  "17:38": ["All bad behavior is condemned by your Lord.","সকল খারাপ আচরন তোমার প্রভুর দ্বারা নিন্দিত।"],
  "17:39": ["This is some of the wisdom inspired to you by your Lord. You shall not set up another god beside Allah, lest you end up in Gehenna, blamed and defeated.","এগুলো হচ্ছে তোমার কাছে তোমার প্রভুর প্রত্যাদিষ্ট কিছু প্রজ্ঞা/ জ্ঞান। তুমি আল্লাহর পাশে অন্য উপাস্য স্থাপন করবে না, পাছে শেষ পর্যন্ত তুমি জাহান্নামে যাও, দোষী এবং পরাজিত হয়ে।"],
  "17:40": ["Has your Lord given you boys, while giving Himself the angels as daughters?! How could you utter such a blasphemy?","তোমাদের প্রভু কি তোমাদের পুত্র দিয়েছেন, যখন নিজেকে দিয়েছেন কন্যা হিসাবে স্বর্গ-দূতদের? কিভাবে তোমরা এমন মিথ্যারোপ করো?"],
  "17:41": ["We have cited in this Quran (all kinds of examples), that they may take heed. But it only augments their aversion.","আমরা এই কুরআনে উল্লেখ করেছি (সকল প্রকার উদাহরণ), যাতে তারা সতর্ক হতে পারে। অথচ এটি তাদের বিমুখতাই বাড়িয়ে দেয়।"],
  "17:42": ["Say, \"If there were any other gods beside Him, as they claim, they would have tried to overthrow the Possessor of the throne.\"","বল, “যদি তাঁর পাশে অন্য উপাস্যরা থাকতো, যেমন তারা দাবী করে,  তারা সিংহাসনের অধিকারীকে পরাস্ত করার চেষ্টা করতো।"],
  "17:43": ["Be He glorified, He is much too exalted, far above their utterances.","মহিমা তাঁরই, তিনি অত্যন্ত প্রশংশিত, তাদের কথার অনেক ঊর্ধ্বে।"],
  "17:44": ["Glorifying Him are the seven universes, the earth, and everyone in them. There is nothing that does not glorify Him, but you do not understand their glorification. He is Clement, Forgiver.","তাঁর গুনকীর্তন করে সাত মহাবিশ্ব, পৃথিবী, এবং তাদের মধ্যকার সকলে। এমন কিছু নেই যা তাঁর গুনকীর্তন করে না, কিন্তু তোমরা তাদের গুনকীর্তন বুঝো না। তিনি সহনশীল, ক্ষমাকারী।"],
  "17:45": ["When you read the Quran, we place between you and those who do not believe in the Hereafter an invisible barrier.","যখন তুমি কুরআন পাঠ করো, আমরা তোমার এবং তাদের মাঝে এক অদৃশ্য অন্তরায় রেখে দেই যারা পরকালে বিশ্বাস করে না।"],
  "17:46": ["We place shields around their minds, to prevent them from understanding it, and deafness in their ears. And when you preach your Lord, using the Quran alone, they run away in aversion.","আমরা তাদের মনের চারপাশে প্রতিরোধক রাখি, এটি বুঝা থেকে তাদের বাধাঁ দিতে, এবং তাদের কানে দেই বধিরতা। এবং যখন তুমি তোমার প্রভুর কথা প্রচার করো, শুধুমাত্র কুরআনের মাধ্যমে, তারা বিরক্তি নিয়ে পালিয়ে যায়/কেটে পড়ে।"],
  "17:47": ["We are fully aware of what they hear, when they listen to you, and when they conspire secretly—the disbelievers say, \"You are following a crazy man.\"","আমরা পূর্ণ অবগত আছি কি তারা শোনে, যখন তারা তোমার দিকে মনোযোগ দেয়, এবং যখন তারা গোপনে চক্রান্ত করে- অবিশ্বাসীরা বলে, “তোমরা এক পাগল লোককে অনুসরণ করছো।\""],
  "17:48": ["Note how they describe you, and how this causes them to stray off the path.","লক্ষ্য করো কেমন করে তারা তোমার বর্ণনা করে, এবং কেমন করে এটি  তাদেরকে পথ থেকে সরিয়ে দেয়।"],
  "17:49": ["They said, \"After we turn into bones and fragments, we get resurrected anew?!\"","তারা বলে, “আমরা হাড় এবং খন্ডিত অংশে পরিণত হবার পর, আমরা কি নতুন করে পুনরুত্থিত হব?”"],
  "17:50": ["Say, \"Even if you turn into rocks or iron.","বল, “এমনকি যদিও তোমরা পাথর বা লোহা হয়ে যাও।"],
  "17:51": ["\"Even if you turn into any kind of creation that you deem impossible.\" They will then say, \"Who will bring us back?\" Say, \"The One who created you in the first place.\" They will then shake their heads and say, \"When will that be?\" Say, \"It may be closer than you think.\"","এমনকি যদি তোমরা পরিণতও হও এমন কোন সৃষ্টিতে যা তোমরা অসম্ভব বিবেচনা করো। “তারা তখন বলবে, “কে আমাদের ফিরিয়ে আনবে?” বল, “সেই সত্ত্বা যিনি তোমাদের প্রথমবার সৃষ্টি করেছিলেন।\" তারা এরপর তাদের মাথা নাড়াবে এবং বলবে, “সেটা কখন হবে?” বল, “এটি হতে পারে তোমরা যা মনে করো তার চেয়ে নিকটবর্তী।"],
  "17:52": ["The day He summons you, you will respond by praising Him, and you will then realize that you had lasted in this life but a short while.","যেদিন তিনি তোমাদের তলব করবেন, তোমরা সাড়া দেবে তাঁর প্রশংসা দিয়ে, এবং তোমরা তখন উপলব্ধি করবে যে তোমরা এই জীবনে খুব কম সময়েই ছিলে।"],
  "17:53": ["Tell My servants to treat each other in the best possible manner, for the devil will always try to drive a wedge among them. Surely, the devil is man's most ardent enemy.","আমার বান্দাদের বল পরস্পরের সাথে সম্ভাব্য সর্বোত্তম ব্যবহার করতে, কারন শয়তান সব সময় তাদের মধ্যে বিভেদ চালানোর চেষ্টা করবে। নিশ্চয়, শয়তান মানুষের সবচেয়ে ঘোর শত্রু।"],
  "17:54": ["Your Lord knows you best. According to His knowledge, He may shower you with mercy, or He may requite you. We did not send you to be their advocate.","তোমাদের প্রভু তোমাদের সর্বোত্তম জানেন। তার জ্ঞানানুসারে, তিনি তোমাদের উপর দয়া বর্ষণ করতে পারেন, অথবা তিনি হয়তো তোমাদের শাস্তি দিবেন। আমরা তোমাকে তাদের উকিল হতে পাঠাইনি।"],
  "17:55": ["Your Lord is the best knower of everyone in the heavens and the earth. In accordance with this knowledge, we preferred some prophets over others. For example, we gave David the Psalms.","তোমার প্রভু আকাশমণ্ডলী ও পৃথিবীর মধ্যকার সকলের বিষয়ে সর্বোত্তম জানেন। এই জ্ঞান অনুযায়ী, আমরা কিছু নবীকে অন্যদের থেকে পছন্দ করেছিলাম। উদাহরণ স্বরূপ, আমরা দাউদকে যবুর দিয়েছিলাম।"],
  "17:56": ["Say, \"Implore whatever idols you have set up beside Him.\" They have no power to relieve your afflictions, nor can they prevent them.","বল, “মিনতি কর সেসব উপাস্যদের কাছে তোমরা তাঁর পাশে যাদের স্থাপন করেছ।\" তোমাদের দুর্দশা দূর করার কোন শক্তি তাদের নেই, না তারা সেগুলো ঠেকাতে পারে।"],
  "17:57": ["Even the idols that they implore are seeking the ways and means towards their Lord. They pray for His mercy, and fear His retribution. Surely, the retribution of your Lord is dreadful.","এমনকি যাদের কাছে তারা মিনতি করে সেই উপাস্যরা তাদের প্রভুর নিকটবর্তী হবার পথ ও উপায় খুঁজছে। তারা তাঁর দয়ার জন্য প্রার্থনা করে, এবং তাঁর শাস্তির ভয় করে। নিশ্চয়, তোমার প্রভুর শাস্তি ভয়াবহ।"],
  "17:58": ["There is not a community that we will not annihilate before the Day of Resurrection, or inflict severe retribution upon them. This is already written down in the book.","এমন কোন সম্প্রদায় নেই যে আমরা পুনরুত্থান দিনের আগে ধ্বংস করবো না, কিংবা তাদের উপর কঠোর শাস্তি আরোপ করবো না। এটি ইতোমধ্যেই বইয়ে লেখা আছে।"],
  "17:59": ["What stopped us from sending the miracles is that the previous generations have rejected them. For example, we showed Thamûd the camel, a profound (miracle), but they transgressed against it. We sent the miracles only to instill reverence.","অলৌকিকতা পাঠানো থেকে যা আমাদের নিবৃত্ত করেছিল তা হলো আগের প্রজন্মরা সেগুলো প্রত্যাখ্যান করেছে। উদাহরণ স্বরূপ, আমরা সামুদকে উট দেখিয়েছিলাম, এক প্রগাঢ় (অলৌকিকতা), কিন্তু তারা এর বিরুদ্ধে সীমাতিক্রম করেছিল। আমরা কেবল ভক্তি সঞ্চারের জন্য অলৌকিকতাগুলো পাঠিয়েছিলাম।"],
  "17:60": ["We informed you that your Lord fully controls the people, and we rendered the vision that we showed you a test for the people, and the tree that is accursed in the Quran. We showed them solid proofs to instill reverence in them, but this only augmented their defiance.","আমরা তোমাকে জানিয়েছিলাম যে তোমার প্রভু লোকদের পূর্ণরূপে নিয়ন্ত্রন করেন, এবং আমরা সেই দৃশ্য তোমাকে দেখিয়েছিলাম, যা লোকদের জন্য একটি পরীক্ষা, এবং সেই গাছ যা কুরআনে অভিসপ্ত। আমরা তাদের মধ্যে ভক্তি সঞ্চারের জন্য তাদেরকে দৃঢ় প্রমান দেখিয়েছিলাম, কিন্তু এটি শুধু তাদের অবাধ্যতা বাড়িয়েছে।"],
  "17:61": ["When we said to the angels, \"Fall prostrate before Adam,\" they fell prostrate, except Satan. He said, \"Shall I prostrate to one You created from mud?\"","যখন আমরা ফেরেশতাদের বললাম, “আদমের সামনে সেজদাবনত হও।\" তারা সেজদাবনত হলো, শয়তান ছাড়া। সে বলল, “আমি কি তার প্রতি সেজদা করবো যাকে আপনি কাদাঁ থেকে সৃষ্টি করেছেন?”"],
  "17:62": ["He said, \"Since You have honored him over me, if You respite me till the Day of Resurrection, I will possess all his descendants, except a few.\"","সে বলল, “যেহেতু আপনি তাকে আমার উপর সন্মান দিয়েছেন, যদি আপনি আমাকে পুনরুত্থান দিন পর্যন্ত অবকাশ দেন, আমি তার বংশধরদের সকলকে বশে নেব, সামান্য কিছু ছাড়া”।"],
  "17:63": ["He said, \"Then go; you and those who follow you will end up in Hell as your requital; an equitable requital.","তিনি বললেন, “তবে যাও; তুমি এবং যারা তোমাকে অনুসরণ করবে তারা তোমাদের শাস্তি হিসাবে শেষ পর্যন্ত নরকে যাবে; এক ন্যায় সঙ্গত শাস্তি।"],
  "17:64": ["\"You may entice them with your voice, and mobilize all your forces and all your men against them, and share in their money and children, and promise them. Anything the devil promises is no more than an illusion.","“তুমি পারো তোমার আওয়াজ দিয়ে তাদের প্রলুব্ধ করতে, এবং তোমার সব ক্ষমতা এবং সব লোক তাদের বিরুদ্ধে একত্রিত করতে, এবং তাদের অর্থ ও সন্তানাদিতে অংশীদার হতে, এবং তাদের অঙ্গীকার দিতে। যা কিছু শয়তান অঙ্গীকার করে তা মায়ার চেয়ে বেশি কিছু নয়।"],
  "17:65": ["\"As for My servants, you have no power over them.\" Your Lord suffices as an advocate.","আমার বান্দাদের ক্ষেত্রে, তাদের উপর তোমার কোন ক্ষমতা নেই। তোমার প্রভু উকিল হিসেবে যথেষ্ট।"],
  "17:66": ["Your Lord is the One who causes the ships to float on the ocean, that you may seek His bounties. He is Most Merciful towards you.","তোমাদের প্রভুই সে সত্ত্বা যিনি জাহাজগুলোকে সাগরে ভাসিয়ে রাখেন, যাতে তোমরা তার অনুগ্রহ অন্বেষণ করতে পারো। তিনি তোমাদের প্রতি সবথেকে দয়ালু।"],
  "17:67": ["If you are afflicted in the middle of the sea, you forget your idols and sincerely implore Him alone. But as soon as He saves you to the shore, you revert. Indeed, the human being is unappreciative.","যদি তোমরা সমুদ্রের মাঝখানে দুর্দশাগ্রস্থ হও/ যদি তোমরা দুর্দশাগ্রস্থ হও মাঝ সমুদ্রে, তোমরা তোমাদের উপাস্যদের ভুলে যাও এবং মন থেকে শুধু তাঁর কাছে মিনতি করো। কিন্তু তিনি তোমাদের তীরে এনে রক্ষা করা মাত্রই তোমরা আগের অবস্থায় ফিরে যাও। আসলে, মানুষ অকৃতজ্ঞ।"],
  "17:68": ["Have you guaranteed that He will not cause the land, on shore, to swallow you? Or, that He will not send upon you a tempest, then you find no protector?","তোমরা কি নিশ্চয়তা প্রাপ্ত যে তিনি, তীরের উপরস্থ, ভূমিকে দিয়ে তোমাদেরকে গ্রাস করাবেন না? অথবা তিনি তোমাদের উপর কোন প্রবল ঝড় পাঠাবেন না, এরপর তোমরা কোন রক্ষাকারী না পাও?"],
  "17:69": ["Have you guaranteed that He will not return you to the sea another time, then send upon you a storm that drowns you because of your disbelief? Once this happens, we will not give you another chance.","তোমরা কি নিশ্চয়তা প্রাপ্ত যে আরেকবার তিনি তোমাদের সমুদ্রে ফিরিয়ে নিয়ে যাবেন না, এরপর তোমাদের উপর ঝড় পাঠাবেন না যা তোমাদের ডুবিয়ে মারবে তোমাদের অবিশ্বাসের কারনে? যখনই এটা ঘটবে, আমরা তোমাদের আর কোন সুযোগ দেবো না।"],
  "17:70": ["We have honored the children of Adam, and provided them with rides on land and in the sea. We provided for them good provisions, and we gave them greater advantages than many of our creatures.","আমরা আদমের সন্তানদের সন্মানিত করেছি, এবং তাদেরকে স্থলে ও সাগরে বাহন দিয়েছি । আমরা তাদের জন্য উত্তম রিজিক দিয়েছি, এবং আমাদের অনেক সৃষ্টির থেকে আমরা তাদের অধিক সুবিধা দিয়েছি ।"],
  "17:71": ["The day will come when we summon every people, together with their record. As for those who are given a record of righteousness, they will read their record and will not suffer the least injustice.","সে দিন আসবে যখন আমরা সকল মানুষকে তলব করবো, তাদের রেকর্ড সহকারে। তাদের ক্ষেত্রে যাদেরকে সৎকর্মশীলতার রেকর্ড দেয়া হবে, তারা তাদের রেকর্ড পড়বে এবং সামান্যতম অবিচার ভোগ করবে না।"],
  "17:72": ["As for those who are blind in this life, they will be blind in the Hereafter; even a lot worse.","আর তাদের ক্ষেত্রে যারা এই জীবনে অন্ধ, তারা পরকালেও অন্ধ হবে; এমনকি আরো অধিক মন্দ।"],
  "17:73": ["They almost diverted you from the revelations we have given you. They wanted you to fabricate something else, in order to consider you a friend.","তারা তোমাকে আমাদের দেয়া প্রকাশনাবলী থেকে প্রায় সরিয়ে দিয়েছিল। তারা চেয়েছিল তুমি কিছু মিথ্যা উদ্ভাবন করো, যেন তোমাকে বন্ধু গন্য করা যায়।"],
  "17:74": ["If it were not that we strengthened you, you almost leaned towards them just a little bit.","যদি আমরা তোমাকে দৃঢ়তা না দিতাম, তুমি তাদের প্রতি খানিকটা ঝুকেই পড়েছিলে।"],
  "17:75": ["Had you done that, we would have doubled the retribution for you in this life, and after death, and you would have found no one to help you against us.","তুমি যদি তা করতে, আমরা তোমার জন্য শাস্তি দিগুন করতাম এই জীবনে, এবং মৃত্যুর পর, এবং তুমি আমাদের বিরুদ্ধে তোমাকে সাহায্য করার জন্য কাউকে পেতে না।"],
  "17:76": ["They almost banished you from the land to get rid of you, so they could revert as soon as you left.","তারা তোমার কাছ থেকে মুক্তি পাওয়ার জন্য দেশ থেকে তোমাকে প্রায় নির্বাসিতই করেছিল, যাতে তুমি চলে যাওয়া মাত্র তারা আগের অবস্থায় ফিরে যেতে পারে।"],
  "17:77": ["This has been consistently the case with all the messengers that we sent before you, and you will find that our system never changes.","এটি সব বার্তাবাহকদের সাথে অনবরত ঘটে যাওয়া সেই একই ঘটনা যাদেরকে আমরা তোমার পূর্বে পাঠিয়েছিলাম, এবং তুমি দেখবে যে আমাদের নিয়ম কখনো পরিবর্তন হয় না।"],
  "17:78": ["You shall observe the Contact Prayer (Salat) when the sun declines from its highest point at noon, as it moves towards sunset. You shall also observe (the recitation of) the Quran at dawn. (Reciting) the Quran at dawn is witnessed.","তুমি সংযোগ প্রার্থনা (সালাত) পালন করবে যখন দুপুরে সূর্য তার সর্বোচ্চ বিন্দু থেকে ঢলে পড়ে, যেহেতু এটি সূর্যাস্তের দিকে অগ্রসর হয়। তোমরা এছাড়া ফজরে কুরআন (আবৃতি ) করবে। ফজরে কুরআন (আবৃতি )-এর সাক্ষী থাকে।"],
  "17:79": ["During the night, you shall meditate for extra credit, that your Lord may raise you to an honorable rank.","রাতের বেলায়, তুমি অতিরিক্ত কৃতিত্বের জন্য ধ্যান করবে, যাতে তোমার প্রভু তোমাকে এক সন্মানিত পদে উন্নিত করেন।"],
  "17:80": ["And say, \"My Lord, admit me an honorable admittance, and let me depart an honorable departure, and grant me from You a powerful support.\"","এবং বল, “আমার প্রভু, আমাকে সন্মানের সাথে প্রবেশ করান, এবং সন্মানের সাথে বিদায় নিতে দিন, এবং আপনার পক্ষ থেকে আমাকে একটি শক্তিশালী সমর্থন মঞ্জুর করুন।\""],
  "17:81": ["Proclaim, \"The truth has prevailed, and falsehood has vanished; falsehood will inevitably vanish.\"","ঘোষণা করো, “সত্যের জয় হয়েছে, এবং মিথ্যা বিলুপ্ত হয়েছে; মিথ্যা অনিবার্যভাবে বিলুপ্ত হবে।\""],
  "17:82": ["We send down in the Quran healing and mercy for the believers. At the same time, it only increases the wickedness of the transgressors.","আমরা বিশ্বাসীদের জন্য কুরআনে আরোগ্য এবং দয়া অবতীর্ণ করেছি। একই সাথে, এটি কেবল সীমালঙ্ঘনকারীদের পাপাচার বাড়ায়।"],
  "17:83": ["When we bless the human being, he becomes preoccupied and heedless. But when adversity strikes him, he turns despondent.","আমরা যখন মানুষকে অনুগ্রহ করি, সে আছন্ন এবং অমনোযোগী হয়ে যায়। কিন্তু যখন দুর্দশা তাকে আঘাত করে, সে হতাশ হয়ে পড়ে।"],
  "17:84": ["Say, \"Everyone works in accordance with his belief, and your Lord knows best which ones are guided in the right path.\"","বল, “প্রত্যেকে তার বিশ্বাস অনুসারে কাজ করে, এবং তোমার প্রভু সব থেকে ভালো জানেন কারা সঠিক পথে পরিচালিত।\""],
  "17:85": ["They ask you about the revelation. Say, \"The revelation comes from my Lord. The knowledge given to you is minute.\"","তারা তোমাকে প্রকাশনা সম্পর্কে জিজ্ঞাসা করে। বল, “প্রকাশনা আমার প্রভুর পক্ষ থেকে আসে। তোমাকে দেয়া জ্ঞান অতি সামান্য।\""],
  "17:86": ["If we will, we can take back what we revealed to you, then you will find no protector against us.","যদি আমরা চাই, আমরা ফিরিয়ে নিতে পারি যা আমরা তোমার কাছে প্রকাশ করেছি, তখন তুমি আমাদের বিরুদ্ধে কোন রক্ষাকারী পাবে না।"],
  "17:87": ["This is but mercy from your Lord. His blessings upon you have been great.","এটা তো তোমার প্রভুর পক্ষ থেকে দয়া। তোমার উপর তাঁর অনুগ্রহ বিশাল।"],
  "17:88": ["Say, \"If all the humans and all the jinns banded together in order to produce a Quran like this, they can never produce anything like it, no matter how much assistance they lent one another.\"","বল, “যদি সকল মানুষ ও সকল জিন একত্রিত হয় এর মতো একটি কুরআন তৈরি করার জন্য, তারা কখনই এর মতো কোনকিছু তৈরি করতে পারবে না, যতো সহায়তাই তারা একে অন্যকে করুক না কেন”।"],
  "17:89": ["We have cited for the people in this Quran all kinds of examples, but most people insist upon disbelieving.","এই কুরআনে আমরা লোকদের জন্য সব ধরনের উদাহরণ দিয়েছি, কিন্তু বেশির ভাগ লোক অবিশ্বাসের উপর জোর দেয়।"],
  "17:90": ["They said, \"We will not believe you unless you cause a spring to gush out of the ground.","তারা বলল, “আমরা তোমাকে বিশ্বাস করবো না যদি না তুমি  ভুপৃষ্ট থেকে কোন ঝর্না প্রবাহিত করো।"],
  "17:91": ["\"Or unless you own a garden of date palms and grapes, with rivers running through it.","“অথবা যদিনা তুমি একটি খেজুর ও আঙুর বাগানের মালিক হও, যার মধ্যে দিয়ে নদী প্রবাহিত হয়!"],
  "17:92": ["\"Or unless you cause masses from the sky, as you claimed, to fall on us. Or unless you bring Allah and the angels before our eyes.","“অথবা যদিনা, তোমার দাবি অনুযায়ী, আকাশ থেকে আমাদের উপর বস্তুপিন্ডের পতন ঘটাও। অথবা যদিনা তুমি আমাদের চোখের সামনে আল্লাহ এবং ফেরেশতাদের নিয়ে আসো।"],
  "17:93": ["\"Or unless you own a luxurious mansion, or unless you climb into the sky. Even if you do climb, we will not believe unless you bring a book that we can read.\" Say, \"Glory be to my Lord. Am I any more than a human messenger?\"","“অথবা যদিনা তুমি কোন বিলাসবহুল প্রাসাদের মালিক হও, অথবা যদিনা তুমি আকাশে আরোহণ করো। তুমি যদি আরোহণও করো, আমরা বিশ্বাস করবো না যদি না তুমি কোন বই নিয়ে আসো যা আমরা পড়তে পারি। বল, “মহিমা আমার প্রভুর। আমি কি একজন মনুষ্য বার্তাবাহকের চেয়ে বেশি কিছু?”"],
  "17:94": ["What prevented the people from believing when the guidance came to them, is their saying, \"Did Allah send a human being as a messenger?\"","লোকদের কাছে পথ-নির্দেশনা আসার পর বিশ্বাস করা থেকে যা তাদেরকে বাধা দিয়েছিল, তা হচ্ছে তাদের এ কথা যে, “আল্লাহ কি একজন মানুষকে বার্তাবাহক করে পাঠিয়েছিলেন?’"],
  "17:95": ["Say, \"If the earth were inhabited by angels, we would have sent down to them from the sky an angel messenger.\"","বল, “যদি পৃথিবী ফেরেশতাদের বসতি হতো, তাহলে আকাশ থেকে আমরা তাদের কাছে অবতীর্ণ করতাম কোন ফেরেশতা বার্তাবাহক”।"],
  "17:96": ["Say, \"Allah suffices as a witness between me and you. He is fully Cognizant of His worshipers, Seer.\"","বল, “আমার এবং তোমাদের মধ্যে আল্লাহ সাক্ষী হিসাবে যথেষ্ট। তিনি পূর্ণ অবগত তাঁর উপাসনাকারীদের ব্যাপারে, দ্রষ্টা”।"],
  "17:97": ["Whomever Allah guides is the truly guided one. And whomever He sends astray, you will never find for them any lords and masters beside Him. We will summon them on the Day of Resurrection forcibly; blind, dumb, and deaf. Their destination is Hell; whenever it cools down, we will increase their fire.","সে-ই সত্যিকার পথপ্রাপ্ত ব্যক্তি যাকে আল্লাহ পথ দেখান। এবং তিনি যাকে পথভ্রষ্ট করেন, তাদের জন্য তুমি কখনই তাঁর পাশে কোন প্রভু এবং মনিব পাবে না। আমরা তাদেরকে পুনরুত্থান দিনে জোরপূর্বক তলব করবো; অন্ধ, বোবা এবং বধির করে। তাদের গন্তব্য নরক; যখনি তা শীতল হবে, আমরা সেগুলোর আগুন বাড়িয়ে দেবো।"],
  "17:98": ["Such is their just retribution, since they rejected our revelations. They said, \"After we turn into bones and fragments, do we get resurrected into a new creation?\"","এমনই তাদের উচিত শাস্তি, যেহেতু তারা আমাদের প্রকাশনাবলী প্রত্যাখ্যান করেছে। তারা বলেছিল, “আমরা হাড় এবং খন্ডিত অংশে পরিণত হবার পর, আমরা কি এক নতুন সৃষ্টি হয়ে পুনরুত্থিত হব?”"],
  "17:99": ["Could they not see that the Allah who created the heavens and the earth, is able to create the same creations? He has predetermined for them an irrevocable life span? Yet, the disbelievers insist upon disbelieving.","তারা কি দেখতে পায় না যে আল্লাহ যিনি আকাশ মণ্ডলী এবং পৃথিবী সৃষ্টি করেছেন, সৃষ্টি করতে সক্ষম সেই একই সৃষ্টি? তিনি তাদের জন্য পূর্বনির্ধারিত করেছেন এক অপরিবর্তনীয় জীবন কাল? এরপরও, অবিশ্বাসীরা অবিশ্বাসের উপরই জোর দেয়।"],
  "17:100": ["Proclaim, \"If you possessed my Lord's treasures of mercy, you would have withheld them, fearing that you might exhaust them. The human being is stingy.\"","ঘোষণা করো, “যদি তোমরা আমার প্রভুর দয়া ভাণ্ডারের মালিক হতে, তোমরা সেগুলো গুটিয়ে রাখতে, এই ভয়ে যে তোমরা সেগুলো শেষ করে ফেলবে। মানুষ কৃপণ।"],
  "17:101": ["We supported Moses with nine profound miracles—ask the Children of Israel. When he went to them, Pharaoh said to him, \"I think that you, Moses, are bewitched.\"","আমরা মুসাকে নয়টি প্রগাঢ় অলৌকিকতা দিয়ে সমর্থন করেছিলাম- ইসরাইলের সন্তানদের কাছে জিজ্ঞেস করো। যখন সে তাদের কাছে গেল, ফেরাউন তাকে বলেছিল, “আমি মনে করি যে তুমি মুসা জাদুগ্রস্থ”।"],
  "17:102": ["He said, \"You know full well that no one can manifest these except, obviously, the Lord of the heavens and the earth. I think that you, Pharaoh, are doomed.\"","সে বলল, “তুমি খুব ভালো করেই জানো যে এগুলো যেকেউ প্রকাশ করতে পারে না কিন্তু, স্পষ্টতই, আকাশমণ্ডলী এবং পৃথিবীর প্রভু ছাড়া। আমি মনে করি যে তুমি ফেরাউন ধ্বংসপ্রাপ্ত”।"],
  "17:103": ["When he pursued them, as he chased them out of the land, we drowned him, together with those who sided with him, all of them.","যখন সে তাদের পিছু নিলো,যেভাবে সে তাদেরকে দেশের বাইরে পর্যন্ত ধাওয়া করেছিল, আমরা তাকে ডুবিয়ে দিলাম, তাদের সাথে  একত্রে যারা তার পক্ষ নিয়েছিল, তাদের সকলকে।"],
  "17:104": ["And we said to the Children of Israel afterwards, \"Go live in this land. When the final prophecy comes to pass, we will summon you all in one group.\"","এবং পরবর্তীতে আমরা ইসরাইলের সন্তানদের বলেছিলাম, “যাও এই দেশে বাস করো। যখন চূড়ান্ত ভবিষ্যদ্বাণী ঘটবে, আমরা তোমাদের সকলকে একটি দল করে তলব করবো”।"],
  "17:105": ["Truthfully, we sent it down, and with the truth it came down. We did not send you except as a bearer of good news, as well as a warner.","সত্যের সঙ্গে, আমরা একে অবতীর্ণ করেছি, এবং সত্য নিয়ে এটি অবতীর্ণ হয়েছে। আমরা তোমাকে একজন সুসংবাদ বহনকারী, সেই সাথে সতর্ককারী হিসেবে ছাড়া পাঠাইনি।"],
  "17:106": ["A Quran that we have released slowly, in order for you to read it to the people over a long period, although we sent it down all at once.","কুরআন যা আমরা ধীরে ধীরে ছেড়েছি, ক্রমান্বয়ে এটি দীর্ঘ সময়কাল ধরে লোকদের কাছে তোমার পরার জন্য, যদিও আমরা একে হঠাৎ করেই অবতীর্ণ করেছি।"],
  "17:107": ["Proclaim, \"Believe in it, or do not believe in it.\" Those who possess knowledge from the previous scriptures, when it is recited to them, they fall down to their chins, prostrating.","ঘোষণা দাও, “এতে বিশ্বাস করো, অথবা এতে বিশ্বাস না করো। “যারা পূর্ববর্তী ঐশীগ্রন্থের জ্ঞান রাখে, তাদের কাছে যখন এটা আবৃত্তি করা হয়, তারা তাদের মাথা নত করে সেজদায় পড়ে যায়।"],
  "17:108": ["They say, \"Glory be to our Lord. This fulfills our Lord's prophecy.\"","তারা বলে, “মহিমা আমাদের প্রভুর। এটা আমাদের প্রভুর ভবিষ্যদ্বাণী পূর্ণ করে।\""],
  "17:109": ["They fall down on their chins, prostrating and weeping. For it augments their reverence.","তারা তাদের মাথা নত করে সেজদায় পড়ে যায় এবং কাঁদে। কারন এটা তাদের ভক্তি বৃদ্ধি করে।"],
  "17:110": ["Say, \"Call Him Allah, or call Him Most Gracious; whichever name you use, to Him belongs the best names.\" You shall not utter your Contact Prayers (Salat) too loudly, nor secretly; use a moderate tone.","বল, “তাঁকে আল্লাহ ডাকো, অথবা তাঁকে পরম দয়াময় ডাকো; যে নামই তোমরা ব্যবহার করো না কেন, সর্বোত্তম নামগুলো তাঁরই।\" তুমি তোমার সংযোগ প্রার্থনা (সালাত) অতি উচ্চস্বরে পড়বে না, না নীরবে; একটি মধ্যম কণ্ঠস্বর ব্যবহার করো।"],
  "17:111": ["And proclaim: \"Praise be to Allah, who has never begotten a son, nor does He have a partner in His kingship, nor does He need any ally out of weakness,\" and magnify Him constantly.","এবং ঘোষণা করঃ “প্রশংসা আল্লাহর, যিনি কখনই কোন পুত্র জন্ম দেননি, না তাঁর রাজত্বে তাঁর কোন অংশীদার আছে, না দুর্বলতাবশত তাঁর কোন মিত্রের প্রয়োজন আছে”, এবং প্রতিনিয়ত তাঁর মহত্ব বর্ণনা করো।"],
  "18:1": ["Praise Allah, who revealed to His servant this scripture, and made it flawless.","প্রশংসা আল্লাহর, যিনি তাঁর বান্দার কাছে এই ঐশীগ্রন্থ প্রকাশ করেছেন, এবং একে নির্ভূল করেছেন।"],
  "18:2": ["A perfect (scripture) to warn of severe retribution from Him, and to deliver good news to the believers who lead a righteous life, that they have earned a generous recompense.","একটি যথাযথ (ঐশীগ্রন্থ) তাঁর পক্ষ থেকে কঠিন শাস্তির বিষয়ে সতর্ক করতে, এবং বিশ্বাসীদের শুভ সংবাদ দিতে যারা সৎ জীবন-যাপন করে, যে তারা অর্জন করেছে এক মহা প্রতিদান।"],
  "18:3": ["Wherein they abide forever.","যেখানে তারা চিরকাল বসবাস করে।"],
  "18:4": ["And to warn those who said, \"Allah has begotten a son!\"","এবং তাদেরকে সতর্ক করতে যারা বলে, “আল্লাহ পুত্র জন্ম দিয়েছেন!”"],
  "18:5": ["They possess no knowledge about this, nor did their parents. What a blasphemy coming out of their mouths! What they utter is a gross lie.","তারা এ বিষয়ে কোন জ্ঞান রাখে না, না রাখতো তাদের মাতা-পিতারা। কি এক মিথ্যাচারই না তাদের মুখ দিয়ে আসছে! তারা যা বলে তা এক ঘোর মিথ্যাচার।"],
  "18:6": ["You may blame yourself on account of their response to this narration, and their disbelieving in it; you may be saddened.","তুমি হয়তো নিজেকে দোষ দিবে এই বর্ণনার প্রতি তাদের প্রতিক্রিয়ার কারণে, এবং এতে তাদের অবিশ্বাসের কারণে; তুমি হয়তো দু:খিত হবে।"],
  "18:7": ["We have adorned everything on earth, in order to test them, and thus distinguish those among them who work righteousness.","আমরা পৃথিবীর সবকিছু সাজিয়েছি, তাদের পরীক্ষা করার জন্য, এবং এভাবে তাদের মধ্যে যারা সৎ কাজ করে তাদেরকে আলাদা করি।"],
  "18:8": ["Inevitably, we will wipe out everything on it, leaving it completely barren.","অনিবার্যভাবে, আমরা এর সবকিছু মুছে ফেলব, একে পুরোপুরি ধূলিসাৎ করে দিয়ে।"],
  "18:9": ["Why else do you think we are telling you about the people of the cave, and the numbers connected with them? They are among our wondrous signs.","কেনইবা তুমি ভাবো- আমরাই তো তোমাকে বলছি গুহার লোকদের সম্পর্কে, এবং তাদের সাথে সম্পর্কিত সংখ্যা সম্পর্কে ? তারা আমাদের বিস্ময়কর নিদর্শনগুলোর অন্তর্ভুক্ত।"],
  "18:10": ["When the youths took refuge in the cave, they said, \"Our Lord, shower us with Your mercy, and bless our affairs with Your guidance.\"","যখন তরুনেরা গুহায় আশ্রয় নিয়েছিল, তারা বলেছিল, \"আমাদের প্রভু, আমাদের প্রতি আপনার দয়া বর্ষণ করুন, এবং  আপনার পথ-নির্দেশনা দিয়ে আমাদের কাজগুলোকে অনুগ্রহ করুন।”"],
  "18:11": ["We then sealed their ears in the cave for a predetermined number of years.","আমরা এরপর এক পূর্বনির্ধারিত সংখ্যক বছরের জন্য গুহায় তাদের কানে মোহর মেরে দিলাম।"],
  "18:12": ["Then we resurrected them to see which of the two parties could count the duration of their stay therein.","এরপর আমরা তাদের পুনঃরুত্থিত করলাম দেখার জন্য যে দু'দলের কোনটি সেখানে তাদের অবস্থানের সময়কাল গননা করতে পারে।"],
  "18:13": ["We narrate to you their history, truthfully. They were youths who believed in their Lord, and we increased their guidance.","আমরা তোমার কাছে তাদের ইতিহাস বর্ননা করি, সত্যের সাথে।  তারা ছিল তরুন যারা তাদের প্রভুকে বিশ্বাস করেছিল, এবং আমরা তাদের সঠিক নিরদেশেনা বৃদ্ধি করেছিলাম।"],
  "18:14": ["We strengthened their hearts when they stood up and proclaimed: \"Our only Lord is the Lord of the heavens and the earth. We will never worship any other god beside Him. Otherwise, we would be far astray.","আমরা তাদের হৃদয়কে দৃঢ় করেছিলাম যখন তারা দাঁড়ালো এবং ঘোষণা করলো: \"আকাশমন্ডলী এবং পৃথিবীর প্রভুই আমাদের একমাত্র প্রভু। আমরা কখনো তাঁর পাশে অন্যকোন উপাস্যের উপাসনা করবো না। অন্যথায়, আমরা বহুদূরে পথভ্রষ্ট হবো।"],
  "18:15": ["\"Here are our people setting up gods beside Him. If only they could provide any proof to support their stand! Who is more evil than the one who fabricates lies and attributes them to Allah?","এই যে আমাদের লোকেরা তাঁর পাশে উপাস্যদের স্থাপন করছে। যদি শুধু তারা তাদের পক্ষে কোন প্রমান দেখাতে পারতো! কে তার চেয়ে অধিক মন্দ যে মিথ্যা রচনা করে এবং সেগুলো আল্লাহর প্রতি আরোপ করে?"],
  "18:16": ["\"Since you wish to avoid them, and their worshiping of other than Allah, let us take refuge in the cave. May your Lord shower you with His mercy and direct you to the right decision.\"","যেহেতু তোমরা তাদেরকে, এবং আল্লাহ ছাড়া তাদের অন্য কারো উপাসনা করাকে এড়াতে চাও,  সেহেতু চলো আমরা গুহায় আশ্রয় নেই। তোমাদের প্রভু তোমাদেরকে তাঁর দয়া বর্ষণ করুন এবং তোমাদের সঠিক সিদ্ধান্তে পরিচালিত করুন।"],
  "18:17": ["You could see the sun when it rose coming from the right side of their cave, and when it set, it shone on them from the left, as they slept in the hollow thereof. This is one of Allah's portents. Whomever Allah guides is the truly guided one, and whomever He sends astray, you will not find for him a guiding teacher.","তুমি সূর্যকে তাদের গুহার ডান পাশ থেকে উদিত হতে দেখতে পেতে, এবং যখন এটি অস্ত যেত, এটি তাদের বাম দিক থেকে আলোকিত হতো, সেখানকার গর্তে যখন তারা ঘুমিয়ে ছিল। এটি আল্লাহর একটি সতর্কীকরণ। যাকে আল্লাহ পথপ্রদর্শন করেন সেই সত্যিকার পথপ্রাপ্ত ব্যক্তি, এবং যাকে তিনি পথভ্রষ্ট করেন; তুমি তার জন্য কোন পথনির্দেশক শিক্ষক পাবে না।"],
  "18:18": ["You would think that they were awake, when they were in fact asleep. We turned them to the right side and the left side, while their dog stretched his arms in their midst. Had you looked at them, you would have fled from them, stricken with terror.","তুমি মনে করতে যে তারা জাগ্রত, যখন তারা আসলে ঘুমন্ত। আমরা তাদেরকে ডান ও বাম পাশে ফিরাতাম, যখন তাদের কুকুর তার বাহুগুলো তাদের মাঝে টান টান করে রেখেছিল। যদি তুমি তাদের দিকে তাকাতে, তুমি হয়তো তাদের থেকে পালাতে, আতংকগ্রস্থ হয়ে।"],
  "18:19": ["When we resurrected them, they asked each other, \"How long have you been here?\" \"We have been here one day or part of the day,\" they answered. \"Your Lord knows best how long we stayed here, so let us send one of us with this money to the city. Let him fetch the cleanest food, and buy some for us. Let him keep a low profile, and attract no attention.","যখন আমরা তাদের পুনরুজ্জীবিত করলাম, তারা একে অন্যকে জিজ্ঞেস করলো, “তোমরা কতক্ষন এখানে আছো?” “আমরা এখানে এক দিন বা দিনের একাংশ জুড়ে আছি,” তারা জবাব দিল। “তোমাদের প্রভু সবচেয়ে ভাল জানেন কত সময় জুড়ে /ধরে আমরা এখানে অবস্থান করছি, তাই চলো এই পয়সা দিয়ে আমরা আমাদের একজনকে শহরে পাঠাই। সে সবচেয়ে পরিষ্কার খাবার নিয়ে আসুক, এবং কিছু আমাদের জন্য কিনে আনুক। সে যেন তাকে জনসম্মুক্ষে কম প্রকাশ করে, এবং কোন দৃষ্টি আকর্ষণ না করে।"],
  "18:20": ["\"If they discover you, they will stone you, or force you to revert to their religion, then you can never succeed.\"","যদি তারা তোমাদের খুঁজে পায়, তারা তোমাদের পাথর মারবে, অথবা জোড় করে তোমাদেরকে তাদের ধর্মে ফিরিয়ে নেবে, সেক্ষেত্রে তোমরা কখনো সফল হতে পারবে না।\""],
  "18:21": ["We caused them to be discovered, to let everyone know that Allah's promise is true, and to remove all doubt concerning the end of the world. The people then disputed among themselves regarding them. Some said, \"Let us build a building around them.\" Their Lord is the best knower about them. Those who prevailed said, \"We will build a place of worship around them.\"","আমরা তাদেরকে প্রকাশ করালাম, সবাইকে জানাতে যে আল্লাহর অঙ্গীকার সত্য, এবং বিশ্বের পরিসমাপ্তির ব্যাপারে সকল সন্দেহ দূর করার জন্য।এরপর লোকেরা নিজেদের মধ্যে তাদের সম্পর্কে বিবাদে জড়ালো। কেউ কেউ বলল, \"চল আমরা তাদের চারপাশে দালান বানাই।” তাদের প্রভু তাদের সম্পর্কে সর্বোত্তম জ্ঞাত। যারা প্রাধান্য  পেয়েছিল তারা বলল, \"তাদের ঘিরে আমরা একটি উপাসনার জায়গা বানাবো।”"],
  "18:22": ["Some would say, \"They were three; their dog being the fourth,\" while others would say, \"Five; the sixth being their dog,\" as they guessed. Others said, \"Seven,\" and the eighth was their dog. Say, \"My Lord is the best knower of their number.\" Only a few knew the correct number. Therefore, do not argue with them; just go along with them. You need not consult anyone about this.","কেউ কেউ বলে, \"তারা ছিল তিনজন, তাদের কুকুর সহ চার\", যখন অন্যরা বলে, “পাঁচজন; তাদের কুকুর সহ ছয়, ” কারণ তারা অনুমান করেছিল। অন্যরা বলেছিল, \"সাতজন\", এবং আট নম্বরে তাদের কুকুর। বল, \"আমার প্রভু তাদের সংখ্যা সম্পর্কে সবচেয়ে ভাল জানেন। শুধু অল্প কয়েকজনই সঠিক সংখ্যাটি জানত। সেজন্য, তাদের সাথে তর্ক করো না; শুধু তাদের সাথে থাকো।  তোমার এ নিয়ে কারো সাথে পরামর্শের দরকার নেই।"],
  "18:23": ["You shall not say that you will do anything in the future,","তুমি কখনো বলবে না যে তুমি কোনকিছু ভবিষ্যতে করবে,"],
  "18:24": ["without saying, \"Allah willing.\" If you forget to do this, you must immediately remember your Lord and say, \"May my Lord guide me to do better next time.\"","এটা না বলে যে, \"আল্লাহ চাইলে,  যদি তুমি তা করতে ভুলে যাও, সাথে সাথে অবশ্যই তুমি তোমার প্রভুকে স্মরণ করবে এবং বল, \"পরবর্তীতে আরো ভাল করার জন্য আল্লাহ আমায় পথ-প্রদর্শন করুন।\""],
  "18:25": ["They stayed in their cave three hundred years, increased by nine.","তারা তাদের গুহায় ছিল তিনশত বছর, আরো নয় বাড়িয়ে।"],
  "18:26": ["Say, \"Allah is the best knower of how long they stayed there.\" He knows all secrets in the heavens and the earth. By His grace you can see; by His grace you can hear. There is none beside Him as Lord and Master, and He never permits any partners to share in His kingship.","বল, “কত কাল সেখানে তারা ছিল আল্লাহই সবচেয়ে ভাল জানেন।” তিনি আকাশমন্ডলী ও পৃথিবীর সকল রহস্য জানেন। তাঁর দয়ায় তোমরা দেখতে পাও; তাঁর দয়ায় তোমরা শুনতে পাও। তাঁর পাশে প্রভু ও মনিব হিসেবে আর কেউ নেই, এবং তিনি কখনো কোন অংশীদারকে তাঁর রাজত্বে অংশ নিতে অনুমতি দেন না।"],
  "18:27": ["You shall recite what is revealed to you of your Lord's scripture. Nothing shall abrogate His words, and you shall not find any other source beside it.","তুমি আবৃতি করবে তোমার প্রভুর ঐশীগ্রন্থের যাকিছু তোমার কাছে প্রকাশিত হয়। কোন কিছুই তাঁর বানীকে বাতিল/রদ করবে না, এবং এর পাশে অন্যকোন উৎস তুমি খুঁজবে না।"],
  "18:28": ["You shall force yourself to be with those who worship their Lord day and night, seeking Him alone. Do not turn your eyes away from them, seeking the vanities of this world. Nor shall you obey one whose heart we rendered oblivious to our message; one who pursues his own desires, and whose priorities are confused.","তাদের সঙ্গে থাকতে তুমি নিজেকে বাধ্য করবে যারা দিনে ও রাতে তাদের প্রভুর উপাসনা করে, একমাত্র তাঁরই খোঁজে।  তাদের কাছ থেকে মুখ ফিরিয়ে নিও না, এই বিশ্বের তুচ্ছ কিছুর খোঁজে। না তুমি সে ব্যাক্তিকে মান্য করবে আমরা যার হৃদয়কে আমাদের বার্তার প্রতি বেখবর রেখেছি; যে ব্যাক্তি তার নিজ ইচ্ছার অনুসরণ করে, যার অগ্রাধিকারগুলো বিভ্রান্তিকর।"],
  "18:29": ["Proclaim: \"This is the truth from your Lord,\" then whoever wills let him believe, and whoever wills let him disbelieve. We have prepared for the transgressors a fire that will completely surround them. When they scream for help, they will be given a liquid like concentrated acid that scalds the faces. What a miserable drink! What a miserable destiny!","ঘোষনা কর, \"এটি তোমার প্রভুর কাছ থেকে সত্য, ”এরপর যেকেউ চায় তাকে বিশ্বাস করতে দাও, এবং যেকেউ চায় তাকে অবিশ্বাস করতে দাও। আমরা সীমালঙ্ঘনকারীদের জন্য আগুন প্রস্তুত রেখেছি যা তাদেরকে পুরোপুরি ঘিরে ফেলবে। যখন তারা সাহায্যের জন্য চিৎকার করবে, তাদেরকে ঘনীভূত অম্লের মত তরল দেয়া হবে যা মুখগুলোকে ঝলসে দেবে। কি এক শোচনীয় পানীয়!  কি এক শোচনীয় নিয়তি"],
  "18:30": ["As for those who believe and lead a righteous life, we never fail to recompense those who work righteousness.","আর তাদের ক্ষেত্রে যারা বিশ্বাস করে এবং সতকর্মশীল জীবন যাপন করে, যারা সৎকর্ম করে তাদেরকে কখনো আমরা প্রতিদান দিতে ব্যর্থ হই না।"],
  "18:31": ["They have deserved gardens of Eden wherein rivers flow. They will be adorned therein with bracelets of gold, and will wear clothes of green silk and velvet, and will rest on comfortable furnishings. What a wonderful reward; what a wonderful abode!","তারা ইডেনের বাগানগুলোর যোগ্য হয়েছে যেখানে প্রবাহিত হয় নদী। সেখানে সোনার ব্রেসলেট দিয়ে তারা সাজবে, এবং পরিধান করবে সবুজ রেশম ও মখমলের কাপড়, এবং বিশ্রাম নিবে আরামদায়ক আসবাবপত্র ও সাজসরঞ্জামের মাঝে। কতই না উৎকৃষ্ট প্রতিদান; কতই না উৎকৃষ্ট আবাস!"],
  "18:32": ["Cite for them the example of two men: we gave one of them two gardens of grapes, surrounded by date palms, and placed other crops between them.","তাদের জন্য দুই জন লোকের উদাহরণ উদ্ধৃতি করোঃ আমরা তাদের একজনকে আংগুরের দুটি বাগান দিয়েছিলাম, খেজুঁর গাছে ঘেরা, এবং তাদের মাঝে ছিল অন্যান্য ফসলাদি।"],
  "18:33": ["Both gardens produced their crops on time, and generously, for we caused a river to run through them.","উভয় বাগানই তাদের ফসল ফলাত সময়মত, এবং প্রচুর পরিমানে, কারণ আমরা একটি নদীকে তাদের মধ্য দিয়ে প্রবাহিত করেছিলাম।"],
  "18:34": ["Once, after harvesting, he boastfully told his friend: \"I am far more prosperous than you, and I command more respect from the people.\"","একবার, ফসল তোলার পর, সে দম্ভভরে তার বন্ধুকে বলল, \"আমি তোমার চেয়ে অনেক বেশি সমৃদ্ধশালী, এবং আমি লোকদের থেকে অধিক সম্মানের দাবিদার।"],
  "18:35": ["When he entered his garden, he wronged his soul by saying, \"I do not think that this will ever end.","যখন সে তার বাগানে প্রবেশ করলো, সে এ বলে তার আত্মার ক্ষতি করলো, \"আমি মনে করি না যে এটা কখনো শেষ হবে।"],
  "18:36": ["\"Moreover, I think this is it; I do not think that the Hour (the Hereafter) will ever come to pass. Even if I am returned to my Lord, I will (be clever enough to) possess an even better one over there.\"","\"তাছাড়া, আমি মনে করি এটাই সব; আমি মনে করি না যে সেই ঘন্টা (পরকাল) কখনো আসবে। এমনকি আমি আমার প্রভুর কাছে ফিরলেও, ঐখানে এর চেয়েও উত্তম কিছু অধিকার করতে আমি (যথেষ্ট চতুর)  হবো।"],
  "18:37": ["His friend said to him, as he debated with him, \"Have you disbelieved in the One who created you from dust, then from a tiny drop, then perfected you into a man?","তার বন্ধু তাকে বলল, যখন সে তার সাথে বিতর্ক করছিল, \"তুমি কি সেই সত্ত্বাকে অবিশ্বাস করেছ যিনি তোমাকে সৃষ্টি করেছেন ধুলো থেকে,এরপর এক তুচ্ছ ফোটা থেকে, এরপর তোমাকে একজন পূর্ণ মানুষ হিসেবে সুগঠিত করেছেন?"],
  "18:38": ["\"As for me, Allah is my Lord, and I will never set up any other god besides my Lord.","আমার ক্ষেত্রে, আল্লাহ আমার প্রভু, এবং আমি কখনো আমার প্রভুর পাশে অন্য কোনো উপাস্য স্থাপন করবো না।"],
  "18:39": ["\"When you entered your garden, you should have said, 'This is what Allah has given me (Mã Shã Allãh). No one possesses power except Allah (Lã Quwwata Ellã Bellãh).' You may see that I possess less money and less children than you.","\"যখন তুমি তোমার বাগানে প্রবেশ কর, তোমার বলা উচিত ছিল, 'এ তো যা আল্লাহ আমাকে দিয়েছেন (মা শা আল্লাহ)। কেউই ক্ষমতা রাখে না আল্লাহ ছাড়া (লা ক্বু'য়াতা ইল্লা বিল্লাহ) ।' তুমি হয়তো দেখো যে আমি তোমার চেয়ে কম অর্থ এবং কম সন্তানের অধিকারী।"],
  "18:40": ["\"My Lord may grant me better than your garden. He may send a violent storm from the sky that wipes out your garden, leaving it completely barren.","“আমার প্রভু আমাকে হয়তো তোমার বাগানের চেয়ে উত্তম প্রদান করবেন। তিনি হয়তো আকাশ থেকে কোন তীব্র ঝড় পাঠাবেন যা তোমার বাগানকে নিশ্চিহ্ন করে দেবে, একে সম্পূর্ণ ধূলিসাৎ করে দিয়ে।"],
  "18:41": ["\"Or, its water may sink deeper, out of your reach.\"","“অথবা, হয়তো এর পানি গভীরে চলে যাবে, তোমার নাগালের বাইরে।\""],
  "18:42": ["Indeed, his crops were wiped out, and he ended up sorrowful, lamenting what he had spent on it in vain, as his property lay barren. He finally said, \"I wish I never set up my property as a god beside my Lord.\"","বাস্তবেই, তার ফসলাদি নিশ্চিহ্ন হয়েছিল, এবং শেষ পর্যন্ত সে দু:খ ভারাক্রান্ত হলো, পরিতাপ করতে থাকলো তার জন্য যা সে এর পিছনে ব্যয় করেছে অনর্থক, যেহেতু তার সম্পত্তি মরুময় হয়ে রইলো। অবশেষে সে বলল, \"আমি যদি কখনো আমার প্রভুর পাশে আমার সম্পত্তিকে উপাস্য হিসেবে স্থাপন না করতাম।\""],
  "18:43": ["No force on earth could have helped him against Allah, nor was it possible for him to receive any help.","পৃথিবীর কোন শক্তি আল্লাহর বিপক্ষে তাকে সাহায্য করতে পারলো না, না তার পক্ষে কোন সাহায্য পাওয়া সম্ভব ছিল।"],
  "18:44": ["That is because the only true Lord and master is Allah; He provides the best recompense, and with Him is the best destiny.","এটা এ কারনে যে একমাত্র সত্য প্রভু এবং মনিব হচ্ছেন আল্লাহ; তিনি সর্বোত্তম প্রতিদান দেন, এবং তাঁর কাছেই রয়েছে সর্বোত্তম নিয়তি।"],
  "18:45": ["Cite for them the example of this life as water that we send down from the sky to produce plants of the earth, then they turn into hay that is blown away by the wind. Allah is able to do all things.","তাদের জন্য এই জীবনের উদাহরণ দাও যেন পানি যা আমরা আকাশ থেকে বর্ষণ করি পৃথিবীর উদ্ভিদ উৎপন্ন করতে, এরপর এরা পরিণত হয় খড়কূটায় বাতাসে যা উড়ে যায়। আল্লাহ সবকিছু করতে সক্ষম।"],
  "18:46": ["Money and children are the joys of this life, but the righteous works provide an eternal recompense from your Lord, and a far better hope.","অর্থ এবং সন্তানাদি তো হচ্ছে এই জীবনের আনন্দ, কিন্তু সৎকর্ম তোমার প্রভুর পক্ষ থেকে প্রদান করে অনন্তকালের প্রতিদান, এবং অনেক উত্তম আশা।"],
  "18:47": ["The day will come when we wipe out the mountains, and you will see the earth barren. We will summon them all, not leaving out a single one of them.","সে দিন আসবে যখন আমরা পর্বতগুলোকে নিশ্চিহ্ন করবো, এবং পৃথিবীকে তুমি দেখবে মরুময়। আমরা তাদের সকলকে ডেকে পাঠাবো, তাদের একজনকেও ছাড়া হবে না।"],
  "18:48": ["They will be presented before your Lord in a row. You have come to us as individuals, just as we created you initially. Indeed, this is what you claimed will never happen.","তাদেরকে তোমাদের প্রভুর সামনে একটি সাড়ি করে উপস্থিত করা হবে। তোমরা আমাদের কাছে এসেছ আলাদা আলাদাভাবে, ঠিক যেভাবে আমরা প্রথম দিকে তোমাদের সৃষ্টি করেছিলাম।  প্রকৃতপক্ষে, এ তো তা-ই যা কখনো ঘটবে না বলে তোমরা দাবী করেছিলে।"],
  "18:49": ["The record will be shown, and you will see the guilty fearful of its contents. They will say, \"Woe to us. How come this book leaves nothing, small or large, without counting it?\" They will find everything they had done brought forth. Your Lord is never unjust towards anyone.","রেকর্ড দেখানো হবে, এবং তুমি অপরাধীদের দেখবে এর ভেতরকার জিনিস দেখে ভীত। তারা বলবে, \"আমাদের দুঃখ। এই বই কেমন করে কোনকিছু ছাড়ে নি, ছোট অথবা বড়, তা গননা না করে?” তারা যা কিছু করেছিল সবকিছু তারা সামনে পাবে। তাদের করা সবকিছু তারা সামনে পাবে। তোমার প্রভু কখনো কারও প্রতি অন্যায়কারী নন।"],
  "18:50": ["We said to the angels, \"Fall prostrate before Adam.\" They fell prostrate, except Satan. He became a jinn, for he disobeyed the order of His Lord. Will you choose him and his descendants as lords instead of Me, even though they are your enemies? What a miserable substitute!","আমরা ফেরেশতাদের বললাম, \"আদমের সামনে সেজদাবনত হও।” তারা সেজদাবনত হলো, শয়তান ছাড়া। সে জ্বীন হয়ে পড়লো, কারন সে তাঁর প্রভুর আদেশ অমান্য করেছিল। তোমরা কি আমার বদলে তাকে এবং তার বংশধরদের প্রভু হিসেবে পছন্দ করবে, যদিও তারা তোমাদের শত্রু? কি এক শোচনীয় প্রতিস্থাপন!"],
  "18:51": ["I never permitted them to witness the creation of the heavens and the earth, nor the creation of themselves. Nor do I permit the wicked to work in My kingdom.","আমি কখনো তাদেরকে আকাশমন্ডলী ও পৃথিবীর সৃষ্টিতে সাক্ষী হবার অনুমতি দেইনি, না দিয়েছি তাদের নিজেদের সৃষ্টিতে। না আমি মন্দকে আমার রাজত্বে কাজ করার অনুমতি দেই।"],
  "18:52": ["The day will come when He says, \"Call upon My partners, whom you claimed to be gods beside Me,\" they will call on them, but they will not respond to them. An insurmountable barrier will separate them from each other.","সে দিন আসবে যখন সে বলবে, “আমার অংশীদারদের আহবান করো, যাদেরকে তোমরা আমার পাশে উপাস্য হবার দাবি করতে।” তারা তাদেরকে ডাকবে, কিন্তু তারা তাদের প্রতি সাড়া দিবে না। এক দূর্ভেদ্য অন্তরায় তাদের পরস্পরকে আলাদা করবে।"],
  "18:53": ["The guilty will see Hell, and will realize that they will fall into it. They will have no escape therefrom.","অপরাধী নরক দেখবে, এবং বুঝবে যে তারা তাতে পতিত হবে। সেখান থেকে তাদের কোন মুক্তি থাকবে না।"],
  "18:54": ["We have cited in this Quran every kind of example, but the human being is the most argumentative creature.","আমরা এই কুরআনে সব ধরণের উদাহরণ দেই, কিন্তু মানব জাতি সবচেয়ে তর্কপ্রিয় জাঁতী।"],
  "18:55": ["Nothing prevented the people from believing, when the guidance came to them, and from seeking the forgiveness of their Lord, except that they demanded to see the same (kind of miracles) as the previous generations, or challenged to see the retribution beforehand.","কোনকিছুই লোকদের বাধাঁ দেয়নি বিশ্বাস করা থেকে, যখন তাদের কাছে পথ-নিদর্শনা আসলো, এবং দয়া অন্বেষণ করা থেকে তাদের প্রভুর, এছাড়া যে তারা পূর্ববর্তী প্রজন্মদের মত একই (রকম অলৌকিকতা) দেখার দাবি করেছিল, অথবা আগেই শাস্তি দেখার চ্যালেঞ্জ করেছিল।"],
  "18:56": ["We only send the messengers as simply deliverers of good news, as well as warners. Those who disbelieve argue with falsehood to defeat the truth, and they take My proofs and warnings in vain.","আমরা শুধু বার্তাবাহকদের পাঠাই কেবল সুসংবাদ বহনকারী হিসেবে, সেই সাথে সতর্ককারী হিসেবে। যারা অবিশ্বাস করে তারা মিথ্যা দিয়ে তর্ক করে সত্যকে পরাজিত করতে, এবং তারা আমার প্রমানাদি ও সতর্কসংকেতগুলোকে নিরর্থক নেয়।"],
  "18:57": ["Who are more evil than those who are reminded of their Lord's proofs, then disregard them, without realizing what they are doing. Consequently, we place shields on their hearts to prevent them from understanding it (the Quran), and deafness in their ears. Thus, no matter what you do to guide them, they can never ever be guided.","তাদের চেয়ে কে অধিক মন্দ যাদেরকে তাদের প্রভুর প্রমাণাদি স্মরণ করানো হয়, এরপর সেগুলো উপেক্ষা করে, তারা যা করছে তা অনুধাবন না করেই। পরিনামে, আমরা তাদের হৃদয়ের উপর আবরণ দিয়ে রাখি তাদেরকে এটি (কুরআন) বুঝতে বাধাঁ দিতে, এবং বধিরতা দেই তাদের কানে। সুতরাং, তুমি তাদেরকে পথপ্রাপ্ত করতে যাই করো না কেন, তারা কখনো কোন কালেও সুপথপ্রাপ্ত হতে পারবে না।"],
  "18:58": ["Yet, your Lord is the Forgiver, full of mercy. If He called them to account for their deeds, He would annihilate them right there and then. Instead, He gives them a respite until a specific, predetermined time; then they can never escape.","এরপরও, তোমার প্রভু ক্ষমাকারী, দয়ায় পরিপূর্ণ। যদি তিনি তাদের কাজের জন্য হিসাব নিতে তাদেরকে ডাকতেন, তিনি তাদের ঠিক তখনই ধ্বংস করতেন। পরিবর্তে, তিনি তাদেরকে একটি নির্দিষ্ট, পূর্বনির্ধারিত সময় পর্যন্ত অবকাশ দেন; এরপর তারা কখনো পালাতে পারবে না।"],
  "18:59": ["Many a community we annihilated because of their transgressions, we designated a specific time for their annihilation.","আমরা অনেক সম্প্রদায়কে ধ্বংস করেছি তাদের সীমালঙ্ঘনের কারনে, আমরা তাদের ধ্বংসের জন্য একটি নির্দিষ্ট সময় মনোনীত করেছি।"],
  "18:60": ["Moses said to his servant, \"I will not rest until I reach the point where the two rivers meet, no matter how long it takes.\"","মূসা তার ভৃত্যকে বলল, \"আমি বিশ্রাম নিবো না যতক্ষণ না আমি দু'নদীর মিলনস্থলে পৌঁছাই, এতে যতো সময়ই লাগুক না কেন।\""],
  "18:61": ["When they reached the point where they met, they forgot their fish, and it found its way back to the river, sneakily.","যখন তারা সে জায়গায় পৌঁছাল যেখানে এরা মিলেছিল, তারা তাদের মাছের কথা ভুলে গেল, এবং এটি নদীতে ফেরার পথ খুঁজে পেয়েছিল, অগচরে।"],
  "18:62": ["After they passed that point, he said to his servant, \"Let us have lunch. All this traveling has thoroughly exhausted us.\"","তারা সেই জায়গা অতিক্রম করার পর, সে তার ভৃত্যকে বলল, \"চল আমরা দুপুরের খাবার খাই। এই পুরো ভ্রমন আমাদের একেবারেই ক্লান্ত করে দিয়েছে।\""],
  "18:63": ["He said, \"Remember when we sat by the rock back there? I paid no attention to the fish. It was the devil who made me forget it, and it found its way back to the river, strangely.\"","সে বলল, \"মনে আছে কি যখন আমরা সেখানে পাথরের পাশে বসে ছিলাম? আমি মাছটির প্রতি কোন নজর দেইনি। শয়তানই তা আমাকে ভুলিয়ে দিয়েছে,  এবং এটি নদীতে ফেরার পথ খুঁজে পেয়েছিল, অদ্ভূতভাবে।\""],
  "18:64": ["(Moses) said, \"That was the place we were looking for.\" They traced their steps back.","(মুসা) বলল, \"ঐটাই ছিল সেই জায়গা যা আমরা খুঁজছিলাম।” তারা তাদের ফেলে আসা পথ ধরে ফিরে গেল।"],
  "18:65": ["They found one of our servants, whom we blessed with mercy, and bestowed upon him from our own knowledge.","তারা আমাদের বান্দাদের একজনকে পেল, যাকে আমরা দয়া দিয়ে অনুগ্রহ করেছিলাম, এবং তাকে আমাদের নিজস্ব জ্ঞান থেকে প্রদান করেছিলাম।"],
  "18:66": ["Moses said to him, \"Can I follow you, that you may teach me some of the knowledge and the guidance bestowed upon you?\"","মুসা তাকে বলল, \"আমি কি আপনার অনুসরণ করতে পারি, যাতে আপনি আপনার উপর অর্পিত জ্ঞান এবং পথ-নির্দশনার কিছু আমাকে শেখাতে পারেন?\""],
  "18:67": ["He said, \"You cannot stand to be with me.","সে বলল, \"তুমি আমার সাথে স্থির থাকতে পারবে না।"],
  "18:68": ["\"How can you stand that which you do not comprehend?\"","“কিভাবে তুমি তাতে স্থির থাকবে যা তুমি বোঝো না?”"],
  "18:69": ["He said, \"You will find me, Allah willing, patient. I will not disobey any command you give me.\"","সে বলল, “আল্লাহ চাইলে, আমাকে আপনি ধৈর্যশীল পাবেন। আমি আপনার দেয়া কোন আদেশে অবাধ্য হবো না।\""],
  "18:70": ["He said, \"If you follow me, then you shall not ask me about anything, unless I choose to tell you about it.\"","সে বলল, \"যদি তুমি আমার অনুসরণ করো, তাহলে আমাকে কোনকিছুর বিষয়ে তুমি জিজ্ঞেস করবে না, যদি না আমি তোমাকে এ বিষয়ে বলতে পছন্দ করি।”"],
  "18:71": ["So they went. When they boarded a ship, he bore a hole in it. He said, \"Did you bore a hole in it to drown its people? You have committed something terrible.\"","সুতারাং তারা চললো। যখন তারা জাহাজে আরোহন করলো, তাতে সে একটি ছিদ্র করলো। সে বলল, \"আপনি কি লোকদের ডুবানোর জন্য এতে ছিদ্র করেছেন? আপনি ভয়ানক কিছু করেছেন।\""],
  "18:72": ["He said, \"Did I not say that you cannot stand to be with me?\"","সে বলল, \"আমি কি বলিনি যে তুমি আমার সাথে স্থির থাকতে পারবে না?\""],
  "18:73": ["He said, \"I am sorry. Do not punish me for my forgetfulness; do not be too harsh with me.\"","সে বলল, \"আমি দুখিঃত। আমার ভূলো-মনার জন্য আমাকে শাস্তি দিয়েন না; আমার প্রতি এতো রূঢ় হইয়েন না।\""],
  "18:74": ["So they went. When they met a young boy, he killed him. He said, \"Why did you kill such an innocent soul, who did not kill another soul? You have committed something horrendous.\"","তাই তারা চললো। যখন তারা এক কমবয়সী বালকের সাক্ষাৎ পেল। সে বলল, কেন আপনি এমন নিষ্পাপ আত্মাকে হত্যা করলেন,  যে কিনা অন্য মানুষকে হত্যা করেনি? আপনি জঘন্যতম কিছু করেছেন।\""],
  "18:75": ["He said, \"Did I not tell you that you cannot stand to be with me?\"","সে বলল, \"আমি কি বলিনি যে তুমি আমার সাথে স্থির থাকতে পারবে না?\""],
  "18:76": ["He said, \"If I ask you about anything else, then do not keep me with you. You have seen enough apologies from me.\"","সে বলল, “আমি যদি আপনাকে আর কোনকিছু জিজ্ঞেস করি, তবে আমাকে আপনার সাথে রাখবেন না। আপনি আমার কাছ থেকে যথেষ্ঠ অনুনয় দেখেছেন।”"],
  "18:77": ["So they went. When they reached a certain community, they asked the people for food, but they refused to host them. Soon, they found a wall about to collapse, and he fixed it. He said, \"You could have demanded a wage for that!\"","সুতারাং তারা চললো। যখন তারা কোন নির্দিষ্ট সম্প্রদায়ের কাছে পৌছঁলো, তারা লোকদের নিকট খাবার চাইলো, কিন্তু তাদের আপ্যায়ন করতে তারা অস্বীকৃতি জানালো। কিছুক্ষনের মধ্যেই, তারা একটি দেয়ালকে ধ্বসে পড়ার মুখে পেল, এবং সে তা মেরামত করলো। সে বলল, “আপনি এর জন্য পারিশ্রমিক চাইতে পারতেন?”"],
  "18:78": ["He said, \"Now we have to part company. But I will explain to you everything you could not stand.","সে বলল, “এখন আমাদের সঙ্গ ত্যাগ করতে হবে। তবে, আমি তোমাকে ব্যাখ্যা দিবো সবকিছুর যাতে তুমি স্থির থাকতে পারো নি।"],
  "18:79": ["\"As for the ship, it belonged to poor fishermen, and I wanted to render it defective. There was a king coming after them, who was confiscating every ship, forcibly.","“জাহাজটির বিষয়ে, এটি ছিল দরিদ্র জেলেদের, এবং এটিকে আমি ত্রুটিপূর্ণ করতে চেয়েছিলাম। একজন রাজা তাদের পিছনে আসছিল, যে  জোরপূর্বক সব জাহাজ জব্দ করছিল।"],
  "18:80": ["\"As for the boy, his parents were good believers, and we saw that he was going to burden them with his transgression and disbelief.","বালকটির বিষয়ে, তার বাবা-মা ভাল বিশ্বাসী ছিল, এবং আমরা দেখলাম যে সে তার সীমালঙ্গন এবং অবিশ্বাসের কারণে তাদের বোঝা হতে যাচ্ছিল।"],
  "18:81": ["\"We willed that your Lord substitute in his place another son; one who is better in righteousness and kindness.","আমরা চেয়েছিলাম যে তোমার প্রভু তার জায়গায় আরেকটি পুত্র দেন; যে সৎকর্মশীলতা ও দয়ায় উত্তম হবে।"],
  "18:82": ["\"As for the wall, it belonged to two orphan boys in the city. Under it, there was a treasure that belonged to them. Because their father was a righteous man, your Lord wanted them to grow up and attain full strength, then extract their treasure. Such is mercy from your Lord. I did none of that of my own volition. This is the explanation of the things you could not stand.\"","\"দেয়ালটির বিষয়ে, এটি শহরের দুই এতিম বালকের মালিকানায় ছিল। এর নীচে, তাদের গুপ্তধন ছিল। যেহেতু তাদের পিতা ছিল একজন সৎ লোক, তোমার প্রভু চেয়েছিলেন যে তারা বড় হয়ে উঠুক এবং পূর্ণ শক্তি অর্জন করুক, এরপর তাদের গুপ্তধন বের করে আনুক। এমনই তোমার প্রভুর দয়া। আমি এগুলোর কোনকিছুই নিজের ইচ্ছায় করিনি। এটাই হচ্ছে সেসব বিষয়ের ব্যাখ্যা যাতে তুমি স্থির থাকতে পারো নি।\""],
  "18:83": ["They ask you about Zul-Qarnain. Say, \"I will narrate to you some of his history.\"","তারা যুলকারনাইনের বিষয়ে জিজ্ঞেস করে। বল, \"আমি তোমাদেরকে তার কিছু ইতিহাস বর্ণনা করবো।\""],
  "18:84": ["We granted him authority on earth, and provided him with all kinds of means.","আমরা পৃথিবীতে তাকে কর্তৃত্ব দিলাম, এবং তাকে সব ধরনের কলা-কৌশল দিলাম।"],
  "18:85": ["Then, he pursued one way.","এরপর, সে এক পথ ধরলো।"],
  "18:86": ["When he reached the far west, he found the sun setting in a vast ocean, and found people there. We said, \"O Zul-Qarnain, you can rule as you wish; either punish, or be kind to them.\"","যখন সে সুদূর পশ্চিমে পৌছঁল, সে সূর্যকে এক সুবিশাল সমুদ্রে অস্ত যেতে দেখলো, এবং সেখানে লোকদের সন্ধান পেয়েছিল। আমরা বললাম, \"হে যুলকারনাইন, তুমি তোমার ইচ্ছেমত শাসন করতে পারো, হয় শাস্তি দাও, অথবা তাদের প্রতি দয়ালু হও।"],
  "18:87": ["He said, \"As for those who transgress, we will punish them, then, when they return to their Lord, He will commit them to more retribution.","সে বলল, \"তাদের ক্ষেত্রে যারা সীমালঙ্ঘন করে, আমরা তাদের শাস্তি দিব, এরপর, যখন তারা তাদের প্রভুর কাছে ফিরে যাবে, তিনি তাদেরকে আরও অধিক শাস্তি দেবেন।"],
  "18:88": ["\"As for those who believe and lead a righteous life, they receive a good reward; we will treat them kindly.\"","\"আর যারা বিশ্বাস করে এবং সৎ-জীবন যাপন করে, তারা ভাল পুরষ্কার পায়; আমরা তাদের সাথে সদয় আচরণ করবো।\""],
  "18:89": ["Then he pursued another way.","এরপর, সে অন্য পথ ধরলো।"],
  "18:90": ["When he reached the far east, he found the sun rising on people who had nothing to shelter them from it.","যখন সে সুদূর পূবে পৌছঁল, সে সূর্যকে লোকদের উপর উদয় হতে দেখল যাদের কাছে এটি থেকে আশ্র‍য় নেয়ার কিছু ছিল না।"],
  "18:91": ["Naturally, we were fully aware of everything he found out.","স্বভাবতই, আমরা তার দেখতে পাওয়া সবকিছু সম্পর্কে পূর্ণ অবগত ছিলাম।"],
  "18:92": ["He then pursued another way.","এরপর, সে অন্য পথ ধরলো।"],
  "18:93": ["When he reached the valley between two palisades, he found people whose language was barely understandable.","যখন সে দু’টি পর্বত চূড়ার মধ্যবর্তী উপত্যকায় পৌছাঁল, সে লোকদের পেয়েছিল যাদের ভাষা সামান্যই বুঝা যেতো।"],
  "18:94": ["They said, \"O Zul-Qarnain, Gog and Magog are corruptors of the earth. Can we pay you to create a barrier between us and them?\"","তারা বলল, “হে যুলকারনাইন, ইয়াজুজ ও মাজুজ পৃথিবীতে বিপর্যয় সৃষ্টিকারি। আমরা কি আমাদের ও তাদের মাঝে দেয়াল সৃষ্টি করার জন্য তোমাকে মজুরী দিতে পারি?\""],
  "18:95": ["He said, \"My Lord has given me great bounties. If you cooperate with me, I will build a dam between you and them.","সে বলল, “আমার প্রভু আমাকে মহা প্রাচুর্য দিয়েছেন। যদি তোমরা আমার সাথে সহযোগীতা করো, আমি তোমাদের ও তাদের মাঝে বাধঁ নির্মান করবো।"],
  "18:96": ["\"Bring to me masses of iron.\" Once he filled the gap between the two palisades, he said, \"Blow.\" Once it was red hot, he said, \"Help me pour tar on top of it.\"","আমার কাছে লোহার স্তুপ নিয়ে আসো।” যখনি সে দু’টি পর্বত চূড়ার মাঝখানের খালি জায়গা পূর্ণ করলো, সে বলল, \"বাতাস দাও”। যখন তা তপ্ত লাল হলো, সে বলল, “আমাকে এর উপর পিচ ঢালতে সাহায্য করো।”"],
  "18:97": ["Thus, they could not climb it, nor could they bore holes in it.","যেন, তারা এতে চড়তে করতে না পারে, না তারা এতে গর্ত খুঁড়তে পারে।"],
  "18:98": ["He said, \"This is mercy from my Lord. When the prophecy of my Lord comes to pass, He will cause the dam to crumble. The prophecy of my Lord is truth.\"","সে বলল, “এটি আমার প্রভুর পক্ষ থেকে দয়া। যখন আমার প্রভুর ভবিষদ্বানী ঘটবে, তিনি বাধঁটিকে ভেঙে টুকরো টুকরো করে দিবেন। আমার প্রভুর ভবিষ্যদ্বানী সত্য।"],
  "18:99": ["At that time, we will let them invade with one another, then the horn will be blown, and we will summon them all together.","সেই সময়, আমরা তাদের পরস্পরকে হানা-হানি করতে দেব, এরপর শিঙায় ফুঁ দেয়া হবে, এবং আমরা তাদের সবাইকে একত্রে তলব করবো"],
  "18:100": ["We will present Hell, on that day, to the disbelievers.","আমরা নরক উপস্থাপন করবো, ওই দিন, অবিশ্বাসীদের কাছে।"],
  "18:101": ["They are the ones whose eyes were too veiled to see My message. Nor could they hear.","তারাই সেইসব লোক যাদের চোখ এতটাই আবৃত ছিল যে তারা আমার বার্তা দেখতে পারছিল না। না তারা শুনতে পারছিল।"],
  "18:102": ["Do those who disbelieve think that they can get away with setting up My servants as gods beside Me? We have prepared for the disbelievers Hell as an eternal abode.","যারা অবিশ্বাস করে তারা কি মনে করে যে আমার বান্দাদেরকে উপাস্য বানিয়ে তারা পার পেয়ে যাবে? আমরা অবিশ্বাসীদের জন্য নরককে এক চিরস্থায়ী আবাস হিসেবে প্রস্তুত করেছি।"],
  "18:103": ["Say, \"Shall I tell you who the worst losers are?","বল, “আমি কি তোমাদের বলব যে কারা সর্বাধিক ক্ষতিগ্রস্ত?"],
  "18:104": ["\"They are the ones whose works in this life are totally astray, but they think that they are doing good.\"","“তারা সেই ব্যক্তি যাদের কাজ এই জীবনে পুরোপুরি বিপথে গেছে, কিন্তু তারা মনে করে যে তারা ভাল কাজ করছে।\""],
  "18:105": ["Such are the ones who disbelieved in the revelations of their Lord and in meeting Him. Therefore, their works are in vain; on the Day of Resurrection, they have no weight.","তারা এমনই যারা তাদের প্রভুর প্রকাশনাবলিকে এবং তাঁর সাথে সাক্ষাতের বিষয়কে অবিশ্বাস করেছে। সুতরাং, তাদের কাজগুলো ব্যর্থ; পুনরুত্থান দিনে, তাদের কোন ওজন থাকবে না।"],
  "18:106": ["Their just requital is Hell, in return for their disbelief, and for mocking My revelations and My messengers.","তাদের উচিত প্রতিদান হচ্ছে নরক, তাদের অবিশ্বাসের বিনিময়ে, এবং আমার প্রকাশনাবলি ও বার্তাবাহকদের উপহাস করার কারনে।"],
  "18:107": ["As for those who believe and lead a righteous life they have deserved a blissful Paradise as their abode.","তাদের ক্ষেত্রে যারা বিশ্বাস করে ও সৎ-জীবন যাপন করে তারা তাদের বাসস্থান হিসেবে এক পরম সুখের স্বর্গোদ্যানের যোগ্য হয়েছে।"],
  "18:108": ["Forever they abide therein; they will never want any other substitute.","তারা চিরকাল সেখানে বসবাস করে; তারা কখনো অন্যকোন বিকল্প চাইবে না।"],
  "18:109": ["Say, \"If the ocean were ink for the words of my Lord, the ocean would run out, before the words of my Lord run out, even if we double the ink supply.\"","বল, “আমার প্রভুর কথার জন্য সাগর যদি কালি হয়, সাগর ফুরিয়ে যাবে, আমার প্রভুর কথা ফুরানোর আগেই, এমনকি যদি আমরা কালির পরিমান দ্বিগুণও করি।"],
  "18:110": ["Say, \"I am no more than a human like you, being inspired that your god is one god. Those who hope to meet their Lord shall work righteousness, and never worship any other god beside his Lord.\"","বল,  “আমি তোমাদের মত একজন মানুষের চেয়ে বেশি কিছু নই,  প্রত্যাদিষ্ট হয়েছি যে তোমাদের খোদা একজন। যারা তাদের প্রভুর সাথে সাক্ষাতের আশা করে তারা সৎকর্ম করবে, এবং তার প্রভুর পাশে কখনো অন্যকোন উপাস্যের উপাসনা করবে না।"],
  "19:1": ["K. H. Y. 'A. S. (Kãf Hã Yã 'Ayn Sãd)","ক. হ. উ. আ. স. (ক্বাফ হা ইয়া আইন সোয়াদ)"],
  "19:2": ["A narration about your Lord's mercy towards His servant Zachariah.","এটি তোমার প্রভুর দয়া বিষয়ে একটি বর্ণনা তাঁর বান্দা জাকারিয়ার প্রতি।"],
  "19:3": ["He called his Lord, a secret call.","সে তার প্রভুকে ডেকেছিল, গোপনে।"],
  "19:4": ["He said, \"My Lord, the bones have turned brittle in my body, and my hair is aflame with gray. As I implore You, my Lord, I never despair.","সে বলল, \"আমার প্রভু, আমার দেহের হাড়গুলো ভঙ্গুর হয়ে পড়েছে, এবং আমার চুল পেকে সাদা হয়ে গেছে। আমার প্রভু, যেহেতু আমি আপনার কাছে প্রার্থনা করি, আমি কখনো হতাশ নই।"],
  "19:5": ["\"I worry about my dependants after me, and my wife has been sterile. Grant me, from You, an heir.","আমি আমার পর আমার উপর নির্ভরশীলদের জন্য চিন্তিত, এবং আমার স্ত্রী বন্ধা হয়ে আছে। আমাকে আপনার পক্ষ থেকে একজন উত্তরাধিকারী প্রদান করুন।"],
  "19:6": ["\"Let him be my heir and the heir of Jacob's clan, and make him, my Lord, acceptable.\"","তাকে আমার উত্তরাধিকারী করুন এবং উত্তরাধিকারি করুন ইয়াকুব গোত্রের, এবং আমার প্রভু, তাকে গ্রহনযোগ্য করুন।”"],
  "19:7": ["\"O Zachariah, we give you good news; a boy whose name shall be John (Yahya). We never created anyone like him before.\"","হে যাকারিয়া, আমরা তোমাকে সুসংবাদ দিচ্ছি; একটি বালকের যার নাম হবে ইয়াহিয়া। আমরা এর আগে কখনো তার মত কাউকে সৃষ্টি করিনি।”"],
  "19:8": ["He said, \"My Lord, will I have a son despite my wife's sterility, and despite my old age?\"","সে বলল, “আমার প্রভু, আমি কি আমার স্ত্রীর বন্ধাত্য সত্ত্বেও, এবং আমার বৃদ্ধ বয়স সত্ত্বেও পুত্রসন্তান পাবো?"],
  "19:9": ["He said, \"Thus said your Lord: 'It is easy for Me to do. I created you before that, and you were nothing.'\"","তিনি বললেন, “তোমার প্রভু এমনই বলেছেন: এটি আমার জন্য করা সহজ। এর আগে তোমাকে আমি সৃষ্টি করেছি, এবং তুমি কিছুই ছিলে না।”"],
  "19:10": ["He said, \"My Lord, give me a sign.\" He said, \"Your sign is that you will not speak to the people for three consecutive nights.\"","সে বলল, “আমার প্রভু, আমাকে একটি নিদর্শন দিন।”তিনি বললেন, “তোমার নিদর্শন হচ্ছে যে তুমি পর পর তিন রাত লোকদের সাথে কথা বলবে না।”"],
  "19:11": ["He came out to his family, from the sanctuary, and signaled to them: \"Meditate (on Allah) day and night.\"","সে বেড়িয়ে আসলো তার পরিবারের কাছে, উপাসনার জায়গা থেকে, এবং তাদের সংকেত দিলঃ “(আল্লাহর) ধ্যান করো দিনে এবং রাতে।”"],
  "19:12": ["\"O John, you shall uphold the scripture, strongly.\" We endowed him with wisdom, even in his youth.","“হে ইয়াহইয়া, তুমি ঐশীগ্রন্থ আকঁড়ে থাকবে, দৃড়ভাবে।” আমরা তাকে প্রজ্ঞা দান করেছিলাম, এমনকি তার যৌবনেও।"],
  "19:13": ["And (we endowed him with) kindness from us and purity, for he was righteous.","এবং (আমরা তাকে দান করেছিলাম) আমাদের পক্ষ থেকে দয়া ও পবিত্রতা, কারণ সে ছিল সৎকর্মশীল।"],
  "19:14": ["He honored his parents, and was never a disobedient tyrant.","সে তার মাতা-পিতাকে সম্মান করতো, এবং কখনো অবাধ্য স্বেচ্ছাচারী ছিল না।"],
  "19:15": ["Peace be upon him the day he was born, the day he dies, and the day he is resurrected back to life.","তার উপর শান্তি বর্ষিত হোক যেদিন সে জন্মেছিল, যেদিন সে মারা যায়, এবং যেদিন সে জীবিত হয়ে পুনঃরুত্থিত হবে।"],
  "19:16": ["Mention in the scripture Mary. She isolated herself from her family, into an eastern location.","ঐশীগ্রন্থে মরিয়মের বিষয়ে উল্লেখ করো। সে তার পরিবার থেকে নিজেকে বিচ্ছিন্ন করেছিল, পূর্বদিকের একটি স্থানে।"],
  "19:17": ["While a barrier separated her from them, we sent to her our Spirit. He went to her in the form of a human being.","যখন একটি অন্তরায় তাদের থেকে তাকে আলাদা করলো, আমরা তার কাছে আমাদের আত্মা পাঠালাম। সে তার কাছে একজন মানুষ হিসেবে গিয়েছিল।"],
  "19:18": ["She said, \"I seek refuge in the Most Gracious, that you may be righteous.\"","সে (মরিয়ম) বলল, \"আমি পরম দয়ালুর নিকট আশ্রয় প্রার্থনা করি, যে তুমি হয়তো সৎকর্মশীল হবে।"],
  "19:19": ["He said, \"I am the messenger of your Lord, to grant you a pure son.\"","সে বলল, \"আমি তোমার প্রভুর বার্তাবাহক, তোমাকে একটি নিষ্কলুষ পুত্র সন্তান দান করতে।"],
  "19:20": ["She said, \"How can I have a son, when no man has touched me; I have never been unchaste.\"","সে বলল, \"কিভাবে আমার কোন পুত্র সন্তান হতে পারে,  যখন কোন পুরুষ আমাকে স্পর্শ করেনি; আমি কখনো অসতী ছিলাম না।\""],
  "19:21": ["He said, \"Thus said your Lord, 'It is easy for Me. We will render him a sign for the people, and mercy from us. This is a predestined matter.'\"","সে বলল, “তোমার প্রভু এমনই বলেছেন: 'এটি আমার জন্য সহজ। আমরা লোকদের জন্য তাকে করবো একটি নিদর্শন, এবং আমাদের পক্ষ থেকে দয়া। এটি একটি পূর্বনির্ধারিত বিষয়।\""],
  "19:22": ["When she bore him, she isolated herself to a faraway place.","যখন সে তাকে গর্ভে ধারণ করলো, সে নিজেকে দূরবর্তী স্থানে আড়াল করলো।"],
  "19:23": ["The birth process came to her by the trunk of a palm tree. She said, \"(I am so ashamed;) I wish I were dead before this happened, and completely forgotten.\"","একটি খেঁজুর গাছের কান্ডের পাশে তার জন্মদান প্রক্রিয়াটি ঘটলো। সে বলল, \"(আমার এতো লজ্জা হচ্ছে;) এটা ঘটার আগে যদি আমার মৃত্যু হতো, এবং পুরোপুরি বিস্মৃত হতাম।"],
  "19:24": ["(The infant) called her from beneath her, saying, \"Do not grieve. Your Lord has provided you with a stream.","(নবজাতক) তার নীচ থেকে তাকে ডাকল, এ বলে যে, \"দুঃখ করো না। তোমার প্রভু তোমাকে একটি ঝর্ণা প্রদান করেছেন।"],
  "19:25": ["\"If you shake the trunk of this palm tree, it will drop ripe dates for you.","“যদি তুমি এই খেঁজুর গাছের কান্ডে ঝাঁকি দাও, এটি তোমার জন্য পাঁকা খেঁজুড় ফেলবে।"],
  "19:26": ["\"Eat and drink, and be happy. When you see anyone, say, 'I have made a vow of silence; I am not talking today to anyone.' \"","“খাও ও পান করো, এবং সুখী হও। যখন তুমি কাউকে দেখবে, বলবে, ‘আমি মৌন থাকার প্রতিজ্ঞা করেছি; আজ আমি কারো সাথে কথা বলছি না।’”"],
  "19:27": ["She came to her family, carrying him. They said, \"O Mary, you have committed something that is totally unexpected.","সে তার পরিবারের কাছে আসলো, তাকে (ঈসা) বহন করে। তারা বলল, হে মরিয়ম, তুমি এমন  কিছু করেছো যা পুরোপুরি অপ্রত্যাশিত।"],
  "19:28": ["\"O descendant of Aaron, your father was not a bad man, nor was your mother unchaste.\"","হে হারুনের বংশধর, তোমার পিতা কোন খারাপ লোক ছিল না, না তোমার মা অসতী ছিল।\""],
  "19:29": ["She pointed to him. They said, \"How can we talk with an infant in the crib?\"","সে (মরিয়ম) তার দিকে নির্দেশ করলো। তারা বলল, \"কেমন করে কোলের শিশুর সাথে আমরা কথা বলবো?\""],
  "19:30": ["(The infant spoke and) said, \"I am a servant of Allah. He has given me the scripture, and has appointed me a prophet.","(নবজাতক কথা শুরু করল এবং) বলল, \"আমি আল্লাহর একজন সেবক। তিনি আমাকে ঐশীগ্রন্থ দিয়েছেন, এবং আমাকে একজন নবী নিযুক্ত করেছেন।"],
  "19:31": ["\"He made me blessed wherever I go, and enjoined me to observe the Contact Prayers (Salat) and the obligatory charity (Zakat) for as long as I live.","যেখানেই আমি যাই তিনি আমাকে সৌভাগ্যশালী করেছেন, এবং আমাকে আদেশ করেছেন সংযোগ প্রার্থনা (সালাত) ও বাধ্যতামূলক দান (যাকাত) পালন করতে যতদিন আমি বাঁচি।"],
  "19:32": ["\"I am to honor my mother; He did not make me a disobedient rebel.","আমাকে আমার মায়ের সম্মান করতে হবে; আমাকে তিনি (আল্লাহ) অবাধ্য বিদ্রোহী বানাননি।"],
  "19:33": ["\"And peace be upon me the day I was born, the day I die, and the day I get resurrected.\"","“এবং আমার উপর শান্তি হোক যেদিন আমি জন্মেছি, যেদিন আমি মারা যাই, এবং যেদিন আমি পুনরুত্থিত হই।\""],
  "19:34": ["That was Jesus, the son of Mary, and this is the truth of this matter, about which they continue to doubt.","সে-ই ছিল ঈসা, মরিয়ম পুত্র, এবং এটা-ই সত্য, যে বিষয়ে তারা সন্দেহ করতে থাকে।"],
  "19:35": ["It does not befit Allah that He begets a son, be He glorified. To have anything done, He simply says to it, \"Be,\" and it is.","এটা আল্লাহর সাথে মানায় না যে তিনি পুত্র সন্তান জন্ম দেন, তিনি মহিমান্বিত। কোনকিছু করতে হলে, তিনি একে শুধু বলেন, “হও, ”এবং তা হয়ে যায়।"],
  "19:36": ["He also proclaimed, \"Allah is my Lord and your Lord; you shall worship Him alone. This is the right path.\"","তিনি আরো ঘোষনা করলেন, “আল্লাহ আমার প্রভু এবং তোমাদের প্রভু; তোমরা কেবল তাঁরই উপাসনা করবে। এটাই সত্য পথ।"],
  "19:37": ["The various parties disputed among themselves (regarding the identity of Jesus). Therefore, woe to those who disbelieve from the sight of a terrible day.","(ঈসার পরিচয়ের বিষয়ে) বিভিন্ন দল নিজেদের মাঝে বিবাদ করেছে। একারণে, দূর্ভোগ তাদের প্রতি যারা এক ভয়ানক দিনের সাক্ষাতে অবিশ্বাস করে।"],
  "19:38": ["Wait till you hear them and see them when they come to face us. The transgressors on that day will be totally lost.","অপেক্ষা কর যে পর্যন্ত না তুমি তাদের শুনছো এবং দেখছো যখন তারা আমাদের মুখোমুখি হতে আসে। সীমালঙ্ঘনকারীরা ঐদিন পুরোপুরি ক্ষতিগ্রস্ত হবে।"],
  "19:39": ["Warn them about the day of remorse, when judgment will be issued. They are totally oblivious; they do not believe.","তাদেরকে অনুশোচনার দিন সম্পর্কে সতর্ক করো, যখন বিচার প্রকাশ হবে।  তারা পুরোপুরি বেখবর; তারা বিশ্বাস করে না।"],
  "19:40": ["We are the ones who inherit the earth and everyone on it; to us everyone will be returned.","আমরাই সেই সত্ত্বা যারা পৃথিবীর এবং এর সবকিছুর উত্তরাধিকার করি; আমাদের কাছেই সকলে ফিরে আসবে।"],
  "19:41": ["Mention in the scripture Abraham; he was a saint, a prophet.","ঐশীগ্রন্থে ইব্রাহিমের উল্লেখ করো; সে ছিল একজন সাধু, একজন নবী।"],
  "19:42": ["He said to his father, \"O my father, why do you worship what can neither hear, nor see, nor help you in any way?","সে তার পিতাকে বলল, \"হে আমার পিতা, কেন তুমি তার উপাসনা করো যা না পারে শুনতে, না পারেদেখতে, না তোমাকে কোনভাবে সাহায্য করতে পারে?"],
  "19:43": ["\"O my father, I have received certain knowledge that you did not receive. Follow me, and I will guide you in a straight path.","হে আমার পিতা,  আমি সুনির্দিষ্ট জ্ঞান পেয়েছি যা তুমি পাও নি। আমাকে অনুসরণ করো, এবং আমি তোমাকে সোজা পথ দেখাবো।"],
  "19:44": ["\"O my father, do not worship the devil. The devil has rebelled against the Most Gracious.","হে আমার পিতা, শয়তানের উপাসনা করো না। শয়তান পরম দয়ালুর বিরুদ্ধে বিদ্রোহ করেছে।"],
  "19:45": ["\"O my father, I fear lest you incur retribution from the Most Gracious, then become an ally of the devil.\"","হে আমার পিতা, আমার ভয় হয় পাছে তুমি পরম দয়ালু থেকে শাস্তি টেনে আনো, এরপর শয়তানের মিত্র হয়ে পড়ো।"],
  "19:46": ["He said, \"Have you forsaken my gods, O Abraham? Unless you stop, I will stone you. Leave me alone.\"","সে বলল, \"তুমি কি আমার উপাস্যদের পরিত্যাগ করছো, হে ইব্রাহিম? যদি না তুমি থামো, আমি তোমাকে পাথর মারবো। আমাকে আমার মত থাকতে দাও।"],
  "19:47": ["He said, \"Peace be upon you. I will implore my Lord to forgive you; He has been Most Kind to me.","সে বলল, \"তোমার উপর শান্তি বর্ষিত হোক। তোমার ক্ষমার জন্য আমি আমার প্রভুর কাছে মিনতি করবো; তিনি আমার প্রতি পরম দয়ালু।"],
  "19:48": ["\"I will abandon you and the gods you worship besides Allah. I will worship only my Lord. By imploring my Lord alone, I cannot go wrong.\"","আমি তোমাকে এবং আল্লাহর পাশে তোমার উপাসনা করা উপাস্যদের পরিত্যাগ করবো। আমি শুধু আমার প্রভুর উপাসনা করবো। শুধুমাত্র আমার প্রভুর কাছে প্রার্থনা করে, আমি ভুল করতে পারিনা।"],
  "19:49": ["Because he abandoned them and the gods they worshiped beside Allah, we granted him Isaac and Jacob, and we made each of them a prophet.","যেহেতু সে তাদেরকে এবং আল্লাহর পাশে তাদের উপাসনা করা উপাস্যদের পরিত্যাগ করেছিল, আমরা তাকে দিয়েছিলাম ইসহাক ও ইয়াকুব, এবং আমরা তাদের প্রত্যেককে নবী বানিয়েছিলাম।"],
  "19:50": ["We showered them with our mercy, and we granted them an honorable position in history.","আমরা তাদের প্রতি আমাদের দয়া বর্ষণ করেছিলাম, এবং আমরা তাদেরকে ইতিহাসে এক সম্মানিত স্থান দিয়েছিলাম।"],
  "19:51": ["Mention in the scripture Moses. He was devoted, and he was a messenger prophet.","ঐশীগ্রন্থে মুসার উল্লেখ করো। সে ছিল নিবেদিত, এবং সে ছিল বার্তাবাহক নবী।"],
  "19:52": ["We called him from the right side of Mount Sinai. We brought him close, to confer with him.","আমরা সিনাই পর্বতের ডান পাশ থেকে তাকে ডেকেছিলাম। আমরা তাকে নিকটে এনেছিলাম, তার সাথে পরামর্শ করতে।"],
  "19:53": ["And we granted him, out of our mercy, his brother Aaron as a prophet.","এবং আমরা তাকে দিয়েছিলাম, আমাদের দয়া থেকে, তার ভাই হারুনকে একজন নবী হিসেবে।"],
  "19:54": ["And mention in the scripture Ismail. He was truthful when he made a promise, and he was a messenger prophet.","এবং ঐশীগ্রন্থে ইসমাইলের উল্লেখ করো। সে ছিল সত্যবাদী যখন সে কোন প্রতিজ্ঞা করতো, এবং সে ছিল একজন বার্তাবাহক নবী।"],
  "19:55": ["He used to enjoin his family to observe the Contact Prayers (Salat) and the obligatory charity (Zakat); he was acceptable to his Lord.","সে তার পরিবারকে সংযোগ প্রার্থনা (সালাত) ও বাধ্যতামূলক দান (যাকাত) পালনের নির্দেশ দিত; সে ছিল তার প্রভুর কাছে গ্রহণযোগ্য।"],
  "19:56": ["And mention in the scripture Idrîs. He was a saint, a prophet.","এবং ঐশীগ্রন্থে ইদ্রিসের উল্লেখ করো। সে ছিল একজন সাধু, একজন নবী।"],
  "19:57": ["We raised him to an honorable rank.","আমরা তাকে এক সম্মানিত পদমর্যাদায় উন্নীত করেছিলাম।"],
  "19:58": ["These are some of the prophets whom Allah blessed. They were chosen from among the descendants of Adam, and the descendants of those whom we carried with Noah, and the descendants of Abraham and Israel, and from among those whom we guided and selected. When the revelations of the Most Gracious are recited to them, they fall prostrate, weeping.","এরা হচ্ছে নবীদের কয়েকজন যাদেরকে আল্লাহ অনুগ্রহ করেছিলেন। তদের পছন্দ করা হয়েছিল আদমের বংশধরদের থেকে, এবং তাদের বংশধর থেকে যাদেরকে আমরা নুহের সাথে বহন করেছিলাম, এবং ইব্রাহিম ও ইসরাইলের বংশধরদের থেকে, এবং তাদের মধ্য থেকে যাদের আমরা পথপ্রদর্শণ এবং নির্বাচিত করেছিলাম। যখন পরম দয়ালুর প্রকাশনাবলি তাদের কাছে আবৃতি করা হয়, তারা সেজদায় পড়ে কাদঁতে থাকে।"],
  "19:59": ["After them, He substituted generations who lost the Contact Prayers (Salat), and pursued their lusts. They will suffer the consequences.","তাদের পর, তিনি সে প্রজন্মদের প্রতিস্থাপন করেছিলেন যারা সংযোগ প্রার্থনা (সালাত) হারিয়েছিল, এবং তাদের লালসার পিছনে ছুটেছিল। তারা পরিনাম ভোগ করবে।"],
  "19:60": ["Only those who repent, believe, and lead a righteous life will enter Paradise, without the least injustice.","কেবল যারা অনুশোচনা করে, বিশ্বাস করে, এবং সৎকর্মশীল জীবন যাপন করে তারা স্বর্গোদ্যানে প্রবেশ করবে, সামান্যতম অবিচার ছাড়াই।"],
  "19:61": ["The gardens of Eden await them, as promised by the Most Gracious for those who worship Him, even in privacy. Certainly, His promise must come to pass.","ইডেনের বাগানগুলো তাদের জন্য অপেক্ষা করে, যেমন পরম দয়ালু অংগীকার করেছিলেন তাদের জন্য যারা তাঁর উপাসনা করে, এমনকি একাকিত্বে। নিশ্চিতভাবে, তাঁর অংগীকার অবশ্যই সংঘটিত হবে।"],
  "19:62": ["They will not hear any nonsense therein; only peace. They receive their provisions therein, day and night.","তারা সেখানে কোন আজে-বাজে কথা-বার্তা শুনবে না; কেবলই শান্তি। তারা সেখানে তাদের রিজিক পাবে, দিন ও রাতে।"],
  "19:63": ["Such is Paradise; we grant it to those among our servants who are righteous.","এমনই স্বর্গোদ্যান; আমরা আমাদের বান্দাদের মধ্য থেকে তাদের জন্য এটা মঞ্জুর করি যারা সৎকর্মশীল।"],
  "19:64": ["We do not come down except by the command of your Lord. To Him belongs our past, our future, and everything between them. Your Lord is never forgetful.","তোমার প্রভুর আদেশ ছাড়া আমরা অবতরণ করি না। তাঁর অধীনে রয়েছে আমাদের অতীত, আমাদের ভবিষ্যৎ, এবং এদের মধ্যকার সবকিছু। তোমার প্রভু কখনো ভূলেন না।"],
  "19:65": ["The Lord of the heavens and the earth, and everything between them; you shall worship Him and steadfastly persevere in worshiping Him. Do you know of anyone who equals Him?","প্রভু আকাশমণ্ডলী ও পৃথিবীর, এবং এদের মধ্যকার সবকিছুর; তোমরা তাঁর উপাসনা করবে এবং তাঁর উপাসনায় অবিচলতার সাথে অটল থাকবে। তুমি কি কাউকে জানো যে তাঁর সমান?"],
  "19:66": ["The human being asks, \"After I die, do I come back to life?\"","মানুষ জিজ্ঞেস করে, \"আমি মরে যাবার পর, আমি কি পুনরায় জীবিত হব?\""],
  "19:67": ["Did the human being forget that we created him already, and he was nothing?","মানুষ কি ভুলে যায় যে আমরা তাকে ইতোমধ্যেই সৃষ্টি করেছি, এবং সে কিছুই ছিল না?"],
  "19:68": ["By your Lord, we will certainly summon them, together with the devils, and will gather them around Hell, humiliated.","তোমার প্রভুর শপথ, আমরা অবশ্যই তাদের তলব করবো, শয়তানের সাথে একসঙ্গে, এবং নরকের চারপাশে তাদের একত্র করবো, অপদস্থ অবস্থায়।"],
  "19:69": ["Then we will pick out from each group the most ardent opponent of the Most Gracious.","এরপর আমরা প্রত্যেক দল থেকে পরম দয়ালুর সবচেয়ে ঘোর বিরোধীদের বেছে নিব।"],
  "19:70": ["We know full well those who are most deserving of burning therein.","আমরা তাদেরকে খুব ভাল করেই জানি যারা সেখানে পোড়ার সবচেয়ে উপযুক্ত।"],
  "19:71": ["Every single one of you must see it; this is an irrevocable decision of your Lord.","তোমাদের প্রত্যেকে অবশ্যই এটি দেখবে; এটা তোমার প্রভুর এক অনড় সিদ্ধান্ত।"],
  "19:72": ["Then we rescue the righteous, and leave the transgressors in it, humiliated.","এরপর আমরা সৎকর্মশীলদের উদ্ধার করবো, এবং সীমালঙ্ঘনকারীদের এতে ছেড়ে দেবো, অপদস্থ অবস্থায়।"],
  "19:73": ["When our revelations are recited to them, clearly, those who disbelieve say to those who believe, \"Which of us is more prosperous? Which of us is in the majority?\"","যখন তাদের কাছে আমাদের প্রকাশনাবলি অবৃতি করা হয়, সুস্পষ্টভাবে, যারা অবিশ্বাস করে তারা যারা বিশ্বাস করে তাদেরকে বলে, \"আমাদের মধ্যে কারা অধিক সমৃদ্ধশালী? আমাদের মধ্যে কারা সংখ্যাগরিষ্ঠ?"],
  "19:74": ["Many a generation have we annihilated before them; they were more powerful, and more prosperous.","তাদের আগে আমরা অনেক প্রজন্মকে ধ্বংস করেছি; তারা ছিল অধিক ক্ষমতাবান, এবং অধিক সমৃদ্ধশালী।"],
  "19:75": ["Say, \"Those who choose to go astray, the Most Gracious will lead them on, until they see what is promised for them—either the retribution or the Hour. That is when they find out who really is worse off, and weaker in power.\"","বল, \"যারা বিপথে যাওয়া পছন্দ করে, পরম দয়ালু তাদের পরিচালিত করবেন, যে পর্যন্ত না তারা দেখে যা তাদের অংগীকার করা হয়েছে- হয় শাস্তি নয়তো সেই ঘন্টা। ঠিক তখনই তারা দেখবে যে কে অধিকতর মন্দ অবস্থায় রয়েছে, এবং ক্ষমতায় দূর্বলতম।"],
  "19:76": ["Allah augments the guidance of those who choose to be guided. For the good deeds are eternally rewarded by your Lord, and bring far better returns.","আল্লাহ তাদের পথপ্রাপ্তি বাড়িয়ে দেন যারা পথপ্রাপ্ত হওয়া পছন্দ করে। কেননা ভাল কাজ তোমার প্রভুর দ্বারা চিরস্থায়ীভাবে পুরষ্কৃত হয়, এবং অনেক উত্তম প্রতিদান ফিরিয়ে আনে।"],
  "19:77": ["Have you noted the one who rejected our revelations then said, \"I will be given wealth and children\"?!","তুমি কি সে ব্যক্তিকে লক্ষ্য করেছ যে আমাদের প্রকাশনাবলিকে প্রত্যাখ্যান করেছিল এরপর বলল, \"আমাকে সম্পদ এবং সন্তানাদি দেয়া হবে\"?!"],
  "19:78": ["Has he seen the future? Has he taken such a pledge from the Most Gracious?","সে কি ভবিষ্যৎ দেখেছে? সে কি পরম করুণাময়ের কাছ থেকে এমন কোন অঙ্গীকার নিয়েছে?"],
  "19:79": ["Indeed, we will record what he utters, then commit him to ever-increasing retribution.","নিশ্চয়, আমরা সংরক্ষন করবো যা সে বলে, এরপর তাকে চিরবর্ধনশীল শাস্তিতে ফেলবো।"],
  "19:80": ["Then we inherit everything he possessed, and he comes back to us all alone.","এরপর আমরা তার অধিকৃত সবকিছু উত্তরাধিকার করি, এবং সে আমাদের কাছে ফিরে আসে সম্পূর্ণ একা।"],
  "19:81": ["They worship beside Allah other gods that may be of help to them.","তারা আল্লাহর পাশে অন্য উপাস্যদের উপাসনা করে যাতে তাদের সাহায্যে আসতে পারে।"],
  "19:82": ["On the contrary; they will reject their idolatry, and will be their enemies.","উলটো; তারা তাদের অপখোদা উপাসনা করাকে প্রত্যাখ্যান করবে, এবং তাদের শত্রু হয়ে যাবে।"],
  "19:83": ["Do you not see how we unleash the devils upon the disbelievers to stir them up?","তুমি কি দেখো না কিভাবে আমরা অবিশ্বাসীদের পিছনে শয়তানদের ছেড়ে দেই তাদের উত্তেজিত করতে?"],
  "19:84": ["Do not be impatient; we are preparing for them some preparation.","অধৈর্য হইও না; আমরা তাদের জন্য প্রস্তুত করছি কিছু প্রস্তুতি।"],
  "19:85": ["The day will come when we summon the righteous before the Most Gracious in a group.","সে দিন আসবে যখন আমরা পরম করুণাময়ের সামনে সৎকর্মশীলদের তলব করবো একটি দলে।"],
  "19:86": ["And we will herd the guilty to Hell, to be their eternal abode.","এবং আমরা অপরাধীদেরকে নরকের দিকে দলবদ্ধভাবে নিয়ে যাবো, তাদের চিরস্থায়ী আবাসে থাকার জন্য।"],
  "19:87": ["No one will possess the power to intercede, except those who conform to the laws of the Most Gracious.","কেউ সুপারিশ করার অধিকার রাখবে না, তারা ব্যতীত যারা পরম করুণাময়ের আইনের অনুরুপ কাজ করবে।"],
  "19:88": ["They said, \"The Most Gracious has begotten a son!\"","তারা বলল, “পরম করুনাময় পুত্র জন্ম দিয়েছেন!”"],
  "19:89": ["You have uttered a gross blasphemy.","তোমরা এক ঘোর মিথ্যাচার উচ্চারণ করেছো।"],
  "19:90": ["The heavens are about to shatter, the earth is about to tear asunder, and the mountains are about to crumble.","আকাশমণ্ডলী যেন চূর্ণ হয়ে যাবে, পৃথিবী যেন খন্ড-বিখন্ড হয়ে যাবে, এবং পর্বত যেন টুকরো টুকরো হয়ে যাবে।"],
  "19:91": ["Because they claim that the Most Gracious has begotten a son.","কারণ তারা দাবী করে যে পরম করুনাময় পুত্র জন্ম দিয়েছেন।"],
  "19:92": ["It is not befitting the Most Gracious that He should beget a son.","এটা পরম করুনাময়কে মানায় না যে তিনি পুত্র জন্ম দিবেন।"],
  "19:93": ["Every single one in the heavens and the earth is a servant of the Most Gracious.","আকাশমন্ডলী ও পৃথিবীর প্রত্যেকে পরম করুনাময়ের বান্দা।"],
  "19:94": ["He has encompassed them, and has counted them one by one.","তিনি তাদের বেষ্টন করে আছেন, এবং তাদেরকে এক এক করে গুনে রেখেছেন।"],
  "19:95": ["All of them will come before Him on the Day of Resurrection as individuals.","পুনরুত্থান দিনে তারা সকলে তাঁর সামনে আসবে, পৃথকভাবে।"],
  "19:96": ["Surely, those who believe and lead a righteous life, the Most Gracious will shower them with love.","নিশ্চয়ই, যারা বিশ্বাস করে এবং সৎ জীবন যাপন করে, পরম করুনাময় তাদের উপর ভালবাসা বর্ষণ করবেন।"],
  "19:97": ["We thus made this (Quran) elucidated in your tongue, in order to deliver good news to the righteous, and to warn with it the opponents.","আমরা এভাবে তোমার ভাষায় একে (কুরআন) সহজ করেছি, সৎকর্মশীলদের কাছে সুসংবাদ পৌঁছে দিতে, এবং প্রতিপক্ষকে এর দ্বারা সতর্ক করতে।"],
  "19:98": ["Many a generation before them we annihilated; can you perceive any of them, or hear from them any sound?","তাদের পূর্বে আমরা অনেক প্রজন্ম ধ্বংস করেছি; তুমি কি তাদের কাউকে অনুধাবন করো, অথবা তাদের কোন শব্দ শুনো?"],
  "20:1": ["T. H.","ত. হা."],
  "20:2": ["We did not reveal the Quran to you, to cause you any hardship.","তোমাকে কোন কষ্টে ফেলতে, আমরা তোমার কাছে কুরআন প্রকাশ করিনি।"],
  "20:3": ["Only to remind the reverent.","শুধুমাত্র ভক্তদের স্মরণ করাতে।"],
  "20:4": ["A revelation from the Creator of the earth and the high heavens.","পৃথিবী ও উর্ধ্ব আকাশমন্ডলীর সৃষ্টিকর্তার পক্ষ থেকে একটি প্রকাশনা।"],
  "20:5": ["The Most Gracious; He has assumed all authority.","পরম দয়ালু; তিনি সকল কর্তৃত্ব গ্রহন করেছেন।"],
  "20:6": ["To Him belongs everything in the heavens, and the earth, and everything between them, and everything beneath the ground.","আকাশমন্ডলী, ও পৃথিবীর সবকিছু, এবং এগুলোর মাঝের সবকিছু, এবং ভূপৃষ্ঠের নিম্নস্থ সবকিছু তাঁর অধীন।"],
  "20:7": ["Whether you declare your convictions (or not) He knows the secret, and what is even more hidden.","তুমি তোমার প্রত্যয় প্রকাশ করো (বা না করো) তিনি জানেন গোপন বিষয়টি, এবং যা তার চেয়েও গভীরে লুকায়িত।"],
  "20:8": ["Allah: there is no other god besides Him. To Him belong the most beautiful names.","আল্লাহ : তাঁর পাশে অন্য কোন উপাস্য নেই। সবচেয়ে সুন্দর নামগুলো তাঁরই।"],
  "20:9": ["Have you noted the history of Moses?","তুমি কি মুসার ইতিহাস লক্ষ্য করেছ?"],
  "20:10": ["When he saw a fire, he said to his family, \"Stay here. I have seen a fire. Maybe I can bring you some of it, or find some guidance at the fire.\"","যখন সে আগুন দেখল, সে তার পরিবারকে বলল, \"এখানে থাকো। আমি আগুন দেখেছি। হয়তো আমি তা থেকে তোমাদের জন্য কিছু নিয়ে আসতে পারি, অথবা আগুনের কাছে কিছু পথ-নির্দেশনা পেতে পারি।”"],
  "20:11": ["When he came to it, he was called, \"O, Moses.","যখন সে এর কাছে এলো, তাকে ডাকা হলো, \"হে, মুসা।"],
  "20:12": ["\"I am your Lord; remove your sandals. You are in the sacred valley, Tuwã.","আমি তোমার প্রভু; তোমার জুতো খুলো। তুমি পবিত্র উপত্যকা তুয়ায়।"],
  "20:13": ["\"I have chosen you, so listen to what is being revealed.","আমি তোমাকে পছন্দ করেছি, অতঃএব শুনো যা প্রকাশিত হচ্ছে।"],
  "20:14": ["\"I am Allah; there is no other god beside Me. You shall worship Me alone, and observe the Contact Prayers (Salat) to remember Me.","\"আমি আল্লাহ; আমার পাশে অন্যকোন উপাস্য নেই। তুমি কেবল আমারই উপাসনা করবে, এবং আমার স্মরনার্থে/আমাকে স্মরণ করতে সংযোগ প্রার্থণা (সালাত) পালন করবে।"],
  "20:15": ["\"The Hour (end of the world) is surely coming; I will keep it almost hidden. For each soul must be paid for its works.","সেই সময় (বিশ্বের সমাপ্তি) নিশ্চিতই আসছে; একে আমি প্রায় গোপনই রাখবো। কেননা প্রত্যেক আত্মাকে এর কাজের পাওনা অবশ্যই পেতে হবে।"],
  "20:16": ["\"Do not be diverted therefrom by those who do not believe in it— those who pursue their own opinions—lest you fall.","“তাদের দ্বারা এ থেকে বিচ্যুত হইও না যারা এতে বিশ্বাস করে না- যারা নিজেদের ধারনার অনুসরন করে - যাতে তোমার পতন না হয়।"],
  "20:17": ["\"What is this in your right hand, Moses?\"","“তোমার ডান হাতে এটা কি, মুসা?”"],
  "20:18": ["He said, \"This is my staff. I lean on it, herd my sheep with it, and I use it for other purposes.\"","সে বলল, “এটি আমার লাঠি। আমি এতে ভর দেই, এটি দিয়ে আমার ভেড়া চরাই, এবং একে আমি অন্য কাজেও ব্যবহার করি।”"],
  "20:19": ["He said, \"Throw it down, Moses.\"","তিনি বললেন, “এটি নিচে ছুড়ো,  মুসা।”"],
  "20:20": ["He threw it down, whereupon it turned into a moving serpent.","সে এটি নিচে ছুড়ঁলো, যারপর এটি পরিনত হলো একটি চলন্ত সাপে।"],
  "20:21": ["He said, \"Pick it up; do not be afraid. We will return it to its original state.","তিনি বললেন, তোলো এটা; ভয় পেয়ো না। আমরা একে এর আসল অবস্থায় ফিরিয়ে দেবো।"],
  "20:22": ["\"And hold your hand under your wing; it will come out white without a blemish; another proof.","এবং তোমার হাত তোমার বাহুর নিচে রাখো; এটি নিখুঁত সাদা হয়ে বেড়িয়ে আসবে; আরেকটি প্রমান।"],
  "20:23": ["\"We thus show you some of our great portents.","এভাবে আমরা তোমাকে আমাদের মহানিদর্শণগুলোর কিছু দেখাই।"],
  "20:24": ["\"Go to Pharaoh, for he has transgressed.\"","ফেরাউন-এর কাছে যাও, কারণ সে সীমালংঘন করেছে।”"],
  "20:25": ["He said, \"My Lord, cool my temper.","সে বলল, “আমার প্রভু, আমার মেজাজ শান্ত করুন।"],
  "20:26": ["\"And make this matter easy for me.","এবং এ বিষয়টা আমার জন্য সহজ করে দিন।"],
  "20:27": ["\"And untie a knot from my tongue.","এবং আমার মুখের জড়তা দূর করে দিন।"],
  "20:28": ["\"So they can understand my speech.","যেন তারা আমার কথা বুঝতে পারে।"],
  "20:29": ["\"And appoint an assistant for me from my family.","এবং আমার পরিবার থেকে আমার জন্য একজন সহকারী নিযুক্ত করে দিন।"],
  "20:30": ["\"My brother Aaron.","আমার ভাই হারুন।"],
  "20:31": ["\"Strengthen me with him.","তাকে দিয়ে আমাকে শক্তিশালী করুন।"],
  "20:32": ["\"Let him be my partner in this matter.","তাকে এই বিষয়ে আমার অংশীদার করুন।"],
  "20:33": ["\"That we may glorify You frequently.","যাতে আমরা প্রতিনিয়ত আপনার মহিমা প্রকাশ করতে পারি।"],
  "20:34": ["\"And commemorate You frequently.","এবং প্রতিনিয়ত আপনার স্মরণ করতে পারি।"],
  "20:35": ["\"You are Seer of us.\"","‘‘আপনি আমাদের দ্রষ্টা।’’"],
  "20:36": ["He said, \"Your request is granted, O Moses.","তিনি বললেন, “তোমার অনুরোধ মঞ্জুর করা হলো, হে মূসা।"],
  "20:37": ["\"We have blessed you another time.","আমরা তোমাকে আরেকবার অনুগ্রহ করেছিলাম।"],
  "20:38": ["\"When we revealed to your mother what we revealed.","যখন আমরা তোমার মায়ের কাছে যা প্রকাশ করার ছিল তা প্রকাশ করেছিলাম।"],
  "20:39": ["\"Saying: 'Throw him into the box, then throw him into the river. The river will throw him onto the shore, to be picked up by an enemy of Mine and an enemy of his.' I showered you with love from Me, and I had you made before My watchful eye.","এ বলে যেঃ ‘তাকে বাক্সে রাখো, এরপর তাকে নদীতে ভাসিয়ে দাও। নদী তাকে তীরে নিয়ে যাবে, আমার এবং তার একজন শত্রু তাকে তুলে নেবার জন্য।’’ আমি আমার পক্ষ থেকে তোমার প্রতি ভালোবাসা বর্ষণ করেছিলাম, এবং আমার সজাগ দৃষ্টির সামনেই আমি তোমাকে তৈরি করেছিলাম।"],
  "20:40": ["\"Your sister walked to them and said, 'I can tell you about a nursing mother who can take good care of him.' We thus returned you to your mother, that she may be happy and stop worrying. And when you killed a soul, we saved you from the grievous consequences; indeed we tested you thoroughly. You stayed years with the people of Midyan, and now you have come back in accordance with a precise plan.","“তোমার বোন তাদের কাছে গেলো এবং বলল, ‘আমি তোমাদেরকে একজন স্তন্যদানকারিনী মায়ের বিষয়ে বলতে পারি যে তার ভাল যত্ন নিতে পারবে।’ এভাবে আমরা তোমাকে তোমার মায়ের কাছে ফিরিয়ে দিলাম, যাতে সে খুশী হতে পারে এবং দুশ্চিন্তা বন্ধ করে। এবং তুমি যখন একটি আত্মাকে হত্যা করেছিলে, আমরা তোমাকে মর্মান্তিক পরিনাম থেকে রক্ষা করেছিলাম; নিশ্চয়ই আমরা তোমাকে সম্পূর্ণরূপে পরীক্ষা করেছি। তুমি মাদিয়ানের লোকদের সাথে বছরের পর বছর থেকেছো, এবং এখন তুমি ফিরে এসেছ একটি সুনির্দিষ্ট পরিকল্পনা অনুসারে।"],
  "20:41": ["\"I have made you just for Me.","আমি তোমাকে কেবল আমার জন্য গড়েছি।"],
  "20:42": ["\"Go with your brother, supported by My signs, and do not waver in remembering Me.","তোমার ভাইয়ের সাথে যাও, আমার নিদর্শনাবলির সমর্থণ নিয়ে, এবং আমার স্মরনে শৈথিল্য করো না।"],
  "20:43": ["\"Go to Pharaoh, for he transgressed.","ফেরাউনের কাছে যাও, কারণ সে সীমালংঘন করেছে।"],
  "20:44": ["\"Speak to him nicely; he may take heed, or become reverent.\"","তার সাথে সুন্দর করে কথা বল; সে হয়তো উপদেশ গ্রহন করবে, অথবা শ্রদ্ধাশীল হয়ে যাবে।”"],
  "20:45": ["They said, \"Our Lord, we fear lest he may attack us, or transgress.\"","তারা বলল, “আমাদের প্রভু, আমরা ভয় করি যে সে হয়তো আমাদের আক্রমন করবে, অথবা সীমালংঘন করবে।”"],
  "20:46": ["He said, \"Do not be afraid, for I will be with you, listening and watching.","তিনি বললেন, “ভয় পেয়ো না, কারণ আমি তোমাদের সাথে থাকবো, শুনতে এবং দেখতে থাকবো।"],
  "20:47": ["\"Go to him and say, 'We are two messengers from your Lord. Let the Children of Israel go. You must refrain from persecuting them. We bring a sign from your Lord, and peace is the lot of those who heed the guidance.","তার কাছে যাও এবং বল, \"তোমার প্রভুর পক্ষ থেকে আমরা দু'জন বার্তাবাহক। ইসরাইলের সন্তানদের যেতে দাও। তাদেরকে নিপীড়ন করা থেকে তোমাকে অবশ্যই বিরত থাকতে হবে। তোমার প্রভুর পক্ষ থেকে আমরা একটি নিদর্শন এনেছি, এবং শান্তিই তাদের নিয়তি যারা পথ- নির্দেশনায় মনোযোগ দেয়।"],
  "20:48": ["\" 'We have been inspired that the retribution will inevitably afflict those who disbelieve and turn away.' \"","“আমাদের প্রত্যাদেশ করা হয়েছে যে শাস্তি অনিবার্যভাবে আঘাত করবে তাদেরকে, যারা অবিশ্বাস করে এবং মুখ ফিরিয়ে নেয়।”"],
  "20:49": ["He said, \"Who is your Lord, O Moses.\"","সে বলল, \"কে তোমার প্রভু, হে মুসা। \""],
  "20:50": ["He said, \"Our Lord is the One who granted everything its existence, and its guidance.\"","সে বলল, “আমাদের প্রভু সেই সত্ত্বা যিনি সবকিছুকে এর অস্তিত্ব, এবং এর পথ-নির্দেশনা দান করেছেন।\""],
  "20:51": ["He said, \"What about the past generations?\"","সে বলল, “অতীত প্রজন্মের কি হবে?\""],
  "20:52": ["He said, \"The knowledge thereof is with my Lord in a record. My Lord never errs, nor does He forget.\"","সে বলল, \"তার জ্ঞান আছে আমার প্রভুর একটি নথিভুক্ত আছে। আমার প্রভু কখনো ভুল করেন না, না তিনি ভুলে যান।\""],
  "20:53": ["He is the One who made the earth habitable for you, and paved in it roads for you. And He sends down from the sky water with which we produce many different kinds of plants.","তিনিই তোমাদের জন্য পৃথিবীকে বাসযোগ্য করেছেন, এবং এতে তোমাদের জন্য রাস্তা খোদাই করে দিয়েছেন। এবং তিনি আকাশ থেকে পানি বর্ষণ করেন যা দিয়ে আমরা বহু ধরণের উদ্ভিদ উৎপন্ন করি।"],
  "20:54": ["Eat and raise your livestock. These are sufficient proofs for those who possess intelligence.","খাও এবং তোমাদের পালিত পশুদের প্রতিপালন কোর। এগুলো তাদের জন্য যথেষ্ট প্রমান যারা বুদ্ধিমত্তার অধিকারী।"],
  "20:55": ["From it we created you, into it we return you, and from it we bring you out once more.","এর থেকে আমরা তোমাদের সৃষ্টি করেছি, এর মধ্যে আমরা তোমাদের ফিরিয়ে দেবো, এবং এর থেকেই আরো একবার আমরা তোমাদের বের করে আনবো।"],
  "20:56": ["We showed him all our proofs, but he disbelieved and refused.","আমরা তাকে আমাদের সব প্রমান দেখালাম, কিন্তু সে অবিশ্বাস করলো এবং প্রত্যাক্ষান করলো।"],
  "20:57": ["He said, \"Did you come here to take us out of our land with your magic, O Moses?","সে বলল, “তুমি কি তোমার জাদু দিয়ে আমাদেরকে আমাদের দেশ থেকে নিয়ে যেতে এসেছো, হে মুসা?"],
  "20:58": ["\"We will surely show you similar magic. Therefore, set an appointment that neither we, nor you will violate; in a neutral place.\"","“আমরা অবশ্যই তোমাকে অনুরূপ জাদু দেখাবো। অতএব, সাক্ষাতের জন্য একটি সময় নির্ধারণ করো যা না আমরা, না তুমি লঙ্ঘন করবে; একটি নিরপেক্ষ স্থানে।"],
  "20:59": ["He said, \"Your appointed time shall be the day of festivities. Let us all meet in the forenoon.\"","সে বলল, \"তোমাদের নির্ধারিত সময়টি হবে উৎসবের দি্নে। চল আমরা সবাই পূর্বাহ্নে একত্রিত হই।”"],
  "20:60": ["Pharaoh summoned his forces, then came.","ফেরাউন তার বাহিনীকে তলব করলো, এরপর আসলো।"],
  "20:61": ["Moses said to them, \"Woe to you. Do you fabricate lies to fight Allah and thus incur His retribution? Such fabricators will surely fail.\"","মূসা তাদের বলল, \"দূর্ভাগ্য তোমাদের। তোমরা কি আল্লাহর সাথে লড়াই করতে মিথ্যা উদ্ভাবন করো এবং এভাবে তাঁর শাস্তি টেনে আনো? এমন মিথ্যা উদ্ভাবকেরা নিশ্চয় ব্যর্থ হবে।”"],
  "20:62": ["They disputed among themselves, as they conferred privately.","তারা নিজেদের মধ্যে বিবাদে জড়ালো, যখন তারা একান্তে পরামর্শ করছিলো।"],
  "20:63": ["They said, \"These two are no more than magicians who wish to take you out of your land with their magic, and to destroy your ideal way of life.","তারা বলল, \"এরা দু'জন যাদুকরের চেয়ে বেশি কিছু না যারা চায় তাদের যাদু দিয়ে তোমাদেরকে তোমাদের দেশ থেকে বের করে নিয়ে যেতে, এবং তোমাদের আদর্শ জীবন-ব্যবস্থা ধ্বংস করতে।"],
  "20:64": ["\"Let us agree upon one scheme and face them as a united front. The winner today will have the upper hand.\"","চল আমরা একটি পরিকল্পনায় একমত হই এবং সম্মিলিতভাবে তাদের মুখোমুখি হই। আজকের বিজয়ীর কর্তৃত্ব থাকবে।"],
  "20:65": ["They said, \"O Moses, either you throw, or we will be the first to throw.\"","তারা বলল, \"হে মুসা, হয় তুমি ছুঁড়ো, না হয় প্রথমে আমরা ছুড়ঁবো।"],
  "20:66": ["He said, \"You throw.\" Whereupon, their ropes and sticks appeared to him, because of their magic, as if they were moving.","সে বলল, \"তোমরা ছুঁড়ো। “যারপর, তাদের যাদুর কারণে তার কাছে এমন মনে হলো যেন তাদের দড়ি এবং লাঠিগুলো নড়ছিল।"],
  "20:67": ["Moses harbored some fear.","মুসা কিছুটা ভয় পেয়ে গেলো।"],
  "20:68": ["We said, \"Have no fear. You will prevail.","আমরা বললাম, “কোন ভয় করো না। তুমি বিজয়ী হবে।"],
  "20:69": ["\"Throw what you hold in your right hand, and it will swallow what they fabricated. What they fabricated is no more than the scheming of a magician. The magician's work will not succeed.\"","ছুঁড়ো, যা তুমি তোমার ডান হাতে ধরে আছো, এবং এটি গিলে ফেলবে যা তারা বানিয়েছে।  যা তারা বানিয়েছে করেছে তা যাদুকরের কলা-কৌশলের চেয়ে বেশি কিছু নয়। যাদুকরের কাজ সফল হবে না।\""],
  "20:70": ["The magicians fell prostrate, saying, \"We believe in the Lord of Aaron and Moses.\"","যাদুকরেরা সেজদায় লুটিয়ে পড়লো, এ বলে যে, \"আমরা হারুন এবং মুসার প্রভুকে বিশ্বাস করি।\""],
  "20:71": ["He said, \"Did you believe in him without my permission? He must be your chief; the one who taught you magic. I will surely sever your hands and feet on alternate sides. I will crucify you on the palm trunks. You will find out which of us can inflict the worst retribution, and who outlasts whom.\"","সে বলল, “তোমরা কি তাকে আমার অনুমতি ছাড়াই বিশ্বাস করলে? সে নিশ্চয় তোমাদের প্রধান; যে তোমাদের যাদু শিখিয়েছে। আমি অবশ্যই তোমাদের বিপরীত দিকের হাত এবং পা কেটে ফেলবো। আমি তোমাদেরকে খেজুর গাছে ক্রুশবিদ্ধ করবো। তোমরা দেখবে আমাদের মধ্যে কে নিকৃষ্ট শাস্তি আরোপ করতে পারে, এবং কে কার চেয়ে অধিক টিকে থাকে।”"],
  "20:72": ["They said, \"We will not prefer you over the clear proofs that came to us, and over the One who created us. Therefore, issue whatever judgment you wish to issue. You can only rule in this lowly life.","তারা বলল, \"আমাদের কাছে যে স্পষ্ট প্রমাণাদি এসেছে তার উপরে, এবং যেই সত্বা আমাদের সৃষ্টি করেছেন তাঁর উপর আমরা তোমাকে পছন্দ করবো না। সুতরাং, তুমি যে বিচার করতে চাও করো। তুমি শুধু এই তুচ্ছ জীবনেই শাসন করতে পারো।"],
  "20:73": ["\"We have believed in our Lord, that He may forgive us our sins, and the magic that you forced us to perform. Allah is far better and Everlasting.\"","আমরা আমাদের প্রভুতে বিশ্বাস করেছি, যাতে তিনি ক্ষমা করেন আমাদের পাপ, এবং এই যাদু যা দেখাতে তুমি আমাদের বাধ্য করেছো। আল্লাহ আরো অনেক উত্তম এবং চিরস্থায়ী।"],
  "20:74": ["Anyone who comes to his Lord guilty will incur Hell, wherein he never dies, nor stays alive.","যেকেউ তার প্রভুর কাছে অপরাধী হয়ে আসে সে টেনে আনবে নরক, যেখানে সে কখনো মরে না, না জীবিত থাকে।"],
  "20:75": ["As for those who come to Him as believers who had led a righteous life, they attain the high ranks.","আর যারা তাঁর কাছে বিশ্বাসী হিসেবে আসে, যারা কিনা সৎকর্মশীল জীবন যাপন করেছে, তারা উচ্চ পদ অর্জন করে।"],
  "20:76": ["The gardens of Eden, beneath which rivers flow, will be their abode forever. Such is the reward for those who purify themselves.","ইডেনের বাগানগুলো, যার তলদেশে নদী প্রবাহিত হয়, তাদের চিরকালের আবাস হবে। এমনই তাদের জন্য পুরষ্কার যারা নিজেদের পরিশুদ্ধ করে।"],
  "20:77": ["We inspired Moses: \"Lead My servants out, and strike for them a dry road across the sea. You shall not fear that you may get caught, nor shall you worry.\"","আমরা মুসাকে প্রত্যাদেশ করলাম: \"আমার বান্দাদের বের করে নিয়ে যেতে নেতৃত্ব দাও, এবং তাদের জন্য সাগরে আঘাত করে একটি শুকনো রাস্তা বের করো। তোমরা ভয় পাবে না যে তোমরা ধরা পড়ে যাবে, না তোমরা উদ্বিগ্ন হবে।"],
  "20:78": ["Pharaoh pursued them with his troops, but the sea overwhelmed them, as it was destined to overwhelm them.","ফেরাউন তার দল নিয়ে তাদের পিছু নিল, কিন্তু সাগর তাদের নিমজ্জিত করলো, যেমন তার নিয়তি ছিল তাদেরকে নিমজ্জিত করা।"],
  "20:79": ["Thus, Pharaoh misled his people; he did not guide them.","এভাবে, ফেরাউন তার লোকদের পথভ্রষ্ট করেছিলো; সে তাদের পথ-প্রদর্শণ করেনি।"],
  "20:80": ["O Children of Israel, we delivered you from your enemy, summoned you to the right side of Mount Sinai, and we sent down to you manna and quails.","হে ইসরাইলের সন্তানেরা, আমরা তোমাদেরকে তোমাদের শত্রু থেকে উদ্ধার করেছিলাম, তোমাদেরকে সিনাই পর্বতের ডান পাশে তলব করেছিলাম, এবং আমরা তোমাদের কাছে মান্না ও কোয়েল অবতীর্ণ করেছিলাম।"],
  "20:81": ["Eat from the good things we provided for you, and do not transgress, lest you incur My wrath. Whoever incurs My wrath has fallen.","আমরা যে ভাল জিনিস তোমাদেরকে দিয়েছি তা থেকে খাও, এবং সীমালঙ্ঘন করো না, যাতে না তোমরা আমার ক্রোধ টেনে আনো। যেকেউ আমার ক্রোধ টেনে আনে সে পতিত হয়েছে।"],
  "20:82": ["I am surely Forgiving for those who repent, believe, lead a righteous life, and steadfastly remain guided.","আমি অবশ্যই তাদের জন্য ক্ষমাশীল যারা অনুশোচনা করে, বিশ্বাস করে, সৎকর্মশীল জীবন যাপন করে, এবং দৃড়তার সাথে পথে থাকে।"],
  "20:83": ["\"Why did you rush away from your people, O Moses?\"","\"কেন তুমি তোমার লোকদের থেকে তারাহুড় করে চলে গেলে, হে মুসা?\""],
  "20:84": ["He said, \"They are close behind me. I have rushed to You my Lord, that You may be pleased.\"","সে বলল, \"তারা আমার পিছনে নিকটেই আছে। আমি আপনার কাছে ছুটে এসেছি, আমার প্রভু, যাতে আপনি খুশি হোন।\""],
  "20:85": ["He said, \"We have put your people to the test after you left, but the Samarian misled them.\"","তিনি বললেন, \"তুমি চলে আসার পর আমরা তোমার লোকদের পরীক্ষায় ফেলেছি, কিন্তু সামিরীয় ব্যক্তিটি তাদের বিভ্রান্ত করেছে।”"],
  "20:86": ["Moses returned to his people, angry and disappointed, saying, \"O my people, did your Lord not promise you a good promise? Could you not wait? Did you want to incur wrath from your Lord? Is this why you broke your agreement with me?\"","মুসা তার লোকদের কাছে ফিরে এল, রাগান্বিত ও হতাশ হয়ে, এই বলল যে, \"হে আমার লোকেরা, তোমাদের প্রভু কি তোমাদেরকে  একটি ভাল অংগীকার করেননি?  তোমরা কি অপেক্ষা করতে পারলেনা? তোমরা কি তোমাদের প্রভুর কাছ থেকে ক্রোধ টেনে আনতে চেয়েছিলে? এ কারনেই কি তোমরা আমার সাথে তোমাদের চুক্তি ভঙ্গ করেছ?"],
  "20:87": ["They said, \"We did not break our agreement with you on purpose. But we were loaded down with jewelry, and decided to throw our loads in. This is what the Samarian suggested.\"","তারা বলল, \"আমরা ইচ্ছা করে তোমার সাথে আমাদের চুক্তি ভঙ্গ করিনি। কিন্তু আমাদের গহনা আমাদের জন্য বোঝা হয়ে গিয়েছিল, এবং আমরা সিদ্ধান্ত নিলাম আমাদের বোঝাগুলো এর মধ্যে নিক্ষেপ করতে। এই পরামর্শই সামিরীয় ব্যক্তি দিয়েছিল।\""],
  "20:88": ["He produced for them a sculpted calf, complete with a calf's sound. They said, \"This is your god, and the god of Moses.\" Thus, he forgot.","সে তাদের জন্য একটি খোদাইকৃত বাছুর বানিয়েছিল, যা বাছুরের মত ডাকতে  সক্ষম ছিল। তারা বলল, “এটি তোমাদের উপাস্য, এবং মুসার উপাস্য।”এভাবে, সে ভুলে গিয়েছিল।"],
  "20:89": ["Could they not see that it neither responded to them, nor possessed any power to harm them, or benefit them?","তারা কি দেখতে পায়নি যে এটি না তাদের প্রতি সাড়া দিচ্ছিল, না এর কোন ক্ষমতা ছিল তাদের ক্ষতি করার, বা তাদের উপকার করার?"],
  "20:90": ["And Aaron had told them, \"O my people, this is a test for you. Your only Lord is the Most Gracious, so follow me, and obey my commands.\"","এবং হারুন তাদেরকে বলেছিল, \"হে আমার লোকেরা, এটি তোমাদের জন্য একটি পরীক্ষা। পরম দয়ালুই  তোমাদের একমাত্র প্রভু, তাই আমাকে অনুসরণ করো, এবং আমার আদেশ মান্য করো।”"],
  "20:91": ["They said, \"We will continue to worship it, until Moses comes back.\"","তারা বলল, “আমরা এর উপাসনা চালিয়া যাব, যতক্ষণ না মূসা ফিরে আসে”।"],
  "20:92": ["(Moses) said, \"O Aaron, what is it that prevented you, when you saw them go astray,","(মুসা) বলল, “হে হারুন, যখন তুমি তাদেরকে বিপথে যেতে দেখলে, কিসে তোমাকে বাধা দিয়েছিল,"],
  "20:93": ["\"from following my orders? Have you rebelled against me?\"","আমার নির্দেশ অনুসরণ করা থেকে? তুমি কি আমার বিরুদ্ধে বিদ্রোহ করেছ?\""],
  "20:94": ["He said, \"O son of my mother, do not pull me by my beard and my head. I was afraid that you might say, 'You have divided the Children of Israel, and disobeyed my orders.' \"","সে বলল, \"হে আমার মায়ের সন্তান, আমাকে আমার দাড়ি আর মাথা ধরে টেনো না। আমি ভয়ে ছিলাম যে তুমি হয়তো বলবে, 'তুমি ইসরাইলের সন্তানদের বিভক্ত করেছ, এবং আমার আদেশ অমান্য করেছো। ' \""],
  "20:95": ["He said, \"What is the matter with you, O Samarian?\"","সে বলল, “তোমার সমস্যা কি, হে সামারীয়?”"],
  "20:96": ["He said, \"I saw what they could not see. I grabbed a fistful (of dust) from the place where the messenger stood, and used it (to mix into the golden calf). This is what my mind inspired me to do.\"","সে বলল, “আমি দেখেছিলাম যা তারা দেখতে পাইনি। আমি সেখান থেকে এক মুঠো (ধুলো)  তুলে নিলাম যেখানে বার্তাবাহক দাড়িয়েছিল, এবং তা (স্বর্ণের বাছুরের সাথে মেশাতে) ব্যবহার করলাম। এটা  করতেই আমার মন আমাকে উদ্বুদ্ধ করেছিল।"],
  "20:97": ["He said, \"Then go, and, throughout your life, do not even come close. You have an appointed time (for your final judgment) that you can never evade. Look at your god that you used to worship; we will burn it and throw it into the sea, to stay down there forever.\"","সে বলল, “তাহলে যাও, এবং, তোমার সারাজীবনে কাছেও এসো না। (তোমার চূড়ান্ত বিচারের জন্য) তোমার একটি নির্ধারিত সময় আছে যা তুমি কখনো এড়াতে পারবে না। তোমার উপাস্যের দিকে তাকাও যেটাকে তুমি উপাসনা করতে; আমরা এটাকে পুড়িয়ে ফেলব এবং একে সাগরে নিক্ষেপ করবো, যেন তা চিরকাল সেখানে তলিয়ে থাকে।"],
  "20:98": ["Your only god is Allah; the One beside whom there is no other god. His knowledge encompasses all things.","তোমাদের একমাত্র উপাস্য আল্লাহ; সেই সত্ত্বা যারঁ পাশে অন্য কোন উপাস্য নেই। তাঁর জ্ঞান সবকিছুকে ঘিরে আছে।"],
  "20:99": ["We thus narrate to you some news from the past generations. We have revealed to you a message from us.","আমরা এভাবে তোমার কাছে অতীত প্রজন্মের কিছু সংবাদ বর্ননা করি। আমরা তোমার কাছে আমাদের পক্ষ থেকে একটি বার্তা প্রকাশ করেছি।"],
  "20:100": ["Those who disregard it will bear a load (of sins) on the Day of Resurrection.","যারা তা উপেক্ষা করে তারা পুনরুত্থান দিনে (পাপের) বোঝা বহন করবে।"],
  "20:101": ["Eternally they abide therein; what a miserable load on the Day of Resurrection!","তারা সেখানে চিরকাল বাস করে; পুনরুত্থান দিনে কি এক শোচনীয় বোঝা!"],
  "20:102": ["That is the day when the horn is blown, and we summon the guilty on that day blue.","ওটা সে দিন যখন শিঙায় ফু দেয়া হয়, এবং আমরা ঐ দিন অপরাধীদের তলব করি নীল বর্ণে।"],
  "20:103": ["Whispering among themselves, they will say, \"You have stayed (in the first life) no more than ten days!\"","নিজেদের মধ্যে ফিসফিস করে, তারা বলবে, “তোমরা (প্রথম জীবনে) দশ দিনের বেশি অবস্থান করোনি!”"],
  "20:104": ["We are fully aware of their utterances. The most accurate among them will say, \"You stayed no more than a day.\"","তারা যা বলে তা সম্পর্কে  আমরা সম্পূর্ণ অবগত। তাদের মধ্যে যে সবচেয়ে নির্ভূল সে বলবে, “তোমরা এক দিনের বেশি অবস্থান করোনি।”"],
  "20:105": ["They ask you about the mountains. Say, \"My Lord will wipe them out.","তারা তোমাকে পাহাড় সম্পর্কে জিজ্ঞেস করে। বল, “আমার প্রভু এগুলো মুছে ফেলবেন।"],
  "20:106": ["\"He will leave them like a barren, flat land.","তিনি এগুলোকে অনুর্বর, সমতল ভূমির মতো করে দিবেন।"],
  "20:107": ["\"Not even the slightest hill will you see therein, nor a dip.\"","এমনকি তুমি সেখানে সামান্যতম টিলাও দেখবে না, না কোন খাঁদ।”"],
  "20:108": ["On that day, everyone will follow the caller, without the slightest deviation. All sounds will be hushed before the Most Gracious; you will hear nothing but whispers.","ঐ দিনে, প্রত্যেকেই আহ্বানকারীকে অনুসরণ করবে, সামান্যতম বিচ্যুতি ছাড়া। পরম করুনাময়ের সামনে সব শব্দ স্থব্ধ হয়ে যাবে; তুমি ফিসফিস ছাড়া কিছু শুনতে পাবে না।"],
  "20:109": ["On that day, intercession will be useless, except for those permitted by the Most Gracious, and whose utterances conform to His will.","ঐ দিনে, সুপারিশ কোন কাজে আসবে না, তাদের ব্যতিত যারা পরুম করুনাময়ের দ্বারা অনুমোদিত, এবং যাদের কথা তাঁর ইচ্ছা মোতাবেক হয়।"],
  "20:110": ["He knows their past and their future, while none encompasses His knowledge.","তিনি তাদের অতীত এবং ভবিষ্যৎ জানেন, যখন কেউ তাঁর জ্ঞান পরিবেষ্টন করে না।"],
  "20:111": ["All faces will submit to the Living, the Eternal, and those who are burdened by their transgressions will fail.","সকল মুখমণ্ডল সমর্পণ করবে সেই জীবিত, চিরস্থায়ীর কাছে, এবং যারা তাদের সীমালংঘনের দ্বারা ভারাক্রান্ত,  তারা ব্যর্থ হবে।"],
  "20:112": ["As for those who worked righteousness, while believing, they will have no fear of injustice or adversity.","আর যারা সৎ কাজ করেছে, বিশ্বাসী অবস্থায়, তাদের কোন  অবিচার বা দুর্দশার ভয় থাকবে না।"],
  "20:113": ["We thus revealed it, an Arabic Quran, and we cited in it all kinds of prophecies, that they may be saved, or it may cause them to take heed.","আমরা এভাবে এটি প্রকাশ করেছি, একটি আরবী কুরআন, এবং আমরা এতে সব রকমের ভবিষ্যদ্বানী উদ্ধৃত করেছি, যাতে তারা রক্ষা পেতে পারে, অথবা এটি  হয়তো  তাদের উপদেশ গ্রহনের কারণ হবে।"],
  "20:114": ["Most Exalted is Allah, the only true King. Do not rush into uttering the Quran before it is revealed to you, and say, \"My Lord, increase my knowledge.\"","সবচেয়ে উচ্চে  আল্লাহ,  একমাত্র প্রকৃত রাজা। কুরআনের ব্যাপারে তাড়াহুড়া করো না তোমার কাছে এটা প্রকাশ হওয়ার আগে, এবং বলো, “আমার প্রভু, আমার জ্ঞান বৃদ্ধি করুন।”"],
  "20:115": ["We tested Adam in the past, but he forgot, and we found him indecisive.","অতীতে আমরা আদমকে পরীক্ষা করেছি, কিন্তু সে ভুলে গিয়েছিলো, এবং আমরা তাকে সিদ্ধান্তহীন/ দ্বিধান্বিত পেয়েছিলাম।"],
  "20:116": ["Recall that we said to the angels, \"Fall prostrate before Adam.\" They fell prostrate, except Satan; he refused.","স্মরণ কর যে আমরা ফেরেশতাদের বলেছিলাম, “আদমের সামনে সেজদাবনত হও।”তারা সেজদাবনত হলো, শয়তান ছাড়া; সে প্রত্যাক্ষান করলো।"],
  "20:117": ["We then said, \"O Adam, this is an enemy of you and your wife. Do not let him evict you from Paradise, lest you become miserable.","আমরা তারপর বললাম, “হে আদম, এ তোমার এবং তোমার স্ত্রীর একজন শত্রু। তাকে  তোমাদেরকে স্বর্গ থেকে তাড়াতে দিও না, পাছে তোমরা দুর্দশাগ্রস্থ হয়ে পড়ো।"],
  "20:118": ["\"You are guaranteed never to hunger therein, nor go unsheltered.","তোমাদের নিশ্চয়তা দেয়া হল যে সেখানে কখনো ক্ষুধার্থ হবে না, না আশ্রয়হীন হবে।"],
  "20:119": ["\"Nor will you thirst therein, nor suffer from any heat.\"","না তোমরা সেখানে পিপাসার্ত হবে, না কোনরকম গরমে কষ্ট পাবে।'"],
  "20:120": ["But the devil whispered to him, saying, \"O Adam, let me show you the tree of eternity and unending kingship.\"","কিন্তু শয়তান তার কাছে ফিসফিসিয়ে বলল, \"হে আদম, চল আমি তোমাকে অমরত্ব এবং অন্তহীন রাজত্বের গাছটি দেখাই।\""],
  "20:121": ["They ate from it, whereupon their bodies became visible to them, and they tried to cover themselves with the leaves of Paradise. Adam thus disobeyed his Lord, and fell.","তারা তা থেকে খেলো, যারপর তাদের দেহ তাদের কাছে দৃশ্যমান হয়ে পড়লো, এবং তারা স্বর্গের পাতা দিয়ে নিজেদের ঢাকার চেষ্টা করলো। আদম এভাবে তার প্রভুকে অমান্য করলো, এবং পতিত হলো।"],
  "20:122": ["Subsequently, his Lord chose him, redeemed him, and guided him.","পরবর্তীতে, তার প্রভু তাকে মনোনীত  করলেন, তাকে উদ্ধার করলেন, এবং তাকে পথ দেখালেন।"],
  "20:123": ["He said, \"Go down therefrom, all of you. You are enemies of one another. When guidance comes to you from Me, anyone who follows My guidance will not go astray, nor suffer any misery.","তিনি বললেন, \"এখান থেকে নেমে যাও, তোমরা সবাই। তোমরা একে অপরের শত্রু। আমার কাছ থেকে তোমাদের নিকট যখন পথ-নির্দেশনা আসে, যেকেউ আমার পথ-নির্দেশনা অনুসরণ করবে সে বিপথে যাবে না, না কোন দুর্দশা ভোগ করবে।"],
  "20:124": ["\"As for the one who disregards My message, he will have a miserable life, and we resurrect him, on the Day of Resurrection, blind.\"","আর যে-ই আমার বার্তা উপেক্ষা করবে, তার থাকবে দুর্দশাময় জীবন, এবং আমরা তাকে পুনরুত্থিত করবো, পুনরুত্থান দিনে, অন্ধ অবস্থায়।\""],
  "20:125": ["He will say, \"My Lord, why did you summon me blind, when I used to be a seer?\"","সে বলবে, \"আমার প্রভু, কেন আপনি আমাকে অন্ধ করে তলব করলেন, যখন আমি চক্ষুষ্মান ছিলাম?\""],
  "20:126": ["He will say, \"Because you forgot our revelations when they came to you, you are now forgotten.\"","তিনি বলবেন, \"কারণ তুমি আমাদের প্রকাশনাবলি ভুলে গিয়েছিলে যখন সেগুলো তোমার কাছে এসেছিল, এখন তোমাকে ভুলে যাওয়া হয়েছে।\""],
  "20:127": ["We thus requite those who transgress and refuse to believe in the revelations of their Lord. The retribution in the Hereafter is far worse and everlasting.","এভাবে আমরা তাদেরকে  প্রতিফল দেই, যারা সীমালঙ্ঘন করে এবং তোমার প্রভুর প্রকাশনাবলি বিশ্বাস করতে প্রত্যাখ্যান করে। পরকালের শাস্তি আরও অধিক মন্দ এবং চিরস্থায়ী।"],
  "20:128": ["Does it ever occur to them how many previous generations we have annihilated? They are now walking in the homes of those before them. These are signs for those who possess intelligence.","তারা কি কখনো এটা উপলব্ধি করে যে, আমরা পূর্ববর্তী কতগুলো প্রজন্ম ধ্বংস করে দিয়েছি? তারা এখন  তাদের বাড়ি-ঘরে বিচরন করছে, যারা তাদের পূর্বে ছিল। এগুলো তাদের জন্য নিদর্শন, যারা বুদ্ধিমত্তার অধিকারী।"],
  "20:129": ["If it were not for your Lord's predetermined plan, they would have been judged immediately.","যদি এটা তোমার প্রভুর পূর্বনির্ধারিত পরিকল্পনার কারণে না হতো, তবে তৎক্ষণাৎ তাদের বিচার করা হতো।"],
  "20:130": ["Therefore, be patient in the face of their utterances, and praise and glorify your Lord before sunrise and before sunset. And during the night glorify Him, as well as at both ends of the day, that you may be happy.","অতএব, তাদের কথার মুখে ধৈর্য ধরো, এবং তোমার প্রভুর প্রশংসা এবং  মহিমা ঘোষণা করো সূর্যোদয়ের আগে এবং সূর্যাস্তের আগে। এবং রাতে তাঁর মহিমা ঘোষণা করো, সেই সাথে দিনের দুই প্রান্তে, যাতে তুমি সুখী হতে পারো।"],
  "20:131": ["And do not covet what we bestowed upon any other people. Such are temporary ornaments of this life, whereby we put them to the test. What your Lord provides for you is far better, and everlasting.","এবং তাতে লোভ করো না যা আমরা অন্য লোকেদের দান করেছি। এমনই এই জীবনের অস্থায়ী অলংকার, যা দিয়ে আমরা তাদের পরীক্ষায় ফেলি। যা তোমার প্রভু তোমার জন্য প্রদান করেন, তা অনেক উত্তম, এবং চিরস্থায়ী।"],
  "20:132": ["You shall enjoin your family to observe the contact prayers (Salat), and steadfastly persevere in doing so. We do not ask you for any provisions; we are the ones who provide for you. The ultimate triumph belongs to the righteous.","তুমি তোমার পরিবারকে সংযোগ প্রার্থনা (সালাত) পালন করতে নির্দেশ দেবে, এবং তা করতে দৃঢ়ভাবে অবিচল থাকবে। আমরা তোমার কাছে কোন জীবিকা চাই না; আমরাই তোমার জন্য প্রদান করি। চুড়ান্ত বিজয় সৎকর্মশীলদের।"],
  "20:133": ["They said, \"If he could only show us a miracle from his Lord!\" Did they not receive sufficient miracles with the previous messages?","তারা বলল, \"সে যদি কেবল তার প্রভুর পক্ষ থেকে আমারদেরকে কোন অলৌকিক কিছু দেখাতে পারতো!”আগের বার্তাগুলোর সাথে তারা কি যথেষ্ট অলৌকিকতা পায়নি?"],
  "20:134": ["Had we annihilated them before this, they would have said, \"Our Lord, had You sent a messenger to us, we would have followed Your revelations, and would have avoided this shame and humiliation.\"","আমরা যদি এর আগেই তাদের ধ্বংস করে দিতাম, তারা বলত, \"আমাদের প্রভু, আপনি যদি আমাদের কাছে কোন বার্তাবাহক পাঠাতেন, আমরা তাহলে আপনার প্রকাশনাবলি অনুসরণ করতাম, এবং এই লজ্জা ও অপদস্থতা এড়াতে পারতাম।"],
  "20:135": ["Say, \"All of us are waiting, so wait; you will surely find out who are on the correct path, and who are truly guided.\"","বল, \"আমরা সবাই অপেক্ষা করছি, সুতরাং অপেক্ষা করো; তোমরা নিশ্চয় দেখবে, কারা সঠিক পথে আছে, এবং কারা সত্যই পথপ্রাপ্ত।"],
  "21:1": ["Fast approaching is the reckoning for the people, but they are oblivious, averse.","দ্রুত ঘনিয়ে আসছে লোকদের জন্য হিসাব গ্রহনের সময়, কিন্তু তারা বেখবর, বিমুখ।."],
  "21:2": ["When a proof comes to them from their Lord, that is new, they listen to it heedlessly.","যখন তাদের প্রভুর পক্ষ থেকে তাদের কাছে কোন প্রমান আসে, যা নতুন, তারা তা শুনে অমনোযোগী হয়ে।"],
  "21:3": ["Their minds are heedless. And the transgressors confer secretly: \"Is he not just a human being like you? Would you accept the magic that is presented to you?\"","তাদের মন অমনোযোগী। এবং সীমালংঘনকারীরা গোপনে পরামর্শ করেঃ “সে কি তোমাদের মতই একজন মানুষ নয়? যে যাদু তোমাদের কাছে উপস্থাপন করা হয়েছে তোমরা কি তা গ্রহন করবে?"],
  "21:4": ["He said, \"My Lord knows every thought in the heaven and the earth. He is the Hearer, the Omniscient.\"","সে বলল, “আমার প্রভু আকাশ এবং পৃথিবীতে প্রতিটি চিন্তা সম্পর্কে অবগত। তিনি শ্রোতা, সর্বজ্ঞ।”"],
  "21:5": ["They even said, \"Hallucinations,\" \"He made it up,\" and, \"He is a poet. Let him show us a miracle like those of the previous messengers.\"","তারা এমনকি বলল, “দৃষ্টিভ্রম, ” “সে এটা  বানিয়েছে,”এবং, “সে একজন কবি। সে আগের বার্তাবাহকদের মতো আমাদের কাছে কোন অলৌকিকতা  প্রদর্শন করুক।”"],
  "21:6": ["We never annihilated a believing community in the past. Are these people believers?","অতীতে  আমরা কখনো  কোন বিশ্বাসী সম্প্রদায়কে ধ্বংস করিনি। এই লোকেরা কি বিশ্বাসী?"],
  "21:7": ["We did not send before you except men whom we inspired. Ask those who know the scripture, if you do not know.","আমরা তোমার আগে মানুষ ছাড়া কারো কাছে প্রত্যাদেশ দিয়ে পাঠাইনি। তাদের জিজ্ঞেস করো যারা ঐশীগ্রন্থ জানে, যদি তোমরা না জানো।"],
  "21:8": ["We did not give them bodies that did not eat, nor were they immortal.","আমরা তাদের এমন দেহ দেইনি যা খাওয়া-দাওয়া করতো না, না তারা অমর ছিল।"],
  "21:9": ["We fulfilled our promise to them; we saved them together with whomever we willed, and annihilated the transgressors.","তাদের প্রতি আমরা আমাদের অঙ্গীকার পূর্ণ করেছিলাম;  আমরা তাদের  রক্ষা করেছি,  যাদেরকে আমরা চেয়েছি তাদের সাথে, এবং সীমালঙ্ঘনকারীদের ধ্বংস করে দিয়েছিলাম।"],
  "21:10": ["We have sent down to you a scripture containing your message. Do you not understand?","আমরা তোমাদের কাছে তোমাদের বার্তা সংবলিত একটি ঐশীগ্রন্থ অবতীর্ণ করেছি। তোমারা কি বোঝো না?"],
  "21:11": ["Many a community we terminated because of their transgression, and we substituted other people in their place.","আমরা অনেক সম্প্রদায়কে তাদের সীমালঙ্ঘনের কারণে শেষ করে দিয়েছিলাম, এবং আমরা তাদের জায়গায় অন্য লোকদের প্রতিস্থাপন করেছিলাম।"],
  "21:12": ["When our requital came to pass, they started to run.","যখন আমাদের প্রতিফল আসলো, তারা দৌড়ানো শুরু করলো।"],
  "21:13": ["Do not run, and come back to your luxuries and your mansions, for you must be held accountable.","দৌড়িও না, এবং তোমাদের বিলাসিতা ও অট্রালিকায় ফিরে আসো, কারন অবশ্যই তোমাদের হিসাব নেয়া হবে।"],
  "21:14": ["They said, \"Woe to us. We were really wicked.\"","তারা বলল, “দুর্ভাগ্য আমাদের, আমরা আসলেই অন্যায়কারী ছিলাম”।"],
  "21:15": ["This continued to be their proclamation, until we completely wiped them out.","তাদের এই ঘোষনাই অব্যাহত ছিল, যতক্ষণ না আমরা তাদেরকে পুরোপুরি ধ্বংস করে দিয়েছিলাম।"],
  "21:16": ["We did not create the heavens and the earth, and everything between them just for amusement.","আমরা আকাশমন্ডলী ও পৃথিবী, এবং তাদের মধ্যকার সবকিছু শুধুমাত্র আমোদ-প্রমোদের জন্য তৈরি করিনি।"],
  "21:17": ["If we needed amusement, we could have initiated it without any of this, if that is what we wanted to do.","যদি আমাদের আমোদ-প্রমোদের দরকার হতো, আমরা এগুলোর কোনকিছু ছাড়াই তা শুরু করতে পারতাম, যদি তা-ই আমরা করতে চাইতাম।"],
  "21:18": ["Instead, it is our plan to support the truth against falsehood, in order to defeat it. Woe to you for the utterances you utter.","বরং,  সত্যকে  সমর্থন করাই আমাদের পরিকল্পনা মিথ্যার উপর, একে পরাজিত করার উদ্দেশ্যে।  দুর্ভোগ তোমাদের প্রতি  তোমাদের বলা কথার জন্য।"],
  "21:19": ["To Him belongs everyone in the heavens and the earth, and those at Him are never too arrogant to worship Him, nor do they ever waver.","আকাশমণ্ডলী ও পৃথিবীর সকলেই তাঁর, এবং তাঁর কাছে যারা রয়েছে তারা কখনো এতোটা উদ্ধত নয় যে তাঁকে উপাসনায করবে না,  না তারা কখনো দ্বিধান্বিত করে/ গড়ি-মসি করে।"],
  "21:20": ["They glorify night and day, without ever tiring.","তারা রাত-দিন মহিমা প্রকাশ করে, কখনো ক্লান্ত না হয়ে।"],
  "21:21": ["Have they found gods on earth who can create?","তারা কি পৃথিবীতে কোন উপাস্য পেয়েছে যারা সৃষ্টি করতে পারে?"],
  "21:22": ["If there were in them (the heavens and the earth) other gods beside Allah, there would have been chaos. Glory be to Allah; the Lord with absolute authority. He is high above their claims.","যদি এগুলোর (আকাশমন্ডলী ও পৃথিবীর) মধ্যে আল্লাহর পাশে অন্য উপাস্য থাকতো, সেখানে বিশৃঙ্খলা হতো। মহিমা আল্লাহর; পরম কর্তৃত্বময় প্রভু। তিনি তাদের দাবীর অনেক উর্ধ্বে।"],
  "21:23": ["He is never to be asked about anything He does, while all others are questioned.","তিনি যা করেন তার কোনকিছু সম্পর্কে তিনি কখনই জিজ্ঞাসিত হবার নন, যেখানে অন্য সকলে প্রশ্ন করা হবে।"],
  "21:24": ["Have they found other gods beside Him? Say, \"Show me your proof. This is the message to my generation, consummating all previous messages.\" Indeed, most of them do not recognize the truth; this is why they are so hostile.","তারা কি তাঁর পাশে অন্য উপাস্যদের পেয়েছে? বল, \"আমাকে তোমাদের প্রমান দেখাও।\" এটি আমার প্রজন্মের প্রতি, পূর্ববর্তী সকল বার্তার সুসম্পন্নকারী একটি বার্তা। নিশ্চয়,  তাদের অধিকাংশই সত্য চিনে না, একারনেই তারা এতো শত্রুভাবাপন্ন।"],
  "21:25": ["We did not send any messenger before you except with the inspiration: \"There is no god except Me; you shall worship Me alone.\"","আমরা তোমার আগে কোন বার্তাবাহক পাঠাইনি এই প্রত্যাদেশ ছাড়া যে: “আমি ছাড়া অন্যকোন উপাস্য নেই; তোমরা শুধু আমারই উপাসনা করবে।\""],
  "21:26": ["Yet, they said, \"The Most Gracious has begotten a son!\" Glory be to Him. All (messengers) are (His) honored servants.","এরপরও, তারা বলল, \"পরম করুনাময় পুত্র সন্তান জন্ম দিয়েছেন!” মহিমা তাঁরই। সকল (বার্তাবাহক তাঁর) সম্মানিত বান্দা।"],
  "21:27": ["They never speak on their own, and they strictly follow His commands.","তারা কখনো নিজ থেকে  কিছু বলে না, এবং তারা যথাযথভাবে তাঁর আদেশ অনুসরণ করে।"],
  "21:28": ["He knows their future and their past. They do not intercede, except for those already accepted by Him, and they are worried about their own necks.","তিনি তাদের অতীত এবং তাদের ভবিষ্যৎ জানেন। তারা সুপারিশ করে না, তাদের ব্যতীত যারা তাঁর দ্বারা ইতিপূর্বেই স্বীকৃত হয়েছে, এবং তারা তাদের নিজেদের ব্যাপারেই চিন্তিত।"],
  "21:29": ["If any of them claims to be a god beside Him, we requite him with Hell; we thus requite the wicked.","যদি তাদের কেউ তাঁর পাশে কোন উপাস্য হবার দাবি করে, আমরা নরক দিয়ে তার প্রতিফল দেই; আমরা এভাবে পাপীদের প্রতিফল দেই।"],
  "21:30": ["Do the unbelievers not realize that the heaven and the earth used to be one solid mass that we exploded into existence? And from water we made all living things. Would they believe?","অবিশ্বাসীরা কি অঅনুধাবন করে না যে আকাশমন্ডলী ও পৃথিবী একটি নিরেট ভর হয়ে ছিল যার বিস্ফোরণ ঘটিয়ে আমরা অস্তিত্বে এনেছি এবং পানি থেকে আমরা সকল জীবন্ত জিনিস তৈরি করেছি। তারা কি বিশ্বাস করবে?"],
  "21:31": ["And we placed on earth stabilizers, lest it tumbles with them, and we placed straight roads therein, that they may be guided.","এবং আমরা পৃথিবীতে ভারসাম্যকারী স্থাপন করেছি, পাছে তা তোমাদের নিয়ে উলটে পড়ে, এবং আমরা সেখানে সোজা রাস্তা স্থাপন করেছি, যাতে তারা পথ-নির্দেশনা পায়।"],
  "21:32": ["And we rendered the sky a guarded ceiling. Yet, they are totally oblivious to all the portents therein.","এবং আমরা আকাশকে একটি  সুরক্ষিত ছাদ করেছি। এরপরও, তারা সেখানের সব নিদর্শনের প্রতি পুরোপুরি বেখেয়াল।"],
  "21:33": ["And He is the One who created the night and the day, and the sun and the moon; each floating in its own orbit.","এবং তিনিই সেই সত্ত্বা যিনি সৃষ্টি করেছেন রাত ও দিন, এবং সূর্য ও চাঁদ; প্রত্যেকেই নিজ নিজ কক্ষপথে ভাসছে।"],
  "21:34": ["We never decreed immortality for anyone before you; should you die, are they immortal?","তোমার আগে আমরা কখনো  কারো জন্য অমরত্বের নিয়ম করিনি; তোমার মৃত্যু হলে, তারা কি অমর?"],
  "21:35": ["Every soul will taste death, after we put you to the test through adversity and prosperity, then to us you ultimately return.","প্রতিকূলতা এবং সমৃদ্ধির মাধ্যমে আমরা তোমাদের পরীক্ষায় ফেলবার পর, প্রত্যেক আত্মা মৃত্যু আস্বাদন করবে, পরিশেষে আমাদের কাছে তোমরা ফিরে আসো।"],
  "21:36": ["When those who disbelieve see you, they ridicule you: \"Is this the one who challenges your gods?\" Meanwhile, they remain totally heedless of the message from the Most Gracious.","যারা অবিশ্বাস করে তারা যখন তোমাকে দেখে, তারা তোমাকে নিয়ে উপহাস করে: \"এই কি  সে, যে তোমাদের উপাস্যদের চ্যালেঞ্জ করে? \"এদিকে, তারা পরম দয়ালুর বার্তায় পুরোপুরি অমনোযোগী থাকে।"],
  "21:37": ["The human being is impatient by nature. I will inevitably show you My signs; do not be in such a hurry.","মানুষ স্বভাবগতভাবে অধৈর্য। আমি অনিবার্যভাবে তোমাদেরকে আমার নিদর্শন দেখাব; এমন তাড়াহুড়ায় থেকো না।"],
  "21:38": ["They challenge: \"Where is that (retribution), if you are truthful?\"","তারা চ্যালেঞ্জ করে: \"কোথায় সেই (শাস্তি), যদি তোমরা সত্যবাদী হও?”"],
  "21:39": ["If only those who disbelieve could envision themselves when they try to ward off the fire; off their faces and their backs! No one will help them then.","যারা অবিশ্বাস করে তারা যদি শুধু তাদের নিজেদেরকে দেখতে পেত যখন তারা আগুন সরাতে চেষ্টা করে, তাদের মুখ এবং তাদের পিঠ থেকে ! কেউই তখন তাদের সাহায্য করবে না।"],
  "21:40": ["Indeed, it will come to them suddenly, and they will be utterly stunned. They can neither avoid it, nor can they receive any respite.","নিশ্চয়, এটি তাদের কাছে হঠাৎ আসবে, এবং তারা একেবারে হতভম্ব হয়ে পড়বে। না  তারা সেটা এড়াতে পারবে, না তারা কোন অবকাশ পাবে।"],
  "21:41": ["Messengers before you have been ridiculed, and, consequently, those who ridiculed them incurred the retribution for their ridiculing.","তোমার পূর্বেও বার্তাবাহকদের উপহাস করা হয়েছে, এবং, পরিনামে, যারা তাদের নিয়ে উপহাস করেছে তারা তাদের  উপহাসের জন্য শাস্তি টেনে এনেছে।"],
  "21:42": ["Say, \"Who can protect you from the Most Gracious during the night or during the day?\" Indeed, they are totally oblivious to the message of their Lord.","বল, \"কে তোমাদের পরম দয়ালুর কাছ থেকে রক্ষা করতে পারবে রাতে অথবা দিনে? নিশ্চয়,  তারা তাদের প্রভুর বার্তার প্রতি পুরোপুরি বেখবর।"],
  "21:43": ["Do they have gods who can protect them from us? They cannot even help themselves. Nor can they accompany one another when they are summoned to face us.","তাদের কাছে কি উপাস্যরা আছে যারা আমাদের  কাছ থেকে তাদের বাচাঁতে পারে? তারা এমনকি তাদের নিজেদেরকেও সাহায্য করতে পারে না। না তারা একে অন্যের সঙ্গ পাবে যখন তাদেরকে আমাদের মুখোমুখি হবার জন্য একত্রিত করা হবে।"],
  "21:44": ["We have provided for these people and their ancestors, up until an old age. Do they not see that every day on earth brings them closer to the end? Can they reverse this process?","এইসব লোকদের এবং তাদের পূর্বপুরুষদের জন্য আমরা জীবিকা প্রদান করেছি, বুড়ো বয়স পর্যন্ত। তারা কি দেখে না যে পৃথিবীর প্রত্যেকটি দিন তাদেরকে সমাপ্তির কাছে নিয়ে যায়? তারা কি এই প্রক্রিয়া উল্টাতে পারে?"],
  "21:45": ["Say, \"I am warning you in accordance with divine inspiration.\" However, the deaf cannot hear the call, when they are warned.","বল, \"আমি তোমাদেরকে সতর্ক করছি ঐশ্বরিক প্রত্যাদেশ অনুসারে।” কিন্তু, বধির ব্যক্তি ডাক শুনতে পারে না, যখন তাদের সতর্ক করা হয়।"],
  "21:46": ["When a sample of your Lord's retribution afflicts them, they readily say, \"We were indeed wicked.\"","যখন তোমার প্রভুর শাস্তির একটি নমুনা তাদের আঘাত করে, তারা অবলীলায় বলে, “আমরা আসলেই মন্দ ছিলাম”।"],
  "21:47": ["We will establish the scales of justice on the Day of Resurrection. No soul will suffer the least injustice. Even the equivalent of a mustard seed will be accounted for. We are the most efficient reckoners.","আমরা পুনরুত্থান দিনে বিচারের দাঁড়িপাল্লা স্থাপন করবো। কোন আত্মাই সামান্যতম অবিচার ভোগ করবে না। এমনকি একটি সরিষা বীজের সমতুল্য পরিমানেরও হিসাব নেয়া হবে। আমরা সবচেয়ে দক্ষ হিসাব গ্রহণকারী।"],
  "21:48": ["We gave Moses and Aaron the Statute Book, a beacon, and a reminder for the righteous.","আমরা মূসা এবং হারুনকে দিয়েছিলাম বিধান গ্রন্থ, একটি আলোকবর্তিকা, এবং একটি স্মারক সৎকর্মপরায়নদের জন্য।"],
  "21:49": ["The ones who reverence their Lord, even when alone in their privacy, and they worry about the Hour.","যারা তাদের প্রভুকে ভক্তি  করে, এমনকি তাদের একাকীত্বে, এবং তারা সেই ঘন্টার ব্যাপারে উদ্বিগ্ন।"],
  "21:50": ["This too is a blessed reminder that we sent down. Are you denying it?","এটিও একটি বরকতময় স্মারক যা আমরা অবতীর্ণ করেছি। তোমরা কি একে প্রত্যাখ্যান করছো?"],
  "21:51": ["Before that, we granted Abraham his guidance and understanding, for we were fully aware of him.","তার আগে, আমরা ইব্রাহিমকে তার পথ-নির্দেশনা এবং বুঝার ক্ষমতা প্রদান করেছিলাম, কারণ আমরা তার বিষয়ে পুরোপুরি অবগত ছিলাম।"],
  "21:52": ["He said to his father and his people, \"What are these statues to which you are devoting yourselves?\"","সে তার পিতাকে এবং তার লোকদের বলল, \"কি এই মূর্তিগুলো যেগুলোর প্রতি তোমরা নিজেদের উৎসর্গ করছো?\""],
  "21:53": ["They said, \"We found our parents worshiping them.\"","তারা বলল, \"আমরা আমাদের পিতা-মাতাদের দেখেছি এদের উপাসনা করতে।\""],
  "21:54": ["He said, \"Indeed, you and your parents have gone totally astray.\"","সে বলল, \"নিশ্চয়, তোমরা এবং তোমাদের পিতা-মাতারা পুরোপুরি পথভ্রষ্ট হয়েছো।\""],
  "21:55": ["They said, \"Are you telling us the truth, or are you playing?\"","তারা বলল, \"তুমি কি আমাদের সত্য বলছো, নাকি তামাশা করছো?\""],
  "21:56": ["He said, \"Your only Lord is the Lord of the heavens and the earth, who created them. This is the testimony to which I bear witness.","সে বলল, \"তোমাদের একমাত্র প্রভু হচ্ছেন আকাশমন্ডলী এবং পৃথিবীর প্রভু, যিনি তাদের সৃষ্টি করেছেন। এটা সেই সাক্ষ্য যার সাক্ষী আমি দেই।"],
  "21:57": ["\"I swear by Allah, I have a plan to deal with your statues, as soon as you leave.\"","\"আমি আল্লাহর নামে শপথ করছি, তোমাদের মূর্তিগুলোর সাথে আমার কিছু একটা করার পরিকল্পনা আছে, তোমরা চলে যাওয়া মাত্রই।\""],
  "21:58": ["He broke them into pieces, except for a big one, that they may refer to it.","সে সেগুলোকে টুকরো টুকরো করে ফেলল, বড়টাকে ছাড়া, যাতে তারা সেটাকে জিজ্ঞেস করতে পারে।"],
  "21:59": ["They said, \"Whoever did this to our gods is really a transgressor.\"","তারা বলল, \"যে-ই আমাদের উপাস্যদের সাথে এরকম করেছে, সে আসলেই সীমালংঘনকারী।\""],
  "21:60": ["They said, \"We heard a youth threaten them; he is called Abraham.\"","তারা বলল, \"আমরা এক তরুনকে শুনেছি এগুলোকে হুমকি দিতে; তার নাম হলো ইব্রাহিম।"],
  "21:61": ["They said, \"Bring him before the eyes of all the people, that they may bear witness.\"","তারা বলল, তাকে সকল লোকের চোখের সামনে আনো; যাতে তারা সাক্ষী দিতে পারে।\""],
  "21:62": ["They said, \"Did you do this to our gods, O Abraham?\"","তারা বলল, \"তুমি কি আমাদের উপাস্যদের সাথে এরকম করেছ, হে ইব্রাহিম?\""],
  "21:63": ["He said, \"It is that big one who did it. Go ask them, if they can speak.\"","সে বলল, \"এটা তো ঐ বড়টা করেছে। তাদেরকে গিয়ে জিজ্ঞেস করো, যদি তারা কথা বলতে পারে।\""],
  "21:64": ["They were taken aback, and said to themselves, \"Indeed, you are the ones who have been transgressing.\"","তারা অবাক হয়ে গেলো, এবং নিজেদের মধ্যে বলাবলি করলো, \"নিশ্চয়, তোমরাই সীমালঙ্ঘন করছিলে।\""],
  "21:65": ["Yet, they reverted to their old ideas: \"You know full well that these cannot speak.\"","এরপরও, তারা তাদের পুরনো ধারণায় ফিরে গেল: \"তুমি ভাল করেই জানো যে এরা কথা বলতে পারে না।\""],
  "21:66": ["He said, \"Do you then worship besides Allah what possesses no power to benefit you or harm you?","সে বলল, \"তবে কি তোমরা আল্লাহর পাশে তার উপাসনা করো যা তোমাদের উপকার বা ক্ষতি করার কোন ক্ষমতা রাখে না?"],
  "21:67": ["\"You have incurred shame by worshiping idols beside Allah. Do you not understand?\"","আল্লাহর পাশে অন্য উপাস্যদের উপাসনা করে তোমরা লাঞ্চনা টেনে এনেছ। তোমরা কি বোঝো না?\""],
  "21:68": ["They said, \"Burn him and support your gods, if this is what you decide to do.\"","তারা বলল, \"তাকে পুড়িয়ে ফেলো এবং তোমাদের উপাস্যদের সমর্থন করো, যদি তোমরা এটাই করার সিদ্ধান্ত নাও।\""],
  "21:69": ["We said, \"O fire, be cool and safe for Abraham.\"","আমরা বললাম, \"হে আগুন, ইব্রাহিমের জন্য শীতল এবং নিরাপদ হয়ে যাও।\""],
  "21:70": ["Thus, they schemed against him, but we made them the losers.","এভাবে, তারা তার বিরুদ্ধে ষড়যন্ত্র করেছিলো, কিন্তু আমরা তাদেরকেই পরাজিত করে দিয়েছিলাম।"],
  "21:71": ["We saved him, and we saved Lot, to the land that we blessed for all the people.","আমরা তাকে রক্ষা করেছিলাম, এবং আমরা রক্ষা করেছিলাম লূতকে, সেই ভূমিতে  নিয়ে যা আমরা সকল লোকদের জন্য অনুগ্রহময় করেছিলাম।"],
  "21:72": ["And we granted him Isaac and Jacob as a gift, and we made them both righteous.","এবং আমরা তাকে ইসহাক ও ইয়াকুবকে দিয়েছিলাম উপহার হিসেবে, এবং আমরা তাদের উভয়কে সৎকর্মশীল করেছিলাম।"],
  "21:73": ["We made them imams who guided in accordance with our commandments, and we taught them how to work righteousness, and how to observe the Contact Prayers (Salat) and the obligatory charity (Zakat). To us, they were devoted worshipers.","আমরা তাদেরকে ইমাম বানিয়েছিলাম যারা আমাদের প্রত্যাদেশ অনুসারে পথ দেখাতো, এবং আমরা তাদের শিখিয়েছিলাম কিভাবে সৎকর্ম করতে হয়, এবং কিভাবে সংযোগ প্রার্থনা (সালাত) এবং বাধ্যতামূলক দান (যাকাত) পালন করতে হয়। আমাদের কাছে, তারা নিবেদিত উপাসনাকারী ছিল।"],
  "21:74": ["As for Lot, we granted him wisdom and knowledge, and we saved him from the community that practiced abominations; they were wicked and evil people.","লূতের ক্ষেত্রে, আমরা তাকে প্রজ্ঞা ও জ্ঞান প্রদান করেছিলাম, এবং আমরা তাকে সেই সম্প্রদায় থেকে রক্ষা করেছিলাম যারা নিদারুণ ঘৃণ্য কাজ চর্চা করতো; তারা ছিল অন্যায়কারী এবং মন্দ লোক।"],
  "21:75": ["We admitted him into our mercy, for he was righteous.","আমরা তাকে আমাদের  অনুগ্রহের অন্তর্ভূক্ত করিয়েছিলাম, কারণ সে ছিল সৎকর্মপরায়ন।"],
  "21:76": ["And, before that, Noah called and we responded to him. We saved him and his family from the great disaster.","এবং, এর আগে, নূহ ডেকেছিল এবং আমরা তার ডাকে সাড়া দিয়েছিলাম। আমরা তাকে এবং তার পরিবারকে সেই মহা দূর্যোগ থেকে বাঁচিয়েছিলাম।"],
  "21:77": ["We supported him against the people who rejected our revelations. They were evil people, so we drowned them all.","আমরা তাকে সে লোকদের বিপক্ষে সমর্থন দিয়েছিলাম যারা আমাদের প্রকাশনাবলি প্রত্যাখ্যান করেছিল। তারা ছিল মন্দ লোক, তাই আমরা তাদের সকলকে ডুবিয়ে দিয়েছিলাম।"],
  "21:78": ["And David and Solomon, when they once ruled with regard to someone's crop that was destroyed by another's sheep. We witnessed their judgment.","আর দাউদ এবং সোলায়মান, একবার তারা যখন বিচার করেছিলো কোন একজনের ফসল নিয়ে  যা আরেকজনের ভেড়া নষ্ট করেছিলো। আমরা তাদের বিচার প্রত্যক্ষ করেছিলাম।"],
  "21:79": ["We granted Solomon the correct understanding, though we endowed both of them with wisdom and knowledge. We committed the mountains to serve David in glorifying (Allah), as well as the birds. This is what we did.","আমরা সোলায়মানকে সঠিক বুঝ দিয়েছিলাম, যদিও আমরা তাদের দু'জনকেই প্রজ্ঞা ও জ্ঞান দান করেছিলাম। (আল্লাহর) মহিমা প্রকাশে আমরা দাউদের সেবায় নিযুক্ত করেছিলাম পাহাড়দেরকে, সেই সাথে পাখিদেরও।  আমরা এটাই করেছিলাম।"],
  "21:80": ["And we taught him the skill of making shields to protect you in war. Are you then thankful?","এবং যুদ্ধে তোমাদের রক্ষা করতে আমরা তাকে ঢাল বানানোর কৌশল শিখিয়েছিলাম। তবে কি তোমরা কৃতজ্ঞ ?"],
  "21:81": ["For Solomon, we committed the wind gusting and blowing at his disposal. He could direct it as he wished, to whatever land he chose, and we blessed such land for him. We are fully aware of all things.","সোলায়মানের জন্য, আমরা তার আয়ত্তে এনে দিয়েছিলাম বায়ুকে যা তার ইচ্ছামতো আন্দোলিত এবং প্রবাহিত হতো,  সে একে তার ইচ্ছামতো নির্দেশ করতে পারতো, তার পছন্দের যে কোন ভূমিতে, এবং আমরা এমন ভূমিকে তার জন্য ধন্য করতাম। আমরা সব বিষয়ে পুরোপুরি অবগত।"],
  "21:82": ["And of the devils there were those who would dive for him (to harvest the sea), or do whatever else he commanded them to do. We committed them in his service.","এবং শয়তানদের মধ্যে ছিল তারা যারা তার জন্য ডুব দিতো (সাগর থেকে উত্তোলন করতে), অথবা তা-ই করতো যা সে তাদেরকে করতে আদেশ করতো। আমরা তার সেবায় তাদের নিযুক্ত করেছিলাম।"],
  "21:83": ["And Job implored his Lord: \"Adversity has befallen me, and, of all the merciful ones, You are the Most Merciful.\"","এবং আয়ুব তার প্রভুর কাছে মিনতি করেছিল: \"আমি দূর্দশা  পীড়িত হয়েছি, এবং, সকল দয়ালুর মধ্যে, আপনি সবচেয়ে দয়ালু।"],
  "21:84": ["We responded to him, relieved his adversity, and restored his family for him, even twice as much. That was a mercy from us, and a reminder for the worshipers.","আমরা তার ডাকে সাড়া দিয়েছিলাম, তার দূর্দশা দূর করেছিলাম, এবং তার জন্য তার পরিবারকে ফিরিয়ে দিয়েছিলাম, এমনকি দ্বিগুণ আকারে। সেটা ছিল আমাদের পক্ষ থেকে দয়া, এবং উপাসনাকারীদের জন্য একটি স্মারক।"],
  "21:85": ["Also, Ismail, Idrîs, Zal-Kifl; all were steadfast, patient.","আরও, ইসমাইল, ইদ্রিস, জুল-কিফল; সকলেই ছিল অবিচল, ধৈর্যশীল।"],
  "21:86": ["We admitted them into our mercy, for they were righteous.","আমরা তাদেরকে আমাদের দয়ার অন্তর্ভুক্ত করিয়েছিলাম, কারণ তারা ছিল সৎকর্মশীল।"],
  "21:87": ["And Zan-Noon (Jonah, \"the one with an 'N' in his name\"), abandoned his mission in protest, thinking that we could not control him. He ended up imploring from the darkness (of the big fish's belly): \"There is no god other than You. Be You glorified. I have committed a gross sin.\"","এবং জান-নূন (ইউনুছ,  যার নামে 'ন' আছে), প্রতিবাদে তাকে দেওয়া বিশেষ কাজ থেকে সরে দাঁড়িয়েছিল, এই ভেবে যে আমরা তাকে নিয়ন্ত্রণ করতে পারবো না, শেষ পর্যন্ত সে (বড় মাছের পেটের) অন্ধকার থেকে অনুনয় করতে লাগলো: \"আপনি ছাড়া অন্যকোন উপাস্য নেই। আপনি মহিমান্বিত। আমি এক গুরুতর পাপ করেছি।"],
  "21:88": ["We responded to him, and saved him from the crisis; we thus save the believers.","আমরা তার ডাকে সাড়া দিয়েছিলাম, এবং তাকে সেই সংকট থেকে রক্ষা করেছিলাম;  আমরা এভাবে বিশ্বাসীদের রক্ষা করি।"],
  "21:89": ["And Zachariah implored his Lord: \"My Lord, do not keep me without an heir, though You are the best inheritor.\"","এবং জাকারিয়া তার প্রভুর কাছে মিনতি করেছিল: \"আমার প্রভু,  আমাকে উত্তরাধিকার শূন্য করে রাখবেন না, যদিও আপনিই সর্বোত্তম উত্তরাধিকারী।”"],
  "21:90": ["We responded to him and granted him John; we fixed his wife for him. That is because they used to hasten to work righteousness, and implored us in situations of joy, as well as fear. To us, they were reverent.","আমরা তার ডাকে সাড়া দিয়েছিলাম এবং তাকে দান করেছিলাম ইয়াহিয়া; আমরা তার জন্য তার স্ত্রীকে সারিয়ে দিয়েছিলাম। সেটা এ কারনে যে তারা সৎকর্ম করতে ঝাঁপিয়ে পড়তো, এবং আমাদের কাছে অনুনয় করতো আনন্দের সময়ে, একই সাথে ভয়ের সময়। আমাদের কাছে, তারা ছিল ভক্ত।"],
  "21:91": ["As for the one who maintained her virginity, we blew into her from our spirit, and thus, we made her and her son a portent for the whole world.","তার ক্ষেত্রে যে তার সতীত্ব বজায় রেখেছিল, আমরা তার মধ্যে আমাদের রূহ ফুঁকে দিয়েছিলাম, আর এভাবে, আমরা তাকে এবং তার পুত্রকে পুরো বিশ্বের জন্য একটি নিদর্শন করেছিলাম।"],
  "21:92": ["Your congregation is but one congregation, and I alone am your Lord; you shall worship Me alone.","তোমাদের ধর্মগোষ্ঠী তো এক ধর্মগোষ্ঠী, এবং কেবল আমিই তোমাদের প্রভু; তোমরা একমাত্র আমার উপাসনা করবে।"],
  "21:93": ["However, they divided themselves into disputing religions. All of them will come back to us (for judgment).","কিন্তু, তারা নিজেদেরকে বিতর্কিত ধর্মে বিভক্ত করে ফেলল। (বিচারের জন্য) তারা সকলে আমাদের কাছে ফিরে আসবে।"],
  "21:94": ["As for those who work righteousness, while believing, their work will not go to waste; we are recording it.","আর যারা সৎ-কাজ করে, বিশ্বাসী অবস্থায়, তাদের কাজ বিফলে যাবে না; আমরা তা লিপিবদ্ধ করছি।"],
  "21:95": ["It is forbidden for any community we had annihilated to return.","আমরা ধ্বংস করে দিয়েছি এমন কোন জনপদের জন্য আবার ফিরে আসা নিষেধ।"],
  "21:96": ["Not until Gog and Magog reappear, will they then return—they will come from every direction.","যতক্ষণ না ইয়াজুজ এবং মাজুজ পুনরাবির্ভুত হয়,  তখন তারা ফিরবে- তারা সবদিক থেকে আসবে।"],
  "21:97": ["That is when the inevitable prophecy will come to pass, and the disbelievers will stare in horror: \"Woe to us; we have been oblivious. Indeed, we have been wicked.\"","তখনই সেই অনিবার্য ভবিষ্যদ্বাণী পূর্ণ হবে, এবং অবিশ্বাসীরা আতঙ্কিত দৃষ্টিতে তাকিয়ে থাকবেঃ “দুর্ভাগ্য আমাদের, আমরা বেখবর হয়ে ছিলাম। নিশ্চয়, আমরা অন্যায়কারী ছিলাম”।"],
  "21:98": ["You and the idols you worship besides Allah will be fuel for Hell; this is your inevitable destiny.","তোমরা এবং আল্লাহর পাশে যাদেরকে তোমরা উপাসনা করো, তারা নরকের জ্বালানি হবে; এটাই তোমাদের অনিবার্য নিয়তি।"],
  "21:99": ["If those were gods, they would not have ended up in Hell. All its inhabitants abide in it forever.","ঐগুলো যদি উপাস্য হতো, তারা শেষ পর্যন্ত নরকে যেতো না। এর সব বাসিন্দারা এর মধ্যে চিরকাল বাস করবে।"],
  "21:100": ["They will sigh and groan therein, and they will have no access to any news.","তারা সেখানে দীর্ঘশ্বাস ফেলবে এবং আর্তনাদ করবে, এবং তারা কোনো সংবাদ পাবেনা।"],
  "21:101": ["As for those who deserved our magnificent rewards, they will be protected from it.","আর যারা আমাদের চমৎকার পুরস্কার অর্জন করবে, তারা এর থেকে সুরক্ষিত থাকবে।"],
  "21:102": ["They will not hear its hissing. They will enjoy an abode where they can get everything they desire, forever.","তারা এর হিস-হিস শব্দ শুনবে না। তারা এক বাসস্থান উপভোগ করবে যেখানে তারা যা কিছু আকাঙ্ক্ষা করবে তাই পাবে, চিরকাল।"],
  "21:103": ["The great horror will not worry them, and the angels will receive them joyfully: \"This is your day, that has been promised to you.\"","সেই মহা আতঙ্ক তাদেরকে চিন্তিত করবে না, এবং স্বর্গ-দূতেরা তাদেরকে আনন্দের সাথে গ্রহণ করবেঃ “এটা তোমাদের দিন, যার প্রতিশ্রুতি তোমাদেরকে দেয়া হয়েছে”।"],
  "21:104": ["On that day, we will fold the heaven, like the folding of a book. Just as we initiated the first creation, we will repeat it. This is our promise; we will certainly carry it out.","সেই দিনে, আমরা আকাশকে গুটিয়ে নেব, একটা বই গুটিয়ে নেয়ার মত। ঠিক যেভাবে আমরা প্রথম সৃষ্টির সূচনা করেছিলাম, আমরা তার পুনরাবৃত্তি করবো। এটা আমাদের অঙ্গীকার; আমরা অবশ্যই তা সম্পাদন করবো।"],
  "21:105": ["We have decreed in the Psalms, as well as in other scriptures, that the earth shall be inherited by My righteous worshipers.","আমরা যবুরে প্রকাশ করেছি, সেই সাথে অন্যান্য ঐশী-গ্রন্থে, যে পৃথিবীর উত্তরাধিকারী হবে আমার সৎ-কর্মশীল উপাসনাকারীরা।"],
  "21:106": ["This is a proclamation for people who are worshipers.","এটা সেসব লোকদের জন্য একটি ঘোষণা যারা উপাসনাকারী।"],
  "21:107": ["We have sent you out of mercy from us towards the whole world.","পুরো দুনিয়ার প্রতি আমাদের দয়া থেকে আমরা তোমাকে পাঠিয়েছি।"],
  "21:108": ["Proclaim, \"I have been given divine inspiration that your god is one god. Will you then submit?\"","ঘোষণা করো, “আমাকে ঐশ্বরিক প্রত্যাদেশ দেওয়া হয়েছে যে তোমাদের খোদা একজনই।  তবে কি তোমরা নিজেদেরকে সমর্পণ করবে?"],
  "21:109": ["If they turn away, then say, \"I have warned you sufficiently, and I have no idea how soon or late (the retribution) will come to you.","যদি তারা মুখ ফিরিয়ে নেয়, তবে বল, “আমি তোমাদেরকে যথেষ্ট সতর্ক করেছি, এবং আমার কোন ধারনা নেই কতটা শীঘ্র বা দেরিতে (শাস্তি) তোমাদের কাছে আসবে।"],
  "21:110": ["\"He is fully aware of your public utterances, and He is fully aware of everything you conceal.","“তিনি পরিপূর্ণ অবগত তোমাদের প্রকাশ্য বক্তব্যের ব্যাপারে, এবং তিনি পরিপূর্ণ অবগত সে সবকিছু সম্পর্কে, যা তোমরা গোপন করো।"],
  "21:111": ["\"For all that I know, this world is a test for you, and a temporary enjoyment.\"","“যতো দূর আমি জানি, এই দুনিয়া তোমাদের জন্য একটি পরীক্ষা, এবং একটি সাময়িক উপভোগ”।"],
  "21:112": ["Say, \"My Lord, Your judgment is the absolute justice. Our Lord is the Most Gracious; only His help is sought in the face of your claims.\"","বল, “আমার প্রভু, আপনার বিচার পূর্ণ ন্যায়বিচার। আমাদের প্রভু পরম করুণাময়, তোমাদের দাবীর মুখে শুধুমাত্র তাঁর সাহায্য অন্বেষণ করি”।"],
  "22:1": ["O people, you shall reverence your Lord, for the quaking of the Hour is something horrendous.","হে লোকেরা, তোমারদের উচিত তোমাদের প্রভুকে ভক্তি করা, কারন সেই সময়ের কম্পন ভয়াবহ।"],
  "22:2": ["The day you witness it, even a nursing mother will discard her infant, and a pregnant woman will abort her fetus. You will see the people staggering, as if they are intoxicated, even though they are not intoxicated. This is because Allah's retribution is so awesome.","যেদিন তোমরা তা প্রত্যক্ষ করবে, এমনকি একজন স্তন্য দানকারিণী মাও তার শিশুকে পরিত্যাগ করবে, এবং একজন অন্তঃসত্ত্বা নারী গর্ভপাত করবে। তুমি লোকদের টলমল করে হাটঁতে দেখবে, যেন তারা মাতাল, যদিও তারা মাতাল নয়। এটা এ কারনে যে আল্লাহর শাস্তি খুবই ভয়ানক।"],
  "22:3": ["Among the people, there are those who argue about Allah without knowledge, and follow every rebellious devil.","লোকেদের মধ্যে, এমনও আছে যারা আল্লাহর ব্যাপারে তর্ক করে জ্ঞান ছাড়াই, এবং প্রত্যেকটি বিদ্রোহী শয়তানের অনুসরণ করে।"],
  "22:4": ["It is decreed that anyone who allies himself with him, he will mislead him and guide him to the agony of Hell.","এটা নিয়ম করা হয়েছে যে, যেকেউ তার সাথে মিত্রতা করে, তাকে সে পথভ্রষ্ট করবে এবং তাকে নরকের যন্ত্রণার দিকে পথ দেখাবে।"],
  "22:5": ["O people, if you have any doubt about resurrection, (remember that) we created you from dust, and subsequently from a tiny drop, which turns into a hanging (embryo), then it becomes a fetus that is given life or deemed lifeless. We thus clarify things for you. We settle in the wombs whatever we will for a predetermined period. We then bring you out as infants, then you reach maturity. While some of you die young, others live to the worst age, only to find out that no more knowledge can be attained beyond a certain limit. Also, you look at a land that is dead, then as soon as we shower it with water, it vibrates with life and grows all kinds of beautiful plants.","হে লোকেরা, যদি পুনরুত্থানের ব্যাপারে তোমাদের কোন সন্ধেহ থাকে, (স্মরণ করো যে) আমরা তোমাদের ধুলো থেকে সৃষ্টি করেছি, এবং পরবর্তীতে এক অতি ক্ষুদ্র ফোঁটা থেকে, যা এক ঝুলন্ত (ভ্রুনে) পরিণত হয়, এরপর এটি পরিনত হয় একটি মানবাকৃতির ভ্রুনে যাতে জীবন দেওয়া হয় অথবা  জীবনহীন গণ্য করা হয়। আমরা এভাবে তোমাদের জন্য বিষয়গুলো সুস্পষ্ট করি। আমরা গর্ভে স্থাপন করি যা আমাদের ইচ্ছা একটি পূর্ব নির্ধারিত সময়ের জন্য। এরপর আমরা তোমাদের নবজাতক হিসেবে বের করে আনি, এরপর তোমরা প্রাপ্ত বয়সে পৌঁছাও। যেখানে তোমাদের কেউ কেউ যৌবনে মারা যাও, অন্যরা নিকৃষ্ট বয়স পর্যন্ত বেঁচে থাকো, শুধুমাত্রে এটা দেখার জন্য যে একটি নির্দিষ্ট সীমার পর কোন জ্ঞান আহরণ করা যায় না। আবার, তোমরা একটি ভূমিকে দেখো যা কিনা মৃত, এরপর যখনই আমরা এতে পানি বর্ষণ করি, এতে জীবন স্পন্দিত হয় এবং সকল প্রকার সুন্দর উদ্ভিদ জন্মায়।"],
  "22:6": ["This proves that Allah is the Truth, and that He revives the dead, and that He is Omnipotent.","এটা প্রমান করে যে আল্লাহ সত্য, এবং যে তিনি মৃতকে জীবিত করেন, এবং যে তিনি সর্বশক্তিমান।"],
  "22:7": ["And that the Hour is coming, no doubt about it, and that Allah resurrects those who are in the graves.","এবং যে সেই ঘণ্টা আসছে, এ ব্যাপারে কোন সন্ধেহ নেই, এবং যে আল্লাহ পুনরুজ্জীবিত করেন, তাদেরকে, যারা কবরে রয়েছে।"],
  "22:8": ["Among the people there is the one who argues about Allah without knowledge, and without guidance, and without an enlightening scripture.","লোকদের মধ্যে রয়েছে সে ব্যক্তি, যে আল্লাহ সম্পর্কে তর্ক করে জ্ঞান ছাড়া, এবং পথ নির্দেশনা ছাড়া, এবং কোন জ্ঞানালোকপূর্ণ ঐশী-গ্রন্থ ছাড়া।"],
  "22:9": ["Arrogantly he strives to divert the people from the path of Allah. He thus incurs humiliation in this life, and we commit him on the Day of Resurrection to the agony of burning.","দাম্ভিকতার সাথে সে সংগ্রাম করে আল্লাহর পথ থেকে লোকদের সরিয়ে দিতে। এই ভাবে সে এ জীবনে অপমান টেনে আনে, এবং পুনরুত্থান দিনে আমরা তাকে দহন যন্ত্রণায় সোপর্দ করবো।"],
  "22:10": ["This is what your hands have sent ahead for you. Allah is never unjust towards the people.","এটা তাই যা তোমার হাত তোমার জন্য পাঠিয়েছে। আল্লাহ কখনই লোকদের প্রতি অন্যায়কারী নন।"],
  "22:11": ["Among the people there is the one who worships Allah conditionally. If things go his way, he is content. But if some adversity befalls him, he makes an about-face. Thus, he loses both this life and the Hereafter. Such is the real loss.","লোকদের মধ্যে রয়েছে সে ব্যক্তি যে শর্তসাপেক্ষে আল্লাহর উপাসনা করে। যদি সবকিছু তার মত অনুযায়ী যায়, সে সন্তুষ্ট। কিন্তু যদি কিছু দুর্দশা তার উপর পতিত হয়, সে মুখ ফিরিয়ে নেয়। এভাবে, সে এই জীবন এবং পরকাল উভয়ই হারায়। এমনই আসল ক্ষতি।"],
  "22:12": ["He idolizes beside Allah what possesses no power to harm him or benefit him; such is the real straying.","সে আল্লাহর পাশে তার উপাসনা করে যা তার ক্ষতি অথবা তার উপকার করার কোন ক্ষমতা রাখে না; এমনই আসল পথভ্রষ্টতা।"],
  "22:13": ["He idolizes what is more apt to harm him than benefit him. What a miserable lord! What a miserable companion!","সে তার উপাসনা করে যা তার উপকারের চেয়ে ক্ষতি করার বেশি সম্ভাবনা রাখে। কি এক শোচনীয় প্রভু! কি এক শোচনীয় সঙ্গি!"],
  "22:14": ["Allah admits those who believe and lead a righteous life into gardens with flowing streams. Everything is in accordance with Allah's will.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে আল্লাহ তাদের প্রবেশ করাবেন প্রবাহিত ঝর্না সহ বাগানে। সবকিছু আল্লাহর ইচ্ছা অনুযায়ী হয়।"],
  "22:15": ["If anyone thinks that Allah cannot support him in this life and in the Hereafter, let him turn completely to (his Creator in) heaven, and sever (his dependence on anyone else). He will then see that this plan eliminates anything that bothers him.","যদি কেউ ভাবে যে আল্লাহ এই জীবনে এবং পরকালে তাকে পালন করতে পারবে না, তাকে সম্পূর্ণ ভাবে স্বর্গের (তার সৃষ্টিকর্তার) দিকে ফিরতে দাও, এবং ছিন্ন করতে দাও (অন্য কারো প্রতি তার নির্ভরশীলতা)। সে তখন দেখবে যে এই পরিকল্পনা অপসরণ করে যে কোন কিছু, যা তাকে কষ্ট দেয়।"],
  "22:16": ["We have thus revealed clear revelations herein, then Allah guides whomever He wills.","এখানে, আমরা এভাবে স্পষ্ট প্রকাশনাবলী প্রকাশ করেছি, অতঃপর আল্লাহ যাকে ইচ্ছা পথপ্রদর্শন করেন।"],
  "22:17": ["Those who believe, those who are Jewish, the converts, the Christians, the Zoroastrians, and the idol worshipers, Allah is the One who will judge among them on the Day of Resurrection. Allah witnesses all things.","যারা বিশ্বাস করে, যারা ইহুদী, ধর্মান্তরিত, খ্রিষ্টান, জরথুস্ট্রীয়, এবং প্রতিমা উপাসকরা, আল্লাহই সেই স্বত্ত্বা যিনি পুনরুত্থান দিনে তাদের মধ্যে বিচার করবেন। আল্লাহ সবকিছু প্রত্যক্ষ করেন।"],
  "22:18": ["Do you not realize that to Allah prostrates everyone in the heavens and the earth, and the sun, and the moon, and the stars, and the mountains, and the trees, and the animals, and many people? Many others among the people are committed to doom. Whomever Allah shames, none will honor him. Everything is in accordance with Allah's will.","তুমি কি অনুধাবন করো না যে আল্লাহকে সেজদা করে আকাশমন্ডলী এবং পৃথিবীর সবকিছু, এবং সূর্য, এবং চাঁদ, এবং তারাকারাজি, এবং পর্বতসমূহ, এবং বৃক্ষরাজি, এবং পশুকূল এবং অনেক লোকরা? লোকদের মধ্যে অন্য অনেকের ধ্বংস অবধারিত। যাকে আল্লাহ লজ্জিত করেন, কেউ তাকে সম্মান করবে না। সবকিছু আল্লাহর ইচ্ছা অনুসারে হয়।"],
  "22:19": ["Here are two parties feuding with regard to their Lord. As for those who disbelieve, they will have clothes of fire tailored for them. Hellish liquid will be poured on top of their heads.","এই যে দুটি পক্ষ তাদের প্রভুর ব্যাপারে বিবাদ করছে। যারা অবিশ্বাস করে, তাদের জন্য আগুনের পোশাক তৈরি করা হবে। নারকীয় তরল তাদের মাথার উপর ঢালা হবে।"],
  "22:20": ["It will cause their insides to melt, as well as their skins.","এটা তাদের ভিতর গলিয়ে দেবে, সেই সাথে তাদের চামড়া।"],
  "22:21": ["They will be confined in iron pots.","তারা লোহার পাত্রে আবদ্ধ থাকবে।"],
  "22:22": ["Whenever they try to exit such misery, they will be forced back in: \"Taste the agony of burning.\"","যখনি তারা এমন দুর্দশা থেকে বের হতে চেষ্টা করবে, তাদের জোরপূর্বক তাতে ফিরিয়ে দেওয়া হবেঃ  “দহন যন্ত্রণা আস্বাদন করো”।"],
  "22:23": ["Allah will admit those who believe and lead a righteous life into gardens with flowing streams. They will be adorned therein with bracelets of gold, and pearls, and their garments therein will be silk.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, আল্লাহ তাদেরকে প্রবেশ করাবেন প্রবাহিত ঝর্নাসহ বাগানে। তাদেরকে সেখানে সোনার ব্রেচলেট এবং মুক্তা দিয়ে সাজানো হবে, এবং সেখানে তাদের পোশাক হবে রেশমের।"],
  "22:24": ["They have been guided to the good words; they have been guided in the path of the Most Praised.","তারাকে উত্তাম বাক্যের দিকে পরিচালিত করা হয়েছে; তারা পথপ্রদর্শিত হয়েছে পরম প্রশংসনীয়- এর পথে।"],
  "22:25": ["Surely, those who disbelieve and repulse others from the path of Allah, and from the Sacred Masjid that we designated for all the people—be they natives or visitors—and seek to pollute it and corrupt it, we will afflict them with painful retribution.","অবশ্যই, যারা অবিশ্বাস করে এবং অন্যদের বাধাঁ দেয় আল্লাহর পথ থেকে, এবং পবিত্র মসজিদ থেকে যা আমরা সকল লোকদের জন্য নির্ধারিত করেছি- হোক তারা স্থানিয় অথবা দর্শনার্থী - এবং একে দূষিত এবং কলুষিত করতে চায়, আমরা তাদেরকে যন্ত্রণাদায়ক শাস্তি দিয়ে পীড়িত করবো।"],
  "22:26": ["We appointed Abraham to establish the Shrine: \"You shall not idolize any other god beside Me, and purify My shrine for those who visit it, those who live near it, and those who bow and prostrate.","আমরা ইব্রাহিমকে পবিত্র গৃহ স্থাপন করতে নিযুক্ত করেছিলাম : “তুমি আমার পাশে অন্য কোন উপাস্যের উপাসনা করবে না, এবং আমার ঘর পবিত্র রাখবে তাদের জন্য যারা তা দর্শন করতে আসে, যারা এর নিকটে বাস করে, এবং যারা রুকু ও সেজদা করে।"],
  "22:27": ["\"And proclaim that the people shall observe Hajj pilgrimage. They will come to you walking or riding on various exhausted (means of transportation). They will come from the farthest locations.\"","এবং ঘোষণা করো যে লোকেরা হজ্জ তীর্থযাত্রা পালন করবে। তারা তোমার কাছে হেঁটে অথবা বিভিন্ন ক্লান্তিকর (পরিবহনে) চড়ে আসবে। তারা সর্বাধিক দূরবর্তী স্থান থেকে আসবে।"],
  "22:28": ["They may seek commercial benefits, and they shall commemorate Allah's name during the specified days for providing them with livestock. \"Eat therefrom and feed the despondent and the poor.\"","তারা বানিজ্যিক সুবিধা অন্বেষণ করতে পারে, এবং তারা নির্দিষ্ট দিনগুলোতে আল্লাহর নাম স্মরণ করবে তদেরকে গৃহপালিত পশু প্রদান করার জন্য। “সেখান থেকে খাও এবং দুঃস্থ ও গরিবদের খাওয়াও”।"],
  "22:29": ["They shall complete their obligations, fulfill their vows, and visit the ancient shrine.","তারা তাদের কর্তব্য সম্পন্ন করবে, তাদের প্রতিজ্ঞা পূর্ণ করবে, এবং প্রাচীন পবিত্র গৃহটি দর্শন করবে।"],
  "22:30": ["Those who reverence the rites decreed by Allah have deserved a good reward at their Lord. All livestock is made lawful for your food, except for those specifically prohibited for you. You shall avoid the abomination of idol worship, and avoid bearing false witness.","যারা আল্লাহর আদেশক্রিত ধর্মানুষ্ঠানগুলো সম্মান করে তারা তাদের প্রভুর কাছে এক ভালো পুরস্কারের যোগ্য হয়েছে।  সকল গৃহপালিত পশু তোমাদের খাদ্য হিসেবে আইনসিদ্ধ করা হল, সেগুলো ছাড়া যেগুলো তোমাদের জন্য সুনির্দিষ্টভাবে নিষিদ্ধ করা হয়েছে। তোমরা অংশীদার উপাসনার জঘন্যতা এড়িয়ে চলবে, এবং মিথ্যা সাক্ষ্য দেওয়া এড়িয়ে চলবে।"],
  "22:31": ["You shall maintain your devotion absolutely to Allah alone. Anyone who sets up any idol beside Allah is like one who fell from the sky, then gets snatched up by vultures, or blown away by the wind into a deep ravine.","তোমরা তোমাদের একনিষ্ঠতা সম্পূর্ণরূপে কেবল আল্লাহর প্রতি বজায় রাখবে। যেকেউ আল্লাহর পাশে কোনো উপাস্য স্থাপন করে সে তার মতো যে আকাশ থেকে পড়লো, তারপর শকুনেরা তাকে ছিনিয়ে নিল, অথবা বাতাস তাকে এক গভীর গিরিখাতের মধ্যে উড়িয়ে নিয়ে ফেলল।"],
  "22:32": ["Indeed, those who reverence the rites decreed by Allah demonstrate the righteousness of their hearts.","নিশ্চয়, যারা আল্লাহর আদেশক্রিত ধর্মানুষ্ঠানগুলোকে সম্মান করে তারা তাদের হৃদয়ের ন্যায়পরায়ণতা প্রদর্শন করলো।"],
  "22:33": ["The (livestock) provide you with many benefits for a period, before being donated to the ancient shrine.","গৃহপালিতপশু তোমাদেরকে একটি নির্দিষ্ট সময়ের জন্য অনেক উপকারিতা দেয়, প্রাচীন পবিত্র গৃহে দান করার আগে।"],
  "22:34": ["For each congregation we have decreed rites whereby they commemorate the name of Allah for providing them with the livestock. Your god is one and the same god; you shall all submit to Him. Give good news to the obedient.","প্রত্যেক জনপদের জন্য আমরা ধর্মানুষ্ঠানের আদেশ করেছি যার দ্বারা তারা আল্লাহর নাম স্মরণ করে তাদেরকে পালনযোগ্য পশু প্রদান করার জন্য। তোমাদের উপাস্য এক এবং সেই একই উপাস্য। তোমরা সকলে তাঁর কাছে সমর্পিত হবে। অনুগতদের সুসংবাদ দাও।"],
  "22:35": ["They are the ones whose hearts tremble upon mentioning Allah, they steadfastly persevere during adversity, they observe the Contact Prayers (Salat), and from our provisions to them, they give to charity.","তারা সে লোক যাদের হৃদয় আল্লাহর উল্লেখে কম্পিত হয়, তারা প্রতিকূলতার সময়  দৃঢ়তার সাথে অবিচল, তারা সংযোগ প্রার্থনা (সালাত) পালন করে, এবং তাদেরকে দেয়া আমাদের জীবিকা থেকে তারা দান করে।"],
  "22:36": ["The animal offerings are among the rites decreed by Allah for your own good. You shall mention Allah's name on them while they are standing in line. Once they are offered for sacrifice, you shall eat therefrom and feed the poor and the needy. This is why we subdued them for you, that you may show your appreciation.","আল্লাহর আদেশক্রিত ধর্মানুষ্ঠানগুলোর মধ্যে পশু কোরবানি রয়েছে তোমাদের নিজেদের ভালোর জন্য। তোমরা এগুলোর উপর আল্লাহর নাম উচ্চারন করবে যখন এরা সারিতে দাড়িয়ে থাকে। এগুলো কোরবানির জন্য উৎসর্গ হয়ে গেলে তোমরা এদের থেকে খাবে এবং গরীব ও অভাবীদের খাওয়াবে। এই জন্যই আমরা এগুলোকে তোমাদের জন্য বশীভূত করে দিয়েছি, যাতে তোমরা তোমাদের কৃতজ্ঞতা প্রদর্শন করতে পারো।"],
  "22:37": ["Neither their meat, nor their blood reaches Allah. What reaches Him is your righteousness. He has subdued them for you, that you may show your appreciation by glorifying Allah for guiding you. Give good news to the charitable.","না তাদের মাংস, না তাদের রক্ত আল্লাহর কাছে পৌঁছায়। যা তাঁর কাছে পৌঁছায় তা হল তোমাদের সৎ-কর্মশীলতা। তিনি এগুলোকে তোমাদের জন্য বশীভূত করে দিয়েছেন, যাতে আল্লাহর মহিমা ঘোষণা করে তোমার তোমাদের কৃতজ্ঞতা প্রদর্শন করো তোমাদের পথ প্রদর্শন করার জন্য। দানশীলদের সুসংবাদ দাও।"],
  "22:38": ["Allah defends those who believe. Allah does not love any betrayer, unappreciative.","আল্লাহ তাদের পক্ষে থাকেন যারা বিশ্বাস করে। আল্লাহ কোন বিশ্বাসঘাতক, অকৃতজ্ঞকে ভালোবাসেন না।"],
  "22:39": ["Permission is granted to those who are being persecuted, since injustice has befallen them, and Allah is certainly able to support them.","তাদেরকে অনুমতি দেয়া হলো যারা নির্যাতিত হচ্ছে, যেহেতু তাদের উপর অবিচার করা হয়েছে, এবং আল্লাহ অবশ্যই তাদের সমর্থন করতে সক্ষম।"],
  "22:40": ["They were evicted from their homes unjustly, for no reason other than saying, \"Our Lord is Allah.\" If it were not for Allah's supporting of some people against others, monasteries, churches, synagogues, and masjids—where the name of Allah is commemorated frequently—would have been destroyed. Absolutely, Allah supports those who support Him. Allah is Powerful, Almighty.","তারা তাদের বাড়ি থেকে উচ্ছেদ হয়েছিল অন্যায়ভাবে, অন্য কোন কারনে না শুধু এটুকু বলার জন্য “আমাদের প্রভু আল্লাহ”। যদি আল্লাহ কিছু লোককে সমর্থন না করতেন অন্যদের বিরুদ্ধে, মঠ, গির্জা, সিনেগগ এবং মসজিদগুলো- যেখানে আল্লাহর নাম প্রতিনিয়ত স্মরণ করা হয়-ধ্বংস হয়ে যেত। নিঃসন্দেহে, আল্লাহ তাদের সমর্থন করেন যারা তাঁকে সমর্থন করে। আল্লাহ ক্ষমতাধর, সর্বশক্তিমান।"],
  "22:41": ["They are those who, if we appointed them as rulers on earth, they would establish the Contact Prayers (Salat) and the obligatory charity (Zakat), and would advocate righteousness and forbid evil. Allah is the ultimate ruler.","তারা হচ্ছে সেসব লোক, যাদেরকে যদি আমরা পৃথিবীতে শাসক হিসেবে নিয়োগ/মনোনীত করি, তারা সংযোগ প্রার্থনা (সালাত)এবং বাধ্যতামূলক দান (যাকাত) প্রতিষ্ঠা করবে, এবং সৎকর্মশীলতার ওকালতি করবে এবং মন্দ থেকে নিষেধ করবে। আল্লাহ চূড়ান্ত শাসক।"],
  "22:42": ["If they reject you, the people of Noah, 'Ãd, and Thamûd have also disbelieved before them.","যদি তারা তোমাকে প্রত্যাক্ষান করে, তাদের আগে নুহের, আদের এবং সামুদের লোকেরাও অবিশ্বাস করেছিল।"],
  "22:43": ["Also the people of Abraham, and the people of Lot.","ইব্রাহীমের লোকেরা এবং লুতের লোকেরাও।"],
  "22:44": ["And the dwellers of Midyan. Moses was also rejected. I led all those people on, then I called them to account; how (devastating) was My requital!","এবং মাদিয়ানের বাসিন্দারা। মুসাকেও প্রত্যাখ্যান করা হয়েছিল। আমি ঐ সকল লোকদের সুযোগ দিয়ে রেখেছিলাম, এরপর আমি তাদেরকে হিসাবের জন্য ডেকেছিলাম; কেমন (ধ্বংসাত্মক) ছিল আমার শাস্তি!"],
  "22:45": ["Many a community have we annihilated because of their wickedness. They ended up with ruins, stilled wells, and great empty mansions.","অনেক জনপদ আমরা ধ্বংস করে দিয়েছি তাদের অন্যায়ের কারনে। তারা শেষ পর্যন্ত ধ্বংসাবশেষে পরিণত হয়েছিল, নিথর কুয়া এবং বিশাল শূন্য প্রাসাদ সহ।"],
  "22:46": ["Did they not roam the earth, then use their minds to understand, and use their ears to hear? Indeed, the real blindness is not the blindness of the eyes, but the blindness of the hearts inside the chests.","তারা কি পৃথিবী ঘুরে দেখেনি, এরপর তাদের মন ব্যাবহার করে নি বোঝার জন্য, এবং তাদের কান ব্যবহার করেনি শোনার জন্য? নিশ্চয়, চোখের অন্ধত্ব প্রকৃত অন্ধত্ব নয়, বুকের ভেতরে হৃদয়ের অন্ধত্বই প্রকৃত অন্ধত্ব।"],
  "22:47": ["They challenge you to bring retribution, and Allah never fails to fulfill His prophecy. A day of your Lord is like a thousand of your years.","তারা তোমাকে শাস্তি আনার জন্য চ্যালেঞ্জ করে, এবং আল্লাহ কখনো তাঁর ভবিষদ্বানী পূর্ণ করতে ব্যর্থ হন না। তোমার প্রভুর এক দিন তোমাদের এক হাজার বছরের মত।"],
  "22:48": ["Many a community in the past committed evil, and I led them on for awhile, then I punished them. To Me is the ultimate destiny.","অতীতে অনেক জনপদ মন্দ করেছে, এবং আমি তাদেরকে কিছু সময়ের জন্য সুযোগ দিয়ে রেখেছিলাম, এরপর আমি তাদেরকে শাস্তি দিয়েছি। আমার দিকেই চূড়ান্ত নিয়তি।"],
  "22:49": ["Say, \"O people, I have been sent to you as a profound warner.\"","বল, “হে লোকেরা, আমাকে তোমাদের কাছে পাঠানো হয়েছে একজন সুস্পষ্ট সতর্ককারী হিসাবে”।"],
  "22:50": ["Those who believe and lead a righteous life have deserved forgiveness and a generous recompense.","যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে তারা যোগ্য হয়েছে ক্ষমা এবং উদার প্রতিদানের।"],
  "22:51": ["As for those who strive to challenge our revelations, they incur Hell.","আর যারা আমাদের প্রকাশনাবলীকে চ্যালেঞ্জ করতে সংগ্রাম করে, তারা নরক টেনে আনে।"],
  "22:52": ["We did not send before you any messenger, nor a prophet, without having the devil interfere in his wishes. Allah then nullifies what the devil has done. Allah perfects His revelations. Allah is Omniscient, Most Wise.","তোমার আগে না আমরা পাঠিয়েছি কোন বার্তাবাহক, না কোন নবী, যার ইচ্ছায় শয়তান হস্তক্ষেপ করেনি। এরপর আল্লাহ তা অকার্যকর করেন যা শয়তান করেছে। আল্লাহ তাঁর প্রকাশনাবলীকে যথাযথ করেন। আল্লাহ সর্বজ্ঞ, সব থেকে জ্ঞানী।"],
  "22:53": ["He thus sets up the devil's scheme as a test for those who harbor doubts in their hearts, and those whose hearts are hardened. The wicked must remain with the opposition.","তিনি এভাবে শয়তানের চক্রান্তকে তাদের জন্য একটি পরীক্ষা স্বরুপ করেন যারা তাদের হৃদয়ে সন্দেহ পোষণ করে, এবং যাদের হৃদয় কঠিন হয়ে পড়েছে। অন্যায়কারীরা অবশ্যই বিরোধী দলের সাথে থাকবে।"],
  "22:54": ["Those who are blessed with knowledge will recognize the truth from your Lord, then believe in it, and their hearts will readily accept it. Most assuredly, Allah guides the believers in the right path.","যারা জ্ঞান পেয়ে অনুগ্রহপ্রাপ্ত তারা তোমার প্রভুর পক্ষ থেকে আসা সত্য চিনতে পারবে, এরপর তাতে বিশ্বাস করবে, এবং তাদের হৃদয় নির্দ্বিধায় তা গ্রহন করবে। অবশ্যই, আল্লাহ বিশ্বাসীদের সঠিক পথে পরিচালিত করেন।"],
  "22:55": ["As for those who disbelieve, they will continue to harbor doubts until the Hour comes to them suddenly, or until the retribution of a terrible day comes to them.","আর যারা অবিশ্বাস করে, তারা সন্ধেহ পোষণ করতে থাকবে যতক্ষণ না সেই ঘণ্টা হঠাৎ করেই তাদের কাছে চলে আসে, অথবা যতক্ষণ না এক ভয়ানক দিনের শাস্তি তাদের কাছে এসে যায়।"],
  "22:56": ["All sovereignty on that day belongs to Allah, and He will judge among them. As for those who believe and lead a righteous life, they have deserved the gardens of bliss.","সে দিন সকল সার্বভৌম ক্ষমতা আল্লাহর হবে, এবং তিনি তাদের মধ্যে বিচার করবেন। তাদের ক্ষেত্রে যারা বিশ্বাস করে এবং সৎ জীবন-যাপন করে, তারা পরম সুখের বাগানগুলোর যোগ্য হয়েছে।"],
  "22:57": ["While those who disbelieved and rejected our revelations have incurred a shameful retribution.","যখন যারা অবিশ্বাস করেছিল এবং আমাদের প্রকাশনাবলী প্রত্যাখ্যান করেছিল, তারা টেনে এনেছে এক লজ্জাকর শাস্তি।"],
  "22:58": ["Those who emigrate for the sake of Allah, then get killed, or die, Allah will surely shower them with good provisions. Allah is certainly the best Provider.","যারা আল্লাহর খাতিরে দেশ ত্যাগ করে, এর পর নিহত হয়, অথবা মারা যায়, আল্লাহ অবশ্যই তাদের প্রতি ভালো জীবিকা বর্ষণ করবেন। আল্লাহ নিশ্চয় সর্বোত্তম জীবিকা প্রদানকারী।"],
  "22:59": ["Most assuredly, He will admit them an admittance that will please them. Allah is Omniscient, Clement.","অবশ্যই, তিনি তাদেরকে এমন জায়গায় প্রবেশ করাবেন যা তাদেরকে সন্তুষ্ট করবে। আল্লাহ সর্বজ্ঞ, কৃপাময়।"],
  "22:60": ["It is decreed that if one avenges an injustice that was inflicted upon him, equitably, then is persecuted because of this, Allah will surely support him. Allah is Pardoner, Forgiving.","এটা নিয়ম করা হয়েছে যে যদি কেউ তার উপর আরোপিত কোন অবিচারের প্রতিশোধ গ্রহণ করে, ন্যায়সঙ্গতভাবে, এরপর এর কারনে নির্যাতিত হয়, আল্লাহ অবশ্যই তাকে সমর্থন করবেন। আল্লাহ ক্ষমাকারী, ক্ষমাশীল।"],
  "22:61": ["It is a fact that Allah merges the night into the day, and merges the day into the night, and that Allah is Hearer, Seer.","এটি বাস্তবতা যে আল্লাহ রাতকে দিনের সাথে মিলিয়ে দেন, এবং দিনকে রাতের সাথে মিলিয়ে দেন, এবং যে আল্লাহ শ্রোতা, দ্রষ্টা।"],
  "22:62": ["It is a fact that Allah is the Truth, while the setting up of any idols beside Him constitutes a falsehood, and that Allah is the Most High, the Supreme.","এটি বাস্তবতা যে আল্লাহ হচ্ছেন সত্য, যেখানে তাঁর পাশে কোন উপাস্য স্থাপন করা হচ্ছে এক মিথ্যা দাড় করানো, এবং যে আল্লাহ সর্বোচ্চ, সর্বপ্রধান।"],
  "22:63": ["Do you not see that Allah sends down from the sky water that turns the land green? Allah is Sublime, Cognizant.","তুমি কি দেখো না যে আল্লাহ আকাশ থেকে পানি বর্ষণ করেন যা ভূমিকে সবুজে করে তোলে? আল্লাহ মহিমান্বিত, জ্ঞাতা।"],
  "22:64": ["To Him belongs everything in the heavens and everything on earth. Absolutely, Allah is the Most Rich, Most Praiseworthy.","তাঁর অধীনে রয়েছে আকাশ মণ্ডলীর সবকিছু এবং পৃথিবীর সবকিছু। নিঃসন্দেহে, আল্লাহ সবচেয়ে ধনী, সবচেয়ে প্রশংসনীয়।"],
  "22:65": ["Do you not see that Allah has committed in your service everything on earth? The ships run in the ocean by His command. He prevents the heavenly bodies from crashing onto the earth, except in accordance with His command. Allah is Most Kind towards the people, Most Merciful.","তুমি কি দেখনা যে আল্লাহ তোমাদের সেবায় নিয়োজিত করেছেন পৃথিবীর সব কিছু? জাহাজগুলো মহাসাগরে তাঁর আদেশ মত চলে। তিনি আকাশস্থ বস্তুগুলোকে পৃথিবীর সাথে সংঘর্ষ হওয়া থেকে বিরত রাখেন, তাঁর আদেশ অনুসারে ব্যতীত। আল্লাহ লোকদের প্রতি পরম দয়ালু, পরম করুণাময়।"],
  "22:66": ["He is the One who granted you life, then He puts you to death, then He brings you back to life. Surely, the human being is unappreciative.","তিনিই সে সত্ত্বা যিনি তোমাদেরকে জীবন দান করেছেন, এরপর তিনি তোমাদেরকে মৃত্যু দেন, এরপর তিনি তোমাদেরকে জীবন ফিরিয়ে দেন। নিশ্চয়, মানুষ অকৃতজ্ঞ।"],
  "22:67": ["For each congregation, we have decreed a set of rites that they must uphold. Therefore, they should not dispute with you. You shall continue to invite everyone to your Lord. Most assuredly, you are on the right path.","প্রত্যেক ধর্মগোষ্ঠীর জন্য, আমরা আদেশ করেছি কিছু ধর্মানুষ্ঠান যা তাদেরকে অবশ্যই পালন করতে হবে। অতএব, তাদের উচিত নয় তোমার সাথে তর্ক করা। তুমি তোমার প্রভুর দিকে সকলকে নিমন্ত্রন করতে থাকবে। অবশ্যই, তুমি সঠিক পথে রয়েছ।"],
  "22:68": ["If they argue with you, then say, \"Allah is fully aware of everything you do.\"","যদি তারা তোমার সাথে তর্ক করে, তবে বল, “তোমরা যা কিছুই করো আল্লাহ তা সম্পর্কে পুরোপুরি অবগত”।"],
  "22:69": ["Allah will judge among you on the Day of Resurrection regarding all your disputes.","পুনরুত্থান দিনে আল্লাহ তোমাদের মধ্যে বিচার করবেন তোমাদের সকল বিতর্ক নিয়ে।"],
  "22:70": ["Do you not realize that Allah knows everything in the heavens and everything on earth? All this is recorded in a record. This is easy for Allah to do.","তোমরা কি উপলব্ধি করো না যে আল্লাহ আকাশমণ্ডলীর সবকিছু এবং পৃথিবীর সবকিছু জানেন? এই সবকিছু এক নথীতে নথিভুক্ত আছে। এটা করা আল্লাহর জন্য সহজ।"],
  "22:71": ["Yet, they idolize beside Allah idols wherein He placed no power, and they know nothing about them. The transgressors have no helper.","তবুও, তারা আল্লাহর পাশে উপাস্যদের উপাসনা করে যাতে তিনি কোন ক্ষমতা রাখেননি। সীমালঙ্ঘনকারীদের কোন সাহায্যকারী নেই।"],
  "22:72": ["When our revelations are recited to them, clearly, you recognize wickedness on the faces of those who disbelieve. They almost attack those who recite our revelations to them. Say, \"Shall I inform you of something much worse? Hell is promised by Allah for those who disbelieve; what a miserable destiny.\"","যখন আমাদের প্রকাশনাবলী তাদের কাছে আবৃত্তি করা হয়, স্পষ্টভাবে, তুমি তাদের মুখমণ্ডলে পাপ দেখতে পাবে যারা অবিশ্বাস করে। তারা তাদেরকে প্রায় আক্রমণই করে বসে যারা তাদের কাছে আমাদের প্রকাশনাবলী আবৃত্তি করে। বল, “আমি কি তোমাদেরকে আরও খারাপ কিছু সম্পর্কে জানাবো? আল্লাহ নরকের অঙ্গীকার করেছেন তাদের জন্য যারা অবিশ্বাস করে; কি এক শোচনীয় নিয়তি।\""],
  "22:73": ["O people, here is a parable that you must ponder carefully: the idols you set up beside Allah can never create a fly, even if they banded together to do so. Furthermore, if the fly steals anything from them, they cannot recover it; weak is the pursuer and the pursued.","হে লোকেরা, এই যে এক উপমা যা তোমাদেরকে অবশ্যই সতর্ককতার সাথে ভেবে দেখতে হবেঃ আল্লাহর পাশে তোমরা যে উপাস্যদের স্থাপন করো তারা একটি মাছিও সৃষ্টি করতে পারে না, এমনকি যদি তারা তা করতে একত্রে সঙ্গবদ্ধ/দলবদ্ধ হয়। উপরন্তু, যদি মাছি তাদের কাছ থেকে কোন কিছু চুরি করে,  তারা সেটা পুনরুদ্ধার করতে পারে না; অনুসরণকারী এবং অনুসৃত উভয়ই দূর্বল।"],
  "22:74": ["They do not value Allah as He should be valued. Allah is the Most Powerful, the Almighty.","তারা আল্লাহকে মুল্যায়ন করে না যেভাবে তাঁকে মুল্যায়ন করা উচিৎ। আল্লাহ সবচেয়ে ক্ষমতাধর, সর্বশক্তিমান।"],
  "22:75": ["Allah chooses from among the angels messengers, as well as from among the people. Allah is Hearer, Seer.","আল্লাহ ফেরেশতাদের মধ্য থেকে বার্তাবাহকদের বাছাই করেন, একইভাবে মানুষদের মধ্য থেকেও। আল্লাহ শ্রোতা, দ্রষ্টা।"],
  "22:76": ["He knows their past and their future. To Allah belongs the ultimate control of all matters.","তিনি জানেন তাদের অতীত এবং তাদের ভবিষ্যৎ। আল্লাহর অধীনেই সবকিছুর চূড়ান্ত নিয়ন্ত্রন।"],
  "22:77": ["O you who believe, you shall bow, prostrate, worship your Lord, and work righteousness, that you may succeed.","হে তোমরা যারা বিশ্বাস করো, তোমরা রুকু করবে, সেজদা করবে, তোমাদের প্রভুর উপাসনা করবে, এবং সৎ কাজ করবে, যাতে তোমরা সফল হতে পারো।"],
  "22:78": ["You shall strive for the cause of Allah as you should strive for His cause. He has chosen you and has placed no hardship on you in practicing your religion—the religion of your father Abraham. He is the one who named you \"Submitters\" originally. Thus, the messenger shall serve as a witness among you, and you shall serve as witnesses among the people. Therefore, you shall observe the Contact Prayers (Salat) and give the obligatory charity (Zakat), and hold fast to Allah; He is your Lord, the best Lord and the best Supporter.","তোমরা আল্লাহর উদ্দেশ্যে সংগ্রাম করবে যেভাবে তাঁর উদ্দেশ্যে তোমাদের সংগ্রাম করা উচিত। তিনি তোমাদের পছন্দ করেছেন এবং তোমাদের উপর কোন কষ্ট আরোপ করেননি তোমাদের ধর্ম চর্চায় –তোমাদের পিতা ইব্রাহীমের ধর্ম। সে-ই প্রথম তোমাদের নাম দিয়েছিল “মুসলিম’। সুতরাং, বার্তাবাহক তোমাদের মধ্যে সাক্ষী হিসেবে কাজ করবে, এবং তোমরা লোকেদের মধ্যে সাক্ষী হিসেবে কাজ করবে। অতএব, তোমরা সংযোগ প্রার্থনা (সালাত) পালন করবে এবং বাধ্যতামূলক দান (যাকাত) দেবে, এবং আল্লাহকে  দৃঢ়ভাবে  ধারণ করবে; তিনি তোমাদের প্রভু, সর্বশ্রেষ্ঠ প্রতিপালক এবং সর্বশ্রেষ্ঠ সমর্থনকারী।"],
};
